package.preload["sha256"] = function()
    local bit = bit
    local band, bor, bxor = bit.band, bit.bor, bit.bxor
    local rshift, lshift, bnot, ror = bit.rshift, bit.lshift, bit.bnot, bit.ror
    local tohex = bit.tohex

    local K = {
        0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,
        0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,
        0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,
        0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,
        0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,
        0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,
        0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,
        0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2
    }

    local function add32(a, b, c, d, e)
        return band(a + b + (c or 0) + (d or 0) + (e or 0), 0xFFFFFFFF)
    end

    local function preprocess(msg)
        local len = #msg
        local bitlen = len * 8
        local hi = math.floor(bitlen / 4294967296)
        local lo = bitlen - hi * 4294967296

        msg = msg .. "\128"
        local pad = (56 - (#msg % 64)) % 64
        if pad > 0 then
            msg = msg .. string.rep("\0", pad)
        end

        return msg .. string.char(
            band(rshift(hi, 24), 0xFF),
            band(rshift(hi, 16), 0xFF),
            band(rshift(hi, 8), 0xFF),
            band(hi, 0xFF),
            band(rshift(lo, 24), 0xFF),
            band(rshift(lo, 16), 0xFF),
            band(rshift(lo, 8), 0xFF),
            band(lo, 0xFF)
        )
    end

    local function digest(msg)
        msg = preprocess(msg)

        local h0,h1,h2,h3,h4,h5,h6,h7 =
            0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,
            0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19

        local w = {}

        for i = 1, #msg, 64 do
            for j = 1, 16 do
                local o = i + (j - 1) * 4
                w[j] = bor(
                    lshift(string.byte(msg, o), 24),
                    lshift(string.byte(msg, o + 1), 16),
                    lshift(string.byte(msg, o + 2), 8),
                    string.byte(msg, o + 3)
                )
            end

            for j = 17, 64 do
                local v15 = w[j - 15]
                local v2 = w[j - 2]
                local s0 = bxor(ror(v15, 7), ror(v15, 18), rshift(v15, 3))
                local s1 = bxor(ror(v2, 17), ror(v2, 19), rshift(v2, 10))
                w[j] = add32(w[j - 16], s0, w[j - 7], s1)
            end

            local a,b,c,d,e,f,g,h = h0,h1,h2,h3,h4,h5,h6,h7

            for j = 1, 64 do
                local S1 = bxor(ror(e, 6), ror(e, 11), ror(e, 25))
                local ch = bxor(band(e, f), band(bnot(e), g))
                local t1 = add32(h, S1, ch, K[j], w[j])
                local S0 = bxor(ror(a, 2), ror(a, 13), ror(a, 22))
                local maj = bxor(band(a, b), band(a, c), band(b, c))
                local t2 = add32(S0, maj)

                h = g
                g = f
                f = e
                e = add32(d, t1)
                d = c
                c = b
                b = a
                a = add32(t1, t2)
            end

            h0 = add32(h0, a)
            h1 = add32(h1, b)
            h2 = add32(h2, c)
            h3 = add32(h3, d)
            h4 = add32(h4, e)
            h5 = add32(h5, f)
            h6 = add32(h6, g)
            h7 = add32(h7, h)
        end

        return tohex(h0, 8) .. tohex(h1, 8) .. tohex(h2, 8) .. tohex(h3, 8) ..
            tohex(h4, 8) .. tohex(h5, 8) .. tohex(h6, 8) .. tohex(h7, 8)
    end

    local M = {}
    function M.sumhexa(msg) return digest(msg or "") end
    function M.sum(msg)
        return (digest(msg or ""):gsub("..", function(b)
            return string.char(tonumber(b, 16))
        end))
    end

    return M
end



