misc._indicator_sizes_paint = function()
    if not misc._indicator_sizes_print_req then return end
    misc._indicator_sizes_print_req = false

    if not renderer or not renderer.measure_text then
        local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
        if logs and logs.printl then
            logs.printl(
                {ui_col, "osmanhook > "},
                {colors.gray, "Indicator sizes: (renderer unavailable)"}
            )
        else
            client.log("Indicator sizes: (renderer unavailable)")
        end
        return
    end

    local line_h = 0
    local y1 = renderer.indicator(0, 0, 0, 0, "__osind_a")
    local y2 = renderer.indicator(0, 0, 0, 0, "__osind_b")
    if y1 ~= nil and y2 ~= nil then
        line_h = math.abs((tonumber(y2) or 0) - (tonumber(y1) or 0))
    end
    if line_h <= 0 then
        local _, h = renderer.measure_text(nil, "X")
        line_h = tonumber(h) or 0
    end
    do
        local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
        local msg = string.format("GameSense indicator size: %dpx", tonumber(line_h) or 0)
        if logs and logs.printl then
            logs.printl(
                {ui_col, "osmanhook > "},
                {colors.gray, msg}
            )
        else
            client.log(msg)
        end
    end

    local function is_active(ref)
        if ref == nil then return false end
        if type(ref) == "number" then
            local ok, v = pcall(ui.get, ref)
            return ok and v == true
        end
        if type(ref) == "table" then
            local a = ref[1]
            local b = ref[2]
            if a ~= nil and b ~= nil then
                local ok1, v1 = pcall(ui.get, a)
                local ok2, v2 = pcall(ui.get, b)
                return ok1 and ok2 and v1 == true and v2 == true
            end
            if a ~= nil then
                local ok, v = pcall(ui.get, a)
                return ok and v == true
            end
        end
        return false
    end

    local labels = {
        ["Double tap"] = "DT",
        ["Onshot anti-aimbot"] = "OS",
        ["Force body aim"] = "BAIM",
        ["Damage override"] = "DMG",
        ["Force safe point"] = "SAFE",
        ["Quick peek assist"] = "QP",
        ["Duck peek assist"] = "DUCK",
        ["Freestands"] = "FS",
        ["Force head aim"] = "HEAD",
        ["Jumpshot"] = "JUMP",
        ["Anti-aimbot inverted"] = "INV",
        ["Edgeyaw"] = "EDGE",
        ["Ping spike"] = "PING",
        ["Hitchance override"] = "HC",
        ["Dormant aimbot"] = "DORM",
        ["Lower body yaw breaker"] = "LBY",
        ["Delay shot"] = "DS",
        ["Free look"] = "FREE",
        ["Auto smoke"] = "SMOKE",
    }

    do
        local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
        if logs and logs.printl then
            logs.printl(
                {ui_col, "osmanhook > "},
                {colors.gray, "GameSense feature indicators (active):"}
            )
        else
            client.log("GameSense feature indicators (active):")
        end
    end
    local any = false
    if visuals and type(visuals.keybinding) == "table" then
        for i = 1, #visuals.keybinding do
            local entry = visuals.keybinding[i]
            local nm = entry and entry[1]
            local ref = entry and entry[2]
            if type(nm) == "string" and is_active(ref) then
                any = true
                local short = labels[nm] or nm
                local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
                local msg = string.format("%s (%s): %dpx", tostring(short), tostring(nm), tonumber(line_h) or 0)
                if logs and logs.printl then
                    logs.printl(
                        {ui_col, "osmanhook > "},
                        {colors.gray, msg}
                    )
                else
                    client.log(msg)
                end
            end
        end
    end
    if not any then
        local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
        if logs and logs.printl then
            logs.printl(
                {ui_col, "osmanhook > "},
                {colors.gray, "(none active)"}
            )
        else
            client.log("(none active)")
        end
    end
end
