pui.max = function(var1, var2, mode, specialsvalue)
    local md1, md2;
    if specialsvalue then
        md1 = mode(specialsvalue, var1)
        md2 = mode(specialsvalue, var2)
    else
        md1 = mode(var1)
        md2 = mode(var2)
    end
    return math.max(md1, md2) == md1 and var1 or var2
end
pui.distance = function(origin1, origin2)
    return math.sqrt((origin2.x - origin1.x)^2 + (origin2.y - origin1.y)^2)
end
pui.vecsum = function(vec1, vec2)
