pui.fade_anim = function(speed, color1, color2, text)
    local final_text = ''
    local curtime = globals.curtime()

    for i = 0, #text do
        local x_offset = i * 10
        local wave = math.cos(8 * speed * curtime + x_offset / 30)
        local color = string.format('%02x%02x%02x%02x',
            pui.lerp(color1[1], color2[1], pui.clamp(wave, 0, 1)),
            pui.lerp(color1[2], color2[2], pui.clamp(wave, 0, 1)),
            pui.lerp(color1[3], color2[3], pui.clamp(wave, 0, 1)),
            color1[4]
        )
        final_text = final_text .. '\a' .. color .. text:sub(i, i)
    end
    return final_text
end
pui.bliss_anim = function(speed, color1, color2, text)
    local final_text = ''
    local rt = globals.realtime() or 0
    local pulse = math.sin(rt) * 0.5 + 0.5
    local spd = tonumber(speed) or 2

    for i = 1, #text do
        local phase = rt * spd + i * 0.35
        local wave = math.sin(phase) * 0.5 + 0.5
        local mix = pui.clamp(wave * 0.7 + pulse * 0.3, 0, 1)
        local color = string.format('%02x%02x%02x%02x',
            pui.lerp(color1[1], color2[1], mix),
            pui.lerp(color1[2], color2[2], mix),
            pui.lerp(color1[3], color2[3], mix),
            color1[4]
        )
        final_text = final_text .. '\a' .. color .. text:sub(i, i)
    end
    return final_text
end
pui.get_table = function(tabl)
    if type(tabl) == "number" and ui.type(tabl) ~= "button" and ui.type(tabl) ~= "textbox" and ui.type(tabl) ~= "listbox" then
      if ui.type(tabl) == "color_picker" or ui.type(tabl) == "hotkey" then
        return {ui.get(tabl)}
      else
        return ui.get(tabl)
      end
    elseif type(tabl) == "table" then
        local gtlv = {}
        for key, val in pairs(tabl) do
            gtlv[key] = pui.get_table(val)
        end
        return gtlv
    end
end

local function closest_ray_point(p, s, e)
    local t = p - s
    local d = e - s
    local l = d:length()
    if l == 0 then
        return s
    end
    d = d / l
    local r = d:dot(t)
    if r < 0 then
        return s
    elseif r > l then
        return e
    end
    return s + d * r
end

misc.namespam = function(reset)
    if reset then
        if cvar.voice_loopback then cvar.voice_loopback:set_int(0) end
        return
    end
    if not tabs or not tabs["Misc"] or not tabs["Misc"].namespam then return end
    if not ui.get(tabs["Misc"].namespam[1]) then return end
    local pname = ui.get(tabs["Misc"].namespam[2])
    if pname == nil or pname == '' then pname = "osmanhook $$$" end
    client.set_cvar("name", "\x81 " .. pname)
    if cvar.voice_loopback then
        local v = cvar.voice_loopback:get_int()
        cvar.voice_loopback:set_int(v == 0 and 1 or 0)
    end
end

antiaims.point_to_enemy_enforce = function(cmd)
    if not antiaims.point_at_enemy_180_active then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local target_idx = antiaims.target or client.current_threat()
    if target_idx == nil then return end
    local tpose = vector(entity.hitbox_position(target_idx, 0))
    local lpose = vector(client.eye_position())
    if not tpose or not lpose then return end
    local pitcht, yawt = lpose:to(tpose):angles()
    if antiaims.point_at_enemy_mode == "point" then
        cmd.yaw = pui.normalize_yaw(yawt)
    else
        do
            local _, vYaw = client.camera_angles()
            local delta = pui.normalize_yaw(yawt - vYaw)
            local offset = (delta > 0) and 90 or -90
            cmd.yaw = pui.normalize_yaw(yawt + offset)
        end
    end
    local def = antiaims.to_apply and antiaims.to_apply.defensive

    local dp = def and def.pitch or nil
    local pval = nil
    if def and dp and dp ~= "Default" then
        local dc = def.pitchc and def.pitchc[dp]
        if dp == "Up" then
            pval = -89
        elseif dp == "Down" then
            pval = 89
        elseif dp == "Zero" then
            pval = 0
        elseif dp == "Custom" then
            pval = dc
        elseif dp == "Random" then
            pval = client.random_float(-89, 89)
        elseif dp == "Random v2" then
            if type(dc) == "table" then pval = client.random_int(dc[1], dc[2]) end
        elseif dp == "Fluctate" and type(dc) == "table" then
            antiaims.fluctate_handler(cmd, dc[2], dc[3], (dc[4]*0.01)*20, dc[1])
            pval = antiaims.fluctate_def and antiaims.fluctate_def[antiaims.current_cond]
        elseif dp == "Jitter" and type(dc) == "table" then
            antiaims.pitchjit_hamdler(cmd, dc[1], dc[2])
            pval = antiaims.pitch_jit and antiaims.pitch_jit[antiaims.current_cond]
        elseif dp == "L&R" and type(dc) == "table" then
            pval = antiaims.current_side and dc[1] or dc[2]
        end
    else
        local pmode = antiaims.to_apply and antiaims.to_apply.pitch
        if pmode == "Up" then
            pval = -89
        elseif pmode == "Down" then
            pval = 89
        elseif pmode == "Random" then
            pval = client.random_float(-89, 89)
        elseif pmode == "Custom" then
            pval = antiaims.to_apply.pitchc and antiaims.to_apply.pitchc[1]
        elseif pmode == "Off" then
            pval = nil
        else
            local gs_mode = ui.get(skeetgui.aagui.angles.pitch[1])
            if gs_mode == "Off" then
                pval = nil
            elseif gs_mode == "Up" then
                pval = -89
            elseif gs_mode == "Down" then
                pval = 89
            elseif gs_mode == "Random" then
                pval = client.random_float(-89, 89)
            elseif gs_mode == "Custom" then
                pval = ui.get(skeetgui.aagui.angles.pitch[2])
            end
        end
    end
    if pval ~= nil then
        if pval > 89 then pval = 89 end
        if pval < -89 then pval = -89 end
        cmd.pitch = pval
    end
end
pui.split = function(inputstr, sep)
    if sep == nil then
      sep = "%s"
    end
    local t = {}
    for str in string.gmatch(inputstr, "([^"..sep.."]+)") do
      table.insert(t, str)
    end
    return t
end
