pui.split_num = function(number, sep)
    local temp = {}
    for dig in tostring(number):gmatch("%d") do
        table.insert(temp, tonumber(dig))
    end
    return table.concat(temp, sep)
end
function outlined_rectangle(x, y, w, h, r, g, b, a, thickness)
    local data = {
        {x, y, w, thickness},
        {x, y + h - thickness, w, thickness},
        {x, y, thickness, h},
        {x + w - thickness, y, thickness, h},
    }
    for _, data in next, data do
        renderer.rectangle(data[1], data[2], data[3], data[4], r, g, b, a)
    end
end

local function win95_window(x, y, w, h, title, alpha, active)
    alpha = alpha or 255
    if active == nil then active = true end
    local white = {255, 255, 255, alpha}
    local light_gray = {223, 223, 223, alpha}
    local gray = {192, 192, 192, alpha}
    local dark_gray = {128, 128, 128, alpha}
    local black = {0, 0, 0, alpha}
    local blue = {0, 0, 128, alpha}

    renderer.rectangle(x, y, w, h, gray[1], gray[2], gray[3], alpha)
    renderer.rectangle(x, y, w, 1, white[1], white[2], white[3], alpha)
    renderer.rectangle(x, y, 1, h, white[1], white[2], white[3], alpha)
    renderer.rectangle(x + w - 1, y, 1, h, dark_gray[1], dark_gray[2], dark_gray[3], alpha)
    renderer.rectangle(x, y + h - 1, w, 1, dark_gray[1], dark_gray[2], dark_gray[3], alpha)
    renderer.rectangle(x + 1, y + 1, w - 2, h - 2, light_gray[1], light_gray[2], light_gray[3], alpha)

    local title_h = 18
    local bar_col = active and blue or dark_gray
    local text_col = active and white or black
    renderer.rectangle(x + 4, y + 4, w - 8, title_h, bar_col[1], bar_col[2], bar_col[3], alpha)
    renderer.text(x + 8, y + 8, text_col[1], text_col[2], text_col[3], alpha, "b", 0, title or "")

    local bw, bh = 16, 14
    local bx, by = x + w - 6 - bw, y + 6
    renderer.rectangle(bx, by, bw, bh, gray[1], gray[2], gray[3], alpha)
    renderer.rectangle(bx, by, bw, 1, white[1], white[2], white[3], alpha)
    renderer.rectangle(bx, by, 1, bh, white[1], white[2], white[3], alpha)
    renderer.rectangle(bx + bw - 1, by, 1, bh, dark_gray[1], dark_gray[2], dark_gray[3], alpha)
    renderer.rectangle(bx, by + bh - 1, bw, 1, dark_gray[1], dark_gray[2], dark_gray[3], alpha)
    renderer.text(bx + math.floor(bw / 2) - 1, by + 4, black[1], black[2], black[3], alpha, "c", 0, "x")

    return title_h
end



local function rounded_rect(x, y, w, h, r, g, b, a, radius)
    y = y + radius
    local data_circle = {
        {x + radius, y, 180},
        {x + w - radius, y, 90},
        {x + radius, y + h - radius * 2, 270},
        {x + w - radius, y + h - radius * 2, 0},
    }

    local data = {
        {x + radius, y, w - radius * 2, h - radius * 2},
        {x + radius, y - radius, w - radius * 2, radius},
        {x + radius, y + h - radius * 2, w - radius * 2, radius},
        {x, y, radius, h - radius * 2},
        {x + w - radius, y, radius, h - radius * 2},
    }

    for _, data in next, data_circle do
        renderer.circle(data[1], data[2], r, g, b, a, radius, data[3], 0.25)
    end

    for _, data in next, data do
        renderer.rectangle(data[1], data[2], data[3], data[4], r, g, b, a)
    end
end
local function outlined_rounded_rect(x, y, w, h, r, g, b, a, radius, thickness)
    y = y + radius
    local data_circle = {
        {x + radius, y, 180},
        {x + w - radius, y, 270},
        {x + radius, y + h - radius * 2, 90},
        {x + w - radius, y + h - radius * 2, 0},
    }

    local data = {
        {x + radius, y - radius, w - radius * 2, thickness},
        {x + radius, y + h - radius - thickness, w - radius * 2, thickness},
        {x, y, thickness, h - radius * 2},
        {x + w - thickness, y, thickness, h - radius * 2},
    }

    for _, data in next, data_circle do
        renderer.circle_outline(data[1], data[2], r, g, b, a, radius, data[3], 0.25, thickness)
    end

    for _, data in next, data do
        renderer.rectangle(data[1], data[2], data[3], data[4], r, g, b, a)
    end
end







