function _G.ui.new_label(tab, container, name)
    local ind
    local final_name
    if type(name) == "table" then
        final_name = table.concat(name)
    else
        final_name = name ~= nil and tostring(name) or " "
    end
    if final_name == "" then final_name = " " end
    local ok, res = pcall(pui.oglabel, tab, container, final_name)
    if ok then
        ind = res
        pui.uinames[ind] = type(name) == "table" and name[#name] or final_name
    else
        ind = pui.oglabel(tab, container, " ")
        pui.uinames[ind] = " "
    end
    if pui._controls_hook_active and tab == "AA" and container == "Other" then
        table.insert(pui.controls_other, ind)
        ui.set_visible(ind, false)
    elseif pui._controls_hook_active and tab == "AA" and container == "Fake lag" then
        table.insert(pui.controls_fakelag, ind)
    end
    return ind
end

