function _G.ui.name(item)
	if item == nil then
		return nil
	end
	local name
	if pui.in_table(pui.uinames, item, true) then
		name = pui.uinames[item]
	elseif type(item) == "number" then
		name = pui.ogname(item)
	else
		name = nil
	end
	return name
end

if not pui.ui_ref then
	pui.ui_ref = function(x)
		if x == nil then return nil end
		local t = type(x)
		if t == "number" then return x end
		if t ~= "table" then return x end

		local seen = {}
		local cur = x
		while type(cur) == "table" and not seen[cur] do
			seen[cur] = true

			local r = rawget(cur, "ref")
			if type(r) == "number" then return r end
			if type(r) == "table" then
				cur = r
				goto continue
			end

			local r1 = rawget(cur, 1)
			if type(r1) == "number" then return r1 end
			if type(r1) == "table" then
				cur = r1
				goto continue
			end

			break
			::continue::
		end

		return x
	end
end

if not pui._ui_pui_compat then
	pui._ui_pui_compat = true
	pui.og_ui_get = pui.og_ui_get or ui.get
	pui.og_ui_set = pui.og_ui_set or ui.set
	pui.og_ui_set_visible = pui.og_ui_set_visible or ui.set_visible
	pui.og_ui_set_callback = pui.og_ui_set_callback or ui.set_callback
	pui.og_ui_update = pui.og_ui_update or ui.update

	ui.get = function(control, ...)
		local ref = pui.ui_ref(control)
		if ref == nil or type(ref) ~= "number" then return nil end
		
		local ok, r1, r2, r3, r4, r5 = pcall(pui.og_ui_get, ref, ...)
		if not ok then return nil end
		return r1, r2, r3, r4, r5
	end

	ui.set = function(control, ...)
		local ref = pui.ui_ref(control)
		if ref == nil or type(ref) ~= "number" then return nil end
		local ok = pcall(pui.og_ui_set, ref, ...)
		if not ok then return nil end
		return true
	end

	ui.set_visible = function(control, ...)
		local ref = pui.ui_ref(control)
		if ref == nil or type(ref) ~= "number" then return nil end
		local visible = select(1, ...)
		if not visible and skeetgui then
			
			
			local function _scan(t)
				local rid = pui.ui_ref(t)
				if rid ~= nil and rid == ref then
					return true
				end
				if type(t) == "table" then
					for _, v in pairs(t) do
						if _scan(v) then return true end
					end
				end
				return false
			end
			
			if skeetgui.ragegui and _scan(skeetgui.ragegui) then
				return
			end
			if skeetgui.configgui and _scan(skeetgui.configgui) then
				return
			end
		end
		local ok = pcall(pui.og_ui_set_visible, ref, visible)
		if not ok then return nil end
		return true
	end

	ui.set_callback = function(control, ...)
		local ref = pui.ui_ref(control)
		if ref == nil or type(ref) ~= "number" then return nil end
		local ok = pcall(pui.og_ui_set_callback, ref, ...)
		if not ok then return nil end
		return true
	end

	ui.update = function(control, ...)
		local ref = pui.ui_ref(control)
		if ref == nil or type(ref) ~= "number" then return nil end
		local ok = pcall(pui.og_ui_update, ref, ...)
		if not ok then return nil end
		return true
	end
end

