local function _strip_menu_prefix(s)
    if type(s) ~= "string" then return s end
    local out = s
    for _ = 1, 6 do
        local b0 = string.byte(out, 1)
        local is_color = out:sub(1, 1) == "\a"
        local is_unicode = (b0 ~= nil and b0 > 127)
        if not is_color and not is_unicode then
            break
        end
        local stripped = (out:gsub("^%S+%s+", ""))
        if stripped == out then
            break
        end
        out = stripped
    end
    return out
end

pui.switch_get = function()
    local v = ui.get(switch)
    if type(v) ~= "string" then return v end
    local name = _strip_menu_prefix(v)
    if name == "Overview" then return "Home" end
    if name == "Anti-Aimbot angles" then return "Anti-aimbot angles" end
    if name == "Aimtools" then return "Rage" end
    if name == "Manipulations" or (type(name) == "string" and name:find("Manipulations", 1, true)) then return "Manipulations" end
    return name
end

