    if not tabs or not tabs["Home"] then return end
    local h = tabs["Home"]

    local function _sv(x, v)
        if x == nil then return end
        if pui.visibleparse then
            pcall(pui.visibleparse, x, v)
            return
        end
        if type(x) == "table" then
            for _, it in pairs(x) do
                _sv(it, v)
            end
            return
        end
        pcall(ui.set_visible, x, v)
    end

    local main = pui.home_section_get and pui.home_section_get() or "Community configs"
    local other = pui.other_section_get and pui.other_section_get() or nil

    _sv(h.other_section_space, true)
    _sv(h.other_section, true)
    _sv(h.home_section_space, false)
    _sv(h.home_section, false)

    _sv({
        h.overview_hello,
        h.overview_online,
        h.overview_version,
        h.overview_welcome,
    }, false)

    _sv({
        h.cloud_cfg_header,
