        h.cloud_btn_load,
        h.cloud_btn_delete,
        h.cloud_btn_like,
        h.author_label,
        h.likes_label,
        h.loads_label,
        h.updated_label
    }, true)

    local show_socials = (other == "Socials" or other == 1)
    local show_cfg_update = (other == "Cloud" or other == 2)
    local show_stats = (other == "Stats" or other == 3)

    _sv(h.discord_button, show_socials)
    _sv(h.telegram_button, show_socials)
    _sv(h.cfg_update_combo, show_cfg_update)
    _sv(h.cfg_update_btn, show_cfg_update)
