do
local function get_steam_info()
    local steam_api = panorama.open("CSGOHud")
    local username = steam_api.MyPersonaAPI.GetName()
    local steam_id = steam_api.MyPersonaAPI.GetXuid()

    return {
        username = username,
        steam_id = steam_id
    }
end

local function url_encode(str)
    if str then
        str = string.gsub(str, "\n", "\r\n")
        str = string.gsub(str, "([^%w ])", function(c)
            return string.format("%%%02X", string.byte(c))
        end)
        str = string.gsub(str, " ", "+")
    end
    return str
end

local function auth_url_path(url)
    if type(url) ~= "string" then return "" end
    local p = url:match("^https?://[^/]+(/.*)$") or url
    p = p:match("^[^?]+") or p
    if p == "" then p = "/" end
    return p
end

local AUTH_CLIENT_SECRET = "asdasd123"

local auth = {
    
    client_secret = "asdasd123",
    
    session_key = nil,
    
    session_expires = 0
}


local function hmac_sha256(key, message)
    local sha256 = require("sha256")
    local block_size = 64
    
    
    if #key > block_size then
        key = sha256.sum(key)
    end
    if #key < block_size then
        key = key .. string.rep("\0", block_size - #key)
    end
    
    
    local o_key_pad = ""
    local i_key_pad = ""
    for i = 1, block_size do
        local byte = string.byte(key, i)
        o_key_pad = o_key_pad .. string.char(bit.bxor(byte, 0x5c))
        i_key_pad = i_key_pad .. string.char(bit.bxor(byte, 0x36))
    end
    
    
    local inner_hash = sha256.sumhexa(i_key_pad .. message)
    local inner_hash_bin = inner_hash:gsub("..", function(b)
        return string.char(tonumber(b, 16))
    end)
    local hmac = sha256.sumhexa(o_key_pad .. inner_hash_bin)
    
    return hmac
end


local function sign_request(method, url, body, timestamp)
    method = method:upper()
    timestamp = timestamp or tostring(client.unix_time())
    body = body or ""
    
    
    local message = method .. "\n" .. auth_url_path(url) .. "\n" .. timestamp .. "\n" .. body
    
    
    local combined_secret = AUTH_CLIENT_SECRET
    if auth.session_key then
        combined_secret = combined_secret .. auth.session_key
    end
    
    
    local signature = hmac_sha256(combined_secret, message)
    
    return signature, timestamp
end


local function auth_init_session(callback)
    local steam = get_steam_info()
    local url = online_counter.server_url .. "/api/auth/init"
    local timestamp = tostring(client.unix_time())
    
    
    local message = "POST\n" .. auth_url_path(url) .. "\n" .. timestamp .. "\n"
    local signature = hmac_sha256(AUTH_CLIENT_SECRET, message)
    
    local body = json.stringify({
        steam_id = steam.steam_id,
        username = steam.username,
        timestamp = timestamp,
        signature = signature
    })
    
    http.post(url, {
        body = body,
        headers = {
            ["Content-Type"] = "application/json",
            ["X-Client-Signature"] = signature,
            ["X-Timestamp"] = timestamp
        }
    }, function(success, response)
        if success and response and response.body then
            local ok, data = pcall(json.parse, response.body)
            if ok and data and data.ok and data.session_key then
                auth.session_key = data.session_key
                auth.session_expires = (data.expires or 3600) + client.unix_time()
                if callback then callback(true) end
                return
            end
        end
        if callback then callback(false) end
    end)
end


local function auth_get(url, callback, options)
    options = options or {}
    
    
    if not auth.session_key or client.unix_time() >= auth.session_expires then
        auth_init_session(function(success)
            if success then
                auth_get(url, callback, options)
            else
                if callback then callback(false, nil) end
            end
        end)
        return
    end
    
    local signature, timestamp = sign_request("GET", url, nil)
    
    local headers = options.headers or {}
    headers["X-Client-Signature"] = signature
    headers["X-Timestamp"] = timestamp
    if auth.session_key then
        headers["X-Session-Key"] = auth.session_key
    end
    options.headers = headers
    
    http.get(url, options, function(success, response)
        if callback then callback(success, response) end
    end)
end


local function auth_post(url, options, callback)
    options = options or {}
    local body = options.body or ""
    
    
    if not auth.session_key or client.unix_time() >= auth.session_expires then
        auth_init_session(function(success)
            if success then
                auth_post(url, options, callback)
            else
                if callback then callback(false, nil) end
            end
        end)
        return
    end
    
    local signature, timestamp = sign_request("POST", url, body)
    
    local headers = options.headers or {}
    headers["Content-Type"] = headers["Content-Type"] or "application/json"
    headers["X-Client-Signature"] = signature
    headers["X-Timestamp"] = timestamp
    if auth.session_key then
        headers["X-Session-Key"] = auth.session_key
    end
    
    http.post(url, {
        body = body,
        headers = headers
    }, function(success, response)
        if callback then callback(success, response) end
    end)
end


_G.auth = auth
_G.auth_get = auth_get
_G.auth_post = auth_post
_G.auth_init_session = auth_init_session
_G.get_steam_info = get_steam_info
_G.url_encode = url_encode
end

do
local function online_counter_send_ping()
    online_counter.user_data = _G.get_steam_info()

    local encoded_username = _G.url_encode(online_counter.user_data.username)
    local encoded_steam_id = _G.url_encode(online_counter.user_data.steam_id)

    local ping_url = string.format(
        "%s/api/ping?username=%s&steam_id=%s",
        online_counter.server_url,
        encoded_username,
        encoded_steam_id
    )

    auth_get(ping_url, function(success, response)
        if success and response then
            client.delay_call(0.3, function()
                local online_url = online_counter.server_url .. "/api/online"
                _G.auth_get(online_url, function(s2, r2)
                    local new_count
                    if s2 and r2 and type(r2) == "table" and r2.body then
                        new_count = string.match(r2.body, '"online"[%s]*:[%s]*([%d]+)')
                        if new_count then new_count = tonumber(new_count) end
                    end
                    if new_count then
                        online_counter.count = tostring(new_count)
                    end
                end)
            end)
        end
    end)
end


local function online_counter_update_count()
    local _url = online_counter.server_url .. "/api/online"
    _G.auth_get(_url, function(success, response)
        if not success or not response then
            online_counter.count = "(offline)"
            return
        end

        local count
        if type(response) == "table" and response.body then

            count = string.match(response.body, '"online"[%s]*:[%s]*([%d]+)')


            if count then
                count = tonumber(count)
            end
        end

        if count then
            online_counter.count = tostring(count)
        else
            online_counter.count = "(offline)"
        end
    end)
end


_G.auth_init_session(function(success)
    if success then
        online_counter_send_ping()
        online_counter_update_count()
    else
        online_counter.count = "Auth failed"
    end
end)


_G.online_counter_send_ping = online_counter_send_ping
_G.online_counter_update_count = online_counter_update_count
end

do
local network_resolver = {
    history = {},
    player_records = {},
    last_simulation_time = {},
    last_post_time = {},
