    enabled = false
}

local function _get_resolver_control()
    if not tabs or not tabs["Rage"] then return nil end
    return tabs["Rage"].resolver
end

local function resolver_is_enabled()
    local ctrl = _get_resolver_control()
    if not ctrl then return false end
    if type(ctrl) == "table" then
        local c = ctrl[1] or ctrl.checkbox or ctrl.enabled
        return c and ui.get(c) or false
    end
    return ui.get(ctrl)
end

local function on_resolver_toggle_cb()
    local enabled = resolver_is_enabled()
    network_resolver.enabled = enabled
end

local function resolver_http_post(data, callback)
    local sid = tostring(data and data.steam_id or "")
    if sid == "" then return end
    local now = globals.realtime()
    if network_resolver.pending_posts[sid] then return end
    if network_resolver.last_post_time[sid] and (now - network_resolver.last_post_time[sid] < network_resolver.post_interval) then return end
    local success, encoded_data = pcall(json.stringify, data)
    if not success then
        return nil
    end

    local base = tostring(online_counter.server_url or ""):match("^%s*(.-)%s*$")
    local url = base .. "/api/resolver"
    network_resolver.pending_posts[sid] = true
    auth_post(url, { body = encoded_data, headers = { ["Content-Type"] = "application/json" } }, function(success, response)
        if not success or not response or not response.body then
            network_resolver.pending_posts[sid] = false
            network_resolver.last_post_time[sid] = globals.realtime()
            return
        end

        local ok, decoded_response = pcall(json.parse, response.body)
        if ok then
            if callback then callback(decoded_response) end
        end
        network_resolver.pending_posts[sid] = false
        network_resolver.last_post_time[sid] = globals.realtime()
    end)
end

local function get_hitbox_position(player, hitbox)
    local x, y, z = entity.hitbox_position(player, hitbox)
    return x and {x = x, y = y, z = z} or nil
end

function network_resolver.record_player(player)
    if not entity.is_alive(player) then return end

    local steam_id = entity.get_steam64(player)
    local sidn = tonumber(steam_id)
    if not steam_id or sidn == 0 or tostring(steam_id) == "0" then return end

    if not network_resolver.player_records[steam_id] then
        network_resolver.player_records[steam_id] = {
            last_angles = {},
            desync_history = {},
            shot_records = {},
            missed_shots = 0,
            hit_shots = 0,
            learned_side = nil
        }
    end

    local sim_time = entity.get_prop(player, "m_flSimulationTime")
    local eye_angles = {entity.get_prop(player, "m_angEyeAngles")}

    if sim_time ~= network_resolver.last_simulation_time[steam_id] then
        table.insert(network_resolver.player_records[steam_id].last_angles, {
            angles = eye_angles,
            sim_time = sim_time,
            hitbox_pos = get_hitbox_position(player, 0)
        })

        if #network_resolver.player_records[steam_id].last_angles > 8 then
            table.remove(network_resolver.player_records[steam_id].last_angles, 1)
        end

        network_resolver.last_simulation_time[steam_id] = sim_time
    end
end


function network_resolver.resolve_angles(player)
    local steam_id = entity.get_steam64(player)
    local sidn = tonumber(steam_id)
    if not steam_id or sidn == 0 or tostring(steam_id) == "0" or not network_resolver.player_records[steam_id] then return end

    local records = network_resolver.player_records[steam_id]
    if #records.last_angles < 2 then return end

    local angle_delta = records.last_angles[#records.last_angles].angles[2] - records.last_angles[#records.last_angles - 1].angles[2]
    local desync_side = angle_delta > 0 and 1 or -1
    table.insert(records.desync_history, desync_side)

    if #records.desync_history > 5 then
        table.remove(records.desync_history, 1)
    end


    local resolve_angle = records.last_angles[#records.last_angles].angles[2]
    local learned_side = tonumber(records.learned_side)
    if learned_side then
        resolve_angle = resolve_angle + (58 * learned_side)
    end

    return resolve_angle
end

client.set_event_callback("aim_fire", function(fire)
    local steam_id = entity.get_steam64(fire.target)
    local sidn = tonumber(steam_id)
    if not steam_id or sidn == 0 or tostring(steam_id) == "0" then return end
    local records = network_resolver.player_records[steam_id]
    if not records then return end

    resolver_http_post({
        steam_id = tostring(steam_id),
        desync_history = records.desync_history,
        missed_shots = records.missed_shots,
        hit_shots = records.hit_shots or 0,
        total_shots = #records.shot_records
    }, function(response)
        if response and response.learned_side then
            local ls = tonumber(response.learned_side)
            if ls then
                records.learned_side = ls
            end
        end
    end)
end)

function network_resolver.on_shot_fired(e)
    if not network_resolver.enabled then return end

    local target = e.target
    if not target then return end

    local steam_id = entity.get_steam64(target)
    local sidn = tonumber(steam_id)
    if not steam_id or sidn == 0 or tostring(steam_id) == "0" or not network_resolver.player_records[steam_id] then return end

    local rec = network_resolver.player_records[steam_id]
    rec.total_shots = (rec.total_shots or 0) + 1
    table.insert(rec.shot_records, {
        tick = e.tick,
        predicted_angle = rec.last_angles[#rec.last_angles],
        hit = e.hit,
        teleported = e.teleported
    })
end

local last_resolver_update = globals.realtime()
local last_resolver_log = 0
function network_resolver.update()
    if not network_resolver.enabled then return end
    if globals.realtime() - last_resolver_update < 0.25 then return end
    last_resolver_update = globals.realtime()

    local targets = entity.get_players(true)
    local processed = 0
    for _, p in ipairs(targets) do
        local __sid = entity.get_steam64(p)
        local __sidn = tonumber(__sid)
        if __sid and (__sidn ~= 0 and tostring(__sid) ~= "0") then
            processed = processed + 1
        end
    end
    if processed > 0 then
        local now = globals.realtime()
        if now - last_resolver_log > 2.0 then
            last_resolver_log = now
        end
    end
    for _, player in ipairs(targets) do
        local sid = entity.get_steam64(player)
        local sidn = tonumber(sid)
        if sid and (sidn ~= 0 and tostring(sid) ~= "0") then
            network_resolver.record_player(player)
            local resolved_angle = network_resolver.resolve_angles(player)
            if resolved_angle then
                plist.set(player, "Force body yaw value", resolved_angle)
            end
        end
    end

    local sel = pui.switch_get and pui.switch_get() or ui.get(switch)
    if sel == "Other" and other_scroll_update then other_scroll_update() end
    local __is_aa = (sel == "Anti-aimbot angles")
    local mode_ctrl = tabs and tabs["Fake lag"] and tabs["Fake lag"].mode or nil
    local anim_ctrl = tabs and tabs["Fake lag"] and tabs["Fake lag"].anim_label or nil
    if not __is_aa then
        for _, id in ipairs(pui.controls_fakelag) do
            local is_info = fakelag_info and (id == fakelag_info.hello or id == fakelag_info.welcome or id == fakelag_info.online or id == fakelag_info.build or id == fakelag_info.section or id == fakelag_info.section_space or id == fakelag_info.anim_label or id == fakelag_info.home_section or id == fakelag_info.home_section_space)
            if not is_info and anim_ctrl ~= nil and id == anim_ctrl then
                is_info = true
            end
            local is_mode = (mode_ctrl ~= nil and id == mode_ctrl)
            if not is_info and not is_mode then
                ui.set_visible(id, false)
            end
        end
    end
end

client.set_event_callback("net_update_end", network_resolver.update)
client.set_event_callback("aim_fire", network_resolver.on_shot_fired)

