    cloud_cfg_names = {}
    cloud_cfg_meta = {}
    cloud_cfg_refresh_list = nil
    function _json_like(s)
        if type(s) ~= "string" then return false end
        local first = s:match("^%s*(.)")
        return first == "{" or first == "["
    end

    function _fmt_date_short(s)
        if type(s) ~= "string" then return s end
        local y, m, d = s:match("^(%d%d%d%d)%-(%d%d)%-(%d%d)")
        if y and m and d then
            return d .. "." .. m .. "." .. y
        end
        return s
    end

    CFG_ICON = " "

    local function _cloud_strip_colors(s)
        if type(s) ~= "string" then return s end
        return (s:gsub("\a%x%x%x%x%x%x%x%x", ""))
    end

    function cloud_cfg_update_meta_labels(name)
        local m = cloud_cfg_meta[name]
        local cd = '\aCDCDCDFF'
        local updated_raw = m and m.updated or "???"
        local updated_fmt = _fmt_date_short(updated_raw)
        if tabs and tabs["Home"] then
            if tabs["Home"].author_label then ui.set(tabs["Home"].author_label, pui.logoh..""..cd.." Author: "..tostring(m and m.author or "unknown")) end
            if tabs["Home"].likes_label then ui.set(tabs["Home"].likes_label, pui.logoh..""..cd.." Likes: "..tostring(m and m.likes or 0)) end
            if tabs["Home"].loads_label then ui.set(tabs["Home"].loads_label, pui.logoh..""..cd.." Loads: "..tostring(m and m.loads or 0)) end
            if tabs["Home"].updated_label then ui.set(tabs["Home"].updated_label, pui.logoh..""..cd.." Last updated: "..tostring(updated_fmt)) end
            if tabs["Home"].cloud_btn_delete_el or tabs["Home"].cloud_btn_delete then
                if tabs["Home"].cloud_btn_delete_el then
                    pcall(function() tabs["Home"].cloud_btn_delete_el:disabled(false) end)
                else
                    pcall(ui.set_enabled, tabs["Home"].cloud_btn_delete, true)
                end
            end
        end
    end

    local function cloud_log(action, name)
        local ui_col = pui.menu_col()
        logs.printl(
            {{255, 255, 255}, "osmanhook > cloud "},
            {ui_col, tostring(action)},
            {ui_col, " \""},
            {ui_col, tostring(name)},
            {ui_col, "\""}
        )
    end
    local function cfg_log(action, name)
