    function cloud_cfg_like_selected()
        local listbox = tabs and tabs["Home"] and tabs["Home"].cloud_cfg_listbox
        local sel = listbox and ui.get(listbox) or nil
        local name
        if type(sel) == "number" then
            name = cloud_cfg_names[sel + 1]
        elseif type(sel) == "string" then
            local s = sel
            s = _cloud_strip_colors(s)
            if type(s) == "string" and s:sub(1, #CFG_ICON) == CFG_ICON then s = s:sub(#CFG_ICON + 1) end
            if s ~= "Cloud is down!" and s ~= "No configs found" then name = s end
        end
        if not name or #name == 0 then
            cfg_error("Select a config first")
            return
        end
        local steam = get_steam_info()
        local url = online_counter.server_url .. "/api/configs?action=like"
        local body = json.stringify({ steam_id = steam.steam_id, name = name })
        auth_post(url, { body = body, headers = { ["Content-Type"] = "application/json" } }, function(success, response)
            if not success or not response or not response.body then
                cfg_error("Cloud request failed")
                return
            end
            if not _json_like(response.body) then
                cfg_error("Cloud request failed")
                return
            end
            local ok, data = pcall(json.parse, response.body)
            if not ok or not data or not data.ok then
                cfg_error(data and data.message or "Like failed")
                return
            end
            cloud_log("Liked", name)
            client.delay_call(0.2, function() cloud_cfg_refresh_list() end)
        end)
    end

    function cloud_cfg_delete_selected()
        local listbox = tabs and tabs["Home"] and tabs["Home"].cloud_cfg_listbox
        local sel = listbox and ui.get(listbox) or nil
        local name
        if type(sel) == "number" then
            name = cloud_cfg_names[sel + 1]
        elseif type(sel) == "string" then
            local s = sel
            s = _cloud_strip_colors(s)
            if type(s) == "string" and s:sub(1, #CFG_ICON) == CFG_ICON then s = s:sub(#CFG_ICON+1) end
            if s ~= "Cloud is down!" and s ~= "No configs found" then name = s end
        end
        if not name or #name == 0 then
            cfg_error("Select a config first")
            return
        end

        local steam = get_steam_info()
        local meta = cloud_cfg_meta[name]
        if not meta or not meta.owner_id or meta.owner_id ~= steam.steam_id then
            cfg_error("You can only delete your own configs")
            return
        end

        local url = online_counter.server_url .. "/api/configs?action=delete"
        local body = json.stringify({ steam_id = steam.steam_id, name = name })
        auth_post(url, { body = body, headers = { ["Content-Type"] = "application/json" } }, function(success, response)
            if not success or not response or not response.body then
                cfg_error("Delete request failed")
                return
            end
            if not _json_like(response.body) then
                cfg_error("Delete request failed")
                return
            end
            local ok, data = pcall(json.parse, response.body)
            if not ok or not data or not data.ok then
                cfg_error(data and data.message or "Delete failed")
                return
            end
            cloud_log("Deleted", name)
            client.delay_call(0.2, function() cloud_cfg_refresh_list() end)
        end)
    end

    cloud_cfg_refresh_list = function()
        local listbox = tabs and tabs["Home"] and tabs["Home"].cloud_cfg_listbox
        local sort_ctrl = tabs and tabs["Home"] and tabs["Home"].cloud_cfg_sort

        local sort_mode = sort_ctrl and ui.get(sort_ctrl) or "Alphabetical"
        local sort_param = ""
        if sort_mode == "Most loaded" then
            sort_param = "&sort=loads"
        elseif sort_mode == "Recently updated" then
            sort_param = "&sort=recent"
        end

        local url = string.format("%s/api/configs?action=list%s", online_counter.server_url, sort_param)
        auth_get(url, function(success, response)
            if not listbox then return end

            local mc = pui.menu_col and pui.menu_col() or {255, 255, 255}
            local r, g, b = tonumber(mc[1]) or 255, tonumber(mc[2]) or 255, tonumber(mc[3]) or 255
            local icon = string.format("\a%02X%02X%02XFF%s\aFFFFFFFF", r, g, b, CFG_ICON)

            if not success or not response or response.status ~= 200 or not response.body then
                ui.update(listbox, {icon.."Cloud is down!"})
                cloud_cfg_names = {}
                return
            end
            if not _json_like(response.body) then
                ui.update(listbox, {icon.."Cloud is down!"})
                cloud_cfg_names = {}
                return
            end
            local ok, data = pcall(json.parse, response.body)
            if not ok then
                ui.update(listbox, {icon.."Cloud is down!"})
                cloud_cfg_names = {}
                return
            end
            local display = {}
            cloud_cfg_names = {}
            if data and data.ok and data.configs then
                for i, item in ipairs(data.configs) do
                    local name = item.name or ("cfg_"..i)
                    cloud_cfg_names[#cloud_cfg_names+1] = name
                    display[#display+1] = icon..name
                    cloud_cfg_meta[name] = {
                        author = item.author,
                        likes = tonumber(item.likes) or 0,
                        loads = tonumber(item.loads) or 0,
                        updated = item.updated or item.last_updated,
                        owner_id = item.owner_id
                    }
                end
            end
            if #display == 0 then
                display = {icon.."No configs found"}
            end
            ui.update(listbox, display)
            local sel = listbox and ui.get(listbox) or nil
            local current
            if type(sel) == "number" then
                current = cloud_cfg_names[sel + 1]
            elseif type(sel) == "string" then
                local s = sel
                s = _cloud_strip_colors(s)
                if type(s) == "string" and s:sub(1, #CFG_ICON) == CFG_ICON then s = s:sub(#CFG_ICON+1) end
                if s ~= "Cloud is down!" and s ~= "No configs found" then current = s end
            end
            if not current then current = cloud_cfg_names[1] end
            if current then cloud_cfg_update_meta_labels(current) end
        end)
    end

