    function cloud_cfg_load_selected()
        local listbox = tabs and tabs["Home"] and tabs["Home"].cloud_cfg_listbox
        local sel = listbox and ui.get(listbox) or nil
        local name
        if type(sel) == "number" then
            name = cloud_cfg_names[sel + 1]
        elseif type(sel) == "string" then
            local s = sel
            s = _cloud_strip_colors(s)
            if type(s) == "string" and s:sub(1, #CFG_ICON) == CFG_ICON then s = s:sub(#CFG_ICON+1) end
            if s ~= "Cloud is down!" and s ~= "No configs found" then name = s end
        end
        if not name or #name == 0 then return end
      local url = string.format("%s/api/configs?action=get&name=%s", online_counter.server_url, url_encode(name))
      auth_get(url, function(success, response)
          if not success or not response or response.status ~= 200 or not response.body then
              return
          end
          if not _json_like(response.body) then
              return
          end
          local ok, data = pcall(json.parse, response.body)
          if not ok then
              return
          end
          if not data or not data.config then
              return
          end
            local parsed
            local ok1, res1 = pcall(json.parse, data.config)
            if ok1 then
                if type(res1) == "table" then
                    parsed = res1
                elseif type(res1) == "string" then
                    local ok2, res2 = pcall(json.parse, res1)
                    if ok2 and type(res2) == "table" then parsed = res2 end
                end
            end
            if not parsed or tonumber(parsed["Version"]) ~= tonumber(_VER) then return end
            local sel = tabs["Configs"].onlyload and ui.get(tabs["Configs"].onlyload) or {}
            local load_all = (#sel == 0)
            for _, v in ipairs(sel) do if v == "All" then load_all = true break end end
            if load_all then
                pui.set_cfg(parsed)
                pui.keypos = parsed["pui.keypos"]
                pui.specpos = parsed["pui.specpos"]
            else
                for _, cat in ipairs(sel) do
                    if cat == "Anti-Aim" then
                        pui.set_cfg(parsed["Anti-Aimbot"], tabs["Anti-aimbot angles"])
                    elseif cat == "Visuals" then
                        pui.set_cfg(parsed["Visuals"], tabs["Visuals"])
                    elseif cat == "Misc" then
                        pui.set_cfg(parsed["Misc"], tabs["Misc"])
                    elseif cat == "Rage" then
                        pui.set_cfg(parsed["Rage"], tabs["Rage"])
                    end
                end
            end

            
            if switch ~= nil and ui.set ~= nil then
                pcall(ui.set, switch, (switchtb and switchtb[1]) or ui.get(switch))
            end

            cloud_log("Loaded", name)
        end)
    end

