if tabs and tabs["Anti-aimbot angles"] then
    tabs["Manipulations"] = tabs["Manipulations"] or tabs["Anti-aimbot angles"]["Manipulations"]
    tabs["Visuals"] = tabs["Visuals"] or {}
    local vsrc = tabs["Anti-aimbot angles"]["Visuals"]
    tabs["Visuals"].indicators = (vsrc and vsrc.indicators) or tabs["Visuals"].indicators
    tabs["Visuals"].crossdamage = (vsrc and vsrc.crossdamage) or tabs["Visuals"].crossdamage
    tabs["Visuals"].arrows = (vsrc and vsrc.arrows) or tabs["Visuals"].arrows
    tabs["Visuals"].scopelines = (vsrc and vsrc.scopelines) or tabs["Visuals"].scopelines
    tabs["Visuals"].sidemark = (vsrc and vsrc.sidemark) or tabs["Visuals"].sidemark
    tabs["Visuals"].predictbox = (vsrc and vsrc.predictbox) or tabs["Visuals"].predictbox
    tabs["Visuals"].betternade = (vsrc and vsrc.betternade) or tabs["Visuals"].betternade
    tabs["Visuals"].watermark = (vsrc and vsrc.watermark) or tabs["Visuals"].watermark
    if tabs["Visuals"].watermark and tabs["Visuals"].watermark[3] then
        pcall(ui.set, tabs["Visuals"].watermark[3], "Top-Right")
    end
    tabs["Visuals"].spectators = (vsrc and vsrc.spectators) or tabs["Visuals"].spectators
    tabs["Visuals"].keybinds = (vsrc and vsrc.keybinds) or tabs["Visuals"].keybinds
    tabs["Visuals"].velwar = (vsrc and vsrc.velwar) or tabs["Visuals"].velwar
    tabs["Visuals"].defind = (vsrc and vsrc.defind) or tabs["Visuals"].defind
