					else
						local ok_sel, v_sel = pcall(ui.get, switch)
						if ok_sel then tsel = v_sel end
					end

					
					if tsel ~= "Visuals" then
						if sync_ref then pcall(ui.set_visible, sync_ref, false) end
						if unicode_ref then pcall(ui.set_visible, unicode_ref, false) end
