local function _init_tabs_visibility_once()
    if pui._tabs_initialized then return end
    pui._tabs_initialized = true
    if tabs then
        if switch then
            local cur = ui.get(switch)
            local ok = false
            if type(cur) == "string" then
                for i = 1, #switchtb do
                    if cur == switchtb[i] then ok = true break end
                end
            end
            ui.set(switch, ok and cur or switchtb[1])
        end
        if pui.visibleparse then pui.visibleparse(tabs, false) end
        if pui.visible_tabs then pui.visible_tabs() end
        if switch then
            ui.set_callback(switch, function()

                if pui.visible_tabs then pui.visible_tabs() end
            end)
        end

        if not pui._cloud_cfg_initialized then
            pui._cloud_cfg_initialized = true
            local h = tabs and tabs["Home"] or nil

            if h and h.cloud_cfg_listbox then
                pcall(ui.set_callback, h.cloud_cfg_listbox, function()
                    local listbox = h.cloud_cfg_listbox
                    local sel = listbox and ui.get(listbox) or nil
                    local name
                    if type(sel) == "number" then
                        name = cloud_cfg_names[sel + 1]
                    elseif type(sel) == "string" then
                        local s = _cloud_strip_colors(sel)
                        if type(s) == "string" and s:sub(1, #CFG_ICON) == CFG_ICON then s = s:sub(#CFG_ICON+1) end
                        if s ~= "Cloud is down!" and s ~= "No configs found" then name = s end
                    end
                    if name then cloud_cfg_update_meta_labels(name) end
                end)
            end

            if h and h.cloud_cfg_sort then
                pcall(ui.set_callback, h.cloud_cfg_sort, function()
                    if cloud_cfg_refresh_list then cloud_cfg_refresh_list() end
                end)
            end

            if cloud_cfg_refresh_list then
                cloud_cfg_refresh_list()
            end
        end
    end
    client.unset_event_callback("paint_ui", _init_tabs_visibility_once)
end
client.set_event_callback("paint_ui", _init_tabs_visibility_once)

if tabs and tabs["Configs"] and tabs["Configs"].onlyload then
    ui.set(tabs["Configs"].onlyload, {})
    ui.set_callback(tabs["Configs"].onlyload, function(id)
        local sel = ui.get(id) or {}
        local has_all = false
        for _, v in ipairs(sel) do if v == "All" then has_all = true break end end
        if has_all and #sel > 1 then

            local filtered = {}
            for _, v in ipairs(sel) do if v ~= "All" then table.insert(filtered, v) end end
            ui.set(id, filtered)
        end
    end)
end

do
    local function _set_blurified_white_if_old()
        local t = tabs and tabs["Manipulations"]
        local u = t and t.uistyle
        if not (u and u[1] and u[8] and u[9]) then return end
        local style = ui.get(u[1])
        if style ~= "Blurified" then return end
        local lbl = {ui.get(u[8])}
        local txt = {ui.get(u[9])}
        if lbl[1] == 120 and lbl[2] == 150 and lbl[3] == 200 and lbl[4] == 255 then
            ui.set(u[8], 255, 255, 255, 255)
        end
        if txt[1] == 35 and txt[2] == 35 and txt[3] == 40 and txt[4] == 255 then
            ui.set(u[9], 255, 255, 255, 255)
        end
    end
    local t = tabs and tabs["Manipulations"]
    local u = t and t.uistyle
    if u and u[1] then
        ui.set_callback(u[1], function()
            _set_blurified_white_if_old()
        end)
        _set_blurified_white_if_old()
    end
end


visuals.panorama_is_in_game = function()
    local local_player = entity.get_local_player()
    if local_player == nil then return false end
    local team = entity.get_prop(local_player, "m_iTeamNum")
    return team ~= nil
end

visuals.panorama_contains = function(t, value)
    if t == nil then return false end
    if type(t) ~= "table" then
        t = ui.get(t)
    end
    if type(t) == "table" then
        for _, v in ipairs(t) do
            if v == value then return true end
        end
    end
    return false
end

visuals.panorama_mainmenueditor = panorama.loadstring([[return {
    set: (str, toggle) => {
        var element = $.GetContextPanel().FindChildTraverse(str);
        if (element != null){
            element.visible = toggle;
        }
    }
}]], "MainMenu")()

visuals.panorama_buttons = function()
    if not ui.get(tabs["Visuals"].panorama_removal[1]) then return end
    local sel = pui.switch_get and pui.switch_get() or ui.get(switch)
    if sel ~= "Visuals" then
        
        ui.set_visible(tabs["Visuals"].panorama_removal[4], false)
        ui.set_visible(tabs["Visuals"].panorama_removal[5], false)
        return
    end
    local SelectedPanoramasGame = ui.get(tabs["Visuals"].panorama_removal[4])
    local SelectedPanoramasMenu = ui.get(tabs["Visuals"].panorama_removal[5])

    if visuals.panorama_is_in_game() then
        ui.set_visible(tabs["Visuals"].panorama_removal[4], true)
        ui.set_visible(tabs["Visuals"].panorama_removal[5], false)
        for _, element in pairs(visuals.panorama_buttons_game) do
            if visuals.panorama_contains(SelectedPanoramasGame, element.name) then
                visuals.panorama_mainmenueditor.set(element.value, false)
            else
                visuals.panorama_mainmenueditor.set(element.value, true)
            end
        end
    else
        ui.set_visible(tabs["Visuals"].panorama_removal[4], false)
        ui.set_visible(tabs["Visuals"].panorama_removal[5], true)
        for _, element in pairs(visuals.panorama_buttons_menu) do
            if visuals.panorama_contains(SelectedPanoramasMenu, element.name) then
                visuals.panorama_mainmenueditor.set(element.value, false)
            else
                visuals.panorama_mainmenueditor.set(element.value, true)
            end
        end
    end
end

visuals.panorama_background_handler = function()
    if not ui.get(tabs["Visuals"].panorama_removal[1]) then return end
    local sel = pui.switch_get and pui.switch_get() or ui.get(switch)
    if sel ~= "Visuals" then
        
        ui.set_visible(tabs["Visuals"].panorama_removal[6], false)
        return
    end
    local SelectedPanoramas = ui.get(tabs["Visuals"].panorama_removal[6])

    if not visuals.panorama_is_in_game() then
        ui.set_visible(tabs["Visuals"].panorama_removal[6], true)
        for _, element in pairs(visuals.panorama_background) do
            if visuals.panorama_contains(SelectedPanoramas, element.name) then
                visuals.panorama_mainmenueditor.set(element.value, false)
            else
                visuals.panorama_mainmenueditor.set(element.value, true)
            end
        end
    else
        ui.set_visible(tabs["Visuals"].panorama_removal[6], false)
        return
    end
end

visuals.panorama_blur = function()
    if not ui.get(tabs["Visuals"].panorama_removal[1]) then return end
    client.set_cvar("@panorama_disable_blur", ui.get(tabs["Visuals"].panorama_removal[2]))
end

visuals.panorama_box_shadow = function()
    if not ui.get(tabs["Visuals"].panorama_removal[1]) then return end
    client.set_cvar("@panorama_disable_box_shadow", ui.get(tabs["Visuals"].panorama_removal[3]))
end

do
    local pr = tabs and tabs["Visuals"] and tabs["Visuals"].panorama_removal
    if pr and pr[1] then
        ui.set_callback(pr[1], function(id)
            if ui.get(id) then
                client.set_event_callback("paint_ui", visuals.panorama_background_handler)
                client.set_event_callback("paint_ui", visuals.panorama_buttons)
                visuals.panorama_blur()
