local autohs_state = {active = false, engaged = false, prev_dt_enabled = nil, prev_os_enabled = nil, prev_os_hotkey = nil}

local function autohs_get_weapon_type()
    local lplayer = entity.get_local_player()

    if lplayer == nil then return nil end
    local w = entity.get_player_weapon(lplayer)
    if w == nil then return nil end
    local info = csgo_weapons(w)
    if not info then return nil end
    if info.type == "sniperrifle" then
        if info.idx == 40 then return "Scout" end
        if info.idx == 9 then return "AWP" end
        return "Auto Snipers"
    elseif info.type == "pistol" then
        if info.idx == 1 then return "Desert Eagle" end
        if info.idx == 64 then return "Revolver R8" end
        return "Pistols"
    elseif info.type == "smg" then
        return "SMG"
    elseif info.type == "rifle" then
        return "Rifles"
    end
    return nil
end

local function autohs_get_state()
    local l = entity.get_local_player()
    if l == nil then return nil end
    local flags = entity.get_prop(l, "m_fFlags") or 0
    local onground = bit.band(flags, 1) == 1
    local duck = entity.get_prop(l, "m_flDuckAmount") or 0
    local vx, vy = entity.get_prop(l, "m_vecVelocity")
    vx = tonumber(vx) or 0
    vy = tonumber(vy) or 0
    local speed = math.sqrt(vx*vx + vy*vy)
    local slow = false
    do
        local sm = skeetgui and skeetgui.aagui and skeetgui.aagui.other and skeetgui.aagui.other.slow_motion or nil
        if type(sm) == "table" and sm[1] ~= nil and sm[2] ~= nil then
            local ok1, a = pcall(ui.get, sm[1])
            local ok2, b = pcall(ui.get, sm[2])
            slow = (ok1 and a == true) and (ok2 and b == true)
        end
    end
    local crouched = bit.band(flags, 2) == 2 or duck > 0.55
    local moving = speed > 3
    if not onground then
        if crouched then return "Air-Crouch" end
        return "Air"
    end
    if crouched then
        if moving then return "Move-Crouch" end
        return "Crouch"
    end
    if moving then
        if slow then return "Slow Walk" end
        return "Moving"
    end
    return "Standing"
end

local function autohs_update_values()
    if not autohs_state.active then
        local ok_dt, dtv = pcall(ui.get, skeetgui.ragegui.aimbot.double_tap[1])
        local ok_os, osv = pcall(ui.get, skeetgui.aagui.other.on_shot_antiaim[1])
        local ok_hk, hkv = false, nil
        if skeetgui.aagui.other.on_shot_antiaim[2] then
            ok_hk, hkv = pcall(ui.get, skeetgui.aagui.other.on_shot_antiaim[2])
        end
        autohs_state.prev_dt_enabled = ok_dt and dtv or false
        autohs_state.prev_os_enabled = ok_os and osv or false
        autohs_state.prev_os_hotkey = ok_hk and hkv or nil
        autohs_state.active = true
    end
    pcall(ui.set, skeetgui.ragegui.aimbot.double_tap[1], false)
    pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[1], true)
    if skeetgui.aagui.other.on_shot_antiaim[2] then
        if not pui.try_set_any then
            pcall(function() ui.set(skeetgui.aagui.other.on_shot_antiaim[2], "Always on") end)
        else
            pui.try_set_any(skeetgui.aagui.other.on_shot_antiaim[2], {"Always on", "Always On", "Always", "Enabled", true})
        end
    end
    autohs_state.engaged = true
end
local function autohs_idle_values()
    autohs_state.active = autohs_state.active or false
    if autohs_state.active then
        if autohs_state.prev_os_enabled ~= nil then pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[1], autohs_state.prev_os_enabled) end
        if skeetgui.aagui.other.on_shot_antiaim[2] and autohs_state.prev_os_hotkey ~= nil then
            pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[2], autohs_state.prev_os_hotkey)
        end
        if autohs_state.prev_dt_enabled ~= nil then
            pcall(ui.set, skeetgui.ragegui.aimbot.double_tap[1], autohs_state.prev_dt_enabled)
        end
    else
        pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[1], false)
    end
    autohs_state.engaged = false
end
local function autohs_restore_values()
    if autohs_state.active then
        if autohs_state.prev_dt_enabled ~= nil then pcall(ui.set, skeetgui.ragegui.aimbot.double_tap[1], autohs_state.prev_dt_enabled) end
        if autohs_state.prev_os_enabled ~= nil then pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[1], autohs_state.prev_os_enabled) end
        if skeetgui.aagui.other.on_shot_antiaim[2] and autohs_state.prev_os_hotkey ~= nil then
            pcall(ui.set, skeetgui.aagui.other.on_shot_antiaim[2], autohs_state.prev_os_hotkey)
        end
    end
    autohs_state.active = false
    autohs_state.engaged = false
    autohs_state.prev_dt_enabled = nil
    autohs_state.prev_os_enabled = nil
    autohs_state.prev_os_hotkey = nil

    autohs_state.want = nil
    autohs_state.use = nil
    autohs_state.want_since = nil
end
local function autohs_should_update()
    if not tabs or not tabs["Anti-aimbot angles"] or not tabs["Anti-aimbot angles"].auto_hide_shots then return false end
    local w = autohs_get_weapon_type()
    if not w then return false end
    local wsel = ui.get(tabs["Anti-aimbot angles"].auto_hide_shots[2])
    local w_ok = true
    if type(wsel) == "table" and #wsel > 0 then
        w_ok = pui.in_table(wsel, w)
    end
    if not w_ok then return false end
    local st = autohs_get_state()
    if not st then return false end
    local ssel = ui.get(tabs["Anti-aimbot angles"].auto_hide_shots[3])
    local s_ok = false
    if type(ssel) == "table" and #ssel > 0 then
        s_ok = pui.in_table(ssel, st)
    end
    if not s_ok then return false end
    return true
end
local function autohs_on_setup(cmd)
    if not tabs or not tabs["Anti-aimbot angles"] or not tabs["Anti-aimbot angles"].auto_hide_shots then return end
    local ok_on, on = pcall(ui.get, tabs["Anti-aimbot angles"].auto_hide_shots[1])
    if not ok_on or on ~= true then autohs_restore_values(); return end

    local ok_should, want = pcall(autohs_should_update)
    want = ok_should and want == true or false

    autohs_state.want = (autohs_state.want == nil) and want or autohs_state.want
    autohs_state.want_since = autohs_state.want_since or globals.tickcount()
    autohs_state.use = (autohs_state.use == nil) and want or autohs_state.use

    local now = globals.tickcount()
    if want ~= autohs_state.want then
        autohs_state.want = want
        autohs_state.want_since = now
    end
    if (now - (autohs_state.want_since or now)) >= 2 then
        autohs_state.use = autohs_state.want
    end

    if autohs_state.use then
        autohs_update_values()
    else
        autohs_idle_values()
    end
end
local autohs_cb_registered = false
local autohs_anim_guard = false
local function update_auto_hide_shots_visibility()
    local ok_on, on = pcall(ui.get, tabs["Anti-aimbot angles"].auto_hide_shots[1])
    local show = ok_on and on == true
    pcall(ui.set_visible, tabs["Anti-aimbot angles"].auto_hide_shots[2], show)
    pcall(ui.set_visible, tabs["Anti-aimbot angles"].auto_hide_shots[3], show)
end


update_auto_hide_shots_visibility()
ui.set_callback(tabs["Anti-aimbot angles"].auto_hide_shots[1], function(id)
    local on = ui.get(id)

    if not autohs_anim_guard then
        autohs_anim_guard = true
        local aa = tabs and tabs["Anti-aimbot angles"]
        if aa and aa.auto_hide_shots_anim then
            pcall(ui.set, aa.auto_hide_shots_anim[1], on)
            pcall(ui.set, aa.auto_hide_shots_anim[2], on)
        end
        autohs_anim_guard = false
    end

    ui.set_visible(tabs["Anti-aimbot angles"].auto_hide_shots[2], on)
    ui.set_visible(tabs["Anti-aimbot angles"].auto_hide_shots[3], on)
    if on then
        if not autohs_cb_registered then
            client.set_event_callback("setup_command", autohs_on_setup)
            autohs_cb_registered = true
        end
    else
        if autohs_cb_registered then
            client.unset_event_callback("setup_command", autohs_on_setup)
            autohs_cb_registered = false
        end
        autohs_restore_values()
    end
end)

do
    local aa = tabs and tabs["Anti-aimbot angles"]
    if aa and aa.auto_hide_shots and aa.auto_hide_shots_anim then
        local master = aa.auto_hide_shots[1]
        local a = aa.auto_hide_shots_anim[1]
        local b = aa.auto_hide_shots_anim[2]

        local function forward_anim(id)
            if autohs_anim_guard then return end
            autohs_anim_guard = true
            local on = ui.get(id)
            pcall(ui.set, master, on)
            pcall(ui.set, a, on)
            pcall(ui.set, b, on)
            autohs_anim_guard = false
        end

        if a then ui.set_callback(a, forward_anim) end
        if b then ui.set_callback(b, forward_anim) end

        local ok_master, on = pcall(ui.get, master)
        if ok_master then
            pcall(ui.set, a, on)
            pcall(ui.set, b, on)
        end

        pcall(ui.set_visible, master, false)
        if b then pcall(ui.set_visible, b, false) end
    end
end

