            if b then pcall(ui.set, b, on) end
            if c then pcall(ui.set, c, on) end
            if d then pcall(ui.set, d, on) end
            manuals_anim_guard = false
        end

        if a then ui.set_callback(a, forward_anim) end
        if b then ui.set_callback(b, forward_anim) end
        if c then ui.set_callback(c, forward_anim) end
        if d then ui.set_callback(d, forward_anim) end

        if master then
            ui.set_callback(master, function(id)
                if manuals_anim_guard then return end
                manuals_anim_guard = true
                local on = ui.get(id)
                if a then pcall(ui.set, a, on) end
                if b then pcall(ui.set, b, on) end
                if c then pcall(ui.set, c, on) end
                if d then pcall(ui.set, d, on) end
                manuals_anim_guard = false
            end)
        end

        local ok_master, on = pcall(ui.get, master)
        if ok_master then
            if a then pcall(ui.set, a, on) end
            if b then pcall(ui.set, b, on) end
            if c then pcall(ui.set, c, on) end
            if d then pcall(ui.set, d, on) end
        end

        pcall(ui.set_visible, master, false)
        if b then pcall(ui.set_visible, b, false) end
        if c then pcall(ui.set_visible, c, false) end
        if d then pcall(ui.set_visible, d, false) end
    end
end
