local fakelag_welcome_hint = false
do
	local count_key = "osmanhook::reloadtimes"
	local last_rt_key = "osmanhook::reloadtimes_last_rt"
	local now_rt = (globals and globals.realtime and globals.realtime()) or 0
	local last_rt = (database and database.read) and tonumber(database.read(last_rt_key)) or nil
	local n = (database and database.read) and tonumber(database.read(count_key)) or 0

	
	if last_rt == nil or now_rt < (last_rt - 1) then
		n = 1
	else
		n = n + 1
	end

	if database and database.write then
		pcall(database.write, count_key, n)
		pcall(database.write, last_rt_key, now_rt)
	end

	fakelag_welcome_hint = n > 2
end

