local function _update_stats_labels()
    local mc = pui.menu_col()
    local r, g, b = tonumber(mc[1]) or 255, tonumber(mc[2]) or 255, tonumber(mc[3]) or 255
    local col = string.format("\a%02X%02X%02XFF", r, g, b)
    local reset = "\aFFFFFFFF"
    local grey = "\aFFFFFF30"
    local sel = pui.switch_get and pui.switch_get() or ui.get(switch)
    local show = false
    if sel == "Home" then
        local h = tabs and tabs["Home"]
        if h and h.other_section then
            local other = pui.other_section_get and pui.other_section_get() or ui.get(h.other_section)
            show = other == "Stats" or other == 3
        end
    end
    if stats_ui and stats_ui.header then
        ui.set(stats_ui.header, col.." ".."\aCDCDCDFF".." Statistics")
    end
    if stats_ui and stats_ui.spacer then
        ui.set(stats_ui.spacer, "\aFFFFFF30‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾‾")
    end
    local seconds = aa_stats.seconds_base + (globals.realtime() - aa_stats.start_realtime)
    local hours = seconds / 3600.0
    local hitrate = (aa_stats.shots > 0) and (aa_stats.hits / aa_stats.shots * 100.0) or 0.0
    if hitrate < 0 then hitrate = 0 elseif hitrate > 100 then hitrate = 100 end
    local total = math.max(0, math.floor(seconds + 0.5))
    local h = math.floor(total / 3600)
    local m = math.floor((total % 3600) / 60)
    local hours_str = string.format("%02d:%02d", h, m)
    if stats_ui and stats_ui.hours then
    ui.set(stats_ui.hours,  string.format("%sHours played -: %s%s", grey, col, hours_str))
    end
    if stats_ui and stats_ui.loaded then
    ui.set(stats_ui.loaded, string.format("%sTimes loaded -: %s%d", grey, col, aa_stats.times_loaded))
    end
    if stats_ui and stats_ui.killed then
    ui.set(stats_ui.killed, string.format("%sEnemies killed -: %s%d", grey, col, aa_stats.kills))
    end
    if stats_ui and stats_ui.hitrate then
    ui.set(stats_ui.hitrate,string.format("%sHitrate -: %s%.0f%%", grey, col, hitrate))
    end
    if stats_ui and stats_ui.points then
    ui.set(stats_ui.points, string.format("%sPoints earned -: %s%d", grey, col, aa_stats.points))
    end
    if stats_ui and stats_ui.header then
    ui.set_visible(stats_ui.header, show)
    end
    if stats_ui and stats_ui.spacer then
    ui.set_visible(stats_ui.spacer, show)
    end
    if stats_ui and stats_ui.hours then
    ui.set_visible(stats_ui.hours, show)
    end
    if stats_ui and stats_ui.loaded then
    ui.set_visible(stats_ui.loaded, show)
    end
    if stats_ui and stats_ui.killed then
    ui.set_visible(stats_ui.killed, show)
    end
    if stats_ui and stats_ui.hitrate then
    ui.set_visible(stats_ui.hitrate, show)
    end
    if stats_ui and stats_ui.points then
    ui.set_visible(stats_ui.points, show)
    end
end
