        if hr < 0 then hr = 0 elseif hr > 100 then hr = 100 end
        database.write("osmanhook::stats_hitrate", hr)
    end
end)
local function is_bot(ent)
    if not ent or ent == 0 then return true end
    local steam64 = entity.get_steam64(ent)
    local sidn = tonumber(steam64)
    if not steam64 or steam64 == "0" or sidn == 0 or steam64 == "" or steam64 == "BOT" then return true end
    return false
end

client.set_event_callback("player_death", function(e)
    local attacker = client.userid_to_entindex(e.attacker)
    local victim = client.userid_to_entindex(e.userid)
    local lp = entity.get_local_player()
    if attacker == lp and attacker ~= nil and victim ~= lp then
        local victim_is_bot = is_bot(victim)
        if not victim_is_bot then
            aa_stats.kills = (aa_stats.kills or 0) + 1
            aa_stats.points = (aa_stats.points or 0) + 2
            database.write("osmanhook::stats_kills", aa_stats.kills)
            database.write("osmanhook::stats_points", aa_stats.points)
        end
    end
    if victim == lp and victim ~= nil then
        local killer_is_bot = is_bot(attacker)
        if killer_is_bot then
            return
        end
        aa_stats.points = (aa_stats.points or 0) - 3
        database.write("osmanhook::stats_points", aa_stats.points)
    end
    if misc and misc.trashmsg then
        pcall(misc.trashmsg, e)
    end
end)

client.set_event_callback("shutdown", function()

    pcall(database.write, "osmanhook::stats_kills", aa_stats.kills or 0)
    pcall(database.write, "osmanhook::stats_shots", aa_stats.shots or 0)
    pcall(database.write, "osmanhook::stats_hits", aa_stats.hits or 0)
    pcall(database.write, "osmanhook::stats_points", aa_stats.points or 0)
    local seconds = (aa_stats.seconds_base or 0) + (globals.realtime() - (aa_stats.start_realtime or globals.realtime()))
    pcall(database.write, "osmanhook::stats_seconds", seconds)
end)



