pui.pui_cfg_proxy = function(node)
    if node == nil then return nil end

    local t = type(node)
    if t == "number" then
        local ctx = registry and registry[node]
        local self = ctx and ctx.self
        if type(self) == "table" and rawget(self, "__name") == "pui::element" then
            return self
        end
        return nil
    end

    if t == "table" then
        if rawget(node, "__name") == "pui::element" then
            return node
        end
        local out = {}
        for k, v in pairs(node) do
            local pv = pui.pui_cfg_proxy(v)
            if pv ~= nil then
                out[k] = pv
            end
        end
        return out
    end

    return nil
end

pui.pui_cfg_package = function(src)
    if pui._pui_cfg_pkg and pui._pui_cfg_src == src then
        return pui._pui_cfg_pkg
    end
    if type(pui) ~= "table" or type(pui.setup) ~= "function" then
        return nil
    end
    local proxy = pui.pui_cfg_proxy(src)
    if type(proxy) ~= "table" then
        return nil
    end
    local ok, pkg = pcall(pui.setup, proxy)
    if not ok or type(pkg) ~= "table" or type(pkg.save) ~= "function" or type(pkg.load) ~= "function" then
        return nil
    end
    pui._pui_cfg_src = src
    pui._pui_cfg_pkg = pkg
    return pkg
end

pui.pui_cfg_fix_hotkeys = function(pkg, raw, category)
    if not pkg or type(pkg[0]) ~= "table" then return end
    if type(raw) ~= "table" or type(category) ~= "string" then return end

    local _dirs = dirs
    if type(_dirs) ~= "table" then
        _dirs = {}
        _dirs.find = function(t, path)
            local p, k
            for _, s in ipairs(path) do
                k, p, t = s, t, t[s]
                if t == nil then return end
            end
            return p[k]
        end
        _dirs.pave = function(t, place, path)
            local p = t
            for i, v in ipairs(path) do
                if type(p[v]) == "table" then
                    p = p[v]
                else
                    p[v] = (i < #path) and {} or place
                    p = p[v]
                end
            end
            return t
        end
        _dirs.extract = function(t, path)
            if not path or #path == 0 then return t end
            local j = _dirs.find(t, path)
            return _dirs.pave({}, j, path)
        end
    end

    local packed = _dirs.extract(raw, { category })
    local refs = _dirs.extract(pkg[0], { category })
    if type(packed) ~= "table" or type(refs) ~= "table" then return end

    pui.traverse(refs, function(ref, path)
        if type(ref) ~= "number" then return end
        local proxy = registry and registry[ref]
        if not proxy or proxy.type ~= "hotkey" then return end

        local value = _dirs.find(packed, path)
        if type(value) ~= "table" then return end
        if value[#value] == "~" then value[#value] = nil end

        if type(value[1]) == "boolean" then
            _dirs.pave(packed, { value[2], value[3] or 0 }, path)
        end
    end)
end

pui.get_config = function(tabl)
    local config = {}
    local pkg = pui.pui_cfg_package(tabl)

    local function merge_missing(dst, src)
        if type(dst) ~= "table" or type(src) ~= "table" then return end
        for k, v in pairs(src) do
            if dst[k] == nil then
                dst[k] = v
            elseif type(dst[k]) == "table" and type(v) == "table" then
                merge_missing(dst[k], v)
            end
        end
    end

    for key, val in pairs(tabl) do
        if key == "Configs" or key == "Home" then goto skip end
        local legacy = pui.get_table(val)
        if pkg then
            local ok, packed = pcall(pkg.save, pkg, key)
            if ok and type(packed) == "table" then
                merge_missing(packed, legacy)
                config[key] = packed
            else
                config[key] = legacy
            end
        else
            config[key] = legacy
        end
        ::skip::
    end
    if config["Anti-aimbot angles"] and config["Anti-Aimbot"] == nil then
        config["Anti-Aimbot"] = config["Anti-aimbot angles"]
        config["Anti-aimbot angles"] = nil
    end
    config["User"] = _USER
    config["ID"] = client.unix_time()
    config["Version"] = _VER
    config["pui.keypos"] = pui.keypos
    config["pui.specpos"] = pui.specpos
    config["pui.wtpos"] = pui.wtpos
    do
        local pkg_gs = (skeetgui ~= nil and pui.pui_cfg_package and pui.pui_cfg_package(skeetgui)) or nil
        if pkg_gs then
            local ok, packed = pcall(pkg_gs.save, pkg_gs, "aagui")
            if ok and type(packed) == "table" then
                config["GameSense"] = config["GameSense"] or {}
                config["GameSense"].aagui = packed
            end
        end
    end
    return json.stringify(config)
end

cfg.names = database.read("osmanhook::cfg_names") or {}
cfg._suspend_switch_load = cfg._suspend_switch_load or false

local function cfg_colored_name(name)
    return name
end

 cfg.update_listbox = function()
     if not tabs or not tabs["Configs"] then return end
     local listbox = tabs["Configs"].configbox
     if not listbox then return end

     local display = {}
     if cfg and type(cfg.names) == "table" then
         for _, n in ipairs(cfg.names) do
             if type(n) == "string" and n ~= "" then
                 display[#display + 1] = cfg_colored_name(n)
             end
         end
     end
     if #display == 0 then
         display = {"Cloud is down!"}
     end
     pcall(ui.update, listbox, display)
 end

local function cfg_parse_raw(rawcfg)
    if type(rawcfg) ~= "string" then
        return nil, "Invalid Config"
    end

    local prefix = "osmanhook:"
    local s = rawcfg
    s = s:gsub("%z", "")
    local trimmed = s:gsub("^%s+", ""):gsub("%s+$", "")

    do
        local okj, t = pcall(json.parse, trimmed)
        if okj and type(t) == "table" then
            return t
        end
    end

    local payload
    local start = trimmed:find(prefix, 1, true)
    if start then
        payload = trimmed:sub(start + #prefix)
    else
        payload = trimmed
    end
    payload = payload:gsub("%s+", "")
    payload = payload:match("^([A-Za-z0-9%+/%=]+)") or payload

    local ok_dec, decoded = pcall(base64.decode, payload)
    if not ok_dec or type(decoded) ~= "string" then
        return nil, "Failed to parse config"
    end

    local ok_json, parsedcfg = pcall(json.parse, decoded)
    if not ok_json or type(parsedcfg) ~= "table" then
        return nil, "Failed to parse config"
    end

    return parsedcfg
end

cfg.autosave_key = cfg.autosave_key or ("osmanhook::autosave_cfg_v" .. tostring(_VER or ""))

cfg.autosave = function()
    if not database or not database.write then return end
    if not tabs or not pui.get_config then return end
    local ok, payload = pcall(pui.get_config, tabs)
    if ok and type(payload) == "string" and #payload > 0 then
        pcall(database.write, cfg.autosave_key, payload)
    end
end

cfg.autoload = function(only_aa)
    if not database or not database.read then return end
    local raw = database.read(cfg.autosave_key)
    if type(raw) ~= "string" or #raw < 1 then return end

    local parsedcfg, err = cfg_parse_raw(raw)
    if not parsedcfg then
        return
    end
    if tonumber(parsedcfg["Version"]) ~= tonumber(_VER) then
        return
    end

    if only_aa then
        local aa_cfg = parsedcfg["Anti-aimbot angles"] or parsedcfg["Anti-Aimbot"]
        if type(aa_cfg) ~= "table" then return end
        pui.set_cfg({["Anti-aimbot angles"] = aa_cfg})
        if pui.apply_defensive_cfg_from_table then
            pui.apply_defensive_cfg_from_table(aa_cfg)
        end
    else
        pui.set_cfg(parsedcfg)
        local aa_cfg = parsedcfg["Anti-aimbot angles"] or parsedcfg["Anti-Aimbot"]
        if pui.apply_defensive_cfg_from_table and type(aa_cfg) == "table" then
            pui.apply_defensive_cfg_from_table(aa_cfg)
        end
        if pui.apply_gamesense_cfg then
            pui.apply_gamesense_cfg(parsedcfg)
        end
        if type(parsedcfg["pui.keypos"]) == "table" then pui.keypos = parsedcfg["pui.keypos"] end
        if type(parsedcfg["pui.specpos"]) == "table" then pui.specpos = parsedcfg["pui.specpos"] end
        if type(parsedcfg["pui.wtpos"]) == "table" then pui.wtpos = parsedcfg["pui.wtpos"] end
        if database and database.write then
            pcall(database.write, "osmanhook::keypos", pui.keypos)
            pcall(database.write, "osmanhook::specpos", pui.specpos)
            pcall(database.write, "osmanhook::wtpos", pui.wtpos)
        end
    end
end

local function cfg_sanitize_name(name)
    if type(name) ~= "string" then return nil end
    local s = name:gsub("%z", "")
    s = s:gsub("[%c]", "")
    s = s:gsub("^%s+", ""):gsub("%s+$", "")
    s = s:gsub("[<>:\"/\\|%?%*]", "_")
    s = s:gsub("%s+", " ")
    if #s < 1 then return nil end
    return s
end

local function cfg_file_path_for_name(name)
    local safe = cfg_sanitize_name(name)
    if not safe then return nil end
    return string.format("%s31415926535.cfg", safe)
end

pui.apply_gamesense_cfg = function(root)
    if type(root) ~= "table" then return end
    local gs = root["GameSense"]
    if type(gs) ~= "table" then return end
    local pkg_gs = (skeetgui ~= nil and pui.pui_cfg_package and pui.pui_cfg_package(skeetgui)) or nil
    if not pkg_gs then return end
    if type(gs.aagui) == "table" then
        local raw = { aagui = gs.aagui }
        if pui.pui_cfg_fix_hotkeys then
            pui.pui_cfg_fix_hotkeys(pkg_gs, raw, "aagui")
        end
        pcall(pkg_gs.load, pkg_gs, raw, "aagui")
    end
end

local function _update_switch_configs()
    if not switch then return end
    local items = {}
    if type(switchtb) == "table" then
        for _, base in ipairs(switchtb) do
            table.insert(items, base)
        end
    end
    if cfg and type(cfg.names) == "table" then
        for _, n in ipairs(cfg.names) do
            if type(n) == "string" and n ~= "" then
                table.insert(items, n)
            end
        end
    end

    local idx
    if pui.table_index then
        idx = pui.table_index(items, ui.get(switch))
    else
        for i, name in ipairs(items) do
            if name == ui.get(switch) then idx = i break end
        end
    end

    if idx and #items > 0 and idx > #items then
        if cfg and cfg._suspend_switch_load then
            local fallback = pui.last_switch_tab or (type(switchtb) == "table" and switchtb[1] or ui.get(switch))
            pui.last_switch_tab = fallback
            pcall(ui.set, switch, fallback)
            if pui.visible_tabs then pui.visible_tabs() end
            return
        end
        local cfgname = ui.get(switch)
        if tabs and tabs["Configs"] and tabs["Configs"].textbox then
            pcall(ui.set, tabs["Configs"].textbox, cfgname)
            pcall(cfg.load)
        end
        local fallback = pui.last_switch_tab or (type(switchtb) == "table" and switchtb[1] or ui.get(switch))
        pui.last_switch_tab = fallback
        pcall(ui.set, switch, fallback)
        if pui.visible_tabs then pui.visible_tabs() end
    else
        pui.last_switch_tab = ui.get(switch)
        if pui.visible_tabs then pui.visible_tabs() end
    end
end

pui.set_cfg = function(cfg_tbl, tab)
    local tab = tab or tabs
    if cfg_tbl == nil then return end
    local pkg = pui.pui_cfg_package(tabs)

    if pkg and type(cfg_tbl) == "table" then
        local function _normalize_numeric_string_keys(t)
            if type(t) ~= "table" then return end
            local moves = {}
            for k, v in pairs(t) do
                if type(v) == "table" then
                    _normalize_numeric_string_keys(v)
                end
                if type(k) == "string" then
                    local n = tonumber(k)
                    if n ~= nil and tostring(n) == k then
                        moves[#moves + 1] = { old = k, new = n, val = v }
                    end
                end
            end
            for _, m in ipairs(moves) do
                if t[m.new] == nil then
                    t[m.new] = m.val
                end
                t[m.old] = nil
            end
        end

        local function _shallow_copy(t)
            local out = {}
            for k, v in pairs(t) do out[k] = v end
            return out
        end

        if tab == tabs then
            local raw = cfg_tbl
            if raw["Anti-aimbot angles"] == nil and raw["Anti-Aimbot"] ~= nil then
                raw = _shallow_copy(raw)
                raw["Anti-aimbot angles"] = raw["Anti-Aimbot"]
            end

            local function _list_has(list, v)
                if type(list) ~= "table" or v == nil then return false end
                for i = 1, #list do
                    if list[i] == v then return true end
                end
                return false
            end

            local function _norm_yaw_base(v)
                if v == "Default" then return "Local view" end
                return v
            end

            local function _fix_legacy_aa(cfg)
                local aa = cfg and cfg["Anti-aimbot angles"]
                if type(aa) ~= "table" then return end
                if type(antiaims) ~= "table" or type(antiaims.conds) ~= "table" then return end

                local yawbox = antiaims.yawbox or {"Off", "180", "Spin", "Static", "Delayed"}
                local basebox = antiaims.basebox or {"Local view", "At targets", "Closest enemy"}

                for _, cond in ipairs(antiaims.conds) do
                    local t = aa[cond]
                    if type(t) == "table" then
                        if t.yaw_base ~= nil then
                            t.yaw_base = _norm_yaw_base(t.yaw_base)
                        end

                        if type(t.yaw) == "string" then
                            if t.yaw == "L&R" then
                                t.yaw_lr = true
                                t.yaw = "180"
                            end

                            if t.yaw:find(" ", 1, true) ~= nil then
                                local b, y = t.yaw:match("^(.-)%s+(%S+)$")
                                b = _norm_yaw_base(b)
                                if b ~= nil and y ~= nil and _list_has(yawbox, y) and _list_has(basebox, b) then
                                    t.yaw = y
                                    t.yaw_base = b
                                end
                            end
                        end

                        if type(t.yaw_base) == "string" and t.yaw_base:find(" ", 1, true) ~= nil then
                            local b, y = t.yaw_base:match("^(.-)%s+(%S+)$")
                            b = _norm_yaw_base(b)
                            if b ~= nil and y ~= nil and _list_has(yawbox, y) and _list_has(basebox, b) then
                                if t.yaw == nil or not _list_has(yawbox, t.yaw) then
                                    t.yaw = y
                                end
                                t.yaw_base = b
                            end
                        end
                    end
                end
            end

            _fix_legacy_aa(raw)

            _normalize_numeric_string_keys(raw)
            if type(raw["Anti-aimbot angles"]) == "table" then
                pui.pui_cfg_fix_hotkeys(pkg, raw, "Anti-aimbot angles")
                pcall(pkg.load, pkg, raw, "Anti-aimbot angles")
            end
            if type(raw["Rage"]) == "table" then
                pui.pui_cfg_fix_hotkeys(pkg, raw, "Rage")
                pcall(pkg.load, pkg, raw, "Rage")
            end
            if type(raw["Visuals"]) == "table" then
                pui.pui_cfg_fix_hotkeys(pkg, raw, "Visuals")
                pcall(pkg.load, pkg, raw, "Visuals")
            end
            if type(raw["Misc"]) == "table" then
                pui.pui_cfg_fix_hotkeys(pkg, raw, "Misc")
                pcall(pkg.load, pkg, raw, "Misc")
            end
        elseif tab == tabs["Anti-aimbot angles"] then
            local raw = { ["Anti-aimbot angles"] = cfg_tbl }
            _normalize_numeric_string_keys(raw)
            pui.pui_cfg_fix_hotkeys(pkg, raw, "Anti-aimbot angles")
            pcall(pkg.load, pkg, raw, "Anti-aimbot angles")
        elseif tab == tabs["Rage"] then
            local raw = { ["Rage"] = cfg_tbl }
            _normalize_numeric_string_keys(raw)
            pui.pui_cfg_fix_hotkeys(pkg, raw, "Rage")
            pcall(pkg.load, pkg, raw, "Rage")
        elseif tab == tabs["Visuals"] then
            local raw = { ["Visuals"] = cfg_tbl }
            _normalize_numeric_string_keys(raw)
            pui.pui_cfg_fix_hotkeys(pkg, raw, "Visuals")
            pcall(pkg.load, pkg, raw, "Visuals")
        elseif tab == tabs["Misc"] then
            local raw = { ["Misc"] = cfg_tbl }
            _normalize_numeric_string_keys(raw)
            pui.pui_cfg_fix_hotkeys(pkg, raw, "Misc")
            pcall(pkg.load, pkg, raw, "Misc")
        end
    end
    if type(tab) == "number" and ui.type(tab) ~= "label" then
        if ui.type(tab) == "color_picker" then
            if type(cfg_tbl) == "table" then
                ui.set(tab, unpack(cfg_tbl))
            elseif type(cfg_tbl) == "string" then
                if cfg_tbl:sub(1, 1) == "#" then
                    local r, g, b, a = pui.hex_to_rgb(cfg_tbl)
                    if r ~= nil then ui.set(tab, r, g, b, a or 255) end
                    return
                end
                local nums = {}
                for n in string.gmatch(cfg_tbl, "%d+") do
                    nums[#nums+1] = tonumber(n)
                end
                if #nums >= 3 then
                    ui.set(tab, nums[1], nums[2], nums[3], nums[4] or 255)
                end
            end
        elseif ui.type(tab) == "hotkey" then
            if type(cfg_tbl) == "table" then
                if cfg_tbl[#cfg_tbl] == "~" then cfg_tbl[#cfg_tbl] = nil end
                if type(cfg_tbl[1]) == "boolean" then
                    ui.set(tab, cfg_tbl[2], cfg_tbl[3])
                else
                    ui.set(tab, cfg_tbl[1], cfg_tbl[2])
                end
            end
        elseif ui.type(tab) == "textbox" then
            if cfg_tbl ~= nil and type(cfg_tbl) == "string" and string.len(cfg_tbl) > 0 then
                ui.set(tab, cfg_tbl)
            end
        elseif ui.type(tab) == "checkbox" then
            if type(cfg_tbl) ~= "boolean" then
                local v = cfg_tbl
                if type(v) == "string" then
                    v = (v == "true" or v == "True" or v == "on" or v == "On" or v == "1")
                elseif type(v) == "number" then
                    v = v ~= 0
                else
                    v = not not v
                end
                ui.set(tab, v)
            else
                ui.set(tab, cfg_tbl)
            end
        elseif ui.type(tab) == "combobox" then
            local v = cfg_tbl
            if type(v) == "table" then v = v[1] end
            if v ~= nil then pcall(ui.set, tab, v) end
        elseif ui.type(tab) == "multiselect" then
            local list = {}
            if type(cfg_tbl) == "table" then
                for _, v in ipairs(cfg_tbl) do
                    if v ~= "~" then list[#list+1] = v end
                end
            elseif type(cfg_tbl) == "string" then
                for s in string.gmatch(cfg_tbl, "([^,]+)") do
                    local trimmed = (s:gsub("^%s+", ""):gsub("%s+$", ""))
                    if trimmed ~= "" then list[#list+1] = trimmed end
                end
            end
            if #list > 0 then pcall(ui.set, tab, list) end
        elseif ui.type(tab) == "slider" then
            local v = cfg_tbl
            if type(v) == "table" then v = v[1] end
            if type(v) == "string" then
                if v == "Fake lag" then
                    v = 1
                elseif v == "Defensive" then
                    v = 2
                elseif v == "Anti-brute" then
                    v = 3
                else
                    v = tonumber(v)
                end
            end
            if type(v) == "number" then pcall(ui.set, tab, v) end
        elseif ui.type(tab) ~= "listbox" then
            local function _try_set(v)
                return pcall(ui.set, tab, v)
            end
            if not _try_set(cfg_tbl) then
                if type(cfg_tbl) == "string" then
                    local num = tonumber(cfg_tbl)
                    if num ~= nil then
                        _try_set(num)
                    else
                        local t = {}
                        for s in string.gmatch(cfg_tbl, "([^,]+)") do
                            t[#t+1] = (s:gsub("^%s+", ""):gsub("%s+$", ""))
                        end
                        if #t > 0 then
                            _try_set(t)
                        end
                    end
                elseif type(cfg_tbl) == "number" or type(cfg_tbl) == "table" or type(cfg_tbl) == "boolean" then
                    _try_set(cfg_tbl)
                end
            end
        end
    elseif type(tab) == "table" and tab ~= tabs["Configs"] and tab ~= tabs["Home"] then
        for key, val in pairs(tab) do
            local next_cfg = nil
            if type(cfg_tbl) == "table" then
                if type(key) == "number" and cfg_tbl[key] == nil then
                    next_cfg = cfg_tbl[tostring(key)]
                else
                    next_cfg = cfg_tbl[key]
                end
            end
            if next_cfg == nil and type(key) == "string" and key == "Anti-aimbot angles" and type(cfg_tbl) == "table" then
                next_cfg = cfg_tbl["Anti-Aimbot"]
            end
            if next_cfg ~= nil then
                pui.set_cfg(next_cfg, val)
            end
        end
    end
end
pui.apply_defensive_cfg_from_table = function(aa_cfg)
    if type(aa_cfg) ~= "table" or not tabs or not tabs["Anti-aimbot angles"] or not antiaims or not antiaims.conds then
        return
    end
    for _, cond in ipairs(antiaims.conds) do
        local cond_cfg = aa_cfg[cond]
        local cond_tab = tabs["Anti-aimbot angles"][cond]
        if type(cond_cfg) == "table" and type(cond_tab) == "table" then
            local def_cfg = cond_cfg.defensive
            local def_tab = cond_tab.defensive
            if type(def_cfg) == "table" and type(def_tab) == "table" then
                pui.set_cfg(def_cfg, def_tab)
            end
        end
    end
end
cfg.import = function()
    local rawcfg = (clipboard and clipboard.get and clipboard.get()) or (clip and clip.get and clip.get()) or nil
    if type(rawcfg) ~= "string" then
        cfg_error("Invalid Config")
        return
    end

    local parsedcfg, err = cfg_parse_raw(rawcfg)
    if not parsedcfg then
        cfg_error(err or "Failed to parse config")
        return
    end
    if tonumber(parsedcfg["Version"]) ~= tonumber(_VER) then
        cfg_error(string.format("CFG Version mismatch current version: %s cfg version: %s", _VER, parsedcfg["Version"]))
        return
    end

    pui.set_cfg(parsedcfg)
    local aa_cfg = parsedcfg["Anti-aimbot angles"] or parsedcfg["Anti-Aimbot"]
    if pui.apply_defensive_cfg_from_table and type(aa_cfg) == "table" then
        pui.apply_defensive_cfg_from_table(aa_cfg)
    end
    if pui.apply_gamesense_cfg then
        pui.apply_gamesense_cfg(parsedcfg)
    end
    if type(parsedcfg["pui.keypos"]) == "table" then pui.keypos = parsedcfg["pui.keypos"] end
    if type(parsedcfg["pui.specpos"]) == "table" then pui.specpos = parsedcfg["pui.specpos"] end
    if type(parsedcfg["pui.wtpos"]) == "table" then pui.wtpos = parsedcfg["pui.wtpos"] end
    if database and database.write then
        pcall(database.write, "osmanhook::keypos", pui.keypos)
        pcall(database.write, "osmanhook::specpos", pui.specpos)
        pcall(database.write, "osmanhook::wtpos", pui.wtpos)
    end
    cfg_log("Loaded", "Clipboard")
end


cfg.save = function()
    local cfgname = ui.get(tabs["Configs"].textbox)
    if cfgname == nil or string.len(table.concat(pui.split(cfgname))) < 1 then
        cfg_error("Select Configs or Enter Config Name")
        return
    end

    local cofg = pui.get_config(tabs)
    if not pui.in_table(cfg.names, cfgname) then
        table.insert(cfg.names, cfgname)
        cfg.update_listbox()
        database.write("osmanhook::cfg_names", cfg.names)
    end
    local file_path = cfg_file_path_for_name(cfgname)
    if not file_path then
        cfg_error("Invalid Config")
        return
    end
    writefile(file_path, "osmanhook:"..base64.encode(cofg))
    cfg_log("Saved", cfgname)
end

cfg.export = function()
    local setclip = (clipboard and clipboard.set) or (clip and clip.set) or nil
    if setclip then
        setclip("osmanhook:"..base64.encode(pui.get_config(tabs)))
    end
end

cfg.restore = function()
    local cfgname = ui.get(tabs["Configs"].textbox)
    if cfgname == nil or string.len(table.concat(pui.split(cfgname))) < 1 then
        cfg_error("Select Configs or Enter Config Name")
        return
    end
    if not pui.in_table(cfg.names, cfgname) then
        local file_path = cfg_file_path_for_name(cfgname)
        if (file_path and readfile(file_path)) or readfile(string.format("%s31415926535.cfg", cfgname)) then
            table.insert(cfg.names, cfgname)
            cfg.update_listbox()
            database.write("osmanhook::cfg_names", cfg.names)
        else
            cfg_error("No Config To Restore")
        end
    end
end

cfg.load = function()
    local cfgname = ui.get(tabs["Configs"].textbox)
    if cfgname == nil or string.len(table.concat(pui.split(cfgname))) < 1 then
        cfg_error("Select Configs or Enter Config Name")
        return
    end

    local rawcfg = nil
    local file_path = cfg_file_path_for_name(cfgname)
    if file_path then
        rawcfg = readfile(file_path)
    end
    if rawcfg == nil then
        rawcfg = readfile(string.format("%s31415926535.cfg", cfgname))
    end
    if not rawcfg or type(rawcfg) ~= "string" then
        cfg_error("No Config To Load")
        return
    end

    local parsedcfg, err = cfg_parse_raw(rawcfg)
    if not parsedcfg then
        cfg_error(err or "Failed to parse config")
        return
    end
    if tonumber(parsedcfg["Version"]) ~= tonumber(_VER) then
        cfg_error(string.format("CFG Version mismatch current version: %s cfg version: %s", _VER, parsedcfg["Version"]))
        return
    end

    pui.set_cfg(parsedcfg)
    local aa_cfg = parsedcfg["Anti-aimbot angles"] or parsedcfg["Anti-Aimbot"]
    if pui.apply_defensive_cfg_from_table and type(aa_cfg) == "table" then
        pui.apply_defensive_cfg_from_table(aa_cfg)
    end
    if pui.apply_gamesense_cfg then
        pui.apply_gamesense_cfg(parsedcfg)
    end
    if type(parsedcfg["pui.keypos"]) == "table" then pui.keypos = parsedcfg["pui.keypos"] end
    if type(parsedcfg["pui.specpos"]) == "table" then pui.specpos = parsedcfg["pui.specpos"] end
    if type(parsedcfg["pui.wtpos"]) == "table" then pui.wtpos = parsedcfg["pui.wtpos"] end
    if database and database.write then
        pcall(database.write, "osmanhook::keypos", pui.keypos)
        pcall(database.write, "osmanhook::specpos", pui.specpos)
        pcall(database.write, "osmanhook::wtpos", pui.wtpos)
    end
    cfg_log("Loaded", cfgname)
end

cfg.delete = function()
    local cfgname = ui.get(tabs["Configs"].textbox)
    if cfgname == nil or string.len(table.concat(pui.split(cfgname))) < 1 then
        cfg_error("Select Configs or Enter Config Name")
        return
    end
    if pui.in_table(cfg.names, cfgname) then
        for i, name in ipairs(cfg.names) do
            if name == cfgname then
                table.remove(cfg.names, i)
                break
            end
        end
        cfg.update_listbox()
        database.write("osmanhook::cfg_names", cfg.names)
        local legacy_path = string.format("%s31415926535.cfg", cfgname)
        local safe_path = cfg_file_path_for_name(cfgname)
        if safe_path and readfile(safe_path) then pcall(writefile, safe_path, "") end
        if readfile(legacy_path) then pcall(writefile, legacy_path, "") end
        cfg_log("Deleted", cfgname)
    else
        cfg_error("Config not found")
    end
end

ui.set_callback(tabs["Configs"].configbox, function(id)
    local sel = ui.get(id)
    local name = nil
    if type(sel) == "number" then
        name = cfg.names[sel + 1]
    elseif type(sel) == "string" then
        for i, n in ipairs(cfg.names) do
            if sel == n or sel == (cfg_colored_name and cfg_colored_name(n) or n) then
                name = n
                break
            end
        end
    end
    if name then
        ui.set(tabs["Configs"].textbox, name)
    end
end)
do
    if type(cfg.names) ~= "table" then cfg.names = {} end

    for i = #cfg.names, 1, -1 do
        local name = cfg.names[i]
        if type(name) ~= "string" or name == "" then
            table.remove(cfg.names, i)
        else
            local legacy_path = string.format("%s31415926535.cfg", name)
            local safe_path = cfg_file_path_for_name(name)
            if not readfile(legacy_path) and (not safe_path or not readfile(safe_path)) then
            table.remove(cfg.names, i)
            end
        end
    end
    database.write("osmanhook::cfg_names", cfg.names)
    if cfg and cfg.update_listbox then
        pcall(cfg.update_listbox)
    end
end

ui.set_callback(tabs["Configs"].importcfg, cfg.import)
ui.set_callback(tabs["Configs"].loadcfg, cfg.load)
ui.set_callback(tabs["Configs"].savecfg, cfg.save)
ui.set_callback(tabs["Configs"].deletecfg, cfg.delete)
ui.set_callback(tabs["Configs"].exportcfg, cfg.export)
 
pui.cmd_ticks = function(cmd)
    local dt = ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2])
    local hs = not dt and ui.get(skeetgui.aagui.other.on_shot_antiaim[1]) and ui.get(skeetgui.aagui.other.on_shot_antiaim[2])
    local fakelagoffset = (hs and 1 or ui.get(dt and skeetgui.ragegui.aimbot.double_tap_lag_limit or skeetgui.aagui.fakelag.limit)) + 1
    local choked = cmd and cmd.chokedcommands or nil
    if choked == nil then
        local ok, gc = pcall(globals.chokedcommands)
        if ok and type(gc) == "number" then choked = gc end
    end
    if choked ~= nil and choked > 0 then
        fakelagoffset = choked
    end
    return pui.round(globals.tickcount()/math.max(1, fakelagoffset))
end
pui.multi_parse = function(multiselect, val)
    return pui.in_table(ui.get(multiselect), val)
end
pui.combo_parse = function(combo, ...)
    args = {...}
    return pui.in_table(args, combo)
end

hide = hide or {}
_native_ref_cache = _native_ref_cache or {}

local function _is_protected_native_ref(id)
	if type(id) ~= "number" then return false end
	local cached = _native_ref_cache[id]
	if cached ~= nil then return cached end
	local found = false
	local function scan(t)
		if found or t == nil then return end
		local tt = type(t)
		if tt == "number" then
			if t == id then
				found = true
				return
			end
		elseif tt == "table" then
			for _, v in pairs(t) do
				if found then return end
				scan(v)
			end
		end
	end
	if skeetgui then
		if skeetgui.ragegui then scan(skeetgui.ragegui) end
		if not found and skeetgui.configgui then scan(skeetgui.configgui) end
	end
	_native_ref_cache[id] = found
	return found
end

pui.visibleparse = function(tables, bool)
	if type(tables) == "number" then
		if bool == false and _is_protected_native_ref and _is_protected_native_ref(tables) then
			return
		end
		if bool == false then
			hide[tables] = tables
		end
		pcall(ui.set_visible, tables, bool)
		return
	end

    if type(tables) ~= "table" then
        return
    end

     
    if rawget(tables, "__name") == "pui::element" then
        local elem_ref = rawget(tables, "ref")
        if type(elem_ref) == "number" then
            if bool == false and _is_protected_native_ref and _is_protected_native_ref(elem_ref) then
                return
            end
            if bool == false then
                hide[elem_ref] = elem_ref
            end
            pcall(ui.set_visible, elem_ref, bool)
            return
        end
    end


    for k, t in pairs(tables) do
        if k ~= "__name" and k ~= "__metatable" and k ~= "__index" and k ~= "__newindex" then
            pui.visibleparse(t, bool)
        end
    end
end
pui.set_visibleA = function(tables, val, bol)
    for k, v in pairs(tables) do
        if k == val then
            pui.visibleparse(v, bol == nil and true or bol)
        else
            pui.visibleparse(v, false)
        end
    end
end
pui.checkbox_visible = function(tab, bool)
    local visible = (bool ~= nil and bool or true)
    if type(tab) ~= "table" then
        if type(tab) == "number" then ui.set_visible(tab, visible) end
        return
    end
    local base = tab[1]
    local base_ok = type(base) == "number"
    local base_on = false
    if base_ok then
        local ok, val = pcall(ui.get, base)
        local function to_bool(x)
            return type(x) == "boolean" and x or false
        end
        base_on = ok and to_bool(val) or false
        ui.set_visible(base, visible)
    end
    for _, control in pairs(tab) do
        if control ~= base and type(control) == "number" then
            ui.set_visible(control, visible and base_ok and base_on)
        end
    end
end

pui.visible_misc = function(tab)
    for k, v in pairs(tab) do
        if v == tab.animbreak then
            ui.set_visible(v[1], true)
            local enable = ui.get(v[1])
            for _, val in pairs(v) do
                if val ~= tab.animbreak[1] then
                    if val == tab.animbreak[7] then
                        ui.set_visible(val, #ui.get(v[6]) > 0 and enable)
                    else
                        ui.set_visible(val, enable)
                    end
                end
            end
        elseif v == tab.logs then
            local enable = ui.get(v[1])
            local onhit = pui.multi_parse(v[3], "On Hit")
            local onmiss = pui.multi_parse(v[3], "On Miss")
            local onhurt = pui.multi_parse(v[3], "On Hurt")
            local onfire = pui.multi_parse(v[3], "Ragebot fire")
            local is2 = #ui.get(v[2]) > 0
            local ens2 = enable and is2
            ui.set_visible(v[1], true)
            ui.set_visible(v[2], enable)
            ui.set_visible(v[3], ens2)
            ui.set_visible(v[4], ens2 and onhit)
            ui.set_visible(v[5], ens2 and onhit)
            ui.set_visible(v[6], ens2 and onmiss)
            ui.set_visible(v[7], ens2 and onmiss)
            ui.set_visible(v[8], ens2 and onhurt)
            ui.set_visible(v[9], ens2 and onhurt)
            ui.set_visible(v[10], ens2 and onfire)
            ui.set_visible(v[11], ens2 and onfire)
        else
            pui.checkbox_visible(v)
        end
    end

    local u = tab and tab.uistyle
    if u then
        local style = nil
        pcall(function() style = ui.get(u[1]) end)
        pcall(ui.set_visible, u[1], true)
        pcall(ui.set_visible, u[2], style == "Skeet")
        pcall(ui.set_visible, u[3], style == "??" or style == "Methamod")
        pcall(ui.set_visible, u[4], style == "??" or style == "Blurified")
        local is_blur = style == "Blurified"
        pcall(ui.set_visible, u[5], is_blur)
        pcall(ui.set_visible, u[6], is_blur)
        pcall(ui.set_visible, u[7], is_blur)
        pcall(ui.set_visible, u[8], is_blur)
        pcall(ui.set_visible, u[9], is_blur)
        pcall(ui.set_visible, u[10], is_blur)
        pcall(ui.set_visible, u[11], is_blur)
        pcall(ui.set_visible, u[12], is_blur)
    end
end

pui.customize_mode_get = function(ctrl)
    if ctrl == nil then return nil end
    local ok, v = pcall(ui.get, ctrl)
    if not ok then return nil end
    if v == "Fake lag" or v == "Defensive" or v == "Anti-brute" then
        return v
    end
    if type(v) == "number" then
        if v == 1 then return "Fake lag" end
        if v == 2 then return "Defensive" end
        if v == 3 then return "Anti-brute" end
    end
    return nil
end

pui.visible_aa = function(tab)
    local enabled = true
    if tab[1] ~= nil then
        local ok, v = pcall(ui.get, tab[1])
        if ok and type(v) == "boolean" then
            enabled = v
        end
        ui.set_visible(tab[1], true)
    end

    if tab.aa_page ~= nil then
        ui.set_visible(tab.aa_page, enabled)
        if tab.aa_page_space ~= nil then
            ui.set_visible(tab.aa_page_space, enabled)
        end
        local page = ui.get(tab.aa_page)
        if tostring(page or ""):find("Anti-aimbot addons", 1, true) ~= nil then
            if tab.override_controls ~= nil then
                for _, ref in pairs(tab.override_controls) do
                    ui.set_visible(ref, false)
                end
            end
            if pui.visible_aa_addons then
                pui.visible_aa_addons(tab)
            end
            return
        end
    end

    local cond
    do
        local ok, val = pcall(ui.get, tab.condition)
        cond = ok and val or nil
    end
    if cond == nil then
        cond = (antiaims and antiaims.conds and antiaims.conds[1]) or "Shared"
    end
    ui.set_visible(tab.condition, enabled)
    if tab.condition_space ~= nil then
        ui.set_visible(tab.condition_space, enabled)
    end

    if tab.override_controls ~= nil then
        for name, ref in pairs(tab.override_controls) do
            ui.set_visible(ref, enabled and cond == name)
        end
    end

    ui.set_visible(tab.builder, enabled)
    for k, v in pairs(tab) do
        if v ~= tab[1] and v ~= tab.aa_page and v ~= tab.condition and v ~= tab.condition_space and v ~= tab.builder and v ~= tab.override_controls then
            if k == cond then
                local is_g = cond == "Shared"
                local override_on = false
                if not is_g and v.override ~= nil then
                    local ok, ov = pcall(ui.get, v.override)
                    override_on = ok and (type(ov) == "boolean" and ov or false) or false
                end
                local ng = not is_g and enabled and override_on
                local mode
                if v.customize ~= nil and pui.customize_mode_get then
                    mode = pui.customize_mode_get(v.customize)
                end
                if mode == nil then
                    local mode_ctrl = tabs and tabs["Fake lag"] and tabs["Fake lag"].mode or nil
                    mode = (pui.customize_mode_get and pui.customize_mode_get(mode_ctrl)) or "Fake lag"
                end
                if tabs and tabs.angles then
                    local ang = tabs.angles
                    local hide_base = (mode == "Defensive")
                    if ang.pitch and ang.pitch[1] then 
                        ui.set_visible(ang.pitch[1], not hide_base) 
                    end
                    if ang.yaw_base then 
                        ui.set_visible(ang.yaw_base, not hide_base) 
                    end
                    if ang.yaw and ang.yaw[1] then 
                        ui.set_visible(ang.yaw[1], not hide_base) 
                    end
                end

                for key, value in pairs(v) do
                    if type(value) == "number" then
                        local vis
                        if not is_g and value ~= v.override then
                            vis = enabled and override_on
                        else
                            vis = enabled
                        end

                        if mode == "Defensive" and (key == "pitch" or key == "pitch_label" or key == "yaw_base") then
                            vis = false
                        end
                        if mode ~= "Fake lag" and (key == "fakelag" or key == "fakelag_label" or key == "fakelaglimit") then
                            vis = false
                        end
                        if mode == "Fake lag" and key == "force_def" then
                            vis = false
                        end
                        if mode == "Anti-brute" and key == "force_def" then
                            vis = false
                        end
                        if value == tab[cond].yaw_lr then
                            local yaw_type = ui.get(tab[cond].yaw)
                            if pui.combo_parse(yaw_type, "Off") then
                                vis = false
                            end
                        end
                        ui.set_visible(value, vis)
                     elseif value == tab[cond].fakelagc then
                         local fltype = ui.get(tab[cond].fakelag)
                         if mode == "Fake lag" then
                             pui.set_visibleA(value, (enabled and is_g) and fltype or (ng and enabled) and fltype)
                         else
                             pui.visibleparse(value, false)
                         end
                     elseif value == tab[cond].pitchc then
                         local ptype = ui.get(tab[cond].pitch)
                         local show = (enabled and is_g) and pui.combo_parse(ptype, "Custom") or (ng and enabled) and pui.combo_parse(ptype, "Custom")
                         if mode == "Defensive" then
                             show = false
                         end
                         ui.set_visible(value[1], show)
                     elseif value == tab[cond].yaw_jitterc then
                         local yaw_jtype = ui.get(tab[cond].yaw_jitter)
                         if not pui.combo_parse(yaw_jtype, "Off") then
                            pui.set_visibleA(value, (enabled and is_g) and yaw_jtype or (ng and enabled) and yaw_jtype)
                        else
                            pui.visibleparse(value, false)
                        end
                    elseif value == tab[cond].yawc then
                        local yaw_type = ui.get(tab[cond].yaw)
                        local lr = (tab[cond].yaw_lr ~= nil and ui.get(tab[cond].yaw_lr)) or false
                        if lr and not pui.combo_parse(yaw_type, "Off") then
                            yaw_type = "L&R"
                        end
                        if not pui.combo_parse(yaw_type, "Off") then
                            pui.set_visibleA(value, (enabled and is_g) and yaw_type or (ng and enabled) and yaw_type)
                        else
                            pui.visibleparse(value, false)
                        end
                    elseif value == tab[cond].body_yawc then
                        local body_ytype = ui.get(tab[cond].body_yaw)
                        if not pui.combo_parse(body_ytype, "Off", "Opposite") then
                            pui.set_visibleA(value, (enabled and is_g) and body_ytype or (ng and enabled) and body_ytype)
                        else
                            pui.visibleparse(value, false)
                        end
                    					elseif value == tab[cond].defensive then
						if mode ~= "Defensive" then

							pui.visibleparse(value, false)
						elseif tab[cond].def_flick == nil or tab[cond].def_flick[1] == nil or not ui.get(tab[cond].def_flick[1]) then
							local defen = ui.get(value.enable)
							local ptich = ui.get(value.pitch)
							local gdef = is_g and defen
							local ngdef = ng and defen
							local enable_vis = (is_g and enabled or ng and enabled)
							ui.set_visible(value.enable, enable_vis)
							if value.enable_space ~= nil then
								ui.set_visible(value.enable_space, enable_vis and defen)
							end
							ui.set_visible(value.pitch, (gdef or ngdef) and enabled)
							pui.set_visibleA(value.pitchc, ptich, (gdef or ngdef) and enabled)
							if value.pitch_space ~= nil then
								ui.set_visible(value.pitch_space, (gdef or ngdef) and enabled)
							end
							local p180 = ui.get(value.point_180)
							ui.set_visible(value.yaw, (gdef and enabled or ngdef and enabled) and not p180)
							if not p180 then
								pui.set_visibleA(value.yawc, ((gdef or ngdef) and enabled) and ui.get(value.yaw))
							else
								pui.visibleparse(value.yawc, false)
							end
							if value.yaw_space ~= nil then
								ui.set_visible(value.yaw_space, (gdef and enabled or ngdef and enabled) and not p180)
							end

							local gen_vis = enable_vis
							ui.set_visible(value.yaw_generation, gen_vis)
							local yaw_gen_enabled = value.yaw_generation and ui.get(value.yaw_generation)
							ui.set_visible(value.yaw_gen_min, gen_vis and yaw_gen_enabled)
							ui.set_visible(value.yaw_gen_max, gen_vis and yaw_gen_enabled)
							ui.set_visible(value.pitch_generation, gen_vis)
							local pitch_gen_enabled = value.pitch_generation and ui.get(value.pitch_generation)
							ui.set_visible(value.pitch_gen_min, gen_vis and pitch_gen_enabled)
							ui.set_visible(value.pitch_gen_max, gen_vis and pitch_gen_enabled)
							ui.set_visible(value.point_180, (gdef or ngdef) and enabled and ui.get(value.yaw) == "180")
							ui.set_visible(value.tick, gdef and enabled or ngdef and enabled)
						end
                    elseif value == tab[cond].def_flick then
						local vis = mode == "Defensive" and enabled
						antiaims._def_flick_vis = antiaims._def_flick_vis or {}
						antiaims._def_flick_vis[cond] = vis
						ui.set_visible(value[1], vis)
						if value[2] ~= nil then
							ui.set_visible(value[2], false)
						end
                    elseif value == tab[cond].anti_brute then
                        if mode ~= "Anti-brute" then
                            pui.visibleparse(value, false)
                        else
                            local is_cond_visible = enabled and (is_g or ng)
                            local ab_enabled = is_cond_visible and ui.get(value.enabled)
                            ui.set_visible(value.enabled, is_cond_visible)
                            ui.set_visible(value.type, is_cond_visible and ab_enabled)
                            ui.set_visible(value.mode, is_cond_visible and ab_enabled)
                            local is_timer = ab_enabled and ui.get(value.mode) == "Timer"
                            ui.set_visible(value.time, is_cond_visible and is_timer)
                            local cur_type = ab_enabled and ui.get(value.type) or nil
                            if type(value.phase) == "table" then
                                for i = 1, 5 do
                                    local ph = value.phase[i]
                                    if ph ~= nil then
                                        local this_phase = cur_type == ("Phase " .. i)
                                        local ph_vis = is_cond_visible and ab_enabled and this_phase
                                        ui.set_visible(ph.yaw, ph_vis)
                                        local yaw_mode = ph_vis and ui.get(ph.yaw) or nil
                                        local lr = yaw_mode == "Left & Right"
                                        ui.set_visible(ph.yaw_left, ph_vis and lr)
                                        ui.set_visible(ph.yaw_right, ph_vis and lr)
                                        ui.set_visible(ph.yaw_modifier, ph_vis)
                                        local mod = ph_vis and ui.get(ph.yaw_modifier) or nil
                                        local need_lim = mod == "Offset" or mod == "Center" or mod == "Random" or mod == "Spin"
                                        ui.set_visible(ph.yaw_modifier_limit, ph_vis and need_lim)
                                    end
                                end
                            end
                        end
                    elseif value == tab.aa_other_label or value == tab.aa_other_spacer then
                        pui.visibleparse(value, enabled)
                    else
                        pui.visibleparse(value, enabled)
                    end
                end
            elseif v == tab.manuals or v == tab.lby_breaker or v == tab.lagrandom then
                pui.visibleparse(v, false)
            elseif v == tab.other or v == tab.inverter or v == tab.edgeyaw or v == tab.freestand or v == tab.exttep or v == tab.addons then
                pui.visibleparse(v, false)
            else
                pui.visibleparse(v, false)
            end
        end
    end
end

pui.visible_aa_addons = function(tab)
    if not tab then return end
    local enabled = true
    if tab[1] ~= nil then
        local ok, v = pcall(ui.get, tab[1])
        if ok and type(v) == "boolean" then enabled = v end
        ui.set_visible(tab[1], true)
    end

    if tab.aa_page ~= nil then ui.set_visible(tab.aa_page, enabled) end
    if tab.aa_page_space ~= nil then ui.set_visible(tab.aa_page_space, enabled) end
    if tab.condition ~= nil then ui.set_visible(tab.condition, false) end
    if tab.condition_space ~= nil then ui.set_visible(tab.condition_space, false) end
    if tab.builder ~= nil then ui.set_visible(tab.builder, false) end

    if antiaims and antiaims.conds then
        for _, cname in ipairs(antiaims.conds) do
            if tab[cname] ~= nil then
                pui.visibleparse(tab[cname], false)
            end
        end
    end

    if tab.aa_autogen_btn ~= nil then
        pcall(ui.set_visible, tab.aa_autogen_btn, true)
    end

    pui.visibleparse(tab.inverter, enabled)
    pui.visibleparse(tab.edgeyaw, enabled)
    pui.visibleparse(tab.freestand, enabled)
    pui.visibleparse(tab.exttep, enabled)
    pui.checkbox_visible(tab.manuals, enabled)
    if tab.manuals_anim ~= nil then
        pcall(ui.set_visible, tab.manuals[1], false)
        for i = 1, 4 do
            local r = tab.manuals_anim[i]
            if r ~= nil then
                pcall(ui.set_visible, r, enabled and i == 1)
            end
        end
    end
    pui.checkbox_visible(tab.lby_breaker, enabled)
    pui.visibleparse(tab.other, enabled)
    pui.visibleparse(tab.addons, enabled)
    pui.visibleparse(tab.auto_hide_shots_spacer, enabled)
    if tab.auto_hide_shots_anim ~= nil then
        pcall(ui.set_visible, tab.auto_hide_shots_anim[1], enabled)
        pcall(ui.set_visible, tab.auto_hide_shots_anim[2], false)
    end
    if tab.auto_hide_shots ~= nil and tab.auto_hide_shots[1] ~= nil then
        pcall(ui.set_visible, tab.auto_hide_shots[1], false)
    end
    if not enabled and tab.auto_hide_shots ~= nil then
        pcall(ui.set_visible, tab.auto_hide_shots[2], false)
        pcall(ui.set_visible, tab.auto_hide_shots[3], false)
    end

    if enabled and update_auto_hide_shots_visibility then
        update_auto_hide_shots_visibility()
    end
    if enabled and update_auto_hide_shots_label then
        update_auto_hide_shots_label()
    end
end

antiaims.auto_generate_presets = function()
    if not tabs or not tabs["Anti-aimbot angles"] or not antiaims or not antiaims.conds then return end

    local function set_cond_mode(cond_name, mode)
        local cond_tab = tabs["Anti-aimbot angles"][cond_name]
        if type(cond_tab) ~= "table" then return end

        local customize_ctrl = cond_tab.customize
        if customize_ctrl and pui.customize_mode_get then
            pcall(ui.set, customize_ctrl, mode)
        end
    end

    local function reset_builder_for(cond_name)
        local cond_tab = tabs["Anti-aimbot angles"][cond_name]
        if type(cond_tab) ~= "table" then return end

        if cond_name ~= "Shared" and cond_tab.override then
            pcall(ui.set, cond_tab.override, true)
        end

        if cond_tab.customize then
            pcall(ui.set, cond_tab.customize, "Fake lag")
        end

        if cond_tab.pitch then pcall(ui.set, cond_tab.pitch, "Off") end
        if cond_tab.pitchc and cond_tab.pitchc[1] then
            pcall(ui.set, cond_tab.pitchc[1], 0)
        end

        if cond_tab.yaw then pcall(ui.set, cond_tab.yaw, "Off") end
        if cond_tab.yawc then
            for _, ref in pairs(cond_tab.yawc) do
                if type(ref) == "number" then
                    pcall(ui.set, ref, 0)
                elseif type(ref) == "table" then
                    for _, r in ipairs(ref) do
                        pcall(ui.set, r, 0)
                    end
                end
            end
        end

        if cond_tab.yaw_lr then pcall(ui.set, cond_tab.yaw_lr, false) end
        if cond_tab.yaw_base then pcall(ui.set, cond_tab.yaw_base, "Local view") end

        if cond_tab.yaw_jitter then pcall(ui.set, cond_tab.yaw_jitter, "Off") end
        if cond_tab.yaw_jitterc then
            for _, v in pairs(cond_tab.yaw_jitterc) do
                if type(v) == "number" then
                    pcall(ui.set, v, 0)
                elseif type(v) == "table" then
                    for _, r in ipairs(v) do
                        pcall(ui.set, r, 0)
                    end
                end
            end
        end

        if cond_tab.body_yaw then pcall(ui.set, cond_tab.body_yaw, "Off") end
        if cond_tab.body_yawc then
            for _, v in pairs(cond_tab.body_yawc) do
                if type(v) == "number" then
                    pcall(ui.set, v, 0)
                elseif type(v) == "table" then
                    for _, r in ipairs(v) do
                        pcall(ui.set, r, 0)
                    end
                end
            end
        end
        if cond_tab.body_yaw_freestand then pcall(ui.set, cond_tab.body_yaw_freestand, false) end

        if cond_tab.body_delay then pcall(ui.set, cond_tab.body_delay, "Static") end
        if cond_tab.body_delay_ticks then pcall(ui.set, cond_tab.body_delay_ticks, 0) end

        if cond_tab.fakelag then pcall(ui.set, cond_tab.fakelag, "Maximum") end
        if cond_tab.fakelaglimit then pcall(ui.set, cond_tab.fakelaglimit, 14) end
        if cond_tab.fakelagc then
            for _, refs in pairs(cond_tab.fakelagc) do
                if type(refs) == "table" then
                    for _, r in ipairs(refs) do
                        pcall(ui.set, r, 0)
                    end
                end
            end
        end

        local def = cond_tab.defensive
        if type(def) == "table" then
            if def.enable then pcall(ui.set, def.enable, false) end
            if def.pitch then pcall(ui.set, def.pitch, "Default") end
            if def.yaw then pcall(ui.set, def.yaw, "Default") end
            if def.tick then pcall(ui.set, def.tick, 1) end
            if def.pitchc then
                for _, v in pairs(def.pitchc) do
                    if type(v) == "number" then
                        pcall(ui.set, v, 0)
                    elseif type(v) == "table" then
                        for _, r in ipairs(v) do
                            pcall(ui.set, r, 0)
                        end
                    end
                end
            end
            if def.yawc then
                for _, v in pairs(def.yawc) do
                    if type(v) == "number" then
                        pcall(ui.set, v, 0)
                    elseif type(v) == "table" then
                        for _, r in ipairs(v) do
                            pcall(ui.set, r, 0)
                        end
                    end
                end
            end
            if def.point_180 then pcall(ui.set, def.point_180, false) end
        end

        if cond_tab.force_def then pcall(ui.set, cond_tab.force_def, "Off") end

        local ab = cond_tab.anti_brute
        if type(ab) == "table" and ab.enabled then
            pcall(ui.set, ab.enabled, false)
        end
    end

    local function set_defensive_for(cond_name)
        set_cond_mode(cond_name, "Defensive")
        local cond_tab = tabs["Anti-aimbot angles"][cond_name]
        if type(cond_tab) ~= "table" then return end
        local def = cond_tab.defensive
        if type(def) ~= "table" then return end

        pcall(ui.set, def.enable, true)
        pcall(ui.set, def.pitch, "Adaptive")
        local dp = def.pitchc and def.pitchc["Adaptive"] or nil
        if type(dp) == "table" then
            if dp[1] then pcall(ui.set, dp[1], -25) end
            if dp[2] then pcall(ui.set, dp[2], 35) end
            if dp[3] then pcall(ui.set, dp[3], 80) end
        end

        pcall(ui.set, def.yaw, "Adaptive")
        local dy = def.yawc and def.yawc["Adaptive"] or nil
        if type(dy) == "table" then
            if dy[1] then pcall(ui.set, dy[1], -130) end
            if dy[2] then pcall(ui.set, dy[2], 130) end
            if dy[3] then pcall(ui.set, dy[3], 35) end
            if dy[4] then pcall(ui.set, dy[4], 80) end
        end

        if def.tick then pcall(ui.set, def.tick, 6) end
        if cond_tab.force_def then pcall(ui.set, cond_tab.force_def, "On-Hittable") end

        if cond_tab.yaw_jitter then pcall(ui.set, cond_tab.yaw_jitter, "Random") end
    end

    local function set_aggressive_for(cond_name)
        set_cond_mode(cond_name, "Fake lag")
        local cond_tab = tabs["Anti-aimbot angles"][cond_name]
        if type(cond_tab) ~= "table" then return end

        if cond_tab.defensive and cond_tab.defensive.enable then
            pcall(ui.set, cond_tab.defensive.enable, false)
        end

        if cond_tab.yaw then pcall(ui.set, cond_tab.yaw, "180") end
        if cond_tab.yawc and cond_tab.yawc["180"] then
            pcall(ui.set, cond_tab.yawc["180"], 0)
        end

        if cond_tab.yaw_jitter then
            pcall(ui.set, cond_tab.yaw_jitter, "Random")
            local jc = cond_tab.yaw_jitterc and cond_tab.yaw_jitterc["Random"] or nil
            if type(jc) == "table" then
                if jc[1] then pcall(ui.set, jc[1], -140) end
                if jc[2] then pcall(ui.set, jc[2], 140) end
            end
        end

        if cond_tab.body_yaw then pcall(ui.set, cond_tab.body_yaw, "Jitter") end
        local by = cond_tab.body_yawc and cond_tab.body_yawc["Jitter"] or nil
        if type(by) == "table" then
            if by[1] then pcall(ui.set, by[1], -40) end
            if by[2] then pcall(ui.set, by[2], 40) end
        end
    end

    for _, cond in ipairs(antiaims.conds) do
        reset_builder_for(cond)
    end

    for _, cond in ipairs({"Air", "Air-Crouch", "Crouch", "Crouch-Moving", "Manuals"}) do
        set_defensive_for(cond)
    end

    for _, cond in ipairs(antiaims.conds) do
        if cond ~= "Shared" and cond ~= "Fakelags" and cond ~= "Duckpeek" and cond ~= "Air" and cond ~= "Air-Crouch" and cond ~= "Crouch" and cond ~= "Crouch-Moving" then
            set_aggressive_for(cond)
        end
    end
end

pui.visible_visuals = function(tab)
    for k, v in pairs(tab) do
        if v == tab.watermark then
            ui.set_visible(v[1], true)
            if v[2] then ui.set_visible(v[2], true) end
            if v[3] then ui.set_visible(v[3], true) end
            if v[4] and v[2] then ui.set_visible(v[4], pui.multi_parse(v[2], "Name")) end
            if v[5] and v[2] then ui.set_visible(v[5], pui.multi_parse(v[2], "Name")) end
        elseif v == tab.altui_icon_colors then
            local vis = pui.is_altui and not pui.defaulttab
            ui.set_visible(v[1], vis)
            local enabled = vis and ui.get(v[1])
            ui.set_visible(v[2], enabled)
            ui.set_visible(v[3], enabled)
            ui.set_visible(v[4], enabled)
            ui.set_visible(v[5], enabled)
            ui.set_visible(v[6], enabled)
            ui.set_visible(v[7], enabled)
        elseif v == tab.visuals_other_label or v == tab.visuals_other_spacer or v == tab.visuals_other_space then
            ui.set_visible(v, false)
        elseif v == tab.simple_watermark then
            ui.set_visible(v[1], true)
            local enabled = ui.get(v[1])
            ui.set_visible(v[2], enabled)
            ui.set_visible(v[3], enabled)
            ui.set_visible(v[4], enabled)
            ui.set_visible(v[5], enabled)
        elseif v == tab.betternade then
            ui.set_visible(v[1], true)
            local enabled = ui.get(v[1])
            ui.set_visible(v[2], enabled)
            local enb = enabled and #ui.get(v[2]) > 0
            ui.set_visible(v[3], enabled and #ui.get(v[2]) > 0)
            ui.set_visible(v[4], enb and pui.multi_parse(v[3], "Radius"))
            pui.visibleparse(v.smoke, enabled and pui.multi_parse(v[2], "Smoke") and pui.multi_parse(v[3], "Radius"))
            pui.visibleparse(v.fire, enabled and pui.multi_parse(v[2], "Fire") and pui.multi_parse(v[3], "Radius"))
            ui.set_visible(v[5], enb and pui.multi_parse(v[3], "Smoke Timer"))
            ui.set_visible(v[6], enb and pui.multi_parse(v[3], "Smoke Timer"))
        elseif v == tab.arms_skin then
            ui.set_visible(v[1], true)
            local enabled = ui.get(v[1])
            ui.set_visible(v[2], enabled)
            ui.set_visible(v[3], enabled)
            ui.set_visible(v[4], enabled)
            ui.set_visible(v[5], enabled)
            if v[6] then ui.set_visible(v[6], enabled) end
        elseif v == tab.uistyle then
            local style = nil
            pcall(function() style = ui.get(v[1]) end)
            pcall(ui.set_visible, v[1], true)
            pcall(ui.set_visible, v[2], style == "Skeet")
            pcall(ui.set_visible, v[3], style == "??" or style == "Methamod")
            pcall(ui.set_visible, v[4], style == "??" or style == "Blurified")
            local is_blur = style == "Blurified"
            pcall(ui.set_visible, v[5], is_blur)
            pcall(ui.set_visible, v[6], is_blur)
            pcall(ui.set_visible, v[7], is_blur)
            pcall(ui.set_visible, v[8], is_blur)
            pcall(ui.set_visible, v[9], is_blur)
            pcall(ui.set_visible, v[10], is_blur)
            pcall(ui.set_visible, v[11], is_blur)
            pcall(ui.set_visible, v[12], is_blur)
        else
            pui.checkbox_visible(v)
        end
    end
end

	pui.visible_rage = function(tab)
		for k, v in pairs(tab) do
			if v == tab.jumpshot then
				ui.set_visible(v[1], true)
				local enb = ui.get(v[1])
				ui.set_visible(v[2], enb)
				ui.set_visible(v[3], enb)
				ui.set_visible(v[4], enb and pui.multi_parse(v[3], "R8"))
				ui.set_visible(v[5], enb and pui.multi_parse(v[3], "Scout"))
			elseif v == tab.unsafe_charge then
				ui.set_visible(v[1], true)
				local enb = ui.get(v[1])
				ui.set_visible(v[2], enb)
			elseif v == tab.hitchance or v == tab.dormant then
				ui.set_visible(v[1], true)
				local enb = ui.get(v[1])
				ui.set_visible(v[2], enb)
				ui.set_visible(v[3], enb)
				pui.set_visibleA(v.tbl, ui.get(v[3]), enb)
			elseif v == tab.aimhelper then
				ui.set_visible(v[1], true)
				local enb = true
				ui.set_visible(v[2], enb)
				if v.tbl ~= nil then
					local weapon = ui.get(v[2])
					pui.set_visibleA(v.tbl, weapon, enb)
					local cfg = v.tbl[weapon]
					if cfg then
						if cfg.force_safe then
							local ok, val = pcall(ui.get, cfg.force_safe)
							local is_multi = ok and type(val) == "table"
							pcall(ui.set_visible, cfg.force_safe, enb)
							if cfg.force_safe_hp then
								if is_multi then
									local use_hp = enb and pui.multi_parse(cfg.force_safe, "Target HP below X")
									pcall(ui.set_visible, cfg.force_safe_hp, use_hp)
								else
									pcall(ui.set_visible, cfg.force_safe_hp, enb)
								end
							end
							if cfg.force_safe_miss then
								if is_multi then
									local use_miss = enb and pui.multi_parse(cfg.force_safe, "X Shots missed")
									pcall(ui.set_visible, cfg.force_safe_miss, use_miss)
								else
									pcall(ui.set_visible, cfg.force_safe_miss, enb)
								end
							end
						else
							if cfg.force_safe_hp then pcall(ui.set_visible, cfg.force_safe_hp, false) end
							if cfg.force_safe_miss then pcall(ui.set_visible, cfg.force_safe_miss, false) end
						end

						if cfg.prefer_body then
							local enable_pb = enb
							pcall(ui.set_visible, cfg.prefer_body, enable_pb)
							local use_hp   = enable_pb and pui.multi_parse(cfg.prefer_body, "Target HP below X")
							local use_miss = enable_pb and pui.multi_parse(cfg.prefer_body, "X Shots missed")
							if cfg.prefer_body_hp then pcall(ui.set_visible, cfg.prefer_body_hp, use_hp) end
							if cfg.prefer_body_miss then pcall(ui.set_visible, cfg.prefer_body_miss, use_miss) end
						else
							if cfg.prefer_body_hp then pcall(ui.set_visible, cfg.prefer_body_hp, false) end
							if cfg.prefer_body_miss then pcall(ui.set_visible, cfg.prefer_body_miss, false) end
						end

						if cfg.force_body then
							local enable_fb = enb
							pcall(ui.set_visible, cfg.force_body, enable_fb)
							local use_hp   = enable_fb and pui.multi_parse(cfg.force_body, "Target HP below X")
							local use_miss = enable_fb and pui.multi_parse(cfg.force_body, "X Shots missed")
							if cfg.force_body_hp then pcall(ui.set_visible, cfg.force_body_hp, use_hp) end
							if cfg.force_body_miss then pcall(ui.set_visible, cfg.force_body_miss, use_miss) end
						else
							if cfg.force_body_hp then pcall(ui.set_visible, cfg.force_body_hp, false) end
							if cfg.force_body_miss then pcall(ui.set_visible, cfg.force_body_miss, false) end
						end

						if cfg.ping_spike_value then
							pcall(ui.set_visible, cfg.ping_spike_value, enb)
						end
					end
				end
			elseif v == tab.ai_peek then
				ui.set_visible(v[1], true)
				local enb = ui.get(v[1])
				ui.set_visible(v[2], enb)
            ui.set_visible(v[3], enb)
            ui.set_visible(v[4], enb)
            ui.set_visible(v[5], enb)
        elseif v == tab.lethal then
            ui.set_visible(v[1], true)
            local enb = ui.get(v[1])
            ui.set_visible(v[2], enb)
            ui.set_visible(v[3], enb)
            pui.set_visibleA(v.tbl, ui.get(v[3]), enb)
        elseif v == tab.mpoints then
            ui.set_visible(v[1], true)
            local enabled = ui.get(v[1])
            ui.set_visible(v[2], enabled)
            local cwp = ui.get(v[2])
            pui.set_visibleA(v.enbl, cwp, enabled)
            pui.set_visibleA(v.tbl, cwp, enabled and ui.get(v.enbl[cwp]))
        else
            pui.checkbox_visible(v)
        end
    end

    if tab and tab.lethal then
        pcall(function()
            local v = tab.lethal
            ui.set_visible(v[1], true)
            local enb = ui.get(v[1])
            ui.set_visible(v[2], enb)
            ui.set_visible(v[3], enb)
            if v.tbl ~= nil then
                pui.set_visibleA(v.tbl, ui.get(v[3]), enb)
            end
        end)
    end
end

pui.visible_manipulations = function(tab)
	if not tab then return end
	if pui.visibleparse then
		pcall(pui.visibleparse, tab, true)
	end

	local u = tab.uistyle
	if u then
		for i = 1, #u do
			pcall(ui.set_visible, u[i], false)
		end
	end

	local k = tab.keynames
	if k then
		for _, ref in pairs(k) do
			if ref ~= nil then
				pcall(ui.set_visible, ref, true)
			end
		end
	end
end

pui.visible_tabs = function(tables)
    tables = tables ~= nil and tables or tabs
    local tsel = pui.switch_get and pui.switch_get() or ui.get(switch)

    local home_section = nil
    if tsel == "Home" and pui.home_section_get then
        home_section = pui.home_section_get()
    end

    if tsel ~= "Home" and tabs and tabs["Home"] then
        local h = tabs["Home"]
        local function _hide(x)
            if not x then return end
            if type(x) == "table" then
                for _, r in pairs(x) do _hide(r) end
                return
            end
            pcall(ui.set_visible, x, false)
        end
        _hide(h.cloud_cfg_header)
        _hide(h.cloud_cfg_listbox)
        _hide(h.cloud_cfg_sort)
        _hide(h.cloud_btn_load)
        _hide(h.cloud_btn_delete)
        _hide(h.cloud_btn_like)
        local has_config = cloud_cfg_meta and next(cloud_cfg_meta) ~= nil
        if not has_config then
            _hide(h.author_label)
            _hide(h.likes_label)
            _hide(h.loads_label)
            _hide(h.updated_label)
        end
    end

    if pui._last_visible_tabs_sel == tsel and (tsel ~= "Home" or pui._last_visible_home_section == home_section) then
        if type(tables) ~= "table" then return end
        local v = tables[tsel]
        if v == nil then return end

        if tsel == "Configs" then
            pcall(pui.visibleparse, v, true)
            return
        end

        if tsel == "Manipulations" then
            pcall(pui.visible_manipulations, v)
        elseif tsel == "Rage" then
            pcall(pui.visible_rage, v)
        elseif tsel == "Misc" then
            pcall(pui.visible_misc, v)
        elseif tsel == "Visuals" then
            pcall(pui.visible_visuals, v)
            if tables["Anti-aimbot angles"] ~= nil and tables["Anti-aimbot angles"]["Visuals"] ~= nil then
                pcall(pui.visible_visuals, tables["Anti-aimbot angles"]["Visuals"])
            end
        elseif tsel == "Anti-aimbot angles" then
            pcall(pui.visible_aa, v)
        elseif tsel == "Other" or tsel == "Fake lag" then
            pcall(pui.visibleparse, v, true)
            if tables["Anti-aimbot angles"] ~= nil and pui.visible_aa ~= nil then
                pcall(pui.visible_aa, tables["Anti-aimbot angles"])
            end
        elseif tsel == "Home" then
            if _home_toggle_section_visibility then _home_toggle_section_visibility() end
        else
            pcall(pui.visibleparse, v, true)
        end
        return
    end
    pui._last_visible_tabs_sel = tsel
    pui._last_visible_home_section = home_section

    if tabs.settings_label_rage then ui.set_visible(tabs.settings_label_rage, false) end
    if tabs.settings_spacer_rage_visuals then ui.set_visible(tabs.settings_spacer_rage_visuals, false) end
    if tabs.settings_space_rage then ui.set_visible(tabs.settings_space_rage, false) end
    if tabs.settings_label_visuals then ui.set_visible(tabs.settings_label_visuals, false) end
    if tabs.settings_spacer_visuals_misc then ui.set_visible(tabs.settings_spacer_visuals_misc, false) end
    if tabs.settings_space_visuals then ui.set_visible(tabs.settings_space_visuals, false) end
    if tabs.settings_space_misc then ui.set_visible(tabs.settings_space_misc, false) end

    if type(tables) ~= "table" then return end

    for k, v in pairs(tables) do
        if not (tsel == "Home" and pui.home_section_get and pui.home_section_get() == "Configs" and k == "Configs") then
            pui.visibleparse(v, false)
        end
    end

    local v = tables[tsel]
    if v == nil then return end
    if tsel == "Manipulations" then
        pcall(pui.visible_manipulations, v)
    elseif tsel == "Rage" then
        pcall(pui.visible_rage, v)
    elseif tsel == "Misc" then
        pcall(pui.visible_misc, v)
    elseif tsel == "Visuals" then
        pcall(pui.visible_visuals, v)
        if tables["Anti-aimbot angles"] ~= nil and tables["Anti-aimbot angles"]["Visuals"] ~= nil then
            pcall(pui.visible_visuals, tables["Anti-aimbot angles"]["Visuals"])
        end
    elseif tsel == "Anti-aimbot angles" then
        pcall(pui.visible_aa, v)
    elseif tsel == "Other" or tsel == "Fake lag" then
        pcall(pui.visibleparse, v, true)
        if tables["Anti-aimbot angles"] ~= nil and pui.visible_aa ~= nil then
            pcall(pui.visible_aa, tables["Anti-aimbot angles"])
        end
    elseif tsel == "Home" then
        if _home_toggle_section_visibility then _home_toggle_section_visibility() end
    else
        pcall(pui.visibleparse, v, true)
    end
end

pui.is_altui = false
pui.oldchosen = nil
pui.is_intab = ffi.cast("int*", 0x43479A10)[0] == 1

pui.defaulttab = false

local function menu_visible()

    pui.is_intab = ffi.cast("int*", 0x43479A10)[0] == 1

    if not ui.is_menu_open() then return end
    if not pui.defaulttab then
        pui.visible_tabs()
        if (pui.switch_get and pui.switch_get() or ui.get(switch)) == "Home" and _home_toggle_section_visibility then
            _home_toggle_section_visibility()
        end
    end

    do
        local curtab = pui.switch_get and pui.switch_get() or ui.get(switch)
		if curtab ~= "Anti-aimbot angles" and curtab ~= "Visuals" and curtab ~= "Misc" and curtab ~= "Configs" and curtab ~= "Manipulations" and tabs and tabs["Anti-aimbot angles"] and pui.visibleparse then
            pcall(pui.visibleparse, tabs["Anti-aimbot angles"], false)
        end
    end

    do
        local function _sv(x, v)
            if x == nil then return end
            if pui.visibleparse then
                pcall(pui.visibleparse, x, v)
                return
            end
            if type(x) == "table" then
                for _, it in pairs(x) do
                    _sv(it, v)
                end
                return
            end
            pcall(ui.set_visible, x, v)
        end

        local function _main_tab_name()
            local v = ui.get(switch)
            if type(v) ~= "string" then return v end
            return (v:gsub("^%S+%s+", ""))
        end

        local tab = pui.switch_get and pui.switch_get() or _main_tab_name()
        if tab ~= "Rage" then _sv(tabs and tabs["Rage"], false) end
        if tab ~= "Visuals" and tab ~= "Anti-aimbot angles" then _sv(tabs and tabs["Visuals"], false) end
        if tab ~= "Misc" then _sv(tabs and tabs["Misc"], false) end
        if tab ~= "Anti-aimbot angles" then
            local aa = tabs and tabs["Anti-aimbot angles"]
            if tab ~= "Visuals" then
                _sv(aa and aa["Visuals"], false)
                _sv(aa and aa.indicators_icon, false)
                _sv(aa and aa.indicators_icon_color, false)
                _sv(aa and aa.crossdamage, false)
                _sv(aa and aa.arrows, false)
            end
            if tab ~= "Misc" then
                _sv(aa and aa["Misc"], false)
            end
        end
    end

    ui.set_visible(switch, not pui.defaulttab)
    if switch_title_label then ui.set_visible(switch_title_label, not pui.defaulttab) end
    if switch_space then ui.set_visible(switch_space, not pui.defaulttab) end
    if not pui.defaulttab then pui.visibleparse(skeetgui.aagui, false) end

    local cur = pui.switch_get and pui.switch_get() or ui.get(switch)
    if cur == "Manipulations" and tabs and tabs["Manipulations"] and pui.visible_manipulations then
        pui.visible_manipulations(tabs["Manipulations"])
    end

    if update_fakelag_info then update_fakelag_info() end

end

client.set_event_callback("paint_ui", function()
    pcall(function()
        local show_switch = ui.is_menu_open()
        if pui.visibleparse then
            if switch ~= nil then pcall(pui.visibleparse, switch, show_switch) end
            if switch_space ~= nil then pcall(pui.visibleparse, switch_space, show_switch) end
            if switch_title_label ~= nil then pcall(pui.visibleparse, switch_title_label, show_switch) end
        else
            if switch ~= nil then pcall(ui.set_visible, switch, show_switch) end
            if switch_space ~= nil then pcall(ui.set_visible, switch_space, show_switch) end
            if switch_title_label ~= nil then pcall(ui.set_visible, switch_title_label, show_switch) end
        end

        pcall(menu_visible)
        if pui.visibleparse then
            if switch ~= nil then pcall(pui.visibleparse, switch, show_switch) end
            if switch_space ~= nil then pcall(pui.visibleparse, switch_space, show_switch) end
            if switch_title_label ~= nil then pcall(pui.visibleparse, switch_title_label, show_switch) end
        end
        if update_switch_title_label then pcall(update_switch_title_label) end
        if update_spin_if_label then pcall(update_spin_if_label) end
        if update_auto_hide_shots_label then pcall(update_auto_hide_shots_label) end
        if update_manuals_label then pcall(update_manuals_label) end
        if update_fakelag_label then pcall(update_fakelag_label) end
        if update_pitch_label then pcall(update_pitch_label) end
        if update_fakelag_type_label then pcall(update_fakelag_type_label) end
        if update_defensive_flick_label then pcall(update_defensive_flick_label) end

        do
            if ui.is_menu_open() and entity.get_local_player() == nil then
                if visuals and visuals.spectators then pcall(visuals.spectators) end
                if visuals and visuals.keybinds then pcall(visuals.keybinds) end
                if logs and logs.screen_handler then pcall(logs.screen_handler) end
                if hitlogger and hitlogger.render_astral and pui and pui.get_screen then pcall(hitlogger.render_astral, pui.get_screen()) end
                if visuals and visuals.velocity_warning then pcall(visuals.velocity_warning) end
                if visuals and visuals.defensive_indicator then pcall(visuals.defensive_indicator) end
            end
        end

        do
            local vtab = tabs and tabs["Visuals"]
            local wm = vtab and vtab.watermark
            if wm and wm[1] then
                pcall(ui.set, wm[1], true)
                if not pui._wm_force_cb_set then
                    pui._wm_force_cb_set = true
                    pcall(ui.set_callback, wm[1], function(id)
                        local ok, v = pcall(ui.get, id)
                        if ok and not v then
                            pcall(ui.set, id, true)
                        end
                    end)
                end
            end
        end
    end)
end)

hitlogger.entries = {}
hitlogger.max_entries = 8
hitlogger.duration = 5
hitlogger.animations = {}
hitlogger.last_hitgroup = {}
hitlogger.x = database.read("osmanhook::hitlogger_x") or 300
hitlogger.y = database.read("osmanhook::hitlogger_y") or 100
hitlogger.dragging = false
hitlogger.drag_offset_x = 0
hitlogger.drag_offset_y = 0

hitlogger.add_entry = function(event_type, target_name, damage, hitgroup, weapon, reason)
    local entry = {
        event_type = event_type,
        target_name = target_name or "Unknown",
        damage = damage or 0,
        hitgroup = hitgroup or 0,
        weapon = weapon or "Unknown",
        reason = reason or nil,
        timestamp = globals.curtime(),
        alpha = 255,
        y_offset = 0
    }

    table.insert(hitlogger.entries, 1, entry)

    while #hitlogger.entries > hitlogger.max_entries do
        table.remove(hitlogger.entries)
    end
end

hitlogger.update_animations = function()
    local curtime = globals.curtime()

    for i, entry in ipairs(hitlogger.entries) do
        local age = curtime - entry.timestamp
        local max_age = hitlogger.duration

        if age > max_age then
            table.remove(hitlogger.entries, i)
        else

            local fade_start = max_age * 0.7
            if age > fade_start then
                local fade_progress = (age - fade_start) / (max_age - fade_start)
                entry.alpha = math.floor(255 * (1 - fade_progress))
            end


            local slide_duration = 0.3
            if age < slide_duration then
                local slide_progress = age / slide_duration
                entry.y_offset = math.floor(20 * (1 - slide_progress))
            else
                entry.y_offset = 0
            end
        end
    end
end

hitlogger.get_hitgroup_name = function(hitgroup)
    local hitgroups = {
        [0] = "Generic",
        [1] = "Head",
        [2] = "Chest",
        [3] = "Stomach",
        [4] = "Left Arm",
        [5] = "Right Arm",
        [6] = "Left Leg",
        [7] = "Right Leg",
        [8] = "Neck",
        [9] = "Generic",
        [10] = "Generic"
    }
    return hitgroups[hitgroup] or "Generic"
end

