    end
end

hitlogger.render_stasis_style = function(screen)
    local x = screen.x - hitlogger.x
    local y = hitlogger.y
    local entry_height = 20
    local padding = 3
    local count = math.min(#hitlogger.entries, hitlogger.max_entries)
    if count == 0 and not ui.is_menu_open() then return end
    local previews = {
        {event_type = "hit",  target_name = "Enemy", damage = 97, hitgroup = 3, alpha = 255, y_offset = 0},
        {event_type = "miss", target_name = "Enemy", damage = 0,  hitgroup = 1, reason = "?", alpha = 255, y_offset = 0},
        {event_type = "hurt", target_name = "Enemy", damage = 24, hitgroup = 4, alpha = 255, y_offset = 0},
    }
    local items = (count > 0) and hitlogger.entries or previews
    local items_count = (count > 0) and count or #previews
    for i = 1, items_count do
        local entry = items[i]
        if i > hitlogger.max_entries then break end
        local entry_y = y + (i - 1) * (entry_height + padding) + entry.y_offset
        local width = 300
        renderer.rectangle(x - width, entry_y, width, entry_height, 0, 0, 0, math.floor(entry.alpha * 0.5))
        local text = string.format("%s %s %s %d", entry.event_type, entry.target_name, hitlogger.get_hitgroup_name(entry.hitgroup), entry.damage)
        renderer.text(x - width + 8, entry_y + entry_height / 2, 255, 255, 255, entry.alpha, "c", 0, text)
    end
end

hitlogger.render_chinese_style = function(screen)
    local base_x = screen.x - hitlogger.x
    local base_y = hitlogger.y
    local color = {ui.get(tabs["Manipulations"].uistyle[3])}
    local count = math.min(#hitlogger.entries, hitlogger.max_entries)
    if count == 0 and not ui.is_menu_open() then return end
    local previews = {
        {event_type = "hit",  target_name = "Enemy", damage = 97, hitgroup = 3, alpha = 255, y_offset = 0},
        {event_type = "miss", target_name = "Enemy", damage = 0,  hitgroup = 1, reason = "?", alpha = 255, y_offset = 0},
        {event_type = "hurt", target_name = "Enemy", damage = 24, hitgroup = 4, alpha = 255, y_offset = 0},
    }
    local items = (count > 0) and hitlogger.entries or previews
    local items_count = (count > 0) and count or #previews
    for i = 1, items_count do
        local entry = items[i]
        if i > hitlogger.max_entries then break end
        local y = base_y + (i - 1) * 28 + entry.y_offset
        local text = string.format("%s %s %s %d", entry.event_type, entry.target_name, hitlogger.get_hitgroup_name(entry.hitgroup), entry.damage)
        local w, h = renderer.measure_text("b", text)
        rounded_rect(base_x - w - 14, y - 2, w + 12, h + 6, color[1], color[2], color[3], math.floor(entry.alpha * 0.25), 5)
        renderer.text(base_x - w - 8, y + 1, 240, 240, 240, entry.alpha, nil, 0, text)
    end
end

hitlogger.render_win95_style = function(screen)
    local base_x = screen.x - hitlogger.x
    local base_y = hitlogger.y
    local count = math.min(#hitlogger.entries, hitlogger.max_entries)
    if count == 0 and not ui.is_menu_open() then return end

    local previews = {
        {event_type = "hit",  target_name = "Enemy", damage = 97, hitgroup = 3, alpha = 255, y_offset = 0},
        {event_type = "miss", target_name = "Enemy", damage = 0,  hitgroup = 1, reason = "?", alpha = 255, y_offset = 0},
        {event_type = "hurt", target_name = "Enemy", damage = 24, hitgroup = 4, alpha = 255, y_offset = 0},
    }

    local items = (count > 0) and hitlogger.entries or previews
    local items_count = (count > 0) and count or #previews

    local lines = {}
    local max_w = 0
    local max_a = 0
    for i = 1, items_count do
        local entry = items[i]
        local hg = hitlogger.get_hitgroup_name(entry.hitgroup)
        local reason = entry.reason or "?"
        local msg
        local msg_colored
        local a = tonumber(entry.alpha or 255) or 255
        local base_hex = '\a' .. pui.rgb_to_hex({0, 0, 0, a})
        local dr, dg, db = 0, 200, 0
        if entry.event_type == "miss" then
            dr, dg, db = 255, 0, 0
        elseif entry.event_type == "hurt" then
            dr, dg, db = 255, 165, 0
        end
        local hit_hex = '\a' .. pui.rgb_to_hex({dr, dg, db, a})
        if entry.event_type == "miss" then
            local name = tostring(entry.target_name or "Enemy")
            local hg_t = tostring(hg or "body")
            msg = string.format("Missed in %s's %s due to %s", name, hg_t, tostring(reason))
            msg_colored = base_hex .. "Missed in " .. hit_hex .. name .. base_hex .. "'s " .. hit_hex .. hg_t .. base_hex .. " due to " .. tostring(reason)
        elseif entry.event_type == "hurt" then
            local name = tostring(entry.target_name or "Enemy")
            local hg_t = tostring(hg or "body")
            local dmg = tonumber(entry.damage or 0) or 0
            msg = string.format("Hurt by %s in %s for %d", name, hg_t, dmg)
            msg_colored = base_hex .. "Hurt by " .. hit_hex .. name .. base_hex .. " in " .. hit_hex .. hg_t .. base_hex .. " for " .. hit_hex .. tostring(dmg)
        else
            local name = tostring(entry.target_name or "Enemy")
            local hg_t = tostring(hg or "body")
            local dmg = tonumber(entry.damage or 0) or 0
            msg = string.format("Hit %s in %s for %d", name, hg_t, dmg)
            msg_colored = base_hex .. "Hit " .. hit_hex .. name .. base_hex .. " in " .. hit_hex .. hg_t .. base_hex .. " for " .. hit_hex .. tostring(dmg)
        end
        local w = select(1, renderer.measure_text(nil, msg)) or 0
        if w > max_w then max_w = w end
        if a > max_a then max_a = a end
        lines[i] = {msg = msg, msg_colored = msg_colored or msg, ev = entry.event_type, alpha = a}
    end
    if max_a == 0 then max_a = 255 end

    local title_h = 18
    local pad = 6
    local row_h = 16
    local inner_h = items_count * row_h + pad * 2
    local w_total = math.max(180, max_w + pad * 2 + 22)
    local h_total = title_h + 12 + inner_h + 12

    local x = base_x - w_total
    local y = base_y
    win95_window(x, y, w_total, h_total, "Hitlogs", max_a)

    local ix = x + 6
    local iy = y + 4 + title_h + 8
    local iw = w_total - 12
    local ih = h_total - (iy - y) - 6
    renderer.rectangle(ix, iy, iw, ih, 255, 255, 255, max_a)
    outlined_rectangle(ix, iy, iw, ih, 0, 0, 0, max_a, 1)

    local ty = iy + pad
    for i = 1, items_count do
        local ln = lines[i]
        local a = ln.alpha or max_a
        local dr, dg, db = 0, 0, 0
        renderer.rectangle(ix + 4, ty + 5, 6, 6, dr, dg, db, a)
        renderer.text(ix + 14, ty + 2, 0, 0, 0, a, nil, 0, ln.msg_colored or ln.msg)
        ty = ty + row_h
    end
end

  hitlogger.render_blurified_style = function(screen)
    local base_x = screen.x - hitlogger.x
    local base_y = hitlogger.y
    local bg_col = {ui.get(tabs["Manipulations"].uistyle[5])}
    local outline_col = {ui.get(tabs["Manipulations"].uistyle[6])}
    local sep_col = {ui.get(tabs["Manipulations"].uistyle[7])}
    local label_col = {ui.get(tabs["Manipulations"].uistyle[8])}
    local text_col = {ui.get(tabs["Manipulations"].uistyle[9])}
    local hit_col = {ui.get(tabs["Manipulations"].uistyle[10])}
    local miss_col = {ui.get(tabs["Manipulations"].uistyle[11])}
    local do_glow = ui.get(tabs["Manipulations"].uistyle[4])
    local padding_x, padding_y = 12, 6
    local row_h = 26

    local count = math.min(#hitlogger.entries, hitlogger.max_entries)
    if count == 0 and not ui.is_menu_open() then return end
    local previews = nil
    if ui.is_menu_open() and count == 0 then
        previews = {
            {event_type = "hit",   target_name = "Enemy", damage = 97, hitgroup = 3, alpha = 255, y_offset = 0},
            {event_type = "miss",  target_name = "Enemy", damage = 0,  hitgroup = 1, reason = "?", alpha = 255, y_offset = 0},
            {event_type = "hurt",  target_name = "Enemy", damage = 24, hitgroup = 4, alpha = 255, y_offset = 0},
        }
    end

    local items_count = (count > 0) and count or #previews
    local gap = 3
    for i = 1, items_count do
        local entry = hitlogger.entries[i] or previews[i]
        local is_miss = entry.event_type == "miss"
        local is_hit = entry.event_type == "hit"
        local is_hurt = entry.event_type == "hurt"
        local is_kill = entry.event_type == "kill" or entry.event_type == "killed"
        local hg = hitlogger.get_hitgroup_name(entry.hitgroup)
        local reason = entry.reason or "?"
        local msg
        if is_miss then
            msg = string.format("Missed in %s's %s due to %s", tostring(entry.target_name or "Enemy"), tostring(hg or "body"), tostring(reason))
        elseif is_kill then
            msg = string.format("Killed %s in %s", tostring(entry.target_name or "Enemy"), tostring(hg or "body"))
        elseif is_hurt then
            msg = string.format("Hurt by %s in %s for %d damage", tostring(entry.target_name or "Enemy"), tostring(hg or "body"), tonumber(entry.damage or 0) or 0)
        else
            msg = string.format("Hit %s in %s for %d damage", tostring(entry.target_name or "Enemy"), tostring(hg or "body"), tonumber(entry.damage or 0) or 0)
        end

        local w_text, h_text = renderer.measure_text(nil, msg)
        local dot_d = 10
        local dot_gap = 6
        local w_row = math.max(220, padding_x*2 + dot_d + dot_gap + w_text)
        local radius = math.floor(row_h * 0.5)
        local panel_alpha = entry.alpha or 255
        local y_row = base_y + (i - 1) * (row_h + gap) + (entry.y_offset or 0)
        local x_row = base_x - w_row


        local ev = is_miss and miss_col or hit_col
        local fill_r = bg_col[1]
        local fill_g = bg_col[2]
        local fill_b = bg_col[3]
        local fill_a = math.floor(((bg_col[4] or 140)) * panel_alpha/255)


        if renderer.blur and ui.get(tabs["Manipulations"].uistyle[12]) then
            local r = radius
            renderer.blur(x_row + r, y_row, w_row - 2*r, row_h, 15)
            renderer.blur(x_row, y_row + r, r, row_h - 2*r, 15)
            renderer.blur(x_row + w_row - r, y_row + r, r, row_h - 2*r, 15)
        end

        rounded_rect(x_row, y_row, w_row, row_h, fill_r, fill_g, fill_b, fill_a, radius)
        if do_glow then
            local glow1 = {fill_r, fill_g, fill_b, math.floor(fill_a * 0.25)}
            local glow2 = {fill_r, fill_g, fill_b, math.floor(fill_a * 0.12)}
            pui.shadow(x_row, y_row, w_row, row_h, radius, radius, glow1, glow2)
        end

        do
            local ev_glow1 = {ev[1], ev[2], ev[3], math.floor((panel_alpha) * 0.20)}
            local ev_glow2 = {ev[1], ev[2], ev[3], math.floor((panel_alpha) * 0.10)}
            pui.shadow(x_row, y_row, w_row, row_h, radius, radius, ev_glow1, ev_glow2)
        end
        pui.rec_outline(x_row, y_row, w_row, row_h, radius, 1, {outline_col[1], outline_col[2], outline_col[3], math.floor((outline_col[4] or 255) * panel_alpha/255)})


        local dot_x = x_row + padding_x
        local dot_y = y_row + row_h/2 - dot_d/2
        do
            local ev_glow1 = {ev[1], ev[2], ev[3], math.floor((panel_alpha) * 0.22)}
            local ev_glow2 = {ev[1], ev[2], ev[3], math.floor((panel_alpha) * 0.12)}
            pui.shadow(dot_x - 6, dot_y - 6, dot_d + 12, dot_d + 12, math.floor((dot_d + 12)/2), math.floor((dot_d + 12)/2), ev_glow1, ev_glow2)
            rounded_rect(dot_x, dot_y, dot_d, dot_d, ev[1], ev[2], ev[3], panel_alpha, math.floor(dot_d/2))
        end


        local text_x = dot_x + dot_d + dot_gap
        local text_y = y_row + row_h/2 - h_text/2
        local function draw_seg(str, r, g, b, a, bold)
            renderer.text(text_x, text_y, r, g, b, a, bold and "b" or nil, 0, str)
            local w = select(1, renderer.measure_text(bold and "b" or nil, str))
            text_x = text_x + w
        end
        if is_miss then
            draw_seg("Missed in ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(entry.target_name or "Enemy"), 255, 255, 255, panel_alpha)
            draw_seg("'s ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(hg or "body"), ev[1], ev[2], ev[3], panel_alpha, true)
            draw_seg(" due to ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(reason), ev[1], ev[2], ev[3], panel_alpha, true)
        elseif is_kill then
            draw_seg("Killed ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(entry.target_name or "Enemy"), 255, 255, 255, panel_alpha)
            draw_seg(" in ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(hg or "body"), ev[1], ev[2], ev[3], panel_alpha, true)
        elseif is_hurt then
            local hev = miss_col
            draw_seg("Hurt by ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(entry.target_name or "Enemy"), 255, 255, 255, panel_alpha)
            draw_seg(" in ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(hg or "body"), hev[1], hev[2], hev[3], panel_alpha, true)
            draw_seg(" for ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(tonumber(entry.damage or 0) or 0), 255, 255, 255, panel_alpha)
            draw_seg(" damage", 255, 255, 255, panel_alpha)
        else
            draw_seg("Hit ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(entry.target_name or "Enemy"), 255, 255, 255, panel_alpha)
            draw_seg(" in ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(hg or "body"), ev[1], ev[2], ev[3], panel_alpha, true)
            draw_seg(" for ", 255, 255, 255, panel_alpha)
            draw_seg(tostring(tonumber(entry.damage or 0) or 0), 255, 255, 255, panel_alpha)
            draw_seg(" damage", 255, 255, 255, panel_alpha)
        end
    end
  end




rage.alive_players = {}
rage.resolver_data = {
    cycle_time = 0,
    missed_shots = {},
    last_hit = {},
    best_angles = {},
    shot_data = {},
    jitter_data = {},
    fakeflick_data = {},
    phase_data = {},
    breaking_lby = {},
    air_data = {},
    cache_data = {},
    side_data = {}
}
rage.paint = function()
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end

    rage.target = client.current_threat()
    rage.target_weapon = entity.get_classname(entity.get_player_weapon(rage.target))
    rage.weapon = entity.get_classname(entity.get_player_weapon(lplayer))
    rage.exploits = ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2]) or ui.get(skeetgui.aagui.other.on_shot_antiaim[1]) and ui.get(skeetgui.aagui.other.on_shot_antiaim[2])
    if rage.weapon ~= nil and ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2]) then
        local next_attack = entity.get_prop(lplayer, "m_flNextAttack") + 0.01
        local checkcheck = entity.get_prop(entity.get_player_weapon(lplayer), "m_flNextPrimaryAttack")
        if checkcheck ~= nil then
            local next_primary_attack = checkcheck ~= nil and checkcheck + 0.01
            if next_attack ~= nil and next_primary_attack ~= nil then
                rage.dt = next_attack - globals.curtime() < 0 and next_primary_attack - globals.curtime() < 0
            else
                rage.dt = false
            end
        end
    else
        rage.dt = false
    end
    local lpos = vector(entity.get_origin(lplayer))
    local tpos = rage.target ~= nil and vector(entity.get_origin(rage.target))
    rage.distance = rage.target ~= nil and pui.distance(lpos, tpos) or 0
    rage.zdelta = rage.distance > 0 and lpos.z - tpos.z
    rage.alive_players = {}
    for i=1, globals.maxplayers() do
        if entity.is_alive(i) and entity.is_enemy(i) then
            table.insert(rage.alive_players, i)
        end
    end
    rage.isnoenemy = #rage.alive_players == 0
    if rage.isnoenemy then
        rage.hittable = false
        return
    end
    for i, ent in ipairs(rage.alive_players) do
        if not entity.is_dormant(ent) then
            local flag = entity.get_esp_data(ent).flags or 0
            if bit.band(flag, bit.lshift(1, 11)) ~= 0 then
                rage.hittable = true
            else
                rage.hittable = false
            end
        else
            rage.hittable = false
        end
    end
end
rage.jumpshot = function(cmd)
    if not ui.get(tabs["Rage"].jumpshot[1]) then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local cweapon = entity.get_player_weapon(lplayer)
    if cweapon == nil then return end
    local anst = get_animstate(lplayer)
    local iscout = rage.weapon == "CWeaponSSG08" and (cmd.in_jump == 1 or not anst.on_ground)
    local isr8 = csgo_weapons(cweapon).is_revolver
    local ir8 =  isr8 and (cmd.in_jump == 1 or not anst.on_ground)
    local nexts = entity.get_prop(lplayer, "m_flNextAttack")
    local nextp = globals.curtime() >= (isr8 and nexts or math.max(entity.get_prop(cweapon, "m_flNextPrimaryAttack"), nexts))
    rage.jumpshoting = false
    if not nextp then return end
    if not rage.hittable then return end
    if ui.get(tabs["Rage"].jumpshot[2]) then
        if pui.multi_parse(tabs["Rage"].jumpshot[3], "R8") and ir8 then
            if rage.distance > ui.get(tabs["Rage"].jumpshot[4])  then return end
            cmd.in_jump = 0
        end
        if pui.multi_parse(tabs["Rage"].jumpshot[3], "Scout") and iscout then
            if rage.distance > ui.get(tabs["Rage"].jumpshot[5])  then return end
            cmd.in_jump = 0
        end
    end
end
visuals.ind_iconify = function(text)
    local mapping = {
        ["DT"] = "DT",
        ["OS"] = "OSAA", 
        ["FB"] = "BODY",
        ["MD"] = "DMG",
        ["SP"] = "SAFE",
        ["QP"] = "PEEK",
        ["DP"] = "DUCK",
        ["FS"] = "FS",
        ["JS"] = "SHOT",
        ["HS"] = "HEAD",
        ["HC"] = "HITC",
        ["EY"] = "EDGE",
        ["LBY"] = "LBY",
        ["DS"] = "DS",
        ["DA"] = "DORM",
        ["PING"] = "PING"
    }
    
    local s = tostring(text or "")
    for key, val in pairs(mapping) do
        if s:match("^" .. key) or s:match("^" .. val) then
            return val
        end
    end
    return text
end

