		svg = svg:gsub("%s+xml:space=\"[^\"]*\"", "")
		svg = svg:gsub("%s+xmlns:xlink=\"[^\"]*\"", "")
		svg = svg:gsub("%s+id=\"[^\"]*\"", "")

		local vb = svg:match('viewBox="([^"]+)"')
		local body = svg:match("<svg[^>]*>([%s%S]-)</svg>")
		if vb and body then
			svg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="' .. vb .. '">' .. body .. '</svg>'
		end
