visuals.get_bomb_texture = function()
    visuals.ind_textures = visuals.ind_textures or {}
    local ind = visuals.ind_textures
    if ind.bomb_loaded then
        return ind.bomb
    end
    ind.bomb_loaded = true

    local raw = nil
    if readfile ~= nil then
        raw = readfile("lua/icons svg format/bomb_c4.svg")
        if raw == nil then
            raw = readfile("icons svg format/bomb_c4.svg")
        end
    elseif type(visuals.bomb_svg_raw) == "string" and #visuals.bomb_svg_raw > 0 then
        raw = visuals.bomb_svg_raw
    end
    if type(raw) ~= "string" then
        return nil
    end

    if raw:find("<svg", 1, true) then
        local ok_svg, tid = pcall(renderer.load_svg, raw, 32, 32)
        if ok_svg and type(tid) == "number" and tid > 0 then
            ind.bomb = tid
            return tid
        end
    end
    return nil
end

