visuals.get_defuse_texture = function()
    visuals.ind_textures = visuals.ind_textures or {}
    if visuals.ind_textures.defuse_loaded then
        return visuals.ind_textures.defuse
    end
    visuals.ind_textures.defuse_loaded = true

    local raw = nil
    if readfile ~= nil then
        raw = readfile("lua/icons svg format/defuser.svg")
        if raw == nil then
            raw = readfile("icons svg format/defuser.svg")
        end
    elseif type(visuals.defuse_svg_raw) == "string" and #visuals.defuse_svg_raw > 0 then
        raw = visuals.defuse_svg_raw
    end
    if type(raw) ~= "string" then
        return nil
    end

    if raw:find("<svg", 1, true) then
        local ok_svg, tid = pcall(renderer.load_svg, raw, 32, 32)
        if ok_svg and type(tid) == "number" and tid > 0 then
            visuals.ind_textures.defuse = tid
            return tid
        end
    end
    return nil
end

