visuals.get_ping_texture = function()
	visuals.ind_textures = visuals.ind_textures or {}
	local ind = visuals.ind_textures

	if not ind.ping_loaded then
		ind.ping_loaded = true
		ind.ping_frames = {}

		if type(visuals.ping_svg_raw) == "table" then
			for i = 1, #visuals.ping_svg_raw do
				local raw = visuals.ping_svg_raw[i]
				if type(raw) == "string" and raw:find("<svg", 1, true) then
					local ok_svg, tid = pcall(renderer.load_svg, raw, 32, 32)
					if ok_svg and type(tid) == "number" and tid > 0 then
						ind.ping_frames[#ind.ping_frames + 1] = tid
					end
				end
			end
		end
	end

	local frames = ind.ping_frames or {}
	local count = #frames
	if count == 0 then
		return nil
	end

	if count >= 4 then
		local ping_ms = 0
		local rlat = (client.real_latency and client.real_latency()) or (client.latency and client.latency()) or 0
		if type(rlat) == "number" then
			ping_ms = math.floor(rlat * 1000 + 0.5)
		end

		local idx
		if ping_ms <= 30 then
			idx = 4
		elseif ping_ms <= 70 then
			idx = 3
		elseif ping_ms <= 110 then
			idx = 2
		else
			idx = 1
		end

		if idx < 1 then idx = 1 end
		if idx > count then idx = count end
		return frames[idx]
	end

	local now = globals.realtime()
	ind.ping_anim_last = ind.ping_anim_last or now
	ind.ping_anim_idx = ind.ping_anim_idx or 1

	if now - ind.ping_anim_last >= 0.35 then
		ind.ping_anim_last = now
		local idx = ind.ping_anim_idx + 1
		if idx > count then
			idx = 1
		end
		ind.ping_anim_idx = idx
	end

	return frames[ind.ping_anim_idx]
end

visuals.win95_warn_icon_b64 = visuals.win95_warn_icon_b64 or [[]]
visuals.get_win95_warn_texture = function()
    visuals.ind_textures = visuals.ind_textures or {}
    if visuals.ind_textures.win95_warn_loaded then
        return visuals.ind_textures.win95_warn
    end

    local raw = nil
    if type(visuals.win95_warn_icon_b64) == "string" and #visuals.win95_warn_icon_b64 > 0 then
        raw = visuals.win95_warn_icon_b64
    end
    if type(raw) ~= "string" or #raw == 0 then
        return nil
    end

    raw = raw:gsub("%s+", "")
    local ok_dec, decoded = pcall(base64.decode, raw)
    if not ok_dec or type(decoded) ~= "string" then
        visuals.ind_textures.win95_warn_loaded = true
        visuals.ind_textures.win95_warn = nil
        return nil
    end

    if #decoded < 24 or decoded:sub(1, 8) ~= "\137PNG\r\n\26\n" or decoded:sub(13, 16) ~= "IHDR" then
        visuals.ind_textures.win95_warn_loaded = true
        visuals.ind_textures.win95_warn = nil
        return nil
    end

    local w, h = 48, 48
    do
        local b1, b2, b3, b4, b5, b6, b7, b8 = decoded:byte(17, 24)
        if b1 and b2 and b3 and b4 and b5 and b6 and b7 and b8 then
            w = b1 * 16777216 + b2 * 65536 + b3 * 256 + b4
            h = b5 * 16777216 + b6 * 65536 + b7 * 256 + b8
        end
    end
    if type(w) ~= "number" or type(h) ~= "number" or w <= 0 or h <= 0 then
        w, h = 48, 48
    end

    local ok_png, tid = pcall(renderer.load_png, decoded, w, h)
    if ok_png and type(tid) == "number" and tid > 0 then
        visuals.ind_textures.win95_warn_loaded = true
        visuals.ind_textures.win95_warn = tid
        visuals.ind_textures.win95_warn_w = w
        visuals.ind_textures.win95_warn_h = h
        return tid
    end

    visuals.ind_textures.win95_warn_loaded = true
    visuals.ind_textures.win95_warn = nil
    return nil
end

