visuals.get_osaa_texture = function()
    visuals.ind_textures = visuals.ind_textures or {}
    local ind = visuals.ind_textures

    if ind.osaa_loaded then
        return ind.osaa
    end
    ind.osaa_loaded = true

    local raw = nil
    if type(visuals.osaa_svg_raw) == "string" and #visuals.osaa_svg_raw > 0 then
        raw = visuals.osaa_svg_raw
    elseif readfile ~= nil then
        raw = readfile("lua/icons svg format/icon_star_multi.svg")
        if raw == nil then
            raw = readfile("icons svg format/icon_star_multi.svg")
        end
    end
    if type(raw) ~= "string" then
        return nil
    end

    if raw:find("<svg", 1, true) then
        local ok_svg, tid = pcall(renderer.load_svg, raw, 32, 32)
        if ok_svg and type(tid) == "number" and tid > 0 then
            ind.osaa = tid
            return tid
        end
    end
    return nil
end

visuals.hitrate_svg_raw = visuals.hitrate_svg_raw or nil

local osind = { buf = {}, active = {} }
local bomb_flash = { last_sec = nil, flash_until = 0 }
local function os_tag(src)
    local s = tostring(src or "")
    if s == "A" or s:match("^A[%s%-%:]") then return "A" end
    if s == "B" or s:match("^B[%s%-%:]") then return "B" end
    if s == "FATAL" or s:find(" HP") then return "FATAL" end
    if s:match("^HIT_PERCENTAGE ") then return "HIT_PERCENTAGE" end
    if s == "TA" or s == "Target" or s == "TARGET" or s:match("^TA[:%s]") or s:match("^Target[:%s]") or s:match("^TARGET[:%s]") then return "TA" end
    if s:match("^DEFUSING") or s:match("^Defusing") then return "DEFUSING" end
    return s
end
local function os_iconify(s)
    s = tostring(s or "")
    if s:match("^HIT_PERCENTAGE%s") then
        return s:gsub("^HIT_PERCENTAGE%s*", "")
    end
    if ui.get(tabs["Visuals"].indicators_icon) then
        return visuals.ind_iconify(s)
    end
    return s
end
local function os_lerp(a,b,t)
    return a + (b - a) * t
end

local function os_get_indicator_texture(key)
	if not key then return nil end

	local function _safe_get(fn)
		if fn == nil then return nil end
		local ok, tex = pcall(fn)
		if ok and type(tex) == "number" and tex > 0 then
			return tex
		end
		return nil
	end

	if key == "DT" then
		return _safe_get(visuals.get_dt_texture)
	end
	if key == "MD" or key == "DMG" then
		return _safe_get(visuals.get_dmg_texture)
	end
	if key == "SP" or key == "SAFE" then
		return _safe_get(visuals.get_safe_texture)
	end
	if key == "FB" or key == "BAIM" or key == "BODY" then
		return _safe_get(visuals.get_body_texture)
	end
	if key == "DEFUSING" then
		return _safe_get(visuals.get_defuse_texture)
	end
	if key == "PING" then
		return _safe_get(visuals.get_ping_texture)
	end
	if key == "A" or key == "B" then
		return _safe_get(visuals.get_bomb_texture)
	end
	if key == "TA" or key == "Target" or key == "TARGET" then
		return _safe_get(visuals.get_target_texture)
	end
	if key == "HIT_PERCENTAGE" then
		return _safe_get(visuals.get_hitrate_texture)
	end
	if key == "OSAA" then
		return _safe_get(visuals.get_osaa_texture)
	end
	return nil
end

visuals.bomb_plant = visuals.bomb_plant or { start = nil, site = nil, active = false }
visuals._plant_site_to_letter = visuals._plant_site_to_letter or function(site)
    if site == nil then return nil end
    if site == 0 or site == "0" or site == "A" or site == "a" then return "A" end
    if site == 1 or site == "1" or site == "B" or site == "b" then return "B" end
    local s = tostring(site)
    if s == "A" or s == "a" then return "A" end
    if s == "B" or s == "b" then return "B" end
    return nil
end

client.set_event_callback("bomb_beginplant", function(e)
    local lp = entity.get_local_player()
    if lp == nil or not entity.is_alive(lp) then return end

    local planter = nil
    pcall(function()
        if e and e.userid ~= nil then
            planter = client.userid_to_entindex(e.userid)
        end
    end)
    if planter ~= lp then return end

    local bp = visuals.bomb_plant
    bp.start = globals.curtime()
    bp.active = true
    bp.site = visuals._plant_site_to_letter(e and (e.site or e.bombsite or e.bomb_site or e.siteid))
end)

client.set_event_callback("bomb_abortplant", function(e)
    local bp = visuals.bomb_plant
    bp.start = nil
    bp.active = false
    bp.site = nil
end)

client.set_event_callback("bomb_planted", function(e)
    local bp = visuals.bomb_plant
    bp.start = nil
    bp.active = false
    bp.site = nil
end)

client.set_event_callback("indicator", function(ind)
	if ind == nil or ind.text == nil then return end
	local vtab = tabs and tabs["Visuals"] or nil
	local iconify_enabled = false
	if vtab and vtab.indicators_icon then
		local ok, v = pcall(ui.get, vtab.indicators_icon)
		if ok then
			iconify_enabled = (v == true)
		end
	end
	
	if not iconify_enabled then
		local r = ind.r or 255
		local g = ind.g or 255
		local b = ind.b or 255
		local a = ind.a or 255
		pcall(renderer.indicator, r, g, b, a, tostring(ind.text))
		return
	end
	local t = tostring(ind.text)
	if t == "" then return end
	osind.buf[#osind.buf + 1] = {
		 r = ind.r or 255,
		 g = ind.g or 255,
		 b = ind.b or 255,
		 a = ind.a or 255,
		 text = t
	}
end)

client.set_event_callback("paint", function()
    local seen = {}
    local vtab = tabs and tabs["Visuals"] or nil
    local iconify_enabled = false
    if vtab and vtab.indicators_icon then
        local ok, v = pcall(ui.get, vtab.indicators_icon)
        if ok then
            iconify_enabled = (v == true)
        end
    end

    local preview_active = (misc and misc._ind_preview_until ~= nil and globals.realtime() < misc._ind_preview_until and ui.is_menu_open()) or false
    if preview_active then
        iconify_enabled = true
    end

    local icon_r, icon_g, icon_b, icon_a = 255, 255, 255, 255
    local override_icon_color = false
    if vtab and vtab.indicators_icon_color then
        local ok_col, col = pcall(ui.get, vtab.indicators_icon_color)
        if ok_col then
            if type(col) == "table" then
                icon_r = col[1] or 255
                icon_g = col[2] or 255
                icon_b = col[3] or 255
                icon_a = col[4] or 255
            else
                local ok2, r2, g2, b2, a2 = pcall(function()
                    return ui.get(vtab.indicators_icon_color)
                end)
                if ok2 and type(r2) == "number" then
                    icon_r, icon_g, icon_b, icon_a = r2, (g2 or 255), (b2 or 255), (a2 or 255)
                end
            end
            override_icon_color = iconify_enabled and (icon_r ~= 255 or icon_g ~= 255 or icon_b ~= 255 or icon_a ~= 255)
        end
    end
    
    if not iconify_enabled then
        osind.buf = {}
        osind.active = {}
        misc._ind_preview_seeded = false
        return
    end

    if preview_active then
        if not misc._ind_preview_seeded then
            osind.buf = {}
            osind.active = {}
            misc._ind_preview_seeded = true
        else
            osind.buf = {}
        end

        local function push(key, text, loader)
            local tex = nil
            if loader ~= nil then
                local ok, t = pcall(loader)
                if ok and type(t) == "number" and t > 0 then
                    tex = t
                end
            end
            osind.buf[#osind.buf + 1] = {
                r = 255,
                g = 255,
                b = 255,
                a = 255,
                text = tostring(text or ""),
                key = key,
                tex = tex
            }
        end

        push("DT", "DT", visuals.get_dt_texture)
        push("DMG", "DMG", visuals.get_dmg_texture)
        push("SAFE", "SAFE", visuals.get_safe_texture)
        push("BAIM", "BAIM", visuals.get_body_texture)
        push("PING", "PING", visuals.get_ping_texture)
        push("A", "A 25.0s", visuals.get_bomb_texture)
        push("DEFUSING", "DEFUSING", visuals.get_defuse_texture)
        push("TA", "Target", visuals.get_target_texture)
        push("HIT_PERCENTAGE", "HIT_PERCENTAGE 75%", visuals.get_hitrate_texture)
        push("OSAA", "OSAA", visuals.get_osaa_texture)
    else
        misc._ind_preview_seeded = false
    end

    if #osind.buf > 0 then
        local sw, sh = client.screen_size()
        local base_y = sh * 0.5 + 50
        local next_row_y = base_y + 15
        for i = 1, #osind.buf do
            local it = osind.buf[i]
            local raw = it.text
            local key = it.key or os_tag(raw)
            local display = os_iconify(raw)
            local a = it.a or 255
            local has_tex = (type(it.tex) == "number" and it.tex > 0)
            if a > 0 and ((display ~= nil and tostring(display) ~= "") or has_tex) then
                local e = osind.active[key]
                if not e then
                    e = {
                        a = 0,
                        r = 0,
                        g = 0,
                        b = 0,
                        alpha = 0,
                        active = true,
                        ty = next_row_y,
                        cy = next_row_y,
                        text = display
                    }
                    osind.active[key] = e
                else
                    e.text = display
                end
                e.tex = it.tex
                e.target = { r = it.r, g = it.g, b = it.b, a = it.a }
                if not seen[key] then
                    e.ty = next_row_y
                    seen[key] = true
                    next_row_y = next_row_y + 40
                end
            end
        end
        osind.buf = {}
    end

    local rate = math.min(1, globals.frametime() * 20)
    local sw, sh = client.screen_size()
    for k, e in pairs(osind.active) do
        if seen[k] then
            e.alpha = os_lerp(e.alpha, 1, rate)
            e.r = os_lerp(e.r, e.target.r, rate)
            e.g = os_lerp(e.g, e.target.g, rate)
            e.b = os_lerp(e.b, e.target.b, rate)
            e.a = os_lerp(e.a, e.target.a, rate)
        else
            e.alpha = os_lerp(e.alpha, 0, rate)
        end
        e.cy = os_lerp(e.cy, e.ty, rate)
        if e.alpha <= 0.01 then
            osind.active[k] = nil
        else
            local alpha = math.floor(e.a * e.alpha)
            local txt = e.text or k

            local tex = (type(e.tex) == "number" and e.tex > 0) and e.tex or nil
            if tex == nil and iconify_enabled then
                
                local disp_key = os_tag(txt)
                tex = os_get_indicator_texture(disp_key) or os_get_indicator_texture(k)
            end

            if tex ~= nil then
                
                
                local y0 = e.cy
                local t = e.alpha
                local slide = t * (2 - t)
                local x0 = 10
                local font = "+"

                local tw, th = renderer.measure_text(font, txt)
                local text_h = th or 12

                local x_pad = 4
                local sz = math.max(12, math.floor(text_h + 4))
                local icon_advance = sz + 2

                local width_ind = math.floor((tw or 0) / 2)
                local bg_alpha = math.floor(55 * (alpha / 255))

                local draw_y = y0 + text_h

                
                renderer.gradient(4, draw_y, width_ind + 24, text_h + 4, 5, 5, 5, 0, 5, 5, 5, bg_alpha, true)
                renderer.gradient(28 + width_ind, draw_y, 29 + width_ind, text_h + 4, 5, 5, 5, bg_alpha, 5, 5, 5, 0, true)

                
                local tr, tg, tb = icon_r, icon_g, icon_b
                if not override_icon_color then
                    tr = math.floor(e.r + 0.5)
                    tg = math.floor(e.g + 0.5)
                    tb = math.floor(e.b + 0.5)
                end

                
                
                local ix = math.floor((4 + ((x0 + x_pad) - 4) * slide) + 0.5)
                local icon_y = draw_y
                local icon_alpha = math.floor(alpha * (icon_a / 255))
                renderer.texture(tex, ix, icon_y, sz, sz, tr, tg, tb, icon_alpha)

                renderer.text(
                    x0 + x_pad + (icon_advance * slide),
                    draw_y + 1,
                    tr,
                    tg,
                    tb,
                    alpha,
                    font,
                    0,
                    txt
                )
            else
                local y0 = e.cy
                local t = e.alpha
                local slide = t * (2 - t)
                local x0 = 10
                local font = "+"

                local tw, th = renderer.measure_text(font, txt)
                local text_h = th or 12

                local x_pad = 4
                local sz = math.max(12, math.floor(text_h + 4))
                local icon_advance = sz + 2

                local width_ind = math.floor((tw or 0) / 2)
                local bg_alpha = math.floor(55 * (alpha / 255))

                local draw_y = y0 + text_h

                renderer.gradient(4, draw_y, width_ind + 24, text_h + 4, 5, 5, 5, 0, 5, 5, 5, bg_alpha, true)
                renderer.gradient(28 + width_ind, draw_y, 29 + width_ind, text_h + 4, 5, 5, 5, bg_alpha, 5, 5, 5, 0, true)

                local tr, tg, tb = icon_r, icon_g, icon_b
                if not override_icon_color then
                    tr = math.floor(e.r + 0.5)
                    tg = math.floor(e.g + 0.5)
                    tb = math.floor(e.b + 0.5)
                end
                renderer.text(
                    x0 + x_pad + (icon_advance * slide),
                    draw_y + 1,
                    tr,
                    tg,
                    tb,
                    alpha,
                    font,
                    0,
                    txt
                )
            end
        end
    end
end)

visuals.feature_panel = visuals.feature_panel or {
    built = false,
    rows = {},
    base_offset = 15,
    row_spacing = 40,
}

local function feature_smooth(current, target, factor)
    return current + (target - current) * factor
end

local function feature_draw_bar(x, y, w, h, alpha)
    if alpha <= 0 then return end

    local shadow_size = 8
    for i = shadow_size, 1, -1 do
        local a = math.floor(35 * alpha * (i / shadow_size))
        if a > 0 then
            renderer.rectangle(x - i, y - i, w + i * 2, h + i * 2, 0, 0, 0, a)
        end
    end

    renderer.gradient(
        x, y, w, h,
        5, 5, 5, math.floor(55 * alpha),
        5, 5, 5, 0,
        true
    )
end

local function feature_build_rows()
    if visuals.feature_panel.built then return end
    visuals.feature_panel.built = true

    local rows = visuals.feature_panel.rows

    local defs = {
