            is_active = function(inds)
                if not pui.in_table(inds, "Hitrate") then return false end
                local hr = tonumber(database.read("osmanhook::stats_hitrate")) or 0
                return hr > 0
            end,
            base_color = function() return 255, 255, 255 end,
        },
        {
            id = "ping_ddos",
            menu_name = "DDoS On Peek",
            icon_loader = function()
                return visuals.get_ping_texture and visuals.get_ping_texture() or nil
            end,
            icon_w = 24, icon_h = 24,
            label_loader = nil,
            is_active = function(inds)
                if not pui.in_table(inds, "DDoS On Peek") then return false end
                return rage and rage.ddos_on_peek or false
            end,
            base_color = function() return 255, 255, 255 end,
        },
        {
            id = "schizo",
            menu_name = "Schizophrenia",
            icon_loader = function()
                return visuals.get_osaa_texture and visuals.get_osaa_texture() or nil
            end,
            icon_w = 24, icon_h = 24,
            label_loader = nil,
            is_active = function(inds)
                return pui.in_table(inds, "Schizophrenia")
            end,
            base_color = function() return 255, 255, 255 end,
        },
        {
            id = "furkan",
            menu_name = "Furkan No Spread",
