            icon_w = 24, icon_h = 24,
            label_loader = nil,
            is_active = function(inds)
                return pui.in_table(inds, "Furkan No Spread")
            end,
            base_color = function() return 255, 255, 255 end,
        },
    }

    for _, def in ipairs(defs) do
        rows[#rows + 1] = {
            def = def,
            alpha = 0.0,
            progress = 0.0,
            icon_id = nil,
            label_id = nil,
        }
    end
end

function visuals.feature_panel_draw(inds)
    feature_build_rows()

    local lp = entity.get_local_player()
    if not lp or not entity.is_alive(lp) then
        for _, row in ipairs(visuals.feature_panel.rows) do
            row.alpha = feature_smooth(row.alpha, 0.0, 0.15)
        end
        return
    end

    local sw, sh = client.screen_size()
    local base_y = sh * 0.5 + 50
    local cursor_y = visuals.feature_panel.base_offset

    local gl_r, gl_g, gl_b = 255, 255, 255
    local vtab = tabs and tabs["Visuals"]
    if vtab and vtab.indicators_icon_color then
        local ok_col, col = pcall(ui.get, vtab.indicators_icon_color)
        if ok_col and type(col) == "table" then
            gl_r = col[1] or 255
            gl_g = col[2] or 255
            gl_b = col[3] or 255
        end
    elseif pui and pui.menu_col then
        local c = pui.menu_col()
        gl_r, gl_g, gl_b = c[1] or 255, c[2] or 255, c[3] or 255
    end

    for _, row in ipairs(visuals.feature_panel.rows) do
        local def = row.def

        local active = false
        if def.is_active then
            local ok, v = pcall(def.is_active, inds)
            active = ok and v or false
        end

        local target_alpha = active and 1.0 or 0.0
        row.alpha = feature_smooth(row.alpha, target_alpha, 0.12)
        row.progress = feature_smooth(row.progress, active and 1.0 or 0.0, 0.18)

        if row.alpha <= 0.01 then
            goto continue_row
        end

        if not row.icon_id and def.icon_loader then
            local ok_icon, tex = pcall(def.icon_loader)
            if ok_icon and type(tex) == "number" and tex > 0 then
                row.icon_id = tex
            end
        end
        if def.label_loader and not row.label_id then
            local ok_lbl, tex = pcall(def.label_loader)
            if ok_lbl and type(tex) == "number" and tex > 0 then
                row.label_id = tex
            end
        end

        local icon_w = def.icon_w or 24
        local icon_h = def.icon_h or 24

        local label_w, label_h = 0, 0
        if def.label_loader then
            label_w = def.label_w or 32
            label_h = def.label_h or icon_h
        end

        local x = 10
        local y = base_y + cursor_y

        local row_width = icon_w + (label_w > 0 and (6 + label_w) or 0)
        local bar_h = math.max(icon_h, (label_h > 0 and label_h or icon_h)) + 4

        feature_draw_bar(x - 4, y - 2, row_width + 8, bar_h, row.alpha)

        local r, g, b = gl_r, gl_g, gl_b
        if def.base_color then
            r, g, b = def.base_color()
        end
        local a = math.floor(255 * row.alpha)

        if row.icon_id then
            renderer.texture(row.icon_id, x, y, icon_w, icon_h, r, g, b, a)
        end

        if row.label_id and label_w > 0 then
            local pw = math.floor(label_w * math.max(0.0, math.min(row.progress, 1.0)))
            if pw > 0 then
                renderer.texture(
                    row.label_id,
                    x + icon_w + 6,
                    y + math.floor((icon_h - label_h) / 2),
                    pw,
                    label_h,
                    r, g, b, a
                )
            end
        end

        cursor_y = cursor_y + visuals.feature_panel.row_spacing * row.alpha
        ::continue_row::
    end
end

function expind()
    local vtab = tabs and tabs["Visuals"]
    if not vtab or not vtab.addind or not vtab.addind[1] then return end

    if not vtab.indicators_icon then return end
    local ok_master, master = pcall(ui.get, vtab.indicators_icon)
    if not ok_master or not master then return end

    local ok_inds, inds = pcall(ui.get, vtab.addind[1])
    if not ok_inds or type(inds) ~= "table" or #inds == 0 then return end

    feature_build_rows()

    local lp = entity.get_local_player()
    if not lp or not entity.is_alive(lp) then
        return
    end

    for _, row in ipairs(visuals.feature_panel.rows) do
        local def = row.def
        local active = false
        if def and def.is_active then
            local ok, v = pcall(def.is_active, inds)
            active = ok and v or false
        end

        if active then
            if not row.icon_id and def and def.icon_loader then
                local ok_icon, tex = pcall(def.icon_loader)
                if ok_icon and type(tex) == "number" and tex > 0 then
                    row.icon_id = tex
                end
            end

            local r, g, b = 255, 255, 255
            if def and def.base_color then
                local ok_col, cr, cg, cb = pcall(def.base_color)
                if ok_col then
                    r, g, b = cr or r, cg or g, cb or b
                end
            end

            local out_text = tostring(def.menu_name or def.id or "")
            local out_key = tostring(def.id or def.menu_name or "")

            if def and def.id == "target" then
                local idx = (antiaims and antiaims.target) or (rage and rage.target) or client.current_threat()
                local name = nil
                if idx ~= nil and entity and entity.get_player_name then
                    local ok_nm, nm = pcall(entity.get_player_name, idx)
                    if ok_nm and type(nm) == "string" and nm ~= "" then
                        name = nm
                    end
                end
                if name ~= nil then
                    out_text = "Target " .. name
                else
                    out_text = "Target"
                end
                out_key = "TA"

            elseif def and def.id == "hitrate" then
                local hr = tonumber(database.read("osmanhook::stats_hitrate")) or 0
                if hr < 0 then hr = 0 elseif hr > 100 then hr = 100 end
                out_text = string.format("HIT_PERCENTAGE %.0f%%", hr)
                out_key = "HIT_PERCENTAGE"
            end

            osind.buf[#osind.buf + 1] = {
                r = r,
                g = g,
                b = b,
                a = 255,
                text = out_text,
                key = out_key,
                tex = row.icon_id
            }
        end
    end
end

