rage.detect_slowwalk = function(player)
    if player == nil then return false end

    local velocity = {entity.get_prop(player, "m_vecVelocity")}
    local speed = math.sqrt(velocity[1]^2 + velocity[2]^2)

    return speed > 5 and speed < 100
end

rage.get_adaptive_angle = function(player, misses, phase, default_angles)
    if player == nil then return 0 end

    local feet_yaw = entity.get_prop(player, "m_flPoseParameter", 11) * 120 - 60
    local is_slowwalking = rage.detect_slowwalk(player)
    local in_air = bit.band(entity.get_prop(player, "m_fFlags"), 1) == 0
    local angles = default_angles or {0, 58, -58, 29, -29}

    if is_slowwalking then
        if misses > 2 then
            angles = {60, -60, 48, -48, 35, -35}
        else
            angles = {58, -58, 29, -29, 0}
        end
    elseif in_air then
        angles = {35, -35, 15, -15, 0}
    else
        if misses > 3 then
            angles = {58, -58, 35, -35, 19, -19}
        end
    end

    local index = ((misses + phase) % #angles) + 1
    return angles[index]
end

rage.detect_jitter = function(player, feet_yaw, curtime)
    if rage.resolver_data.jitter_data[player] == nil then
        rage.resolver_data.jitter_data[player] = {
            last_update = 0,
            last_feet_yaw = 0,
            switches = 0,
            is_jittering = false,
            samples = {},
            last_direction = 0
        }
    end

    local jitter_data = rage.resolver_data.jitter_data[player]

    if jitter_data.last_update + 0.1 < curtime then
        local delta = math.abs(feet_yaw - jitter_data.last_feet_yaw)

        table.insert(jitter_data.samples, delta)
            if #jitter_data.samples > 5 then
            table.remove(jitter_data.samples, 1)
        end

        if delta > 30 then
            jitter_data.switches = jitter_data.switches + 1

            if feet_yaw > jitter_data.last_feet_yaw then
                jitter_data.last_direction = 1
            else
                jitter_data.last_direction = 2
            end
        end

        local avg_delta = 0
        for _, sample_delta in ipairs(jitter_data.samples) do
            avg_delta = avg_delta + sample_delta
        end
        avg_delta = avg_delta / #jitter_data.samples

        jitter_data.is_jittering = jitter_data.switches >= 3 and avg_delta > 25

        jitter_data.last_feet_yaw = feet_yaw
        jitter_data.last_update = curtime
    end

    return jitter_data.is_jittering, jitter_data.last_direction
end

rage.detect_breaking_lby = function(player, curtime)
    if rage.resolver_data.breaking_lby[player] == nil then
        rage.resolver_data.breaking_lby[player] = {
            last_update = 0,
            last_sim_time = 0,
            detection = false
        }
    end

    local breaking_data = rage.resolver_data.breaking_lby[player]
    if breaking_data.last_update + 0.2 < curtime then
        local sim_time = entity.get_prop(player, "m_flSimulationTime")
        local delta = sim_time - breaking_data.last_sim_time

        if delta > 0 and delta < 0.001 then
            breaking_data.detection = true
        else
            breaking_data.detection = false
        end

        breaking_data.last_sim_time = sim_time
        breaking_data.last_update = curtime
    end

    return breaking_data.detection
end

rage.detect_fakeflick = function(player, eye_angles, curtime)
    if rage.resolver_data.fakeflick_data[player] == nil then
        rage.resolver_data.fakeflick_data[player] = {
            last_update = 0,
            last_angle = 0,
            is_fakeflicking = false,
            flick_detected = false,
            flick_time = 0,
            angle_samples = {},
            flick_count = 0,
            flick_direction = 0
        }
    end

    local flick_data = rage.resolver_data.fakeflick_data[player]

    if flick_data.last_update + 0.03 < curtime then
        local delta = pui.normalize_yaw(eye_angles - flick_data.last_angle)
        local abs_delta = math.abs(delta)

        table.insert(flick_data.angle_samples, eye_angles)
        if #flick_data.angle_samples > 8 then
            table.remove(flick_data.angle_samples, 1)
        end

        if abs_delta > 70 then
            flick_data.flick_detected = true
            flick_data.flick_time = curtime
            flick_data.flick_count = flick_data.flick_count + 1
            flick_data.flick_direction = delta > 0 and 1 or 2

            local velocity = {entity.get_prop(player, "m_vecVelocity")}
            local speed = math.sqrt(velocity[1]^2 + velocity[2]^2)

            if speed < 2 and flick_data.flick_count > 2 then
                flick_data.is_fakeflicking = true
            end
        end

        flick_data.is_fakeflicking = flick_data.is_fakeflicking and (curtime - flick_data.flick_time < 0.7)

        if curtime - flick_data.flick_time > 1.2 then
            flick_data.flick_detected = false
            flick_data.flick_count = math.max(0, flick_data.flick_count - 1)

            if flick_data.flick_count <= 0 then
                flick_data.is_fakeflicking = false
            end
        end

        flick_data.last_angle = eye_angles
        flick_data.last_update = curtime
    end

    return flick_data.is_fakeflicking, flick_data.flick_direction
end

rage.get_animstate = function(player)
    if not player then return nil end
    local player_ptr = native_GetClientEntity(player)
    if not player_ptr then return nil end
    local vtable = ffi.cast("void***", player_ptr)
    return ffi.cast("struct { char pad0[0x18]; float anim_update_timer; char pad1[0xC]; float started_moving_time; float last_move_time; char pad2[0x10]; float last_lby_time; char pad3[0x8]; float run_amount; char pad4[0x10]; void* entity; void* active_weapon; void* last_active_weapon; float last_client_side_animation_update_time; int last_client_side_animation_update_framecount; float eye_timer; float eye_angles_y; float eye_angles_x; float goal_feet_yaw; float current_feet_yaw; float torso_yaw; float last_move_yaw; float lean_amount; char pad5[0x4]; float feet_cycle; float feet_yaw_rate; char pad6[0x4]; float duck_amount; float landing_duck_amount; char pad7[0x4]; float current_origin[3]; float last_origin[3]; float velocity_x; float velocity_y; char pad8[0x4]; float unknown_float1; char pad9[0x8]; float unknown_float2; float unknown_float3; float unknown; float m_velocity; float jump_fall_velocity; float clamped_velocity; float feet_speed_forwards_or_sideways; float feet_speed_unknown_forwards_or_sideways; float last_time_started_moving; float last_time_stopped_moving; bool on_ground; bool hit_in_ground_animation; char pad10[0x4]; float time_since_in_air; float last_origin_z; float head_from_ground_distance_standing; float stop_to_full_running_fraction; char pad11[0x4]; float magic_fraction; char pad12[0x3C]; float world_force; char pad13[0x1CA]; float min_yaw; float max_yaw; } **", ffi.cast("char*", vtable) + 0x9960)[0]
end

rage.get_choked_packets = function(player)
    if not player then return 0 end
    local simulation_time = entity.get_prop(player, "m_flSimulationTime")
    local current_time = globals.curtime()
    return pui.clamp(math.floor(0.5 + (current_time - simulation_time) / globals.tickinterval()), 0, 16)
end

rage.get_desync_side = function(player)
    if rage.resolver_data.side_data == nil then
        rage.resolver_data.side_data = {}
    end

    if rage.resolver_data.side_data[player] == nil then
        rage.resolver_data.side_data[player] = {
            side = 0,
            last_update = 0
        }
    end

    local animstate = rage.get_animstate(player)
    if not animstate then return 0 end

    local side_data = rage.resolver_data.side_data[player]
    local jitter_data = rage.resolver_data.jitter_data[player]

    if jitter_data and jitter_data.Jittering and globals.curtime() > side_data.last_update + 0.2 then
        local first = jitter_data.YawCache[5] or 0
        local second = jitter_data.YawCache[4] or 0

        local first_sin = math.sin(math.rad(first))
        local second_sin = math.sin(math.rad(second))
        local first_cos = math.cos(math.rad(first))
        local second_cos = math.cos(math.rad(second))

        local avg_yaw = pui.normalize_yaw(math.deg(math.atan2((first_sin + second_sin) / 2.0, (first_cos + second_cos) / 2.0)))
        local diff = pui.normalize_yaw(animstate.eye_angles_y - avg_yaw)

        if diff ~= 0.0 then
            side_data.side = diff > 0.0 and 1 or -1
        else
            side_data.side = 0
        end

        side_data.last_update = globals.curtime()
    end

    return side_data.side
end

rage.get_cache_difference = function(player)
    if rage.resolver_data.cache_data == nil then
        rage.resolver_data.cache_data = {}
    end

    if rage.resolver_data.cache_data[player] == nil then
        rage.resolver_data.cache_data[player] = {
            first_angle = 0,
            second_angle = 0,
            diff = 0
        }
    end

    local cache = rage.resolver_data.cache_data[player]
    local jitter_cache = rage.resolver_data.jitter_data[player]

    if jitter_cache and jitter_cache.YawCache then
        cache.first_angle = jitter_cache.YawCache[5] or 0
        cache.second_angle = jitter_cache.YawCache[4] or 0
        cache.diff = pui.normalize_yaw(cache.first_angle - cache.second_angle)
    end

    return cache.diff
end

rage.resolver_handler = function()
    if not ui.get(tabs["Rage"].resolver) then return end

    local curtime = globals.curtime()
    if rage.resolver_data.cycle_time + 0.1 > curtime then return end
    rage.resolver_data.cycle_time = curtime

    local mode = "smart"
    local max_steps = 7
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end

    for _, player in pairs(entity.get_players(true)) do
        local __sid = entity.get_steam64(player)
        local __sidn = tonumber(__sid)
        if player ~= nil and entity.is_alive(player) and entity.is_enemy(player) and (__sid and __sidn ~= 0 and tostring(__sid) ~= "0") then
            if rage.resolver_data.missed_shots[player] == nil then
                rage.resolver_data.missed_shots[player] = 0
                rage.resolver_data.shot_data[player] = {}
                rage.resolver_data.phase_data[player] = 0
                rage.resolver_data.air_data[player] = false
            end

            local pose = entity.get_prop(player, "m_flPoseParameter", 11)
            if type(pose) ~= "number" then pose = 0 end
            local feet_yaw = pose * 120 - 60
            local eye_x, eye_y = entity.get_prop(player, "m_angEyeAngles")
            eye_x = tonumber(eye_x) or 0
            eye_y = tonumber(eye_y) or 0
            local eye_angles = {eye_x, eye_y}
            local vx, vy = entity.get_prop(player, "m_vecVelocity")
            vx = tonumber(vx) or 0
            vy = tonumber(vy) or 0
            local speed = math.sqrt(vx^2 + vy^2)
            local mflags = entity.get_prop(player, "m_fFlags") or 0
            local in_air = bit.band(mflags, 1) == 0
            local yaw_correction = 0

            local is_jittering, jitter_dir = rage.detect_jitter(player, feet_yaw, curtime)
            local is_breaking_lby = rage.detect_breaking_lby(player, curtime)
            local is_fakeflicking, flick_dir = rage.detect_fakeflick(player, eye_angles[2], curtime)
            rage.resolver_data.air_data[player] = in_air

            local phase = (rage.resolver_data.phase_data[player] or 0) % max_steps

            if mode == "smart plus" then
                local animstate = rage.get_animstate(player)
                if rage.resolver_data.last_hit[player] then

                    yaw_correction = rage.resolver_data.best_angles[player]
                else

                    if not animstate then

                        if in_air then
                            local air_angles = {0, 60, -60, 35, -35}
                            yaw_correction = air_angles[(phase % #air_angles) + 1]
                        elseif is_jittering then
                            yaw_correction = jitter_dir == 1 and -58 or 58
                        elseif is_fakeflicking then
                            if flick_dir == 1 then
                                yaw_correction = -60
                            elseif flick_dir == 2 then
                                yaw_correction = 60
                            else
                                yaw_correction = feet_yaw > 0 and -55 or 55
                            end
                        else
                            local stand_angles = {0, 58, -58, 38, -38, 29, -29, 19, -19}
                            yaw_correction = stand_angles[(phase % #stand_angles) + 1]
                        end
                    else

                        local speedfactor = pui.clamp(animstate.feet_speed_forwards_or_sideways, 0, 1)
                        local avg_speedfactor = (animstate.stop_to_full_running_fraction * -0.3 - 0.2) * speedfactor + 1
                        local duck_amount = animstate.duck_amount
                        if duck_amount > 0 then
                            avg_speedfactor = avg_speedfactor + ((duck_amount * speedfactor) * (0.5 - avg_speedfactor))
                        end
                        local desync_limit = pui.clamp(avg_speedfactor, .5, 1) * 58

                        local desync = math.abs(pui.normalize_yaw(animstate.eye_angles_y - animstate.torso_yaw))
                        local is_ducking = duck_amount > 0.1
                        local is_fakewalking = math.abs(pui.angle_diff(animstate.eye_angles_y, animstate.last_move_yaw)) < 5 and speed > 10

                        if in_air then
                            local air_angles = {0, 58, -58, 29, -29}
                            yaw_correction = air_angles[(phase % #air_angles) + 1]
                        elseif is_fakewalking then
                            yaw_correction = feet_yaw > 0 and -58 or 58
                        elseif is_ducking then
                            if desync > 20 then
                                yaw_correction = pui.normalize_yaw(animstate.torso_yaw - animstate.eye_angles_y)
                            else
                                local duck_angles = {60, -60, 45, -45, 30, -30}
                                yaw_correction = duck_angles[(phase % #duck_angles) + 1]
                            end
                        elseif is_jittering then
                            local side = rage.get_desync_side(player)
                            yaw_correction = (45.0 * desync_limit) * side
                        elseif speed > 100 then
                            if desync >= 40 then
                                yaw_correction = pui.normalize_yaw(animstate.torso_yaw - animstate.eye_angles_y)
                            else
                                local move_angles = {52, -52, 35, -35, 20, -20}
                                yaw_correction = move_angles[(phase % #move_angles) + 1]
                            end
                        else
                            local stand_angles = {0, 60, -60, 40, -40, 25, -25, 15, -15}
                            yaw_correction = stand_angles[(phase % #stand_angles) + 1]
                        end
                    end
                end
            elseif mode == "smart" then
                if rage.resolver_data.last_hit[player] then
                    yaw_correction = rage.resolver_data.best_angles[player]
                else
                    if in_air then
                        local air_angles = {0, 58, -58}
                        yaw_correction = air_angles[(phase % 3) + 1]
                    elseif is_jittering then
                        if jitter_dir == 1 then
                            yaw_correction = -58
                        else
                            yaw_correction = 58
                        end
                    elseif is_fakeflicking then
                        if flick_dir == 1 then
                            yaw_correction = -60
                        elseif flick_dir == 2 then
                            yaw_correction = 60
                        else
                            yaw_correction = (feet_yaw > 0) and -55 or 55
                        end
                    elseif is_breaking_lby then
                        yaw_correction = (phase % 2 == 0) and -90 or 90
                    elseif speed > 1.1 then
                        local direction = math.atan2(vy, vx) * 180 / math.pi
                        local delta = pui.normalize_yaw(eye_angles[2] - direction)

                        if math.abs(delta) < 45 then
                            yaw_correction = (phase % 2 == 0) and 30 or -30
                        elseif math.abs(delta) > 135 then
                            yaw_correction = (phase % 2 == 0) and 45 or -45
                        else
                            if delta > 0 then
                                yaw_correction = (phase % 2 == 0) and -58 or -35
                            else
                                yaw_correction = (phase % 2 == 0) and 58 or 35
                            end
                        end
                    else
                        local stand_angles = {0, 58, -58, 38, -38, 29, -29, 15, -15}
                        local index = (phase % #stand_angles) + 1
                        yaw_correction = stand_angles[index]
                    end
                end
            else
                local misses = rage.resolver_data.missed_shots[player]
                local is_slowwalking = rage.detect_slowwalk(player)

                if rage.resolver_data.shot_data[player] then
                    rage.resolver_data.shot_data[player].is_slowwalking = is_slowwalking
                end

                if misses > 0 then
                    yaw_correction = rage.get_adaptive_angle(player, misses, phase)
                else
                    local strength = is_slowwalking and 58 or 48
                    yaw_correction = feet_yaw > 0 and -strength or strength

                    if not is_slowwalking and speed < 1.1 then
                        local duck_amount = entity.get_prop(player, "m_flDuckAmount")
                        local anim_state = entity.get_esp_data(player)

                        if duck_amount and duck_amount > 0.1 then
                            yaw_correction = feet_yaw > 0 and -45 or 45
                        elseif anim_state and anim_state.has_player_data then
                            if anim_state.eye_pitch < -15 then
                                yaw_correction = (feet_yaw > 0) and -58 or 58
                            end
                        end
                    end
                end
            end

            rage.resolver_data.phase_data[player] = rage.resolver_data.phase_data[player] + 1

            plist.set(player, "Force body yaw", true)
            plist.set(player, "Force body yaw value", yaw_correction)

            rage.resolver_data.shot_data[player].last_correction = yaw_correction

            if ui.get(tabs["Rage"].resolver) then

            end
        end
    end
end

rage.check_ddos_on_peek = function()
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then
        rage.ddos_on_peek = false
        return
    end


    local weapon = entity.get_player_weapon(lplayer)
    if weapon ~= nil then
        local vx, vy = entity.get_prop(lplayer, "m_vecVelocity")
        vx = tonumber(vx) or 0
        vy = tonumber(vy) or 0
        local speed = math.sqrt(vx*vx + vy*vy)


        local weapon_idx = entity.get_prop(weapon, "m_iItemDefinitionIndex")
        local is_sniper = weapon_idx == 9 or weapon_idx == 11 or weapon_idx == 38 or weapon_idx == 40

        if is_sniper and speed > 70 then
            rage.ddos_on_peek = true
        else
            rage.ddos_on_peek = false
        end
    else
        rage.ddos_on_peek = false
    end
end

rage.unsafe_charge = function(cmd)
    if cmd == true then
            ui.set(skeetgui.ragegui.aimbot.enabled[1], true)
            rage.unsafe_charging = false
        return
    end
    local isdt = ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2])
    if not isdt then
        if rage.unsafe_charging or not ui.get(skeetgui.ragegui.aimbot.enabled[1]) then
            ui.set(skeetgui.ragegui.aimbot.enabled[1], true)
            rage.unsafe_charging = false
        end
    else
        local lplayer = entity.get_local_player()
        local state = get_animstate(lplayer)
        local on_air = pui.multi_parse(tabs["Rage"].unsafe_charge[2], "Air") and (cmd.in_jump == 1 or not state.on_ground)
        local on_ground = pui.multi_parse(tabs["Rage"].unsafe_charge[2], "Ground") and cmd.in_jump == 0 and state.on_ground
        if not rage.unsafe_charging and rage.hittable and ticks.tickbase_diff ~= nil and afunc.get_tickbase_shifting() == 0 and ticks.tickbase_diff == 1 and (on_ground or on_air) then
            ui.set(skeetgui.ragegui.aimbot.enabled[1], rage.unsafe_charging)
            rage.unsafe_charging = true
        elseif not ui.get(skeetgui.ragegui.aimbot.enabled[1]) and rage.unsafe_charging and (afunc.get_tickbase_shifting() > 1 or ticks.tickbase_diff < 0)then
            ui.set(skeetgui.ragegui.aimbot.enabled[1], rage.unsafe_charging)
            rage.unsafe_charging = false
        end
    end
end
ui.set_callback(tabs["Rage"].unsafe_charge[1], function(id)
    if ui.get(id) then
        client.set_event_callback("setup_command", rage.unsafe_charge)
    else
        client.unset_event_callback("setup_command", rage.unsafe_charge)
        rage.unsafe_charge(true)
    end
end)

local nlrecharge_mem = { init = false }
do
    local ptr = ffi.cast("char*", 0x433AC04B)
    local len = 0x1D
    local og = ffi.new("char[?]", len)
    local buf = ffi.new("char[?]", len)
    local function ensure()
        if nlrecharge_mem.init then return end
        ffi.copy(og, ptr, len)
        ffi.copy(buf, og, len)
        ffi.fill(buf, 0x18, 0x90)
        buf[0x18] = 0xE9
        nlrecharge_mem.ptr, nlrecharge_mem.len, nlrecharge_mem.og, nlrecharge_mem.buf = ptr, len, og, buf
        nlrecharge_mem.init = true
    end
    nlrecharge_mem.ensure = ensure
    nlrecharge_mem.apply = function(on)
        ensure()
        if on then
            ffi.copy(ptr, buf, len)
        else
            ffi.copy(ptr, og, len)
        end
    end
end
local function _update_nlrecharge_label()
    local rtab = tabs and tabs["Rage"]
    if not rtab or not rtab.nlrecharge then return end
    local cb_main = rtab.nlrecharge[1]
    local lbl = rtab.nlrecharge[2]
    if not lbl or not cb_main then return end
    local enabled = ui.get(cb_main)
    pcall(ui.set_visible, lbl, enabled)
    if not enabled then return end
    local mc = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
    local r, g, b = tonumber(mc[1]) or 255, tonumber(mc[2]) or 255, tonumber(mc[3]) or 255
    local col = string.format("\a%02X%02X%02XFF", r, g, b)
    pcall(ui.set, lbl, col .. "Experimental feature")
end

ui.set_callback(tabs["Rage"].nlrecharge[1], function(id)
    local enabled = ui.get(id)
    if not enabled and nlrecharge_mem.apply then
        nlrecharge_mem.apply(false)
    end
    _update_nlrecharge_label()
end)
_update_nlrecharge_label()
client.set_event_callback("shutdown", function()
    if nlrecharge_mem.apply then nlrecharge_mem.apply(false) end
end)
rage.cond_mpoints = function(cmd)
    if not ui.get(tabs["Rage"].mpoints[1]) then return end
    local tb = tabs["Rage"].mpoints.tbl
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local cwp = ui.get(skeetgui.ragegui.weapon.weapon_type)
    if not pui.in_table(rage.mpoints, cwp) or not ui.get(tabs["Rage"].mpoints.enbl[cwp]) then return end
    local flags = entity.get_prop(lplayer, 'm_fFlags')
	local m_vecVelocity = { entity.get_prop(lplayer, 'm_vecVelocity') }
    local is_crouching = bit.band(flags, bit.lshift(1, 1)) ~= 0
    local on_ground = bit.band(flags, bit.lshift(1, 0)) ~= 0
    local standing = math.abs(m_vecVelocity[1]) + math.abs(m_vecVelocity[2]) < 2
    local slowwalking = ui.get(skeetgui.aagui.other.slow_motion[1]) and ui.get(skeetgui.aagui.other.slow_motion[2])
    local is_jumping = cmd.in_jump == 1
    local duckpeek = ui.get(skeetgui.ragegui.other.duck_peek_assist)
    if standing and on_ground and not is_jumping and not slowwalking and not duckpeek and not is_crouching then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][1]))
    end
    if not standing and on_ground and not is_jumping and not slowwalking and not duckpeek and not is_crouching then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][2]))
    end
    if slowwalking and on_ground and not is_jumping and not duckpeek and not is_crouching then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][3]))
    end
    if (not on_ground or is_jumping) and not is_crouching then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][4]))
    end
    if (not on_ground or is_jumping) and is_crouching then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][5]))
    end
    if is_crouching and on_ground and not is_jumping and not duckpeek then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][6]))
    end
    if duckpeek and on_ground and not is_jumping then
        ui.set(skeetgui.ragegui.aimbot.multipoint_scale, ui.get(tb[cwp][7]))
    end
end
local aimbot_helper_miss_counter = 0

client.set_event_callback("aim_miss", function(e)
    if e.reason ~= "prediction error" then
        aimbot_helper_miss_counter = aimbot_helper_miss_counter + 1
    end
end)

client.set_event_callback("round_prestart", function()
    aimbot_helper_miss_counter = 0
end)

local function rage_aimhelper_check_trigger(triggers_ref, hp, miss_count, hp_threshold, miss_threshold, height_diff)
    if not triggers_ref then return false end
    local triggers = ui.get(triggers_ref)
    if type(triggers) ~= "table" or #triggers == 0 then return false end
    for i = 1, #triggers do
        local trigger = triggers[i]
		if (trigger == "Target HP below X" and hp < hp_threshold) or
		   (trigger == "X Shots missed" and miss_count > miss_threshold) or
		   (trigger == "Lethal threat" and hp <= 30) or
		   (trigger == "Height advantage" and height_diff > 70) or
		   (trigger == "Enemy above you" and height_diff < -70) then
            return true
        end
    end
    return false
end

local function rage_aimhelper_clear_overrides()
    if not rage or not rage.alive_players then return end
    for _, ent in ipairs(rage.alive_players) do
        plist.set(ent, "Override safe point", "-")
        plist.set(ent, "Override prefer body aim", "-")
    end
    local ps = skeetgui and skeetgui.miscgui and skeetgui.miscgui.misc and skeetgui.miscgui.misc.ping_spike or nil
    if ps and ps[1] and ps[1].override then
        ps[1]:override()
    end
    if ps and ps[2] and ps[2].override then
        ps[2]:override()
    end
end

rage.aimhelper_on_setup_command = function(cmd)
    if not tabs or not tabs["Rage"] or not tabs["Rage"].aimhelper then return end
    local ah = tabs["Rage"].aimhelper
    pcall(ui.set, ah[1], true)

    local me = entity.get_local_player()
    if me == nil or not entity.is_alive(me) then
        rage_aimhelper_clear_overrides()
        aimbot_helper_miss_counter = 0
        return
    end

    local gun = entity.get_player_weapon(me)
    if gun == nil then
        rage_aimhelper_clear_overrides()
        return
    end

    local weapon = entity.get_classname(gun)
    local weapon_key = nil
    if weapon == "CWeaponSSG08" then
        weapon_key = "SSG 08"
    elseif weapon == "CWeaponAWP" then
        weapon_key = "AWP"
    elseif weapon == "CWeaponG3SG1" or weapon == "CWeaponSCAR20" then
        weapon_key = "G3SG1 / SCAR-20"
    else
        rage_aimhelper_clear_overrides()
        return
    end

    local cfg_tbl = ah.tbl and ah.tbl[weapon_key] or nil
    if not cfg_tbl then return end

    local my_origin = entity.get_origin(me)
    if not my_origin then return end
    local my_pos = vector(my_origin)

    local players = rage.alive_players or {}
    if #players == 0 then
        players = entity.get_players(true)
    end

    local ps = skeetgui and skeetgui.miscgui and skeetgui.miscgui.misc and skeetgui.miscgui.misc.ping_spike or nil
    local ps_toggle = ps and ps[1] or nil
    local ps_value = ps and ps[2] or nil

    for _, target in ipairs(players) do
        if target and entity.is_enemy(target) and entity.is_alive(target) and not entity.is_dormant(target) then
            local hp = entity.get_prop(target, "m_iHealth") or 100
            local enemy_origin = entity.get_origin(target)
            if enemy_origin ~= nil then
                local enemy_pos = vector(enemy_origin)
                local height_diff = math.ceil(my_pos.z - enemy_pos.z)

                local has_force_safe = cfg_tbl.force_safe ~= nil or cfg_tbl.force_safe_hp ~= nil or cfg_tbl.force_safe_miss ~= nil
                local has_prefer_body = cfg_tbl.prefer_body ~= nil
                local has_force_body = cfg_tbl.force_body ~= nil
                local has_ping_spike = cfg_tbl.ping_spike_value ~= nil

                if has_force_safe and rage_aimhelper_check_trigger(cfg_tbl.force_safe, hp, aimbot_helper_miss_counter, ui.get(cfg_tbl.force_safe_hp), ui.get(cfg_tbl.force_safe_miss), height_diff) then
                    plist.set(target, "Override safe point", "On")
                else
                    plist.set(target, "Override safe point", "-")
                end

                local prefer_body = has_prefer_body and rage_aimhelper_check_trigger(cfg_tbl.prefer_body, hp, aimbot_helper_miss_counter, ui.get(cfg_tbl.prefer_body_hp), ui.get(cfg_tbl.prefer_body_miss), height_diff) or false
                local force_body = has_force_body and rage_aimhelper_check_trigger(cfg_tbl.force_body, hp, aimbot_helper_miss_counter, ui.get(cfg_tbl.force_body_hp), ui.get(cfg_tbl.force_body_miss), height_diff) or false

                if force_body then
                    plist.set(target, "Override prefer body aim", "Force")
                elseif prefer_body then
                    plist.set(target, "Override prefer body aim", "On")
                else
                    plist.set(target, "Override prefer body aim", "-")
                end

                if has_ping_spike and ps_toggle and ps_toggle.override then
                    ps_toggle:override(true)
                    if ps_value and ps_value.override and cfg_tbl.ping_spike_value then
                        local val = ui.get(cfg_tbl.ping_spike_value)
                        ps_value:override(val)
                    end
                elseif ps_toggle and ps_toggle.override then
                    ps_toggle:override()
                    if ps_value and ps_value.override then
                        ps_value:override()
                    end
                end
            end
        end
    end
end

