rage.ai_peek = rage.ai_peek or {}
rage.ai_peek.anim = rage.ai_peek.anim or {}
rage.ai_peek.cache = rage.ai_peek.cache or {
    qp_enabled = nil,
    qp_hotkey = nil,
    qp_mode = nil,
    qp_distance = nil,
    middle_pos = vector(),
    active_point_index = 0,
    last_returning_time = 0,
    current_target = 0,
}
rage.ai_peek.active_hitboxes = rage.ai_peek.active_hitboxes or {}
rage.ai_peek.hotkeys = rage.ai_peek.hotkeys or { main = false, force_baim = false }
rage.ai_peek.returning = rage.ai_peek.returning or false
rage.ai_peek.targeting = rage.ai_peek.targeting or false
rage.ai_peek.should_return = rage.ai_peek.should_return or false
rage.ai_peek.visual_active = rage.ai_peek.visual_active or false
rage.ai_peek.amount = rage.ai_peek.amount or 4
rage.ai_peek.step_distance = rage.ai_peek.step_distance or 50
rage.ai_peek.positions = rage.ai_peek.positions or {}

do
    local ai_peek = rage.ai_peek

    local hotkey_enum = {
        [0] = "Always on",
        [1] = "On hotkey",
        [2] = "Toggle",
        [3] = "Off hotkey",
    }

    local function _tcontains(t, v)
        if type(t) ~= "table" then return false end
        for i = 1, #t do
            if t[i] == v then return true end
        end
        return false
    end

    local function _lerp_key(key, target, speed)
        ai_peek.anim[key] = ai_peek.anim[key] or 0
        local cur = ai_peek.anim[key]
        local t = globals.frametime() * speed
        if t > 1 then t = 1 end
        cur = cur + (target - cur) * t
        ai_peek.anim[key] = cur
        return cur
    end

    local function _calc(xdelta, ydelta)
        if xdelta == 0 and ydelta == 0 then
            return 0
        end
        return math.deg(math.atan2(ydelta, xdelta))
    end

    local function _get_enemies()
        local out = {}
        local enemies = entity.get_players(true) or {}
        for i = 1, #enemies do
            local ent = enemies[i]
            if ent and entity.is_alive(ent) and not entity.is_dormant(ent) then
                out[#out + 1] = ent
            end
        end
        return out
    end

    function ai_peek.extend_vector(pos, length, angle)
        local rad = math.rad(angle)
        return vector(
            pos.x + (math.cos(rad) * length),
            pos.y + (math.sin(rad) * length),
            pos.z
        )
    end

    function ai_peek.extrapolate_position(ent, origin, ticks, inverted)
        local tickinterval = globals.tickinterval()
        local sv_gravity = cvar.sv_gravity:get_float() * tickinterval
        local sv_jump_impulse = cvar.sv_jump_impulse:get_float() * tickinterval

        local p_origin, prev_origin = origin, origin
        local velocity = vector(entity.get_prop(ent, "m_vecVelocity"))
        local gravity = velocity.z > 0 and -sv_gravity or sv_jump_impulse

        for _ = 1, ticks do
            prev_origin = p_origin
            p_origin = vector(
                p_origin.x + (inverted and -(velocity.x * tickinterval) or (velocity.x * tickinterval)),
                p_origin.y + (inverted and -(velocity.y * tickinterval) or (velocity.y * tickinterval)),
                p_origin.z + (inverted and -((velocity.z + gravity) * tickinterval) or (velocity.z + gravity) * tickinterval)
            )
            local fraction = client.trace_line(-1, prev_origin.x, prev_origin.y, prev_origin.z, p_origin.x, p_origin.y, p_origin.z)
            if fraction <= 0.99 then
                return prev_origin
            end
        end
        return p_origin
    end

    function ai_peek.get_nearest_player(players)
        local lp_eyepos = vector(client.eye_position())
        local _, cam_yaw = client.camera_angles()

        local best = nil
        local best_fov = 180
        for i = 1, #players do
            local pl = players[i]
            local o = vector(entity.get_origin(pl))
            local cur_fov = math.abs(pui.normalize_yaw(_calc(lp_eyepos.x - o.x, lp_eyepos.y - o.y) - cam_yaw + 180))
            if cur_fov < best_fov then
                best_fov = cur_fov
                best = pl
            end
        end
        return best
    end

    ai_peek.hitgroups_to_hitboxes = ai_peek.hitgroups_to_hitboxes or {
        ["Head"] = {0},
        ["Chest"] = {4, 5, 6},
        ["Stomach"] = {2, 3},
        ["Arms"] = {13, 14, 15, 16, 17, 18},
        ["Legs"] = {7, 8, 9, 10},
        ["Feet"] = {11, 12},
    }
    ai_peek.allowed_hitboxes = ai_peek.allowed_hitboxes or {0, 4, 5, 6, 2, 3, 13, 14, 15, 16, 17, 18, 7, 8, 9, 10, 11, 12}

    function ai_peek.update_hitboxes(force_baim)
        local new_hitboxes = {}
        local ok, target_hitboxes = pcall(ui.get, skeetgui.ragegui.aimbot.hitboxes)
        if not ok or type(target_hitboxes) ~= "table" then
            ai_peek.active_hitboxes = new_hitboxes
            return
        end

        local force_baim_disabled_hitgroups = {"Head", "Arms", "Legs", "Feet"}
        for i = 1, #target_hitboxes do
            local hg = target_hitboxes[i]
            if force_baim and _tcontains(force_baim_disabled_hitgroups, hg) then
                goto continue
            end

            local curr = ai_peek.hitgroups_to_hitboxes[hg]
            if curr then
                for j = 1, #curr do
                    local hb = curr[j]
                    if _tcontains(ai_peek.allowed_hitboxes, hb) then
                        new_hitboxes[#new_hitboxes + 1] = hb
                    end
                end
            end
            ::continue::
        end

        ai_peek.active_hitboxes = new_hitboxes
    end

    function ai_peek.skip_func(entindex)
        local ent_classname = entity.get_classname(entindex)
        if ent_classname == "CCSPlayer" and entity.is_enemy(entindex) then
            return false
        end
        return true
    end

    local max_step = 18
    function ai_peek.handle_point(position, prev_position, angle, step_distance, index, view_offset, vec_mins, vec_maxs)
        local start_pos = prev_position and (prev_position - view_offset) or position
        local pos = ai_peek.extend_vector(start_pos, index == 0 and 0 or step_distance, angle)

        local trace_up = trace.hull(
            start_pos,
            start_pos + vector(0, 0, max_step),
            vec_mins,
            vec_maxs,
            {skip = ai_peek.skip_func, mask = 0x201400B}
        ).end_pos

        local trace_horizontal = trace.hull(
            vector(start_pos.x, start_pos.y, trace_up.z),
            vector(pos.x, pos.y, trace_up.z),
            vec_mins,
            vec_maxs,
            {skip = ai_peek.skip_func, mask = 0x201400B}
        ).end_pos

        if pos:dist2d(trace_horizontal) >= step_distance * 0.97 then
            return false
        end

        local trace_down = trace.hull(
            trace_horizontal,
            vector(trace_horizontal.x, trace_horizontal.y, position.z - 240),
            vec_mins,
            vec_maxs,
            {skip = ai_peek.skip_func, mask = 0x201400B}
        ).end_pos

        return trace_down + view_offset
    end

    function ai_peek.setup_points(local_player, position, angle, amount, step_distance)
        local view_offset = vector(entity.get_prop(local_player, "m_vecViewOffset"))
        local vec_mins = vector(entity.get_prop(local_player, "m_vecMins"))
        local vec_maxs = vector(entity.get_prop(local_player, "m_vecMaxs"))

        ai_peek.positions[0] = ai_peek.handle_point(position, nil, 0, step_distance, 0, view_offset, vec_mins, vec_maxs)
        for i = 1, amount do
            local a = (i % 2 == 0) and (angle - 90) or (angle + 90)
            local prev_point = ai_peek.positions[i <= 2 and 0 or i - 2]
            if not prev_point then
                goto continue
            end

            local point = ai_peek.handle_point(position, prev_point, a, step_distance, i, view_offset, vec_mins, vec_maxs)
            if not point or (prev_point and math.abs(prev_point.z - point.z) > max_step) then
                for k = i, amount, 2 do
                    ai_peek.positions[k] = false
                end
                goto continue
            end

            ai_peek.positions[i] = point
            ::continue::
        end
        return ai_peek.positions
    end

    function ai_peek.weapon_can_fire(player, weapon)
        local lp_next = entity.get_prop(player, "m_flNextAttack")
        local w_next = entity.get_prop(weapon, "m_flNextPrimaryAttack")
        if math.max(0, lp_next or 0, w_next or 0) > globals.curtime() or (entity.get_prop(weapon, "m_iClip1") or 0) <= 0 then
            return false
        end
        return true
    end

    function ai_peek.can_target(local_player, target)
        if not target then return false end

        local lp_wpn = entity.get_player_weapon(local_player)
        if not lp_wpn then return false end
        if csgo_weapons(lp_wpn).is_revolver then return false end

        if not ai_peek.weapon_can_fire(local_player, lp_wpn) then
            return false
        end

        local need_scope = false
        do
            local scope_weapons = {"CWeaponSSG08", "CWeaponAWP", "CWeaponG3SG1", "CWeaponSCAR20"}
            if skeetgui and skeetgui.ragegui and skeetgui.ragegui.aimbot and skeetgui.ragegui.aimbot.auto_scope then
                if not ui.get(skeetgui.ragegui.aimbot.auto_scope) and _tcontains(scope_weapons, entity.get_classname(lp_wpn)) then
                    need_scope = entity.get_prop(local_player, "m_bIsScoped") ~= 1
                end
            end
        end
        if need_scope then
            return false
        end

        local dt_active = false
        pcall(function()
            dt_active = ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2])
        end)
        if dt_active and nigger and nigger.can_recharge and not nigger:can_recharge() then
            return false
        end

        local velocity_modifier = entity.get_prop(local_player, "m_flVelocityModifier")
        if velocity_modifier ~= 1 then
            return false
        end

        local esp_data = entity.get_esp_data(target) or {alpha = 0}
        if (esp_data.alpha or 0) < 0.75 then
            return false
        end

        return true
    end

    function ai_peek.trace_enemy(positions, local_player, target, hitboxes)
        local target_health = entity.get_prop(target, "m_iHealth") or 100
        local minimum_damage = ui.get(skeetgui.ragegui.aimbot.minimum_damage)
        local ok_mindmg, ismindmg = pcall(function()
            return ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[1]) and ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[2])
        end)
        if ok_mindmg and ismindmg then
            local v = ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[3])
            if v ~= nil then
                minimum_damage = v
            end
        end

        for i = 1, ai_peek.amount do
            local pos = positions[i]
            if not pos then
                goto continue
            end

            for j = 1, #hitboxes do
                local hitbox = hitboxes[j]
                local hitbox_pos = vector(entity.hitbox_position(target, hitbox))
                local _, damage = client.trace_bullet(
                    local_player,
                    pos.x, pos.y, pos.z,
                    hitbox_pos.x, hitbox_pos.y, hitbox_pos.z,
                    hitbox == 0
                )
                if hitbox == 0 then
                    damage = damage * 4
                end
                if damage >= math.min(minimum_damage, target_health) and damage > 0 then
                    return pos, i
                end
            end

            ::continue::
        end
        return nil, 0
    end

    function ai_peek.set_movement(cmd, destination, local_player)
        local move_yaw = vector(vector(entity.get_origin(local_player)):to(destination):angles()).y
        cmd.in_forward = 1
        cmd.in_back = 0
        cmd.in_moveleft = 0
        cmd.in_moveright = 0
        cmd.in_speed = 0
        cmd.forwardmove = 800
        cmd.sidemove = 0
        cmd.move_yaw = move_yaw
    end

    local function _restore_quickpeek()
        local qp = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist
        local qpm = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_mode
        local qpd = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_distance
        if qp and qp[1] and qp[1].override then
            qp[1]:override()
            if ai_peek.cache.qp_hotkey and qp[1].set_hotkey then
                local mode = hotkey_enum[ai_peek.cache.qp_hotkey[2]] or "On hotkey"
                local key = ai_peek.cache.qp_hotkey[3] or 0
                pcall(qp[1].set_hotkey, qp[1], mode, key)
            else
                pcall(qp[1].set_hotkey, qp[1], "On hotkey")
            end
        end
        if qpm and qpm.override then
            qpm:override()
        end
        if qpd and qpd.override then
            qpd:override()
        end
    end

    ai_peek.restore_quickpeek = _restore_quickpeek

    rage.ai_peek_handler = function(cmd)
        local ap = tabs and tabs["Rage"] and tabs["Rage"].ai_peek
        if not ap then return end

        local lplayer = entity.get_local_player()
        if not lplayer or not entity.is_alive(lplayer) then
            ai_peek.returning = false
            ai_peek.targeting = false
            ai_peek.should_return = false
            ai_peek.visual_active = false
            _restore_quickpeek()
            ai_peek.hotkeys.main = false
            return
        end

        local enabled = ui.get(ap[1])
        local main_key = enabled and ui.get(ap[2])

        if main_key and not ai_peek.hotkeys.main then
            local qp = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist
            local qpm = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_mode
            local qpd = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_distance

            if qp and qp[1] then
                ai_peek.cache.qp_enabled = ui.get(qp[1])
                if qp[1].get_hotkey then
                    ai_peek.cache.qp_hotkey = { qp[1]:get_hotkey() }
                end
            end
            if qpm then
                pcall(function() ai_peek.cache.qp_mode = ui.get(qpm) end)
            end
            if qpd then
                pcall(function() ai_peek.cache.qp_distance = ui.get(qpd) end)
            end

            local lp_origin = vector(entity.get_origin(lplayer))
            ai_peek.cache.middle_pos = ai_peek.extrapolate_position(lplayer, lp_origin, 13, true)
            ai_peek.hotkeys.main = true
        elseif (not main_key) and ai_peek.hotkeys.main then
            _restore_quickpeek()
            ai_peek.hotkeys.main = false
        end

        local force_baim = false
        pcall(function()
            force_baim = ui.get(skeetgui.ragegui.aimbot.force_body_aim[1])
        end)
        if force_baim and not ai_peek.hotkeys.force_baim then
            ai_peek.update_hitboxes(true)
            ai_peek.hotkeys.force_baim = true
        elseif (not force_baim) and ai_peek.hotkeys.force_baim then
            ai_peek.update_hitboxes(false)
            ai_peek.hotkeys.force_baim = false
        end

        if not main_key then
            ai_peek.returning = false
            ai_peek.targeting = false
            ai_peek.should_return = false
            ai_peek.visual_active = false
            return
        end

        local distance_mode = ui.get(ap[3])
        if distance_mode == "Long" then
            ai_peek.step_distance = 50
        elseif distance_mode == "Medium" then
            ai_peek.step_distance = 40
        elseif distance_mode == "Short" then
            ai_peek.step_distance = 30
        end

        local move_mode = ui.get(ap[5]) or {}
        local lp_origin = vector(entity.get_origin(lplayer))

        local middle_pos = ai_peek.cache.middle_pos
        if middle_pos == nil or type(middle_pos) ~= "userdata" then
            ai_peek.cache.middle_pos = lp_origin
            middle_pos = lp_origin
        end

        local dist_to_middle = 0
        do
            local ok, d = pcall(function()
                return middle_pos:dist2d(lp_origin)
            end)
            if ok and type(d) == "number" then
                dist_to_middle = d
            end
        end

        local m_vecVelocity = vector(entity.get_prop(lplayer, "m_vecVelocity"))
        local lp_velocity = m_vecVelocity:length2d()

        local flags = entity.get_prop(lplayer, "m_fFlags")
        local local_override = bit.band(flags, bit.lshift(1, 0)) ~= 1
            or (cmd.in_forward == 1 or cmd.in_moveleft == 1 or cmd.in_moveright == 1 or cmd.in_back == 1 or cmd.in_jump == 1)

        if (not _tcontains(move_mode, "Automatically teleport back")) and (not ai_peek.targeting and not ai_peek.returning)
            or (dist_to_middle > 0.15 and (lp_velocity > 1.011 and lp_velocity ~= 0)) then
            ai_peek.cache.middle_pos = lp_origin
            middle_pos = ai_peek.cache.middle_pos
            do
                local ok2, d2 = pcall(function()
                    return middle_pos:dist2d(lp_origin)
                end)
                if ok2 and type(d2) == "number" then
                    dist_to_middle = d2
                else
                    dist_to_middle = 0
                end
            end
        end

        local target_mode = ui.get(ap[4])
        local target = (target_mode == "Active threat") and client.current_threat() or ai_peek.get_nearest_player(_get_enemies())
        ai_peek.cache.current_target = target

        local angle = target and vector(middle_pos:to(vector(entity.get_origin(target))):angles()).y or select(2, client.camera_angles())
        local positions = ai_peek.setup_points(lplayer, middle_pos, angle, ai_peek.amount, ai_peek.step_distance)
        ai_peek.visual_active = true

        local active_point_pos, active_point_index = nil, 0
        if target and (not local_override) and ai_peek.can_target(lplayer, target) then
            active_point_pos, active_point_index = ai_peek.trace_enemy(positions, lplayer, target, ai_peek.active_hitboxes)
        end

        ai_peek.cache.active_point_index = active_point_index
        ai_peek.targeting = active_point_pos ~= nil

        if _tcontains(move_mode, "Automatically teleport back") then
            ai_peek.should_return = true
        end

        local qp = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist
        local qpm = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_mode
        local qpd = skeetgui and skeetgui.ragegui and skeetgui.ragegui.other and skeetgui.ragegui.other.quick_peek_assist_distance
        if qp and qp[1] and qp[1].override then
            qp[1]:override(true)
            if qp[1].set_hotkey then
                pcall(qp[1].set_hotkey, qp[1], "Always on")
            end
        end
        if qpd and qpd.override then
            qpd:override(math.floor((ai_peek.amount * ai_peek.step_distance) / 2) + 30)
        end

        if ai_peek.targeting then
            ai_peek.set_movement(cmd, active_point_pos, lplayer)
            ai_peek.returning = false
            ai_peek.should_return = true
        elseif local_override then
            ai_peek.returning = false
            ai_peek.should_return = false
        elseif ai_peek.should_return then
            ai_peek.returning = true
        end

        if not ai_peek.returning then
            ai_peek.cache.last_returning_time = globals.tickcount()
        end

        if ai_peek.returning then
            if dist_to_middle < 0.15 then
                ai_peek.returning = false
                ai_peek.should_return = false
            else
                ai_peek.set_movement(cmd, middle_pos, lplayer)
                if _tcontains(move_mode, "Force defensive") then
                    cmd.force_defensive = true
                end
            end
        end

        if qpm and qpm.override then
            if ai_peek.returning then
                pcall(qpm.override, qpm, {"Retreat on shot", "Retreat on key release"})
            else
                if ai_peek.cache.qp_mode ~= nil then
                    pcall(qpm.override, qpm, ai_peek.cache.qp_mode)
                end
            end
        end
    end

    rage.ai_peek_render = function()
        local ap = tabs and tabs["Rage"] and tabs["Rage"].ai_peek
        if not ap then return end
        if not ui.get(ap[1]) then return end

        local lplayer = entity.get_local_player()
        if not lplayer or not entity.is_alive(lplayer) then
            return
        end

        local enabled = ai_peek.visual_active
        local active_point = ai_peek.cache.active_point_index

        local want = enabled and _tcontains(ui.get(ap[5]) or {}, "Peek arrow")
        local alpha = _lerp_key("ai_peek_alpha", want and 255 or 0, 12)
        if alpha <= 1 then
            return
        end

        local sw, sh = client.screen_size()
        local x, y = sw / 2, sh / 2
        local offset_distance = 70

        local mc = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
        local r, g, b = tonumber(mc[1]) or 255, tonumber(mc[2]) or 255, tonumber(mc[3]) or 255

        local left_alpha = _lerp_key("ai_peek_left", (active_point == 1 or active_point == 3) and 255 or 0, 12)
        local right_alpha = _lerp_key("ai_peek_right", (active_point == 2 or active_point == 4) and 255 or 0, 12)

        local scope_offset = entity.get_prop(lplayer, "m_bIsScoped") == 1 and 15 or 0
        local y_offset = _lerp_key("ai_peek_y", scope_offset, 12)

        if left_alpha > 1 then
            renderer.text(x - offset_distance, y - y_offset, r, g, b, left_alpha * (alpha / 255), "c+", 0, "<")
        end

        if right_alpha > 1 then
            renderer.text(x + offset_distance, y - y_offset, r, g, b, right_alpha * (alpha / 255), "c+", 0, ">")
        end
    end

    pcall(function()
        ai_peek.update_hitboxes(ai_peek.hotkeys.force_baim)
    end)
end

do
    local function toggle_ai_peek(id)
        if ui.get(id) then
            client.unset_event_callback("setup_command", rage.ai_peek_handler)
            client.unset_event_callback("paint", rage.ai_peek_render)
            client.set_event_callback("setup_command", rage.ai_peek_handler)
            client.set_event_callback("paint", rage.ai_peek_render)
        else
            client.unset_event_callback("setup_command", rage.ai_peek_handler)
            client.unset_event_callback("paint", rage.ai_peek_render)
            rage.ai_peek.returning = false
            rage.ai_peek.targeting = false
            rage.ai_peek.should_return = false
            rage.ai_peek.visual_active = false
            rage.ai_peek.hotkeys.main = false
            pcall(function()
                if rage.ai_peek.restore_quickpeek then
                    rage.ai_peek.restore_quickpeek()
                end
            end)
        end
    end

    if tabs and tabs["Rage"] and tabs["Rage"].ai_peek and tabs["Rage"].ai_peek[1] then
        ui.set_callback(tabs["Rage"].ai_peek[1], toggle_ai_peek)
        toggle_ai_peek(tabs["Rage"].ai_peek[1])
    end
end

local function modify_velocity(cmd, goalspeed)
	local minspeed = math.sqrt((cmd.forwardmove * cmd.forwardmove) + (cmd.sidemove * cmd.sidemove))
	if goalspeed <= 0 or minspeed <= 0 then
		return
	end

	if cmd.in_duck == 1 then
		goalspeed = goalspeed * 2.94117647
	end

	if minspeed <= goalspeed then
		return
	end

	local speedfactor = goalspeed / minspeed
	cmd.forwardmove = cmd.forwardmove * speedfactor
	cmd.sidemove = cmd.sidemove * speedfactor
end
local player_info_prev = {}
local roundStarted = 0
client.set_event_callback("round_prestart", function()
	local to_invalidate = (cvar.mp_freezetime:get_float() + 1) / globals.tickinterval()

	roundStarted = globals.tickcount() + to_invalidate
end)
local dormantselection = {
    ["Head"] = {0, 1},
    ["Chest"] = {4, 5, 6},
    ["Stomach"] = {2, 3},
    ["Legs"] = {7, 8, 9, 10},
    ["Feet"] = {11, 12},
    ["Arms"] = {13, 14, 15, 16, 17, 18},
}
rage.dormant = function(cmd)
    if not ui.get(tabs["Rage"].dormant[1]) or not ui.get(tabs["Rage"].dormant[2]) then return end
	local lplayer = entity.get_local_player()
	local my_weapon = entity.get_player_weapon(lplayer)
	if not my_weapon then
		return
	end
	local ent = native_GetClientEntity1(my_weapon)
	if ent == nil or not native_IsWeapon(ent) then
		return
	end

	local inaccuracy = native_GetInaccuracy(ent)
	if inaccuracy == nil then		return
	end

	local tickcount = globals.tickcount()
	local player_resource = entity.get_player_resource()
	local eyepos = vector(client.eye_position())
	local simtime = entity.get_prop(lplayer, "m_flSimulationTime")
	local curtime = globals.curtime()
	local weapon = csgo_weapons(my_weapon)
	local scoped = entity.get_prop(lplayer, "m_bIsScoped") == 1
	local onground = bit.band(entity.get_prop(lplayer, 'm_fFlags'), bit.lshift(1, 0))
    local cwp = ui.get(skeetgui.ragegui.weapon.weapon_type)
    if not pui.in_table(rage.weaponstweaks, cwp) then return end
    local goaldmg = ui.get(tabs["Rage"].dormant.tbl[cwp][2])
    if goaldmg < 1 then
        local ismindmg = ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[1]) and ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[2])
        goaldmg = ismindmg and ui.get(skeetgui.ragegui.aimbot.minimum_damage_override[3]) or ui.get(skeetgui.ragegui.aimbot.minimum_damage)
    end
    local goalacurate = ui.get(tabs["Rage"].dormant.tbl[cwp][1])*0.01
	if tickcount < roundStarted then return end
	local can_shoot;
    local nading;
    if weapon.is_revolver then
        can_shoot = curtime > entity.get_prop(my_weapon, "m_flNextPrimaryAttack")
    elseif weapon.is_melee_weapon then
        can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack")) - globals.tickinterval()
    elseif weapon.is_grenade then
        can_shoot = false
    else
        can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack"))
    end
    if weapon.is_grenade and entity.get_prop(my_weapon, "m_fThrowTime") > 0 then nading = true end
    if cmd.in_attack == 1 and can_shoot or nading then return end


	local player_info = {}


	for _, player in ipairs(rage.alive_players) do
		if entity.get_prop(player_resource, "m_bConnected", player) == 1 then
			if plist.get(player, "Add to whitelist") then goto skip end
			if entity.is_dormant(player) then
				local can_hit

				local origin = vector(entity.get_origin(player))
				local x1, y1, x2, y2, alpha_multiplier = entity.get_bounding_box(player)

				if player_info_prev[player] ~= nil and origin.x ~= 0 and alpha_multiplier > 0 then
					local old_origin, old_alpha, old_hittable = unpack(player_info_prev[player])


					local dormant_accurate = alpha_multiplier >= goalacurate



					if dormant_accurate then
						local target = origin + vector(0, 0, 40)
						local pitch, yaw = eyepos:to(target):angles()
						local ent, dmg = client.trace_bullet(lplayer, eyepos.x, eyepos.y, eyepos.z, target.x, target.y, target.z, true)
						can_hit = (dmg >= goaldmg) and (not client.visible(target.x, target.y, target.z))
						if can_shoot and can_hit then
							modify_velocity(cmd, (scoped and weapon.max_player_speed_alt or weapon.max_player_speed)*0.33)


							if not scoped and weapon.type == "sniperrifle" and cmd.in_jump == 0 and onground == 1 then
								cmd.in_attack2 = 1
							end

							if inaccuracy < 0.009 and cmd.chokedcommands == 0 then
								cmd.pitch = pitch
								cmd.yaw = yaw
								cmd.in_attack = 1


								can_shoot = false
								client_log(string_-format('Taking a shot at: %s | tickcount: %d | predcited damage: %d | inaccuracy: %.3f | Alpha: %.3f', entity.get_player_name(player), tickcount, dmg, inaccuracy, alpha_multiplier))
							end
						end
					end
				end
				player_info[player] = {origin, alpha_multiplier, can_hit}
			end
		end
		::skip::
	end
	player_info_prev = player_info
end
