pui.handle_altui = function()
    if not pui.is_altui or pui.defaulttab then return end
    if pui.menu_fademode[0] == 1 then
        pui.is_open = false
    elseif pui.menu_fademode[0] == 2 then
        pui.is_open = true
    end
    if not pui.is_open or not pui.is_intab then
        if pui.altuialpha > 0 then
            pui.altuialpha = pui.lerp(pui.altuialpha, 0, pui.menu_fadespeed)
        else
            return
        end
    end
    if pui.altuialpha < 1 and pui.is_open and pui.is_intab then
        pui.altuialpha = pui.lerp(pui.altuialpha, 1, pui.menu_fadespeed)
    end
    local x, y = ui.menu_position()
    local w, h = ui.menu_size()
    x = x+w + 90
    renderer.rectangle(x - 90, y, 90, h, g[1], g[2], g[3], 255 * pui.altuialpha)
    renderer.rectangle(x - 89, y + 1, 88, h - 2, a[1], a[2], a[3], 255 * pui.altuialpha)
    renderer.rectangle(x - 88, y + 2, 86, h - 4, b[1], b[2], b[3], 255 * pui.altuialpha)
    renderer.rectangle(x - 85, y + 5, 80, h - 10, a[1], a[2], a[3], 255 * pui.altuialpha)
    renderer.rectangle(x - 84, y + 7, 78, h - 13, 12, 12, 12, 255 * pui.altuialpha)
    renderer.gradient(x - 83, y + 8, 38, 2, g1[1], g1[2], g1[3], 200 * pui.altuialpha, g2[1], g2[2], g2[3], 200 * pui.altuialpha, true)
    renderer.gradient(x - 45, y + 8, 38, 2, g2[1], g2[2], g2[3], 200 * pui.altuialpha, g3[1], g3[2], g3[3], 200 * pui.altuialpha, true)
    local wh, hw = 80, h/#switchtb
    pui.attackhover[1] = pui.in_range_rect(cursor, {x = x - 90, y = y}, {90, h})
    for i=1, #switchtb do
        ishovered[i] = pui.in_range_rect(cursor, {x = x - 84, y = y + 7 + hw*(i-1)}, {wh, hw})
    end
    local chosen = pui.table_index(switchtb, ui.get(switch))
    for k, v in ipairs(ishovered) do
        if v and firstclick then
            chosen = k
        end
    end
    if pui.oldchosen ~= chosen then
        ui.set(switch, switchtb[chosen])
    end
    pui.oldchosen = chosen
    local hmod = 4
    for k, v in ipairs(pui.altui) do
        local use_custom_colors = ui.get(tabs["Visuals"].altui_icon_colors[1])
        color = use_custom_colors and {ui.get(tabs["Visuals"].altui_icon_colors[3])} or {90, 90, 90, 255}
        if chosen == k then
            color = use_custom_colors and {ui.get(tabs["Visuals"].altui_icon_colors[5])} or {210, 210, 210, 255}
            renderer.rectangle(x - 83, y + 9 + hmod + 2, 76, hw - 2, g[1], g[2], g[3], 255 * pui.altuialpha)
            renderer.rectangle(x - 83, y + 9 + hmod + 3, 76, hw - 4, b[1], b[2], b[3], 255 * pui.altuialpha)
            renderer.texture(jg, x - 83, y + 9 + hmod + 4, 76, hw - 6, 255, 255, 255, 255 * pui.altuialpha, "r")
        elseif ishovered[k] then
            color = use_custom_colors and {ui.get(tabs["Visuals"].altui_icon_colors[7])} or {167, 167, 167, 255}
        end
        local cw, ch = renderer.measure_text("+d", v)
        renderer.text(x - 84 + 36, y + 7 + hmod + hw*0.5, color[1], color[2], color[3], 255 * pui.altuialpha, "c+d", 0, v)
        hmod = hmod + hw*0.95
    end
end

pui.normalize_yaw = function(yaw)
    return (yaw + 180) % 360 - 180
end

pui.clamp = function(value, min, max)
    return math.min(math.max(value, min), max)
end

pui.angle_diff = function(dest_angle, src_angle)
    local delta = math.fmod(dest_angle - src_angle, 360)
    if dest_angle > src_angle then
        if delta >= 180 then delta = delta - 360 end
    else
        if delta <= -180 then delta = delta + 360 end
    end
    return delta
end

misc.fastladder = function(cmd)
    misc.fastladder_active = false
    if not ui.get(tabs["Misc"].fastladder[1]) then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil then return end
    if entity.get_prop(lplayer, "m_MoveType") == 9 then
        local forward = vector(entity.get_prop(lplayer, "m_vecLadderNormal"));
        if forward:lengthsqr() == 0 then return end

        local view = vector(client.camera_angles())
        local angle = vector(forward:angles())

        local delta_yaw = angle.y - view.y + 180
        local delta_pitch = angle.x - view.x

        delta_yaw = pui.normalize_yaw(delta_yaw)
        delta_pitch = pui.clamp(delta_pitch, -89, 89)

        local abs_yaw = math.abs(delta_yaw)

        local pitch = 89
        local yaw_offset = -90

        local is_looking_down = delta_pitch < -45
        local is_looking_to_right = delta_yaw > 0

        local fwdmove = cmd.forwardmove
        local sidemove = cmd.sidemove

        local wants_forward = (cmd.in_forward == 1 or cmd.in_back == 1 or fwdmove ~= 0)
        local wants_side = (cmd.in_moveleft == 1 or cmd.in_moveright == 1 or sidemove ~= 0)
        if not wants_forward and not wants_side then
            return
        end

        local is_sidemove = sidemove > 0 or cmd.in_moveright == 1
        local is_forwardmove = fwdmove > 0 or cmd.in_forward == 1

        local prefer_side = abs_yaw > 70 and abs_yaw < 135
        local use_side = prefer_side
        if wants_forward and wants_side then
            if math.abs(sidemove) > math.abs(fwdmove) then
                use_side = true
            elseif math.abs(fwdmove) > math.abs(sidemove) then
                use_side = false
            end
        elseif wants_forward then
            use_side = false
        elseif wants_side then
            use_side = true
        end

        if use_side then
            if not is_looking_to_right then
                yaw_offset = -yaw_offset
            end

            if is_looking_to_right then
                is_sidemove = not is_sidemove
            end

            cmd.in_back = is_sidemove and 1 or 0
            cmd.in_forward = is_sidemove and 0 or 1

            if is_looking_to_right then
                is_sidemove = not is_sidemove
            end

            cmd.in_moveleft = is_sidemove and 1 or 0
            cmd.in_moveright = is_sidemove and 0 or 1

            cmd.forwardmove = 0
            cmd.sidemove = cmd.in_moveright == 1 and 450 or -450

            cmd.pitch = pitch
            cmd.yaw = pui.normalize_yaw(angle.y + yaw_offset)

            misc.fastladder_active = true

            return
        end


        if not is_looking_to_right then
            yaw_offset = -yaw_offset
        end

        if not is_looking_down then
            is_forwardmove = not is_forwardmove
        end

        cmd.in_back = is_forwardmove and 0 or 1
        cmd.in_forward = is_forwardmove and 1 or 0

        if not is_looking_to_right then
            is_forwardmove = not is_forwardmove
        end

        cmd.in_moveleft = is_forwardmove and 1 or 0
        cmd.in_moveright = is_forwardmove and 0 or 1

        cmd.sidemove = 0
        cmd.forwardmove = cmd.in_forward == 1 and 450 or -450

        cmd.pitch = pitch
        cmd.yaw = pui.normalize_yaw(angle.y + yaw_offset)

        misc.fastladder_active = true
    end
end
