misc.dumbfuck = function()
    if not ui.get(tabs["Misc"].dumbass_features[1]) then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local self_index = c_entity.new(lplayer)
    local gamerules = entity.get_game_rules()
    local isfreezetime = entity.get_prop(gamerules, "m_bFreezePeriod") == 1
    if ui.get(tabs["Misc"].dumbass_features[2]) == "Push-Ups"
        and (pui.multi_parse(tabs["Misc"].dumbass_features[3], "No enemy") and rage.isnoenemy
             or pui.multi_parse(tabs["Misc"].dumbass_features[3], "Freezetime") and isfreezetime) then
        local self_anim_overlay = self_index:get_anim_overlay(11)
        self_anim_overlay.weight = 1
        self_anim_overlay.sequence = 232
        self_anim_overlay.cycle = misc.cycs*0.001
        misc.cycs = misc.cycs + misc.modify
        misc.modify = (misc.cycs >= 730 or misc.cycs <= 646) and -misc.modify or misc.modify
    end
end

misc.aspectratio = 177
misc.aspectratio_applied = nil
misc.aspectratio_registered = false

misc.aspect_change = function(reset)
    if reset then
        misc.aspectratio = 177
        misc.aspectratio_applied = 0
        client.set_cvar("r_aspectratio", 0)
        return
    end

    local slider_value = ui.get(tabs["Misc"].aspectratio[2])
    if slider_value == 200 then
        slider_value = 59
    end
    if slider_value < 59 then
        slider_value = 59
    end

    if slider_value == 59 then
        if misc.aspectratio_applied ~= 0 then
            misc.aspectratio_applied = 0
            client.set_cvar("r_aspectratio", 0)
        end
        return
    end

    local target_value = slider_value
    local new_value = pui.lerp(misc.aspectratio, target_value, 1, 8)
    if new_value ~= misc.aspectratio then
        misc.aspectratio = new_value
    end

    local cvar_value = tonumber(new_value / 100)
    if misc.aspectratio_applied == nil or math.abs(misc.aspectratio_applied - cvar_value) > 0.0001 then
        misc.aspectratio_applied = cvar_value
        client.set_cvar("r_aspectratio", cvar_value)
    end
end

misc.aspectratio_update = function()
    if not (tabs and tabs["Misc"] and tabs["Misc"].aspectratio and tabs["Misc"].aspectratio[1]) then
        return
    end

    if ui.get(tabs["Misc"].aspectratio[2]) == 200 then
        ui.set(tabs["Misc"].aspectratio[2], 59)
    end

    local enabled = ui.get(tabs["Misc"].aspectratio[1])
    if enabled and not misc.aspectratio_registered then
        misc.aspectratio_registered = true
        client.set_event_callback("paint", misc.aspect_change)
    elseif (not enabled) and misc.aspectratio_registered then
        misc.aspectratio_registered = false
        client.unset_event_callback("paint", misc.aspect_change)
        misc.aspect_change(true)
    end
end

if tabs and tabs["Misc"] and tabs["Misc"].aspectratio and tabs["Misc"].aspectratio[1] then
    ui.set_callback(tabs["Misc"].aspectratio[1], misc.aspectratio_update)
    misc.aspectratio_update()
end

client.set_event_callback("shutdown", function()
    if misc and misc.aspect_change then
        misc.aspect_change(true)
    else
        client.set_cvar("r_aspectratio", 0)
    end
end)

