misc.viewmodel_current = nil
misc.viewmodel_applied = nil
misc.viewmodel_registered = false

misc.viewmodel_init = function()
    misc.viewmodel_current = {
        fov = cvar.viewmodel_fov:get_float(),
        x = cvar.viewmodel_offset_x:get_float(),
        y = cvar.viewmodel_offset_y:get_float(),
        z = cvar.viewmodel_offset_z:get_float(),
    }
    misc.viewmodel_applied = { }
end

misc.viewmod = function(reset)
    local cvar_fov = cvar.viewmodel_fov
    local cvar_offset_x = cvar.viewmodel_offset_x
    local cvar_offset_y = cvar.viewmodel_offset_y
    local cvar_offset_z = cvar.viewmodel_offset_z

    if reset then
        local fov = cvardef.default_view[1]
        local x = cvardef.default_view[2]
        local y = cvardef.default_view[3]
        local z = cvardef.default_view[4]
        cvar_fov:set_raw_float(fov)
        cvar_offset_x:set_raw_float(x)
        cvar_offset_y:set_raw_float(y)
        cvar_offset_z:set_raw_float(z)
        misc.viewmodel_current = { fov = fov, x = x, y = y, z = z }
        misc.viewmodel_applied = { fov = fov, x = x, y = y, z = z }
        return
    end

    if not (tabs and tabs["Misc"] and tabs["Misc"].viewmodel and tabs["Misc"].viewmodel[1]) then
        return
    end
    if not ui.get(tabs["Misc"].viewmodel[1]) then
        return
    end

    if misc.viewmodel_current == nil then
        misc.viewmodel_init()
    end

    local target_fov = ui.get(tabs["Misc"].viewmodel[2]) * 0.1
    local target_x = ui.get(tabs["Misc"].viewmodel[3]) * 0.1
    local target_y = ui.get(tabs["Misc"].viewmodel[4]) * 0.1
    local target_z = ui.get(tabs["Misc"].viewmodel[5]) * 0.1

    misc.viewmodel_current.fov = pui.lerp(misc.viewmodel_current.fov, target_fov, 1, 8)
    misc.viewmodel_current.x = pui.lerp(misc.viewmodel_current.x, target_x, 1, 8)
    misc.viewmodel_current.y = pui.lerp(misc.viewmodel_current.y, target_y, 1, 8)
    misc.viewmodel_current.z = pui.lerp(misc.viewmodel_current.z, target_z, 1, 8)

    local fov = misc.viewmodel_current.fov
    local x = misc.viewmodel_current.x
    local y = misc.viewmodel_current.y
    local z = misc.viewmodel_current.z

    if misc.viewmodel_applied.fov == nil or math.abs(misc.viewmodel_applied.fov - fov) > 0.0001 then
        misc.viewmodel_applied.fov = fov
        cvar_fov:set_raw_float(fov)
    end
    if misc.viewmodel_applied.x == nil or math.abs(misc.viewmodel_applied.x - x) > 0.0001 then
        misc.viewmodel_applied.x = x
        cvar_offset_x:set_raw_float(x)
    end
    if misc.viewmodel_applied.y == nil or math.abs(misc.viewmodel_applied.y - y) > 0.0001 then
        misc.viewmodel_applied.y = y
        cvar_offset_y:set_raw_float(y)
    end
    if misc.viewmodel_applied.z == nil or math.abs(misc.viewmodel_applied.z - z) > 0.0001 then
        misc.viewmodel_applied.z = z
        cvar_offset_z:set_raw_float(z)
    end
end

misc.viewmodel_update = function()
    if not (tabs and tabs["Misc"] and tabs["Misc"].viewmodel and tabs["Misc"].viewmodel[1]) then
        return
    end

    local enabled = ui.get(tabs["Misc"].viewmodel[1])
    if enabled and not misc.viewmodel_registered then
        misc.viewmodel_registered = true
        misc.viewmodel_init()
        client.set_event_callback("paint", misc.viewmod)
    elseif (not enabled) and misc.viewmodel_registered then
        misc.viewmodel_registered = false
        client.unset_event_callback("paint", misc.viewmod)
        misc.viewmod(true)
    end
end

