misc.scopetransp = function(reset)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local chams_enable = ui.get(skeetgui.visualgui.colored_models.local_chams[1])
    local chams_type = ui.get(skeetgui.visualgui.colored_models.local_chams[3])
    local iscoped = (entity.get_prop(lplayer, "m_bIsScoped") == 1
        or entity.get_prop(lplayer, "m_bResumeZoom") == 1)
        and pui.multi_parse(tabs["Misc"].transcope[2], "Scoped")
    local isgranade = rage.weapon ~= nil
        and (string.match(rage.weapon, "Grenade") or rage.weapon == "CFlashbang")
        and pui.multi_parse(tabs["Misc"].transcope[2], "Grenade")
    local alpha = misc.chamscol[4]
    local factor = ui.get(tabs["Misc"].transcope[3])*0.01

    local material = materialsystem.get_model_materials(lplayer)
    if reset then
        if chams_enable then
            ui.set(skeetgui.visualgui.colored_models.local_chams[2],
                misc.chamscol[1], misc.chamscol[2], misc.chamscol[3], misc.chamscol[4])
        else
            for _, v in pairs(material) do
                v:alpha_modulate(255)
            end
        end
        return
    end
    if iscoped or isgranade then
        if chams_enable then
            ui.set(skeetgui.visualgui.colored_models.local_chams[2],
                misc.chamscol[1], misc.chamscol[2], misc.chamscol[3], alpha*factor)
        else
            for _, v in pairs(material) do
                v:alpha_modulate(255*factor)
            end
        end
    else
        if chams_enable then
            ui.set(skeetgui.visualgui.colored_models.local_chams[2],
                misc.chamscol[1], misc.chamscol[2], misc.chamscol[3], alpha)
        else
            for _, v in pairs(material) do
                v:alpha_modulate(255)
            end
        end
    end
end

