    logs.on_fire = function(e)
        if not ui.get(tabs["Misc"].logs[1]) then return end
        local lplayer = entity.get_local_player()
        local p_ent = e.target

        logs[e.id] = {
            original = e,
            dropped_packets = {},

            handle_time = globals.realtime(),
            self_choke = globals.chokedcommands(),

            flags = {
                e.teleported   and "Teleported"   or "",
                e.interpolated and "Interpolated" or "",
                e.extrapolated and "Extrapolated" or "",
                e.boosted      and "Boosted"      or "",
                e.high_priority and "High Priority" or "",
            },

            feet_yaw   = entity.get_prop(p_ent, 'm_flPoseParameter', 11) * 120 - 60,
            correction = plist.get(p_ent, 'Correction active'),
            safety     = logs.get_safety(e, p_ent),

            shot_pos = vector(e.x, e.y, e.z),
            eye      = vector(client.eye_position()),
            view     = vector(client.camera_angles()),

            velocity_modifier = entity.get_prop(lplayer, 'm_flVelocityModifier'),
            total_hits        = entity.get_prop(lplayer, 'm_totalHitsOnServer'),
            history           = globals.tickcount() - e.tick > 0 and tostring(globals.tickcount() - e.tick) .. "t" or "predicted",
        }
    end

    logs.on_hit = function(e)
        if logs[e.id] == nil then return end
        if not ui.get(tabs["Misc"].logs[1]) then return end

        local info =
        {
            col = {ui.get(tabs["Misc"].logs[5])},
            type = math.max(0, entity.get_prop(e.target, 'm_iHealth')) > 0,
            name = entity.get_player_name(e.target),
            hitgroup = logs.hitboxes[e.hitgroup] or '?',
            flags = string.format('%s', table.concat(logs.gen_flags(logs[e.id].flags), " | ")),
            aimed_hitgroup = logs.hitboxes[logs[e.id].original.hitgroup] or '?',
            aimed_hitchance = string.format('%d%%', math.floor(logs[e.id].original.hit_chance + 0.5)),
            mismatch = logs.hitboxes[logs[e.id].original.hitgroup] ~= logs.hitboxes[e.hitgroup] or logs[e.id].original.damage ~= e.damage,
            hp = math.max(0, entity.get_prop(e.target, 'm_iHealth')),
            correction = {string.format("%s", logs[e.id].correction and "on" or "off"), (logs[e.id].feet_yaw < 10 and logs[e.id].feet_yaw > -10) and 0 or logs[e.id].feet_yaw},
        }

        
        if pui.multi_parse(tabs["Misc"].logs[3], "Ragebot fire") then
            if pui.multi_parse(tabs["Misc"].logs[2], "Console")  then
                local ui_col = info.col or {ui.get(tabs["Misc"].logs[5])}
                local hg = string.lower(info.hitgroup)
                local hc_int = math.floor(logs[e.id].original.hit_chance + 0.5)
                local bt = tostring(logs[e.id].history)
                local dmg = e.damage

                logs.printl(
                    {ui_col, "osmanhook "},
                    {colors.gray, "hit "},
                    {info.col, info.name},
                    {colors.gray, " in "},
                    {info.col, hg},
                    {colors.gray, " for "},
                    {info.col, tostring(dmg)},
                    {colors.gray, " damage [hc: "},
                    {info.col, tostring(hc_int)},
                    {colors.gray, " | bt: "},
                    {info.col, bt},
                    {colors.gray, "]"}
                )
            end

            if pui.multi_parse(tabs["Misc"].logs[2], "Screen") and pui.multi_parse(tabs["Misc"].logs[3], "Ragebot fire") then
                info.alpha = -1
                info.time = globals.realtime() + 3
                info.string = {logs.hittype[e.weapon] or "Hit ", info.name, info.hitgroup ~= "generic" and " in " or '', info.hitgroup ~= "generic" and info.hitgroup or '', " for ", info.damage, " dmg (",  e.health, " health remaining)"}
                table.insert(logs.screen_info, 1, info)
            end
        end
    end

    logs.on_miss = function(e)
        if not ui.get(tabs["Misc"].logs[1]) then return end
        local lplayer = entity.get_local_player()
        		local rec = (logs ~= nil and e ~= nil and e.id ~= nil) and logs[e.id] or nil

		local info =
		{
			col = {ui.get(tabs["Misc"].logs[7])},
			name = entity.get_player_name(e.target),
			hitgroup = logs.hitboxes[e.hitgroup] or '?',
			flags = rec and rec.flags and string.format('%s', table.concat(logs.gen_flags(rec.flags), " | ")) or "",
			aimed_hitgroup = (rec and rec.original and logs.hitboxes[rec.original.hitgroup]) and (logs.hitboxes[rec.original.hitgroup]) or '?',
			aimed_hitchance = (rec and rec.original and rec.original.hit_chance) and string.format('%d%%', math.floor(rec.original.hit_chance + 0.5)) or "?",
			mismatch = false,
			hp = math.max(0, entity.get_prop(e.target, 'm_iHealth')),
			reason = e.reason,
			correction = rec and {string.format("%s", rec.correction and "on" or "off"), ((rec.feet_yaw or 0) < 10 and (rec.feet_yaw or 0) > -10) and 0 or (rec.feet_yaw or 0)} or {"off", 0},
			dmg = (rec and rec.original and rec.original.damage) or 0,
		}

		if rec and rec.original then
			local orig_hit = rec.original.hitgroup
			local orig_dmg = rec.original.damage
			local cur_hit = e.hitgroup
			local cur_dmg = e.damage
			if orig_hit ~= nil and cur_hit ~= nil then
				info.mismatch = (logs.hitboxes[orig_hit] ~= logs.hitboxes[cur_hit]) or (orig_dmg ~= cur_dmg)
			else
				info.mismatch = false
			end
		end

        if info.reason == '?' then
            info.reason = "correction"
            if rec and rec.total_hits ~= entity.get_prop(lplayer, 'm_totalHitsOnServer') then
                info.reason = 'damage rejection';
            end
        end

        
        if pui.multi_parse(tabs["Misc"].logs[3], "Missed shot") then
            if pui.multi_parse(tabs["Misc"].logs[2], "Console") then
                local ui_col = info.col or {ui.get(tabs["Misc"].logs[7])}
                local hc_int = (rec and rec.original and rec.original.hit_chance) and math.floor(rec.original.hit_chance + 0.5) or 0
                local bt = rec and tostring(rec.history) or "?"
                local est = tonumber(info.dmg) or 0

                logs._miss_cache = logs._miss_cache or { last_key = nil, count = 0 }
                local cache = logs._miss_cache
                local key = table.concat({
                    info.name or "?",
                    tostring(est),
                    tostring(hc_int),
                    tostring(bt)
                }, "|")

                if cache.last_key == key then
                    cache.count = cache.count + 1
                else
                    cache.last_key = key
                    cache.count = 1
                end

                if cache.count > 1 then
                    logs.printl(
                        {ui_col, "osmanhook "},
                        {colors.gray, "missed shot estimated damage -"},
                        {info.col, tostring(est)},
                        {colors.gray, " [exp: "},
                        {info.col, tostring(est)},
                        {colors.gray, " | hc: "},
                        {info.col, tostring(hc_int)},
                        {colors.gray, " | bt: "},
                        {info.col, bt},
                        {colors.gray, "] ["},
                        {info.col, string.format("%dx", cache.count)},
                        {colors.gray, "]"}
                    )
                else
                    logs.printl(
                        {ui_col, "osmanhook "},
                        {colors.gray, "missed shot estimated damage -"},
                        {info.col, tostring(est)},
                        {colors.gray, " [exp: "},
                        {info.col, tostring(est)},
                        {colors.gray, " | hc: "},
                        {info.col, tostring(hc_int)},
                        {colors.gray, " | bt: "},
                        {info.col, bt},
                        {colors.gray, "]"}
                    )
                end
            end

            if pui.multi_parse(tabs["Misc"].logs[2], "Screen") then
                info.alpha = -1
                info.time = globals.realtime() + 3
                info.string = {"Missed ", info.name, " in ", info.hitgroup, " due to ", tostring(info.reason)}
                table.insert(logs.screen_info, 1, info)
            end
        end
    end

    logs.hittype = {knife = 'Knifed ', inferno = 'Burned ', hegrenade = 'Naded '}
    logs.hurthit = function(e)
        if not ui.get(tabs["Misc"].logs[1]) then return end
        local lplayer = entity.get_local_player()
        local attacker = client.userid_to_entindex(e.attacker)
        local target = client.userid_to_entindex(e.userid)
        if target == lplayer or attacker ~= lplayer then return end
        local info =
        {
            col = {ui.get(tabs["Misc"].logs[5])},
            type = e.health > 0,
            name = entity.get_player_name(target),
            hitgroup = logs.hitboxes[e.hitgroup] or '?',
            hp = e.health,
            damage = e.dmg_health
        }
        if pui.multi_parse(tabs["Misc"].logs[2], "Screen") and pui.multi_parse(tabs["Misc"].logs[3], "On Hit") then
            info.alpha = -1
            info.time = globals.realtime() + 3
            info.string = {logs.hittype[e.weapon] or "Hit ", info.name, info.hitgroup ~= "generic" and " in " or '', info.hitgroup ~= "generic" and info.hitgroup or '', " for ", info.damage, " dmg (",  e.health, " health remaining)"}
            table.insert(logs.screen_info, 1, info)
        end
    end
logs.lerp = function(x, v, t)
    local delta = v - x;

    if math.abs(delta) < 0.005 then
        return v
    end

    return x + delta * t
end
logs.screenp = {}
logs.anim = function(key, val, val1, speed, mode)
    logs.screenp[key] = logs.screenp[key] or val
    logs.screenp[key] = mode(pui.lerp(logs.screenp[key], val1, speed))
    return logs.screenp[key]
end
logs.screen_handler = function()
    if not ui.get(tabs["Misc"].logs[1]) or not pui.multi_parse(tabs["Misc"].logs[2], "Screen") then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil and not ui.is_menu_open() then return end
    local is_scoped = false
    if lplayer ~= nil then
        is_scoped = entity.get_prop(lplayer, "m_bIsScoped") == 1 or entity.get_prop(lplayer, "m_bResumeZoom") == 1
    end
    local spx = (logs.screenpos and logs.screenpos.x) or 0
    local spy = (logs.screenpos and logs.screenpos.y) or 0
    local center = {screen.x * 0.5 + spx, screen.y * 0.5 + 31 + spy}
    local mouse_x, mouse_y = ui.mouse_position()
    local is_clicking = client.key_state(0x01)
    local logs_size = #logs.screen_info
    local preview_value = nil
    if ui.is_menu_open() and logs_size == 0 then
        preview_value = {
            alpha = 0,
            time = globals.realtime() + 999999,
            col = {0, 0, 0, 255},
            string = {"Hit ", "Enemy", " in ", "head", " for ", 97, " dmg"}
        }
        logs_size = 1
    end
    for key = logs_size, 1, -1 do
        local value = logs.screen_info[key] or preview_value

        if value.alpha == 1 then
            table.remove(logs.screen_info, key)
            goto skip
        end
        local alpha = 1 - math.abs(value.alpha)
        local col = value.col or {255, 255, 255, 255}
        local base_color = { col[1] or 255, col[2] or 255, col[3] or 255, (col[4] or 255) * alpha }

        local base_hex = '\a' .. pui.rgb_to_hex(base_color)
        local alternative = '\a' .. pui.rgb_to_hex({255, 255, 255, 200 * alpha})
        local string = alternative

        local parts = value.string
        if type(parts) ~= "table" then
            parts = {tostring(parts or "")}
        end

        for index, text in ipairs(parts) do
            local temp = tostring(text)
            if index % 2 == 0 then
                temp = base_hex .. temp .. alternative
            end
            string = string .. temp
        end

        local fullstr = ""
        for _, t in ipairs(parts) do
            fullstr = fullstr .. tostring(t)
        end
        local w, h = renderer.measure_text('cd', fullstr)
        local x, y = center[1] - w*0.5, center[2] + screen.y*0.2
        if is_scoped then
            x = logs.anim(key, x, center[1] + 50, 0.5, math.ceil)
        else
            x = logs.anim(key, x, center[1] - w*0.5, 0.5, math.floor)
        end
        local gradient = ui.get(tabs["Manipulations"].uistyle[2])
        local style = "Win95"
        local drag_x, drag_y, drag_w, drag_h
        if false then
            drag_x, drag_y, drag_w, drag_h = x - 20, y - h*0.5 + 1, w + 40, h*2 + (gradient and 4 or 2)
        elseif false then
            drag_x, drag_y, drag_w, drag_h = x - 2, y - 2, w + 4, h*1.5
        elseif false then
            drag_x, drag_y, drag_w, drag_h = x - 15, y - 3, w + 30, h*1.6
        elseif false then
            drag_x, drag_y, drag_w, drag_h = x - 20, y - h*0.5 + 1, w + 40, h*2
        elseif style == "Win95" then
            local pad = 3
            local ww = math.max(140, (w or 0) + pad * 2 + 8)
            local hh = 18 + 8 + (h or 12) + 8
            local animkey = tostring(key) .. "_w95"
            local xw = center[1] - ww*0.5
            if is_scoped then
                xw = logs.anim(animkey, xw, center[1] + 50, 0.5, math.ceil)
            else
                xw = logs.anim(animkey, xw, center[1] - ww*0.5, 0.5, math.floor)
            end
            local yw = y - hh*0.5
            drag_x, drag_y, drag_w, drag_h = xw, yw, ww, hh
        elseif style ~= "Astral" then
            drag_x, drag_y, drag_w, drag_h = x - 15, y - 3, w + 30, h*1.6
        end
        if ui.is_menu_open() and drag_x ~= nil and drag_y ~= nil and drag_w ~= nil and drag_h ~= nil then
            local hovering = mouse_x ~= nil and mouse_y ~= nil and mouse_x >= drag_x and mouse_x <= drag_x + drag_w and mouse_y >= drag_y and mouse_y <= drag_y + drag_h
            if is_clicking then
                if not logs.screen_dragging and hovering then
                    logs.screen_dragging = true
                    logs.screen_drag_last = {x = mouse_x, y = mouse_y}
                end
                if logs.screen_dragging then
                    local dx = mouse_x - (logs.screen_drag_last.x or mouse_x)
                    local dy = mouse_y - (logs.screen_drag_last.y or mouse_y)
                    logs.screenpos = logs.screenpos or {x = 0, y = 0}
                    logs.screenpos.x = (logs.screenpos.x or 0) + dx
                    logs.screenpos.y = (logs.screenpos.y or 0) + dy
                    logs.screen_drag_last.x = mouse_x
                    logs.screen_drag_last.y = mouse_y
                    database.write("osmanhook::screenlogpos", logs.screenpos)
                end
            else
                logs.screen_dragging = false
            end
        end
        if false then
            renderer.rectangle(x - 20, y-h*0.5+1, w + 40, h*2 + (gradient and 4 or 2), g[1], g[2], g[3], 255*alpha)
            renderer.rectangle(x - 19, y-h*0.5+2, w + 38, h*2 + (gradient and 2 or 0), a[1], a[2], a[3], 255*alpha)
            renderer.rectangle(x - 18, y-h*0.5+3, w + 36, h*2 - (gradient and 0 or 2), b[1], b[2], b[3], 255*alpha)
            renderer.rectangle(x - 16, y-h*0.5+5, w + 32, h*2 - (gradient and 4 or 6), a[1], a[2], a[3], 255*alpha)
            renderer.texture(jg, x - 15, y-h*0.5+6, w + 30, h*2 - (gradient and 6 or 8), 255, 255, 255, 255*alpha, "r")
            if gradient then
                renderer.gradient(x - 14, y-h*0.5+7, w/2 + 15.5, 1, g1[1], g1[2], g1[3], 255*alpha, g2[1], g2[2], g2[3], 255*alpha, true)
                renderer.gradient(x - 14 + w/2 + 15.5, y-h*0.5+7, w/2 + 13, 1, g2[1], g2[2], g2[3], 255*alpha, g3[1], g3[2], g3[3], 255*alpha, true)
                renderer.gradient(x - 14, y-h*0.5+8, w/2 + 15.5, 1, g1[1], g1[2], g1[3], 120*alpha, g2[1], g2[2], g2[3], 120*alpha, true)
                renderer.gradient(x - 14 + w/2 + 15.5, y-h*0.5+8, w/2 + 13, 1, g2[1], g2[2], g2[3], 120*alpha, true)
                renderer.gradient(x - 14, y-h*0.5+9, w/2 + 15.5, 1, g1[1], g1[2], g1[3], 60*alpha, g2[1], g2[2], g2[3], 60*alpha, true)
                renderer.gradient(x - 14 + w/2 + 15.5, y-h*0.5+9, w/2 + 13, 1, g2[1], g2[2], g2[3], 60*alpha, g3[1], g3[2], g3[3], 60*alpha, true)
            end
        elseif false then
            local color = {ui.get(tabs["Manipulations"].uistyle[3])}
            local glow = ui.get(tabs["Manipulations"].uistyle[4])
            if glow then pui.shadow(x - 4, y - 3, w + 6, h*1.5 + 2, 10, 8, {color[1], color[2], color[3], 50 * alpha}, {color[1], color[2], color[3], 50 * alpha}) end
            rounded_rect(x - 2, y - 2, w + 4, h*1.5, color[1], color[2], color[3], color[4] * alpha, 5)
        elseif false then
            local color = {ui.get(tabs["Manipulations"].uistyle[3])}
            renderer.rectangle(x - 15, y-3, w + 30, h*1.6, 15, 15, 15, color[4]*alpha)
            renderer.rectangle(x - 15, y-3, w + 30, 2, color[1], color[2], color[3], 255*alpha)
        elseif false then
            local bg_col = {ui.get(tabs["Manipulations"].uistyle[5])}
            local outline_col = {ui.get(tabs["Manipulations"].uistyle[6])}
            local do_glow = ui.get(tabs["Manipulations"].uistyle[4])
            local radius = 10
            local bg_x = x - 20
            local bg_y = y - h*0.5 + 1
            local bg_w = w + 40
            local bg_h = h*2
            if renderer.blur and ui.get(tabs["Manipulations"].uistyle[12]) then
                local r = radius
                renderer.blur(bg_x + r, bg_y, bg_w - 2*r, bg_h, 15)
                renderer.blur(bg_x, bg_y + r, r, bg_h - 2*r, 15)
                renderer.blur(bg_x + bg_w - r, bg_y + r, r, bg_h - 2*r, 15)
            end
            rounded_rect(bg_x, bg_y, bg_w, bg_h, bg_col[1], bg_col[2], bg_col[3], math.floor((bg_col[4] or 255) * alpha), radius)
            if do_glow then
                local glow1 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.25) * alpha)}
                local glow2 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.12) * alpha)}
                pui.shadow(bg_x, bg_y, bg_w, bg_h, radius, radius, glow1, glow2)
            end
            pui.rec_outline(bg_x, bg_y, bg_w, bg_h, radius, 1, {outline_col[1], outline_col[2], outline_col[3], math.floor((outline_col[4] or 255) * alpha)})
        elseif style == "Win95" then
            local pad = 3
            local ww = math.max(140, (w or 0) + pad * 2 + 8)
            local hh = 18 + 8 + (h or 12) + 8
            local animkey = tostring(key) .. "_w95"
            local xw = center[1] - ww*0.5
            if is_scoped then
                xw = logs.anim(animkey, xw, center[1] + 50, 0.5, math.ceil)
            else
                xw = logs.anim(animkey, xw, center[1] - ww*0.5, 0.5, math.floor)
            end
            local yw = y - hh*0.5
            win95_window(xw, yw, ww, hh, "Hitlogs", math.floor(255*alpha), true)
            renderer.text(xw + 4, yw + 4 + 18 + 4 + 1, 0, 0, 0, math.floor(255*alpha), nil, 0, fullstr)
        elseif style ~= "Astral" then
            renderer.rectangle(x - 15, y-3, w + 30, h*1.6, 0, 0, 0, math.floor(200*alpha))
        end
        if style ~= "Win95" then
            renderer.text(x, y + (style == "Skeet" and (gradient and 3 or 1) or 0), 255, 255, 255, ((style == "Methamod" or style == "Blurified") and 255 or 200) * alpha, 'd', 0, string)
        end

        local height = (style == "Win95" and (18 + 8 + (h or 12) + 8) or (h*2 + (style == "Skeet" and (gradient and 6 or 4) or 0)))
        height = height * alpha
        center[2] = center[2] + height

        if (globals.realtime() - value.time > 0) or (key > 6) then
            value.alpha = logs.lerp(value.alpha, 1, globals.frametime() * 12)
        else
            value.alpha = logs.lerp(value.alpha, 0, globals.frametime() * 12)
        end

        ::skip::
    end
end

