misc.killer = nil
misc.trashmsg = function(e)
    local tt = tabs and tabs["Misc"] and tabs["Misc"].trashtalk or nil
    if tt == nil or tt[1] == nil then return end
    if not ui.get(tt[1]) then return end
    local lplayer = entity.get_local_player()
    local attacker = client.userid_to_entindex(e.attacker)
    local target = client.userid_to_entindex(e.userid)

    local types = ui.get(tt[3])
    local has_instant = pui.in_table(types, "Instant")
    local has_hrisito = pui.in_table(types, "hrisito")

    local function say_msg(msg)
        if type(msg) ~= "string" then msg = tostring(msg or "") end
        msg = msg:gsub("[\r\n\"]", "")
        if msg == "" then return end
        client.exec("say " .. msg)
    end

    if pui.multi_parse(tt[2], "Kill") and attacker == lplayer and target ~= lplayer then
        local pool = nil
        if has_hrisito and misc.trashmessages.hrisito and misc.trashmessages.hrisito.kill and #misc.trashmessages.hrisito.kill > 0 then
            pool = misc.trashmessages.hrisito.kill
        elseif has_instant and misc.trashmessages.instant and misc.trashmessages.instant.kill and #misc.trashmessages.instant.kill > 0 then
            pool = misc.trashmessages.instant.kill
        end

        if pool then
            say_msg(pool[client.random_int(1, #pool)])
        end
    end
    if pui.multi_parse(tt[2], "Death") and target == lplayer and attacker ~= lplayer then
        if has_instant then
            say_msg(misc.trashmessages.instant.death[client.random_int(1, #misc.trashmessages.instant.death)])
        end
    end
    if pui.multi_parse(tt[2], "Killer Death") then
        if target == lplayer and attacker ~= lplayer then
            misc.killer = attacker
        end
        if target == misc.killer then
            if has_instant then
                say_msg(misc.trashmessages.instant.killer_death[client.random_int(1, #misc.trashmessages.instant.killer_death)])
            end
        end
    end
end
