misc.buybot = function(e)
    if not tabs or not tabs["Misc"] or not tabs["Misc"].buybot then return end
    if not ui.get(tabs["Misc"].buybot[1]) then return end
    if client.userid_to_entindex(e.userid) ~= entity.get_local_player() then return end
    client.delay_call(0.1 + client.latency(), function ()
        local lplayer = entity.get_local_player()
        if lplayer == nil or not entity.is_alive(lplayer) then return end

        local money = entity.get_prop(lplayer, "m_iAccount")
        if type(money) ~= "number" or money <= 1000 then return end

        local team = entity.get_prop(lplayer, "m_iTeamNum")

        local function resolve_weapon(choice)
            if choice == nil or choice == "None" then return nil end

            if choice == "Auto" then
                if team == 2 then
                    return "g3sg1"
                else
                    return "scar20"
                end
            end

            if choice == "FS/T-9" then
                if team == 2 then
                    return "tec9"
                else
                    return "fn57"
                end
            end

            return misc.buylist[choice]
        end

        local buy = ''
        local primary = ui.get(tabs["Misc"].buybot[2])
        local secondary = ui.get(tabs["Misc"].buybot[3])
        local tollie = ui.get(tabs["Misc"].buybot[4])

        local primary_cmd = resolve_weapon(primary)
        if primary_cmd ~= nil then
            buy = buy .. 'buy ' .. primary_cmd .. '; '
        end

        local secondary_cmd = resolve_weapon(secondary)
        if secondary_cmd ~= nil then
            buy = buy .. 'buy ' .. secondary_cmd .. '; '
        end

        if type(tollie) == "table" then
            for i = 1, #tollie do
                local item = misc.buylist[tollie[i]]
                if item ~= nil then
                    buy = buy .. 'buy ' .. item .. '; '
                end
            end
        end

        if buy == '' then return end
        client.exec(buy)
    end)
end

