indicate.get_binds = function()
    indicate._binds = {}
    for k, v in pairs(indicate.all_binds) do
        if type(v) == "number" then
            if ui.get(v) and not pui.in_table(indicate._binds, k) then
                table.insert(indicate._binds, k)
            end
        else
            if k == "DT" then
                local dt_ok = false
                pcall(function()
                    local ref = skeetgui and skeetgui.ragegui and skeetgui.ragegui.aimbot and skeetgui.ragegui.aimbot.double_tap
                    if ref and ref[2] ~= nil then
                        dt_ok = ui.get(ref[2])
                    elseif ref and ref[1] ~= nil then
                        dt_ok = ui.get(ref[1])
                    else
                        dt_ok = false
                    end
                end)
                if dt_ok and not pui.in_table(indicate._binds, k) then
                    table.insert(indicate._binds, k)
                end
            else
                if ui.get(v[1]) and ui.get(v[2]) and not pui.in_table(indicate._binds, k) then
                    if k:lower() == "lby" and (ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2]) or ui.get(skeetgui.aagui.other.on_shot_antiaim[1]) and ui.get(skeetgui.aagui.other.on_shot_antiaim[2])) or (k == "hide" or k == "OS") and ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2]) then goto skiph end
                    table.insert(indicate._binds, k)
                end
            end
        end
        ::skiph::
    end
end
pui.text_fade_animation = function(x, y, speed, color1, color2, text, flag)
    local final_text = ''
    local curtime = globals.curtime()

    for i = 0, #text do
        local x_offset = i * 10
        local wave = math.cos(8 * speed * curtime + x_offset / 30)
        local color = string.format('%02x%02x%02x%02x',
            pui.lerp(color1[1], color2[1], pui.clamp(wave, 0, 1)),
            pui.lerp(color1[2], color2[2], pui.clamp(wave, 0, 1)),
            pui.lerp(color1[3], color2[3], pui.clamp(wave, 0, 1)),
            color1[4]
        )
        final_text = final_text .. '\a' .. color .. text:sub(i, i)
    end
    renderer.text(x, y, color1[1], color1[2], color1[3], color1[4], flag, nil, final_text)
end
pui.rec = function(x, y, w, h, radius, color)
    radius = math.min(x/2, y/2, radius)
    local r, g, b, a = unpack(color)
    renderer.rectangle(x, y + radius, w, h - radius*2, r, g, b, a)
    renderer.rectangle(x + radius, y, w - radius*2, radius, r, g, b, a)
    renderer.rectangle(x + radius, y + h - radius, w - radius*2, radius, r, g, b, a)
    renderer.circle(x + radius, y + radius, r, g, b, a, radius, 180, 0.25)
    renderer.circle(x - radius + w, y + radius, r, g, b, a, radius, 90, 0.25)
    renderer.circle(x - radius + w, y - radius + h, r, g, b, a, radius, 0, 0.25)
    renderer.circle(x + radius, y - radius + h, r, g, b, a, radius, -90, 0.25)
end
pui.rec_outline = function(x, y, w, h, radius, thickness, color)
    radius = math.min(w/2, h/2, radius)
    local r, g, b, a = unpack(color)
    if radius == 1 then
        renderer.rectangle(x, y, w, thickness, r, g, b, a)
        renderer.rectangle(x, y + h - thickness, w , thickness, r, g, b, a)
    else
        renderer.rectangle(x + radius, y, w - radius*2, thickness, r, g, b, a)
        renderer.rectangle(x + radius, y + h - thickness, w - radius*2, thickness, r, g, b, a)
        renderer.rectangle(x, y + radius, thickness, h - radius*2, r, g, b, a)
        renderer.rectangle(x + w - thickness, y + radius, thickness, h - radius*2, r, g, b, a)
        renderer.circle_outline(x + radius, y + radius, r, g, b, a, radius, 180, 0.25, thickness)
        renderer.circle_outline(x + radius, y + h - radius, r, g, b, a, radius, 90, 0.25, thickness)
        renderer.circle_outline(x + w - radius, y + radius, r, g, b, a, radius, -90, 0.25, thickness)
        renderer.circle_outline(x + w - radius, y + h - radius, r, g, b, a, radius, 0, 0.25, thickness)
    end
end
pui.shadow = function(x, y, w, h, width, rounding, accent, accent_inner)
    local thickness = 1
    local Offset = 1
    local r, g, b, a = unpack(accent)
    if accent_inner then
        pui.rec(x, y, w, h + 1, rounding, accent_inner)
    end
    for k = 0, width do
        if a * (k/width)^(1) > 5 then
            local accent = {r, g, b, a * (k/width)^(2)}
            pui.rec_outline(x + (k - width - Offset)*thickness, y + (k - width - Offset) * thickness, w - (k - width - Offset)*thickness*2, h + 1 - (k - width - Offset)*thickness*2, rounding + thickness * (width - k + Offset), thickness, accent)
        end
    end
end
