            pui.lerp(245, 50, pui.clamp(bloom, 0, 1)),
            pui.lerp(200, 50, pui.clamp(bloom, 0, 1)),
            pui.lerp(95, 50, pui.clamp(bloom, 0, 1)),
            pui.lerp(255, 0, pui.clamp(bloom, 0, 1))
        )
        local t = ((math.cos(8 * 0.2 * curtime + 120 / 30) * -0.5) + 0.5)
        local name_full = "OSMANHOOK"
        local len = #name_full

        local ticks_per_step = 20
        local peak_hold_steps = 3
        local phase = math.floor(globals.tickcount() / ticks_per_step)
        local cycle_len = (len - 1) * 2 + peak_hold_steps
        local pos = phase % cycle_len
        local anims
        if pos < len then
            anims = pos + 1
        elseif pos < len + peak_hold_steps then
            anims = len
        else
            anims = len - (pos - (len + peak_hold_steps)) - 1
        end
        text = name_full:sub(1, math.max(1, math.min(len, anims)))
