        renderer.text(indicate.pos2.x - (is_scoped and weight*0.5 or w*0.5 + 7) + 7, indicate.pos2.y + height, 120, 120, 120, 250, "-", 0, misc.ripler[antiaims.current_cond])
        for _, val in ipairs(indicate._binds) do
