pui.calcwtmk = function(tbl)
    if type(tbl) == "table" then
        local t2 = {}
        for i = 1, #tbl do
            local v = tbl[i]
            if v ~= "Config" then
                t2[#t2 + 1] = v
            end
        end
        tbl = t2
    end
    local text = {}
    local lplayer = entity.get_local_player()
    if pui.in_table(tbl, "Name") then
        local cname = (tabs["Visuals"].watermark[5] and ui.get(tabs["Visuals"].watermark[5])) or ""
        local steam_username = panorama.open("CSGOHud").MyPersonaAPI.GetName()
        local steam_id = tostring(panorama.open("CSGOHud").MyPersonaAPI.GetXuid())
        local user_icon = ""
        if steam_id == "76561199818983125" then
            table.insert(text, user_icon .. " " .. "author")
        else
            table.insert(text, user_icon .. " " .. (cname == "" and steam_username or cname))
        end
    end
    if pui.in_table(tbl, "Ticks") then
        table.insert(text, string.format("%d ticks", 1/globals.tickinterval()))
    end
    if pui.in_table(tbl, "Ping") and lplayer ~= nil then
        local ping_ms = math.floor((client.real_latency() or 0) * 1000 + 0.5)
        local icon
        if ping_ms <= 30 then
            icon = ""
        elseif ping_ms <= 60 then
            icon = ""
        elseif ping_ms <= 90 then
            icon = ""
        elseif ping_ms <= 130 then
            icon = ""
        else
            icon = ""
        end
        table.insert(text, string.format("%s %d ms", icon, ping_ms))
    end
    if pui.in_table(tbl, "FPS") then
        table.insert(text, string.format("%d fps", 1/globals.absoluteframetime()))
    end
    if pui.in_table(tbl, "Time") then
        local h, m, s = client.system_time()
        table.insert(text, string.format(" %02d:%02d", h, m))
    end
    return text
end

visuals.watermark = function()
    if renderer == nil or renderer.measure_text == nil then return end
    local lplayer = entity.get_local_player()

    local display_name = (tabs["Visuals"].watermark[5] and ui.get(tabs["Visuals"].watermark[5])) or ""
    local steam_username = panorama.open("CSGOHud").MyPersonaAPI.GetName()
    local steam_id = tostring(panorama.open("CSGOHud").MyPersonaAPI.GetXuid())
    local username = (steam_id == "76561199818983125" and "Welcome back, author!") or (display_name == "" and steam_username or display_name)

    local ping = 0
    if lplayer ~= nil then
        ping = client.latency() * 1000
    end
    ping = math.floor(ping)

    local hours, minutes = client.system_time()
    local time_str = string.format("%02d:%02d", hours, minutes)

    local info = ui.get(tabs["Visuals"].watermark[2]) or {}
    local segments = pui.calcwtmk(info)
    local info_text = table.concat(segments, "  ")
    local brand = "osmanhook"
    local full_text = brand
    if info_text ~= "" then
        full_text = full_text .. "  " .. info_text
    end

    local tw, th = renderer.measure_text(nil, full_text)
    tw = tonumber(tw) or 0
    th = tonumber(th) or 12
    local frame_pad = 6
    local inner_pad = 4
    local title_h = 18
    local top_h = 4 + title_h + 4
    local ww = math.max(180, frame_pad * 2 + tw + inner_pad * 2)
    local content_h = th + inner_pad * 2
    local hh = top_h + content_h + 6
    local margin = 10
    local pos = (tabs["Visuals"].watermark[3] and ui.get(tabs["Visuals"].watermark[3])) or "Top-Right"
    local x, y
    if pos == "Top-Left" then
        x, y = margin, margin
    elseif pos == "Bottom-Left" then
        x, y = margin, screen.y - hh - margin
    elseif pos == "Bottom-Right" then
        x, y = screen.x - ww - margin, screen.y - hh - margin
    else
        x, y = screen.x - ww - margin, margin
    end
    local a = 255

    win95_window(x, y, ww, hh, "Watermark", a, true)

    local content_x = x + frame_pad
    local content_y = y + top_h
    local content_w = ww - frame_pad * 2

    renderer.rectangle(content_x, content_y, content_w, content_h, 255, 255, 255, a)
    renderer.rectangle(content_x, content_y, content_w, 1, 0, 0, 0, a)
    renderer.rectangle(content_x, content_y, 1, content_h, 0, 0, 0, a)
    renderer.rectangle(content_x + content_w - 1, content_y, 1, content_h, 0, 0, 0, a)
    renderer.rectangle(content_x, content_y + content_h - 1, content_w, 1, 0, 0, 0, a)

    renderer.text(content_x + inner_pad, content_y + inner_pad, 0, 0, 0, a, nil, 0, full_text)
end




