visuals.currentkeyname = function()
    local kname = visuals.keybinding[ui.get(tabs["Manipulations"].keynames[1])+1][1]

    if kname == "Disabled" then
        kname = "\aFF0000FFDisabled"
    elseif kname ~= visuals.keynames[ui.get(tabs["Manipulations"].keynames[1])+1] then
        kname = "\aE6D349FF"..kname
    end
    ui.set(tabs["Manipulations"].keynames[2], "Current name: "..kname)
end
do
    local mn = tabs and tabs["Manipulations"]
    local keynames = mn and mn.keynames
    if keynames and keynames[1] then
        ui.set_callback(keynames[1], visuals.currentkeyname)
    end
end

visuals.setkeyname = function()
    local cname = ui.get(tabs["Manipulations"].keynames[3])
    if cname == nil or cname == "" then return end
    local key = ui.get(tabs["Manipulations"].keynames[1]) + 1
    if string.len(table.concat(pui.split(cname))) < 1 then
        ui.set(tabs["Manipulations"].keynames[3], "")
        visuals.keybinding[key][1] = "Disabled"
        visuals.dbknames[key] = "Disabled"
        goto updatestring
    end
    visuals.keybinding[key][1] = cname
    visuals.dbknames[key] = cname
    ui.set(tabs["Manipulations"].keynames[3], "")
    ::updatestring::
    visuals.currentkeyname()
end
visuals.restorekeyname = function()
    local key = ui.get(tabs["Manipulations"].keynames[1]) + 1
    visuals.dbknames[key] = nil
    visuals.keybinding[key][1] = visuals.keynames[key]
    visuals.currentkeyname()
end
do
    local mn = tabs and tabs["Manipulations"]
    local keynames = mn and mn.keynames
    if keynames then
        if keynames[4] then ui.set_callback(keynames[4], visuals.setkeyname) end
        if keynames[5] then ui.set_callback(keynames[5], visuals.restorekeyname) end
    end
end

visuals.modes = {
    "holding",
    "toggled",
    "disabled",
    "~",
}
pui.menukey = {ui.get(skeetgui.miscgui.settings.menu_key)}
visuals.bindings = {}
pui.getlengst = function()
    local bind = ""
    for _, v in ipairs(visuals.bindings) do
        if ui.is_menu_open() then
            if bind == "Menu open" then
                if v[1] ~= "Menu open" and v[2] and ((v[3] and v[3][2]) or 0) > 0 then bind = v[1] end
            else
                if v[2] and ((v[3] and v[3][2]) or 0) > 0 then bind = pui.max(bind, v[1], renderer.measure_text, "c") end
            end
        elseif v[1] ~= "Menu open" then
            if v[2] and ((v[3] and v[3][2]) or 0) > 0 then bind = pui.max(bind, v[1], renderer.measure_text, "c") end
        end

    end
    return string.len(bind) > 0 and bind or nil
end
visuals.alphakeyb = {0, 0, 0, keys = { 0 }}
visuals.keyoldw = nil
visuals.wt_drag = false
visuals.wt_off = {0, 0}
visuals.keybinds = function()
    if not tabs["Visuals"] or not tabs["Visuals"].keybinds or not tabs["Visuals"].keybinds[1] then return end
    local lp = entity.get_local_player()
    if not ui.get(tabs["Visuals"].keybinds[1]) or (lp == nil and not ui.is_menu_open()) then
        if visuals.alphakeyb[1] > 0 then
            visuals.alphakeyb[1] = math.floor(pui.lerp(visuals.alphakeyb[1], 0, 0.095))
            visuals.alphakeyb[2] = math.floor(pui.lerp(visuals.alphakeyb[2], 0, 0.095))
            visuals.alphakeyb[3] = math.floor(pui.lerp(visuals.alphakeyb[3], 0, 0.095))
            for k, v in pairs(visuals.alphakeyb.keys) do
                visuals.alphakeyb.keys[k] = math.floor(pui.lerp(visuals.alphakeyb.keys[k], 0, 0.095))
            end
        else
            return
        end
    end
    (function()
        for k, v in ipairs(visuals.keybinding) do
            k = k + 1
            if v[2] == nil or v[1] == "Disabled" then goto skip end
            if type(v[2]) == "number" then
                local on = ui.get(v[2])
                visuals.bindings[k] = {v[1], on, {on, on and 2 or 0, nil}}
            else
                local enabled = ui.get(v[2][1])
                local bool, mode, key = ui.get(v[2][2])
                mode = mode or (bool and 2 or 0)
                if mode == 3 then
                    visuals.bindings[k] = {v[1], enabled and not bool, {bool, mode, key}}
                else
                    visuals.bindings[k] = {v[1], enabled and bool, {bool, mode, key}}
                end
            end
            ::skip::
        end
    end)()
    local leng = pui.getlengst()
    visuals.bindings[1] = {"Menu open", (ui.get(tabs["Visuals"].keybinds[1]) and ui.is_menu_open() and (leng == "Menu open" or leng == nil)), {[2] = 4, [3] = pui.menukey[3]}}
    if visuals.bindings[1][2] then leng = "Menu open" end
    if leng == nil then
        visuals.alphakeyb[1] = math.floor(pui.lerp(visuals.alphakeyb[1], 0, 0.35))
        visuals.alphakeyb[2] = math.floor(pui.lerp(visuals.alphakeyb[2], 0, 0.35))
        visuals.alphakeyb[3] = math.floor(pui.lerp(visuals.alphakeyb[3], 0, 0.35))
    else
        visuals.alphakeyb[1] = math.ceil(pui.lerp(visuals.alphakeyb[1], 255, 0.35))
        visuals.alphakeyb[2] = math.ceil(pui.lerp(visuals.alphakeyb[2], 120, 0.35))
        visuals.alphakeyb[3] = math.ceil(pui.lerp(visuals.alphakeyb[3], 60, 0.35))
    end
    if visuals.alphakeyb[1] ~= visuals.alphakeyb[1] then
        visuals.alphakeyb[1] = 0
        visuals.alphakeyb[2] = 0
        visuals.alphakeyb[3] = 0
    end
    local style = "Win95"
    if false then
        local w, h = renderer.measure_text(nil, leng)
        if visuals.keyoldw ~= nil and visuals.keyoldw ~= w then
            w = logs.anim("KEYW", visuals.keyoldw, w, 0.5, visuals.keyoldw > w and math.floor or math.ceil)
        end
        visuals.keyoldw = w
        if w < 0 or visuals.keyoldw < 0 then
            w = 0
            visuals.keyoldw = 0
        end
        if w % 2 == 1 then
            w = w + 1
        end
        local gradient = ui.get(tabs["Manipulations"].uistyle[2])

        renderer.rectangle(pui.keypos.x, pui.keypos.y, 110 + w*0.8, h*2 + (gradient and 4 or 2), g[1], g[2], g[3], visuals.alphakeyb[1])
        renderer.rectangle(pui.keypos.x + 1, pui.keypos.y + 1, 110 + w*0.8 - 2, h*2 + (gradient and 2 or 0), a[1], a[2], a[3], visuals.alphakeyb[1])
        renderer.rectangle(pui.keypos.x + 2, pui.keypos.y + 2, 110 + w*0.8 - 4, h*2 - (gradient and 0 or 2), b[1], b[2], b[3], visuals.alphakeyb[1])
        renderer.rectangle(pui.keypos.x + 4, pui.keypos.y + 4, 110 + w*0.8 - 8, h*2 - (gradient and 4 or 6), a[1], a[2], a[3], visuals.alphakeyb[1])
        renderer.texture(jg, pui.keypos.x + 5, pui.keypos.y + 5, 110 + w*0.8 - 10, h*2 - (gradient and 6 or 8), 255, 255, 255, visuals.alphakeyb[1], "r")
        if gradient then
