            renderer.gradient(pui.keypos.x + 6 + (110 + w*0.8 - 10)*0.5, pui.keypos.y + 6, (110 + w*0.8 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphakeyb[1], g3[1], g3[2], g3[3], visuals.alphakeyb[1], true)
            renderer.gradient(pui.keypos.x + 6, pui.keypos.y + 7, (110 + w*0.8 - 10)*0.5, 1, g1[1], g1[2], g1[3], visuals.alphakeyb[2], g2[1], g2[2], g2[3], visuals.alphakeyb[2], true)
            renderer.gradient(pui.keypos.x + 6 + (110 + w*0.8 - 10)*0.5, pui.keypos.y + 7, (110 + w*0.8 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphakeyb[2], g3[1], g3[2], g3[3], visuals.alphakeyb[2], true)
            renderer.gradient(pui.keypos.x + 6, pui.keypos.y + 8, (110 + w*0.8 - 10)*0.5, 1, g1[1], g1[2], g1[3], visuals.alphakeyb[3], g2[1], g2[2], g2[3], visuals.alphakeyb[3], true)
            renderer.gradient(pui.keypos.x + 6 + (110 + w*0.8 - 10)*0.5, pui.keypos.y + 8, (110 + w*0.8 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphakeyb[3], g3[1], g3[2], g3[3], visuals.alphakeyb[3], true)
        end
        renderer.text(pui.keypos.x + (110 + w*0.8)*0.5, pui.keypos.y + h + (gradient and 3 or 1), 255, 255, 255, visuals.alphakeyb[1], "c", 0, "keybinds")
        local hmod = 0
