            local entry_y = pui.keypos.y + gradient_height + radius + title_h + 10
            for _, bind in ipairs(active_binds) do
                if bind[3] > 0 then
                    renderer.text(pui.keypos.x + 6, entry_y, 164, 168, 175, bind[3], "b", 0, bind[1])
                    renderer.text(pui.keypos.x + bg_width - 6, entry_y, 157, 156, 218, bind[3], "rb", 0, "[" .. bind[2] .. "]")
                    entry_y = entry_y + 16
                end
