        local outline_col = {ui.get(tabs["Manipulations"].uistyle[6])}
        local sep_col = {ui.get(tabs["Manipulations"].uistyle[7])}
        local label_col = {ui.get(tabs["Manipulations"].uistyle[8])}
        local text_col = {ui.get(tabs["Manipulations"].uistyle[9])}
        local do_glow = ui.get(tabs["Manipulations"].uistyle[4])
        local padding_x, padding_y = 10, 4
        local row_h = 22
        local row_gap = 3
        local min_w = 100
        local header_text = "Keybinds"
        local active_binds = {}
        for _, v in ipairs(visuals.bindings) do
            local k = v[1]
            visuals.alphakeyb.keys[k] = visuals.alphakeyb.keys[k] or 0
            if v[2] and v[3][2] > 0 then
                visuals.alphakeyb.keys[k] = math.ceil(pui.lerp(visuals.alphakeyb.keys[k], 255, 0.9))
                table.insert(active_binds, {k, visuals.modes[v[3][2]], visuals.alphakeyb.keys[k]})
            else
                visuals.alphakeyb.keys[k] = math.floor(pui.lerp(visuals.alphakeyb.keys[k], 0, 0.9))
            end
            if visuals.alphakeyb.keys[k] ~= visuals.alphakeyb.keys[k] then visuals.alphakeyb.keys[k] = 0 end
        end
        local count = #active_binds
        if count == 0 and not ui.is_menu_open() then return end
        if count == 0 and ui.is_menu_open() then
            active_binds = {{"Double Tap", "toggled", 255}}
            count = 1
        end
        local max_w = 0
        local w_header = select(1, renderer.measure_text("b", header_text))
        for i = 1, count do
