            local w_r = w_right or 0
            local w_h = w_header or 0
            local mw = min_w or 100
            local content_w = math.max(math.max(w_r, w_h), mw)
            content_w = tonumber(content_w) or 0
            max_w = math.max(tonumber(max_w) or 0, content_w)
        end
        local x, y = pui.keypos.x, pui.keypos.y
        local w_h_safe = w_header or 0
        local max_w_safe = max_w or min_w or 0
        local padx = padding_x or 0
        local w_rect = math.max(w_h_safe, max_w_safe) + padx*2
        local header_h = row_h + padding_y*2
        local gap = 3
        local row_box_h = row_h + padding_y*2
        local panel_alpha = visuals.alphakeyb[1]
        local radius = 10
        if renderer.blur and ui.get(tabs["Manipulations"].uistyle[12]) then
            local r = radius
            renderer.blur(x + r, y, w_rect - 2*r, header_h, 15)
            renderer.blur(x, y + r, r, header_h - 2*r, 15)
            renderer.blur(x + w_rect - r, y + r, r, header_h - 2*r, 15)
        end

        rounded_rect(x, y, w_rect, header_h, bg_col[1], bg_col[2], bg_col[3], math.floor((bg_col[4] or 255) * panel_alpha/255), radius)
        if do_glow then
            local glow1 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.25) * panel_alpha/255)}
            local glow2 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.12) * panel_alpha/255)}
            pui.shadow(x, y, w_rect, header_h, radius, radius, glow1, glow2)
        end
        pui.rec_outline(x, y, w_rect, header_h, radius, 1, {outline_col[1], outline_col[2], outline_col[3], math.floor((outline_col[4] or 255) * panel_alpha/255)})
        local w_head, h_head = renderer.measure_text("b", header_text)

        do
            local cy = y + header_h/2
            local ix = x + padding_x - 10
            if do_glow then
                local g1 = {label_col[1], label_col[2], label_col[3], math.floor(60 * panel_alpha/255)}
                local g2 = {label_col[1], label_col[2], label_col[3], math.floor(30 * panel_alpha/255)}
                pui.shadow(ix - 4, cy - 8, 20, 16, 8, 8, g1, g2)
            end
            rounded_rect(ix, cy - 3, 6, 6, label_col[1], label_col[2], label_col[3], math.floor(220 * panel_alpha/255), 3)
            renderer.rectangle(ix + 5, cy - 1, 10, 2, label_col[1], label_col[2], label_col[3], math.floor(220 * panel_alpha/255))
            renderer.rectangle(ix + 13, cy - 2, 2, 2, label_col[1], label_col[2], label_col[3], math.floor(220 * panel_alpha/255))
        end
        renderer.text(x + padding_x + 12, y + header_h/2 - h_head/2, label_col[1], label_col[2], label_col[3], panel_alpha, "b", 0, header_text)

        local content_y = y + header_h + gap
        for i = 1, count do
            local b = active_binds[i]
            local text_right = b[1] .. " [" .. b[2] .. "]"
            local w_right, h_right = renderer.measure_text(nil, text_right)
            local w_row = math.max(w_right + padding_x*2, min_w)
            local y_row = content_y + (i - 1) * (row_box_h + row_gap)
            if renderer.blur and ui.get(tabs["Manipulations"].uistyle[12]) then
                local r = radius
                renderer.blur(x + r, y_row, w_row - 2*r, row_box_h, 15)
                renderer.blur(x, y_row + r, r, row_box_h - 2*r, 15)
                renderer.blur(x + w_row - r, y_row + r, r, row_box_h - 2*r, 15)
            end
            rounded_rect(x, y_row, w_row, row_box_h, bg_col[1], bg_col[2], bg_col[3], math.floor((bg_col[4] or 255) * panel_alpha/255), radius)
            if do_glow then
                local glow1 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.25) * panel_alpha/255)}
                local glow2 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.12) * panel_alpha/255)}
                pui.shadow(x, y_row, w_row, row_box_h, radius, radius, glow1, glow2)
            end
            pui.rec_outline(x, y_row, w_row, row_box_h, radius, 1, {outline_col[1], outline_col[2], outline_col[3], math.floor((outline_col[4] or 255) * panel_alpha/255)})

            do
                local cy = y_row + row_box_h/2
                local ix = x + padding_x - 10
                if do_glow then
                    local g1 = {label_col[1], label_col[2], label_col[3], math.floor(50 * panel_alpha/255)}
                    local g2 = {label_col[1], label_col[2], label_col[3], math.floor(25 * panel_alpha/255)}
                    pui.shadow(ix - 3, cy - 7, 18, 14, 7, 7, g1, g2)
                end
                rounded_rect(ix + 1, cy - 3, 6, 6, label_col[1], label_col[2], label_col[3], 200, 3)
                renderer.rectangle(ix + 6, cy - 1, 6, 2, label_col[1], label_col[2], label_col[3], 200)
            end
            local text_x = x + padding_x + 12
            renderer.text(text_x, y_row + row_box_h/2 - h_right/2, text_col[1], text_col[2], text_col[3], b[3], nil, 0, text_right)
        end
    end
end
pui.get_speclist = function()
    local speclist = {}
    local all = entity.get_all("CCSPlayer")
    for _, v in pairs(all) do
        local m_iObserverMode = entity.get_prop(v, 'm_iObserverMode')
        local m_hObserverTarget = entity.get_prop(v, 'm_hObserverTarget')
        if m_hObserverTarget ~= nil and m_hObserverTarget <= 64 and not entity.is_alive(v) and (m_iObserverMode == 4 or m_iObserverMode == 5) then
            if speclist[m_hObserverTarget] == nil then speclist[m_hObserverTarget] = {} end
            if v == entity.get_local_player() then
                speclist.obs = m_hObserverTarget
                goto comp
            end
            table.insert(speclist[m_hObserverTarget], {v, entity.get_player_name(v)})
            ::comp::
        end
    end
    return speclist
end
pui.get_avatar = function(ent)
    if ent == nil then
        return nil
    end
    local steam_id = entity.get_steam64(ent)
    local avatar = images.get_steam_avatar(steam_id)

    if steam_id == nil or avatar == nil then
        return nil
    end

    return renderer.load_rgba(avatar.contents, avatar.width, avatar.height)
end
visuals.alphaspec = {0, 0, 0, specs = {}}
visuals.specoldw = nil
visuals.spectators = function()
    if not tabs["Visuals"] or not tabs["Visuals"].spectators then return end
    local lplayer = entity.get_local_player()
    if not ui.get(tabs["Visuals"].spectators[1]) or (lplayer == nil and not ui.is_menu_open()) then
        visuals.alphaspec[1] = 0
        visuals.alphaspec[2] = 0
        visuals.alphaspec[3] = 0
        for k, _ in pairs(visuals.alphaspec.specs) do
            visuals.alphaspec.specs[k] = 0
        end
        return
    end
    if not tabs["Visuals"].spectators[2] then return end
    local avatars = ui.get(tabs["Visuals"].spectators[2])
    local players = lplayer ~= nil and pui.get_speclist() or nil
    local leng = (function()
        local spec = ""
        if lplayer == nil or players == nil then
            return ui.is_menu_open() and "username" or nil
        end
        local isd = entity.is_alive(lplayer)
        local ps = players[not isd and entity.get_prop(entity.get_local_player(), "m_hObserverTarget") or entity.get_local_player()]
        if ps == nil then return ps end
        for _, v in pairs(ps) do
            spec = pui.max(spec, v[2], renderer.measure_text, "c")
        end
        return string.len(spec) > 0 and spec or nil
    end)()
    if leng == nil and not ui.is_menu_open() then
        visuals.alphaspec[1] = math.floor(pui.lerp(visuals.alphaspec[1], 0, 0.35))
        visuals.alphaspec[2] = math.floor(pui.lerp(visuals.alphaspec[2], 0, 0.35))
        visuals.alphaspec[3] = math.floor(pui.lerp(visuals.alphaspec[3], 0, 0.35))
    else
        visuals.alphaspec[1] = math.ceil(pui.lerp(visuals.alphaspec[1], 255, 0.35))
        visuals.alphaspec[2] = math.ceil(pui.lerp(visuals.alphaspec[2], 120, 0.35))
        visuals.alphaspec[3] = math.ceil(pui.lerp(visuals.alphaspec[3], 60, 0.35))
    end
    local w, h = renderer.measure_text(nil, leng or "spectators")
    if visuals.specoldw ~= nil and visuals.specoldw ~= w then
        w = logs.anim("SPECW", visuals.specoldw, w, 0.5, visuals.specoldw > w and math.floor or math.ceil)
    end
    visuals.specoldw = w
    local style = "Win95"
    if false then
        if w % 2 == 1 then
            w = w + 1
        end
        local gradient = ui.get(tabs["Manipulations"].uistyle[2])
        renderer.rectangle(pui.specpos.x, pui.specpos.y, 110 + w*0.5, h*2 + (gradient and 4 or 2), g[1], g[2], g[3], visuals.alphaspec[1])
        renderer.rectangle(pui.specpos.x + 1, pui.specpos.y + 1, 110 + w*0.5 - 2, h*2 + (gradient and 2 or 0), a[1], a[2], a[3], visuals.alphaspec[1])
        renderer.rectangle(pui.specpos.x + 2, pui.specpos.y + 2, 110 + w*0.5 - 4, h*2 - (gradient and 0 or 2), b[1], b[2], b[3], visuals.alphaspec[1])
        renderer.rectangle(pui.specpos.x + 4, pui.specpos.y + 4, 110 + w*0.5 - 8, h*2 - (gradient and 4 or 6), a[1], a[2], a[3], visuals.alphaspec[1])
        renderer.texture(jg, pui.specpos.x + 5, pui.specpos.y + 5, 110 + w*0.5 - 10, h*2 - (gradient and 6 or 8), 255, 255, 255, visuals.alphaspec[1], "r")
        if gradient then
            renderer.gradient(pui.specpos.x + 6, pui.specpos.y + 6, (110 + w*0.5 - 10)*0.5, 1, g1[1], g1[2], g1[3], visuals.alphaspec[1], g2[1], g2[2], g2[3], visuals.alphaspec[1], true)
            renderer.gradient(pui.specpos.x + 6 + (110 + w*0.5 - 10)*0.5, pui.specpos.y + 6, (110 + w*0.5 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphaspec[1], g3[1], g3[2], g3[3], visuals.alphaspec[1], true)
            renderer.gradient(pui.specpos.x + 6, pui.specpos.y + 7, (110 + w*0.5 - 10)*0.5, 1, g1[1], g1[2], g1[3], visuals.alphaspec[2], g2[1], g2[2], g2[3], visuals.alphaspec[2], true)
            renderer.gradient(pui.specpos.x + 6 + (110 + w*0.5 - 10)*0.5, pui.specpos.y + 7, (110 + w*0.5 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphaspec[2], g3[1], g3[2], g3[3], visuals.alphaspec[2], true)
            renderer.gradient(pui.specpos.x + 6, pui.specpos.y + 8, (110 + w*0.5 - 10)*0.5, 1, g1[1], g1[2], g1[3], visuals.alphaspec[3], g2[1], g2[2], g2[3], visuals.alphaspec[3], true)
            renderer.gradient(pui.specpos.x + 6 + (110 + w*0.5 - 10)*0.5, pui.specpos.y + 8, (110 + w*0.5 - 10)*0.5 - (w%10 == 0 and 2 or 1), 1, g2[1], g2[2], g2[3], visuals.alphaspec[3], g3[1], g3[2], g3[3], visuals.alphaspec[3], true)
        end
        renderer.text(pui.specpos.x + (110 + w*0.5)*0.5, pui.specpos.y + h + (gradient and 3 or 1), 255, 255, 255, visuals.alphaspec[1], "c", 0, "spectators")
