            renderer.blur(x + w_rect - r, y + r, r, row_h + padding_y*2 - 2*r, 15)
        end
        rounded_rect(x, y, w_rect, row_h + padding_y*2, bg_col[1], bg_col[2], bg_col[3], math.floor((bg_col[4] or 255) * visuals.alphaspec[1]/255), 12)
        if do_glow then
            local glow1 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.25) * visuals.alphaspec[1]/255)}
            local glow2 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.12) * visuals.alphaspec[1]/255)}
            pui.shadow(x, y, w_rect, row_h + padding_y*2, 12, 12, glow1, glow2)
        end
        pui.rec_outline(x, y, w_rect, row_h + padding_y*2, 12, 1, outline_col)
        local cy = y + (row_h + padding_y*2)/2
        local ix = x + padding_x - 10
        if do_glow then
            local g1 = {label_col[1], label_col[2], label_col[3], math.floor(60 * visuals.alphaspec[1]/255)}
            local g2 = {label_col[1], label_col[2], label_col[3], math.floor(30 * visuals.alphaspec[1]/255)}
            pui.shadow(ix - 4, cy - 8, 24, 16, 8, 8, g1, g2)
        end
        rounded_rect(ix, cy - 4, 14, 8, label_col[1], label_col[2], label_col[3], math.floor(220 * visuals.alphaspec[1]/255), 4)
        rounded_rect(ix + 5, cy - 2, 4, 4, label_col[1], label_col[2], label_col[3], 255, 2)
        renderer.text(x + padding_x + 12, y + (row_h + padding_y*2)/2 - h_head/2, label_col[1], label_col[2], label_col[3], visuals.alphaspec[1], "b", 0, header_text)

        local lplayer = entity.get_local_player()
        local isd = lplayer ~= nil and entity.is_alive(lplayer) or true
        local ps = lplayer ~= nil and pui.get_speclist() or nil
        ps = (ps and lplayer ~= nil) and ps[not isd and entity.get_prop(lplayer, "m_hObserverTarget") or lplayer] or nil
        local items_count = (ps and #ps or 0)
        if items_count == 0 and not ui.is_menu_open() then return end
        if items_count == 0 and ui.is_menu_open() then items_count = 1 end
        local gap = 4
        for i = 1, items_count do
            local name = (ps and ps[i] and ps[i][2]) or "username"
            local ent = ps and ps[i] and ps[i][1] or nil
            local w_right, h_right = renderer.measure_text(nil, name)
            local w_row = w_right + padding_x*2 + 18
            local y_row = y + row_h + padding_y*2 + gap + (i - 1) * (row_h + gap)
            if renderer.blur and ui.get(tabs["Manipulations"].uistyle[12]) then
                local r = 12
                renderer.blur(x + r, y_row, w_row - 2*r, row_h, 15)
                renderer.blur(x, y_row + r, r, row_h - 2*r, 15)
                renderer.blur(x + w_row - r, y_row + r, r, row_h - 2*r, 15)
            end
            rounded_rect(x, y_row, w_row, row_h, bg_col[1], bg_col[2], bg_col[3], math.floor((bg_col[4] or 255) * visuals.alphaspec[1]/255), 12)
            if do_glow then
                local glow1 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.25) * visuals.alphaspec[1]/255)}
                local glow2 = {bg_col[1], bg_col[2], bg_col[3], math.floor(((bg_col[4] or 255) * 0.12) * visuals.alphaspec[1]/255)}
                pui.shadow(x, y_row, w_row, row_h, 12, 12, glow1, glow2)
            end
            pui.rec_outline(x, y_row, w_row, row_h, 12, 1, outline_col)
            local cy2 = y_row + row_h/2
            local ix2 = x + padding_x - 10
            if do_glow then
                local g1 = {label_col[1], label_col[2], label_col[3], math.floor(50 * visuals.alphaspec[1]/255)}
                local g2 = {label_col[1], label_col[2], label_col[3], math.floor(25 * visuals.alphaspec[1]/255)}
                pui.shadow(ix2 - 3, cy2 - 7, 22, 14, 7, 7, g1, g2)
            end
            rounded_rect(ix2, cy2 - 4, 12, 8, label_col[1], label_col[2], label_col[3], 200, 4)
            rounded_rect(ix2 + 4, cy2 - 2, 4, 4, label_col[1], label_col[2], label_col[3], 255, 2)
            renderer.text(x + padding_x + 12, y_row + row_h/2 - h_right/2, text_col[1], text_col[2], text_col[3], 255, nil, 0, name)
        end
    end
end
pui.in_range_rect = function(curs, coord, size)
    return curs[1] > coord.x and curs[1] < coord.x + size[1] and curs[2] > coord.y and curs[2] < coord.y + size[2]
end
pui.calcadelta = function(start, dest)
    return {dest[1] - start[1], dest[2] - start[2]}
end
visuals.alphaspencer = {0, 0}
visuals.drag_overlay_alpha = visuals.drag_overlay_alpha or 0
visuals.velwarpos = {x = screen.x*0.5 - 165, y = screen.y*0.25 - 18}
visuals.defindpos = {x = screen.x*0.5 - 88, y = screen.y*0.15 - 18}
visuals.absvelwar = false
visuals.absdefind = false
visuals.draghandler = function()
    if not ui.is_menu_open() then return end
    local lplayer = entity.get_local_player()
    local menu = vector(ui.menu_position())
    local sizemenu = {ui.menu_size()}
