    local any_drag = (visuals.absdefind or visuals.absvelwar or abskey or absspec or abswm or (hitlogger and hitlogger.dragging) or (logs and logs.screen_dragging))
    visuals.drag_overlay_alpha = pui.lerp(visuals.drag_overlay_alpha, any_drag and 140 or 0, 0.15)
    if visuals.drag_overlay_alpha > 0.5 then
        renderer.rectangle(0, 0, screen.x, screen.y, 0, 0, 0, math.floor(visuals.drag_overlay_alpha))
    end
    if tabs["Visuals"] and tabs["Visuals"].defind and tabs["Visuals"].defind[1] and ui.get(tabs["Visuals"].defind[1]) then
        local isinrect = pui.in_range_rect(cursor, visuals.defindpos, {176, 32}) and not pui.in_range_rect(cursor, menu, sizemenu)
        pui.attackhover[5] = {isinrect, tabs["Visuals"].defind[1], visuals.absdefind}
        outlined_rectangle(visuals.defindpos.x, visuals.defindpos.y, 176, 32, 255, 255, 255, 255*visuals.alphaspencer[2], 1)
        renderer.text(visuals.defindpos.x + 88, visuals.defindpos.y + 38, 255, 255, 255, 255*visuals.alphaspencer[2], "c", 0, "Click M2 To Reset Pos")
        if not (abskey or absspec or visuals.absvelwar) and isinrect or visuals.absdefind then
            visuals.alphaspencer[2] = clicked and pui.lerp(visuals.alphaspencer[2], 0, 0.35) or pui.lerp(visuals.alphaspencer[2], 1, 0.35)
            if firstclick or visuals.absdefind then
                visuals.absdefind = clicked
                local delta = pui.calcadelta(oldcursor, cursor)
                local moved = {x = visuals.defindpos.x + delta[1], y = visuals.defindpos.y + delta[2]}
                visuals.defindpos.x = moved.x < 0 and 0 or moved.x > screen.x - 160 and screen.x - 160 or moved.x
                visuals.defindpos.y = moved.y < 0 and 0 or moved.y > screen.y - 32 and screen.y - 32 or moved.y
            elseif client.key_state(0x02) then
                visuals.defindpos = {x = screen.x*0.5 - 88, y = screen.y*0.15 - 18}
