            rect = {w*1.5, h*1.5}
        elseif style == "Win95" then
            local leng = pui.getlengst()
            local w, h = renderer.measure_text(nil, leng or "keybinds")
            rect = {math.max(160, (w or 0) + 64), 18 + 12 + (math.max(1, (#visuals.bindings or 1)) * 16 + 12) + 12}
        elseif false then
            local leng = pui.getlengst()
            local w, h = renderer.measure_text(nil, leng)
            rect = {100 + w*0.75, h*1.5}
        elseif false then
            local padding_x, padding_y = 6, 2
            local row_h = 18
            local row_gap = 3
            local min_w = 100
            local header_text = "Keybinds"
            local active_binds = {}
            for _, v in ipairs(visuals.bindings) do
                local k = v[1]
                if v[2] and v[3][2] > 0 then
                    table.insert(active_binds, {k, visuals.modes[v[3][2]]})
                end
            end
            local count = #active_binds
            if count == 0 then
                active_binds = {{"Double Tap", "toggled"}}
                count = 1
            end
            local max_w = 0
            local w_header = select(1, renderer.measure_text("b", header_text))
            for i = 1, count do
                local b = active_binds[i]
                local text_right = b[1] .. " [" .. b[2] .. "]"
                local w_right = select(1, renderer.measure_text(nil, text_right))
                local w_r = w_right or 0
                local mw = min_w or 100
                local content_w = math.max(w_r, mw)
                max_w = math.max(tonumber(max_w) or 0, tonumber(content_w) or 0)
            end
            local header_h = row_h + padding_y*2
            local gap = 3
            local row_box_h = row_h + padding_y*2
            local content_h = count * row_box_h + (count - 1) * row_gap
            local overall_w = math.max(w_header or 0, max_w or 0) + (padding_x or 0)*2
            rect = {overall_w, header_h + gap + content_h}
        end
        local isinrect = pui.in_range_rect(cursor, pui.keypos, rect) and not pui.in_range_rect(cursor, menu, sizemenu)
        pui.attackhover[2] = {isinrect, tabs["Visuals"].keybinds[1], abskey}
        if not (absspec or visuals.absdefind or visuals.absvelwar) and (isinrect and firstclick or abskey) then
            abskey = clicked
            local delta = pui.calcadelta(oldcursor, cursor)
            local moved = {x = pui.keypos.x + delta[1], y = pui.keypos.y + delta[2]}
            pui.keypos.x = moved.x < 0 and 0 or moved.x > screen.x - rect[1] and screen.x - rect[1] or moved.x
            pui.keypos.y = moved.y < 0 and 0 or moved.y > screen.y - rect[2] and screen.y - rect[2] or moved.y
            database.write("osmanhook::keypos", pui.keypos)
