    end

    if false and tabs["Visuals"] and tabs["Visuals"].watermark and tabs["Visuals"].watermark[1] and ui.get(tabs["Visuals"].watermark[1]) then
        local style = "Win95"
        if style == "Blurified" then
            local info2 = ui.get(tabs["Visuals"].watermark[2]) or {}
            local segments = pui.calcwtmk(info2) or {}
            local padding_x, padding_y = 12, 6
