            local w_total, h_max = 0, 0
            for i = 1, #segments do
                local w, h = renderer.measure_text(nil, segments[i])
                w_total = w_total + w + (i > 1 and sep_w or 0)
                h_max = math.max(h_max, h)
            end
            if #segments == 0 then w_total, h_max = 120, 16 end
            local rect = {w_total + padding_x*2, h_max + padding_y*2}
            local isinrect = pui.in_range_rect(cursor, pui.wtpos, rect) and not pui.in_range_rect(cursor, menu, sizemenu)
            pui.attackhover[6] = {isinrect, tabs["Visuals"].watermark[1], abswm}
            if not (abskey or absspec or visuals.absdefind or visuals.absvelwar) and (isinrect and firstclick or abswm) then
                abswm = clicked
                local delta = pui.calcadelta(oldcursor, cursor)
                local moved = {x = pui.wtpos.x + delta[1], y = pui.wtpos.y + delta[2]}
                pui.wtpos.x = moved.x < 0 and 0 or moved.x > screen.x - rect[1] and screen.x - rect[1] or moved.x
                pui.wtpos.y = moved.y < 0 and 0 or moved.y > screen.y - rect[2] and screen.y - rect[2] or moved.y
                database.write("osmanhook::wtpos", pui.wtpos)
            end
        elseif style == "Win95" then
            local info = ui.get(tabs["Visuals"].watermark[2]) or {}
            local text = pui.calcwtmk(info)
            local combined_text = table.concat(text, " | ")
            local w, h = renderer.measure_text(nil, combined_text)
            local pad = 3
            local ww = math.max(120, (w or 0) + pad * 2 + 8)
            local hh = 18 + 8 + (h or 12) + 8
            local rect = {ww, hh}
            local isinrect = pui.in_range_rect(cursor, pui.wtpos, rect) and not pui.in_range_rect(cursor, menu, sizemenu)
            pui.attackhover[6] = {isinrect, tabs["Visuals"].watermark[1], abswm}
            if not (abskey or absspec or visuals.absdefind or visuals.absvelwar) and (isinrect and firstclick or abswm) then
                abswm = clicked
                local delta = pui.calcadelta(oldcursor, cursor)
                local moved = {x = pui.wtpos.x + delta[1], y = pui.wtpos.y + delta[2]}
                pui.wtpos.x = moved.x < 0 and 0 or moved.x > screen.x - rect[1] and screen.x - rect[1] or moved.x
                pui.wtpos.y = moved.y < 0 and 0 or moved.y > screen.y - rect[2] and screen.y - rect[2] or moved.y
                database.write("osmanhook::wtpos", pui.wtpos)
            end
        end
    end
end
local function handle_attack(cmd)
    if pui.is_altui and not pui.defaulttab and pui.is_open then
        if pui.attackhover[1] then cmd.in_attack = 0; cmd.in_attack2 = 0 end
    end
    if ui.is_menu_open() then
        for i=2, #pui.attackhover do
            if pui.attackhover[i] and ui.get(pui.attackhover[i][2]) and (pui.attackhover[i][1] or pui.attackhover[i][3]) then cmd.in_attack = 0; cmd.in_attack2 = 0 end
        end
    end
end
local fpstweeks = { ["3d sky"] = { cvar = cvar.r_3dsky, value = 1 },
["fog"] = { cvars = { cvar.fog_enable, cvar.fog_enable_water_fog }, value = 1 },
["shadows"] = { cvars = { cvar.r_shadows, cvar.cl_csm_static_prop_shadows, cvar.cl_csm_shadows, cvar.cl_csm_world_shadows, cvar.cl_foot_contact_shadows, cvar.cl_csm_viewmodel_shadows, cvar.cl_csm_rope_shadows, cvar.cl_csm_sprite_shadows, cvar.cl_csm_translucent_shadows, cvar.cl_csm_entity_shadows, cvar.cl_csm_world_shadows_in_viewmodelcascade }, value = 1 },
["blood"] = { cvar = cvar.violence_hblood, value = 1 }, ["decals"] = { cvars = { cvar.r_drawdecals, cvar.r_drawropes, cvar.r_drawsprites }, value = 1 },
["bloom"] = { cvar = cvar.mat_disable_bloom, value = 0 },
["other"] = { cvars = { cvar.r_dynamic, cvar.r_eyegloss, cvar.r_eyes, cvar.r_drawtracers_firstperson, cvar.r_dynamiclighting }, value = 1 } }
local function fpsboost(reset)
    if not reset then
        for key, val in pairs(fpstweeks) do
            if pui.multi_parse(tabs["Visuals"].fpsboost[2], key) then
                if val.cvar then
                    if val.cvar:get_int() == val.value then
                        val.cvar:set_int(val.value == 0 and 1 or (val.value == 1 and 0 or val.value))
                    end
                else
                    for _, v in ipairs(val.cvars) do
                        if v:get_int() == val.value then
                            v:set_int(val.value == 0 and 1 or (val.value == 1 and 0 or val.value))
                        end
                    end
                end
            else
                if val.cvar then
                    if val.cvar:get_int() ~= val.value then
                        val.cvar:set_int(val.value)
                    end
                else
                    for _, v in ipairs(val.cvars) do
                        if v:get_int() ~= val.value then
                            v:set_int(val.value)
                        end
                    end
                end
            end
        end
    else
        for key, val in pairs(fpstweeks) do
            if val.cvar then
                if val.cvar:get_int() ~= val.value then
                    val.cvar:set_int(val.value)
                end
            else
                for _, v in ipairs(val.cvars) do
                    if v:get_int() ~= val.value then
                        v:set_int(val.value)
                    end
                end
            end
        end
    end
end

do
    local vs = tabs and tabs["Visuals"]
    local fb = vs and vs.fpsboost
    if fb and fb[1] then
        local function refresh_fpsboost()
            pcall(client.unset_event_callback, "paint", fpsboost)
            if ui.get(fb[1]) then
                client.set_event_callback("paint", fpsboost)
                fpsboost()
            else
                fpsboost(true)
            end
        end
        ui.set_callback(fb[1], function()
            refresh_fpsboost()
        end)
        if fb[2] then
            ui.set_callback(fb[2], function()
                if ui.get(fb[1]) then
                    fpsboost()
                end
            end)
        end
        refresh_fpsboost()
    end
end

local function trigscp()
    ui.set(skeetgui.visualgui.effects.remove_soverlay, true)
end
local function trigscp1()
    ui.set(skeetgui.visualgui.effects.remove_soverlay, false)
end
local function linear(slot0, slot1, slot2, slot3)
    return slot2 * slot0 / slot3 + slot1
end
local csopealpha = 1
local oldscopelen = nil
local function scopelines()
    local lplayer = entity.get_local_player()
    if lplayer == nil then return end
    if not tabs["Visuals"] or not tabs["Visuals"].scopelines then return end
    trigscp1()
    local animated = ui.get(tabs["Visuals"].scopelines[2])
    local inverted = ui.get(tabs["Visuals"].scopelines[3])
    local is_scoped = entity.is_alive(lplayer) and entity.get_prop(lplayer, "m_bIsScoped") == 1
    local color1 = {ui.get(tabs["Visuals"].scopelines[5])}
    local color2 = {ui.get(tabs["Visuals"].scopelines[7])}
    local gap = ui.get(tabs["Visuals"].scopelines[9])
    local len = ui.get(tabs["Visuals"].scopelines[10])
    local thick = ui.get(tabs["Visuals"].scopelines[11])
    local firstcol = inverted and color2 or color1
    local seccol = inverted and color1 or color2
    oldscopelen = animated and (oldscopelen or len) or 0
    csopealpha = animated and csopealpha or 1
    if animated then
        if is_scoped and entity.is_alive(lplayer) then
            csopealpha = pui.lerp(csopealpha, 1, 0.2)
            oldscopelen = math.floor(pui.lerp(oldscopelen, 0, 0.35, 20))
        else
            csopealpha = pui.lerp(csopealpha, 0, 0.2, 20)
            oldscopelen = math.ceil(pui.lerp(oldscopelen, len, 0.35))
        end
    end
    if animated and csopealpha > 0 or is_scoped then
        if ui.get(tabs["Visuals"].scopelines[7]) ~= "Vertical only" then
            renderer.gradient(screen.x*0.5 - (gap + len), screen.y*0.5 - math.floor(thick*0.5), len + (animated and -oldscopelen or 0), thick, seccol[1], seccol[2], seccol[3], seccol[4] * csopealpha, firstcol[1], firstcol[2], firstcol[3], firstcol[4] * csopealpha, true)
            renderer.gradient(screen.x*0.5 + gap + (animated and oldscopelen or 0), screen.y*0.5 - math.floor(thick*0.5), len + (animated and -oldscopelen or 0), thick, firstcol[1], firstcol[2], firstcol[3], firstcol[4] * csopealpha, seccol[1], seccol[2], seccol[3], seccol[4] * csopealpha, true)
        end
        if ui.get(tabs["Visuals"].scopelines[7]) ~= "Horizontal Only" then
            if ui.get(tabs["Visuals"].scopelines[7]) ~= "T-Shape" then
                renderer.gradient(screen.x*0.5 - math.floor(thick*0.5), screen.y*0.5 - gap - len, thick, len + (animated and -oldscopelen or 0), seccol[1], seccol[2], seccol[3], seccol[4] * csopealpha, firstcol[1], firstcol[2], firstcol[3], firstcol[4] * csopealpha, false)
            end
            renderer.gradient(screen.x*0.5 - math.floor(thick*0.5), screen.y*0.5 + gap + (animated and oldscopelen or 0), thick, len + (animated and -oldscopelen or 0), firstcol[1], firstcol[2], firstcol[3], firstcol[4] * csopealpha, seccol[1], seccol[2], seccol[3], seccol[4] * csopealpha, false)
        end
    end
end
if tabs["Visuals"] and tabs["Visuals"].scopelines and tabs["Visuals"].scopelines[1] then
ui.set_callback(tabs["Visuals"].scopelines[1], function(id)
    local nb = ""
    if ui.get(id) then
        nb = "set_event_callback"
    else
        nb = "unset_event_callback"
    end
    client[nb]("paint_ui", trigscp)
    client[nb]("paint", scopelines)
end)
end
local uimuliplayer = 0
local function indicators_idle()
    if ui.is_menu_open() then
        uimuliplayer = uimuliplayer < 1 and pui.lerp(uimuliplayer, 1, 0.1, 60) or 0
    end
end
local slowalpha = 0
local function velocity_warning()
    local lplayer = entity.get_local_player()
    if lplayer == nil and not ui.is_menu_open() then return end
    if not tabs or not tabs["Visuals"] or not tabs["Visuals"].velwar then return end
    if not tabs["Visuals"].velwar[1] or not ui.get(tabs["Visuals"].velwar[1]) then return end
    local cr, cg, cb, ca = ui.get(tabs["Visuals"].velwar[2])
    cr, cg, cb, ca = tonumber(cr) or 255, tonumber(cg) or 255, tonumber(cb) or 255, tonumber(ca) or 255
    local color = {cr, cg, cb, ca}
    local velmod = (lplayer ~= nil and tonumber(entity.get_prop(lplayer, "m_flVelocityModifier")) or nil) or 0.75
    local decmod = (1 - velmod) * 10
    local flags = (lplayer ~= nil and entity.get_prop(lplayer, "m_fFlags") or nil) or 0
    local injump = (misc and misc.isinjump) or false
    local on_ground = bit.band(flags, bit.lshift(1, 0)) ~= 0 and not injump
    if lplayer ~= nil and not entity.is_alive(lplayer) then
        velmod = 1
        decmod = 10
    end
    if ui.is_menu_open() then
        velmod = velmod == 1 and uimuliplayer or velmod
        slowalpha = pui.lerp(slowalpha, 1, 0.15)
    else
        if on_ground then
            if decmod <= 1 and decmod > 0 then
                slowalpha = decmod
            elseif velmod < 1 then
                slowalpha = pui.lerp(slowalpha, 1, 0.15)
            else
                slowalpha = pui.lerp(slowalpha, 0, 0.35)
            end
        else
            slowalpha = velmod < 1 and pui.lerp(slowalpha, 0, 0.15) or 0
        end
    end
    if slowalpha > 0 then
        local offset = math.max(0, math.min(150, 150 * (tonumber(velmod) or 1)))
        local pos
        if visuals and visuals.velwarpos then
            pos = visuals.velwarpos
        else
            local scr = pui.get_screen()
            pos = {x = scr.x*0.5 - 165, y = scr.y*0.25 - 18}
        end
        local style = "Win95"
        local a0 = math.floor((color[4] or 255) * slowalpha)
        if style == "Win95" then
            local ww, hh = 320, 72
            win95_window(pos.x, pos.y, ww, hh, "Velocity warning!", a0, true)
            local ix = pos.x + 4
            local iy = pos.y + 4 + 18 + 4
            local iw = ww - 8
            local ih = hh - (iy - pos.y) - 4
            renderer.rectangle(ix, iy, iw, ih, 255, 255, 255, a0)
            outlined_rectangle(ix, iy, iw, ih, 0, 0, 0, a0, 1)

            local icon_sz = math.max(8, math.min(44, ih - 2))
            local icon_pad = 12
            local icon_x = ix + 2
            local icon_y = iy + math.floor((ih - icon_sz) * 0.5)
            local bar_x = ix + 8
            do
                local tid = (visuals and visuals.get_win95_warn_texture) and visuals.get_win95_warn_texture() or nil
                if tid ~= nil then
                    renderer.texture(tid, icon_x, icon_y, icon_sz, icon_sz, 255, 255, 255, a0, "f")
                    bar_x = icon_x + icon_sz + icon_pad
                end
            end
            local bar_w = math.max(10, (ix + iw) - bar_x - 4)
            local bar_y = iy + math.floor((ih - 5) / 2)
            local pct = math.max(0, math.min(1, tonumber(velmod) or 1))
            local fill = math.max(0, math.min((bar_w - 2), math.floor((bar_w - 2) * pct)))
            renderer.rectangle(bar_x, bar_y, bar_w, 5, 0, 0, 0, a0)
            renderer.rectangle(bar_x + 1, bar_y + 1, fill, 3, color[1], color[2], color[3], a0)
        else
            renderer.rectangle(pos.x + 12, pos.y + 17, 152, 5, 0, 0, 0, a0)
            renderer.rectangle(pos.x + 13, pos.y + 18, offset, 3, color[1], color[2], color[3], a0)
            renderer.text(pos.x + 12 + offset, pos.y + 19, color[1], color[2], color[3], a0, "-c", 0, string.format("%d%%", (tonumber(velmod) or 1)*100))
            renderer.text(pos.x + 88, pos.y + 13, color[1], color[2], color[3], a0, "-c", 0, "VELOCITY SLOWDOWN!")
        end
    end
end
visuals.velocity_warning = velocity_warning
local defalpha = 0
local function defensive_indicator()
    local lplayer = entity.get_local_player()
    if lplayer == nil and not ui.is_menu_open() then return end
    if not tabs or not tabs["Visuals"] or not tabs["Visuals"].defind then return end
    if not tabs["Visuals"].defind[1] or not ui.get(tabs["Visuals"].defind[1]) then return end
    local dr, dg, db, da = ui.get(tabs["Visuals"].defind[2])
    dr, dg, db, da = tonumber(dr) or 255, tonumber(dg) or 255, tonumber(db) or 255, tonumber(da) or 255
    local color = {dr, dg, db, da}

    local base = 0
    if ticks and ticks.tickbase_diff ~= nil then
        base = ticks.tickbase_diff * -1
    end
    if lplayer ~= nil and not entity.is_alive(lplayer) then
        base = 0
    end
    if ui.is_menu_open() and base <= 0 then
        base = 15 - (15*uimuliplayer)
        defalpha = pui.lerp(defalpha, 1, 0.35)
    else
        if base > 0 then
            defalpha = pui.lerp(defalpha, 1, 0.35)
        elseif not ui.is_menu_open() then
            defalpha = pui.lerp(defalpha, 0, 0.35)
        end
    end
    if defalpha > 0 then
        if base <= 0 then base = 0 end
        local factor = 1 - (base*(1/15))
        local offset = 150 * factor
        local pos
        if visuals and visuals.defindpos then
            pos = visuals.defindpos
        else
            local scr = pui.get_screen()
            pos = {x = scr.x*0.5 - 88, y = scr.y*0.15 - 18}
        end
        renderer.rectangle(pos.x + 12, pos.y + 17, 152, 5, 0, 0, 0, color[4]*defalpha)
        renderer.rectangle(pos.x + 13, pos.y + 18, offset, 3, color[1], color[2], color[3], color[4]*defalpha)
        renderer.text(pos.x + 13 + offset, pos.y + 19, color[1], color[2], color[3], color[4]*defalpha, "-c", 0, string.format("%d%%", factor*100))
        renderer.text(pos.x + 88, pos.y + 13, color[1], color[2], color[3], color[4]*defalpha, "-c", 0, "DEFENSIVE TRIGGER!")
    end
end
visuals.defensive_indicator = defensive_indicator
if tabs["Visuals"] and tabs["Visuals"].velwar and tabs["Visuals"].velwar[1] then
ui.set_callback(tabs["Visuals"].velwar[1], function(id)
