        if (not tabs["Visuals"].defind or not tabs["Visuals"].defind[1] or not ui.get(tabs["Visuals"].defind[1])) then
            client.unset_event_callback("paint", indicators_idle)
            uimuliplayer = 0
        end
    end
end)

