antiaims.current_cond = "Shared"
antiaims.condition = function(cmd)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local flags = entity.get_prop(lplayer, 'm_fFlags')
	local m_vecVelocity = { entity.get_prop(lplayer, 'm_vecVelocity') }
    local is_crouching = bit.band(flags, bit.lshift(1, 1)) ~= 0
    local on_ground = bit.band(flags, bit.lshift(1, 0)) ~= 0
    local standing = math.abs(m_vecVelocity[1]) + math.abs(m_vecVelocity[2]) < 2
    local slowwalking = false
    do
        local sm = skeetgui and skeetgui.aagui and skeetgui.aagui.other and skeetgui.aagui.other.slow_motion or nil
        if type(sm) == "table" then
            if sm[1] ~= nil and sm[2] ~= nil then
                local ok1, a = pcall(ui.get, sm[1])
                local ok2, b = pcall(ui.get, sm[2])
                slowwalking = (ok1 and a == true) and (ok2 and b == true)
            else
                local ref = sm[2] or sm[1]
                if ref ~= nil then
                    local ok, active = pcall(ui.get, ref)
                    slowwalking = ok and type(active) == "boolean" and active or false
                end
            end
        elseif sm ~= nil then
            local ok, active = pcall(ui.get, sm)
            slowwalking = ok and type(active) == "boolean" and active or false
        end
    end
    if standing then
        slowwalking = false
    end
    local is_jumping = cmd.in_jump == 1
    local is_e = cmd.in_use == 1
    local fakelags = not ui.get(skeetgui.ragegui.aimbot.double_tap[2]) and not ui.get(skeetgui.aagui.other.on_shot_antiaim[2])
    local duckpeek = ui.get(skeetgui.ragegui.other.duck_peek_assist)

    do
        local bombs = entity.get_all("CPlantedC4")
        if bombs ~= nil and #bombs > 0 then
            local c4 = bombs[#bombs]
            local defuser = entity.get_prop(c4, "m_hBombDefuser")
            if defuser ~= nil and defuser ~= -1 and defuser == lplayer then
                antiaims.current_cond = "Disabled"
                return
            end
        end
    end

    if ui.get(tabs["Anti-aimbot angles"]["On-Use"].override) and is_e then
        local bomb = entity.get_all("CPlantedC4")
        if #bomb > 0 then
            local lpos = vector(entity.get_origin(lplayer))
            local c4pos = vector(entity.get_origin(bomb[#bomb]))
            if lpos:dist(c4pos) < 50 and entity.get_prop(lplayer, "m_iTeamNum") == 3 then
                antiaims.current_cond = "Disabled"
                return
            end
        end
        antiaims.current_cond = "On-Use"
        return
    elseif is_e then
        antiaims.current_cond = "Disabled"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Duckpeek"].override) and duckpeek then
        antiaims.current_cond = "Duckpeek"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Fakelags"].override) and fakelags then
        antiaims.current_cond = "Fakelags"
        return
    end

    do
        local manual_active = antiaims.is_manual ~= nil and antiaims.manuals and antiaims.manuals[antiaims.is_manual] and antiaims.manuals[antiaims.is_manual].yaw ~= nil
        local manuals_tab = tabs["Anti-aimbot angles"] and tabs["Anti-aimbot angles"]["Manuals"] or nil
        local manuals_override = manuals_tab and manuals_tab.override or nil
        if manual_active and manuals_override ~= nil then
            local ok, ov = pcall(ui.get, manuals_override)
            if ok and ov == true then
                antiaims.current_cond = "Manuals"
                return
            end
        end
    end

    do
        local fs_tab = tabs["Anti-aimbot angles"] and tabs["Anti-aimbot angles"]["Freestand"] or nil
        local fs_override = fs_tab and fs_tab.override or nil
        if fs_override ~= nil and tabs["Anti-aimbot angles"].freestand and tabs["Anti-aimbot angles"].freestand[1] then
            local ok_ov, ov = pcall(ui.get, fs_override)
            if ok_ov and ov == true then
                local ok_fs, fs_val = pcall(ui.get, tabs["Anti-aimbot angles"].freestand[1])
                if ok_fs and fs_val == true then
                    antiaims.current_cond = "Freestand"
                    return
                end
            end
        end
    end

    local slowwalk_override = ui.get(tabs["Anti-aimbot angles"]["Slowwalk"].override)
    if slowwalk_override and slowwalking and not is_jumping and on_ground and not is_crouching then
        antiaims.current_cond = "Slowwalk"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Moving"].override)
        and not is_crouching
        and not standing
        and on_ground
        and not is_jumping
        and (not slowwalking or not slowwalk_override) then
        antiaims.current_cond = "Moving"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Crouch"].override) and is_crouching and on_ground and not is_jumping and standing then
        antiaims.current_cond = "Crouch"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Crouch-Moving"].override) and is_crouching and on_ground and not is_jumping and not standing then
        antiaims.current_cond = "Crouch-Moving"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Air-Crouch"].override) and is_crouching and (not on_ground or is_jumping) then
        antiaims.current_cond = "Air-Crouch"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Air"].override) and ((not on_ground or is_jumping) and not is_crouching) then
        antiaims.current_cond = "Air"
        return
    end
    if ui.get(tabs["Anti-aimbot angles"]["Standing"].override) and standing and on_ground and not is_jumping and not slowwalking and not is_crouching then
        antiaims.current_cond = "Standing"
        return
    end
    antiaims.current_cond = "Shared"
end
antiaims.desync_side = function()
    local lplayer = entity.get_local_player()
    if lplayer == nil then return end

    if globals.chokedcommands() ~= 0 then return end

    local body_yaw = entity.get_prop(lplayer, 'm_flPoseParameter', 11) * 120 - 60

    antiaims.current_side = body_yaw > 0
end

antiaims.freestand_best_side = function(base_yaw)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return nil end

    local target = antiaims.target or client.current_threat()
    if target == nil then
        local players = entity.get_players(true)
        if players and #players > 0 then
            target = players[1]
        else
            return nil
        end
    end

    local tx, ty, tz = entity.hitbox_position(target, 0)
    if not tx then
        tx, ty, tz = entity.get_origin(target)
        if not tx then return nil end
        tz = (tonumber(tz) or 0) + 64
    end

    local ex, ey, ez = client.eye_position()
    if not ex then return nil end

    local yaw = tonumber(base_yaw)
    if yaw == nil then
        local tpose = vector(tx, ty, tz)
        local lpose = vector(ex, ey, ez)
        local _, yawt = lpose:to(tpose):angles()
        yaw = yawt
    end

    local function yaw_to_vec(y)
        local r = math.rad(y)
        return math.cos(r), math.sin(r)
    end

    local lx, ly = yaw_to_vec(yaw + 90)
    local rx, ry = yaw_to_vec(yaw - 90)
    local dist = 32

    local lpx, lpy, lpz = ex + lx * dist, ey + ly * dist, ez
    local rpx, rpy, rpz = ex + rx * dist, ey + ry * dist, ez

    local frac_l = client.trace_line(lplayer, tx, ty, tz, lpx, lpy, lpz)
    local frac_r = client.trace_line(lplayer, tx, ty, tz, rpx, rpy, rpz)

    if frac_l == nil or frac_r == nil then return nil end

    local threshold = 0.05
    if math.abs(frac_l - frac_r) < threshold then
        return antiaims.current_side
    end

    if frac_l < frac_r then
        return true
    elseif frac_r < frac_l then
        return false
    end
    return nil
end
antiaims.manuals = {
    {name = "Left", yaw = -90, key = tabs["Anti-aimbot angles"].manuals[2]},
    {name = "Right", yaw = 90, key = tabs["Anti-aimbot angles"].manuals[3]},
    {name = "Reset", yaw = nil, key = tabs["Anti-aimbot angles"].manuals[4]}
}
antiaims.manual_handler = function()
    if not ui.get(tabs["Anti-aimbot angles"].manuals[1]) then antiaims.is_manual = nil; return end
    local lplayer = entity.get_local_player()
    if not lplayer or not entity.is_alive(lplayer) then return end
    for k, v in pairs(antiaims.manuals) do
        local active, key = ui.get(v.key)
        if v.active == nil then v.active = active end
        if v.active == active then goto exit end
        v.active = active
        if v.yaw == nil then antiaims.is_manual = nil end
        antiaims.is_manual = antiaims.is_manual ~= k and k or nil goto exit
        ::exit::
    end
end

antiaims.calculate = function(tab)
    local r = {}
    for key, value in pairs(tab) do
        if type(value) == "table" then
           r[key] = antiaims.calculate(value)
        else
            r[key] = ui.get(value)
        end
    end
    return r
end
antiaims.maxdelta = function(e)
    local anm = c_entity.new(e):get_anim_state()
    local duckamount = anm.duck_amount
    local speedfraction = math.max(0, math.min(anm.feet_speed_forwards_or_sideways, 1))
    local speedfactor = math.max(0, math.min(1, anm.feet_speed_unknown_forwards_or_sideways))
    local st1 = ((anm.stop_to_full_running_fraction * -0.30000001) - 0.19999999) * speedfraction + 1.0
    if duckamount > 0 then
        st1 = st1 + ((duckamount * speedfactor)*(0.5 - st1))
    end
    des = anm.max_yaw * st1
    return pui.clamp(des, 0, 58)
end
antiaims.safe = false
antiaims.round_ended = false
antiaims.safe_handler = function(cmd)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local is_knife = pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Safe on knife") and rage.weapon == "CKnife"
    local is_zeus = pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Safe on zeus") and rage.weapon == "CWeaponTaser"
    local is_high = pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Safe on heigh") and rage.zdelta and rage.zdelta >= 80 and rage.distance <= 300
    local flags = entity.get_prop(lplayer, 'm_fFlags')
    local is_crouching = bit.band(flags, bit.lshift(1, 1)) ~= 0
    local on_ground = bit.band(flags, bit.lshift(1, 0)) ~= 0
    local is_jumping = cmd.in_jump == 1
    antiaims.safe = ((is_jumping and not on_ground and is_crouching and rage.zdelta and rage.zdelta >= -10) and (is_knife or is_zeus) or is_high) and antiaims.current_cond ~= "On-Use"
end
antiaims.sway, antiaims.sway_vec = {}, {}
antiaims.sway_handler = function(cmd, offset1, offset2, ticks)
    local lplayer = entity.get_local_player()
    local min = math.min(offset1, offset2)
    local max = math.max(offset1, offset2)
    local my_weapon = entity.get_player_weapon(lplayer)
    local simtime = entity.get_prop(lplayer, "m_flSimulationTime")
    local curtime = globals.curtime()
    local can_shoot = false
    local nading = false
    if my_weapon ~= nil then
        local weapon = csgo_weapons(my_weapon)
        if weapon.is_revolver then
            can_shoot = curtime > entity.get_prop(my_weapon, "m_flNextPrimaryAttack")
        elseif weapon.is_melee_weapon then
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack")) - globals.tickinterval()
        elseif weapon.is_grenade then
            can_shoot = false
        else
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack"))
        end
        if weapon.is_grenade and entity.get_prop(my_weapon, "m_fThrowTime") > 0 then nading = true end
    end
    if cmd.in_attack == 1 and can_shoot or nading then return end
    local yaw = entity.get_prop(lplayer, "m_angEyeAngles[1]")
    antiaims.sway[antiaims.current_cond] = antiaims.sway[antiaims.current_cond] or min
    antiaims.sway_vec[antiaims.current_cond] = antiaims.sway_vec[antiaims.current_cond] or 1
    if cmd.chokedcommands == 0 then
        if antiaims.sway[antiaims.current_cond] >= max then
            antiaims.sway_vec[antiaims.current_cond] = -1
        elseif antiaims.sway[antiaims.current_cond] <= min then
            antiaims.sway_vec[antiaims.current_cond] = 1
        end
        if pui.cmd_ticks() % ticks == 0 then
            antiaims.sway[antiaims.current_cond] = pui.clamp(antiaims.sway[antiaims.current_cond] + antiaims.sway_vec[antiaims.current_cond], min, max)
        end
        cmd.yaw = pui.normalize_yaw(yaw + (antiaims.maxdelta(lplayer) * antiaims.sway_vec[antiaims.current_cond]) + antiaims.sway[antiaims.current_cond]*5)
        cmd.allow_send_packet = false
    end
end
antiaims.nway = {}
antiaims.nway_handler = function(cmd, n, angle, delay)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    antiaims.nway[antiaims.current_cond] = antiaims.nway[antiaims.current_cond] or angle
    if cmd.chokedcommands == 0 then
        local mplyer = (angle/n)*2
        if pui.cmd_ticks() % delay > 0 then return end
        if antiaims.nway[antiaims.current_cond] == -angle then
            antiaims.nway[antiaims.current_cond] = angle + mplyer
        end
        antiaims.nway[antiaims.current_cond] = pui.clamp(antiaims.nway[antiaims.current_cond] - mplyer, -angle, angle)
    end
end
antiaims.xway = {}
antiaims.xway_offsets = {}
antiaims.xway_index = {}
antiaims.xway_ticks = {}
antiaims.xway_handler = function(cmd, n, angle, delay)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local cond = antiaims.current_cond

    n = tonumber(n) or 3
    angle = tonumber(angle) or 0
    delay = tonumber(delay) or 1

    n = math.max(2, math.floor(n))
    angle = math.abs(angle)
    delay = math.max(1, math.floor(delay))

    local offsets = antiaims.xway_offsets[cond]
    if not offsets or #offsets ~= n then
        offsets = {}
        if n <= 1 or angle == 0 then
            offsets[1] = angle
        else
            local spread = angle
            local step = (spread * 2) / (n - 1)
            for i = 1, n do
                offsets[i] = -spread + (i - 1) * step
            end
        end
        antiaims.xway_offsets[cond] = offsets
        antiaims.xway_index[cond] = 1
        antiaims.xway_ticks[cond] = 0
    end

    if cmd.chokedcommands == 0 then
        local t = (antiaims.xway_ticks[cond] or 0) + 1
        if t >= delay then
            t = 0
            local idx = (antiaims.xway_index[cond] or 1) + 1
            if idx > #offsets then idx = 1 end
            antiaims.xway_index[cond] = idx
        end
        antiaims.xway_ticks[cond] = t
        local idx = antiaims.xway_index[cond] or 1
        antiaims.xway[cond] = offsets[idx] or 0
    end
end
modifier = {}
antiaims.myaw = {}
antiaims.myaw_handler = function(cmd, minang, maxang, speed, delay)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    antiaims.myaw_ticks = antiaims.myaw_ticks or {}
    antiaims.myaw[antiaims.current_cond] = antiaims.myaw[antiaims.current_cond] or minang
    modifier[antiaims.current_cond] = modifier[antiaims.current_cond] or 1
    delay = math.max(1, math.floor(tonumber(delay) or 1))
    if cmd.chokedcommands == 0 then
        local cond = antiaims.current_cond
        local t = (antiaims.myaw_ticks[cond] or 0) + 1
        if t < delay then
            antiaims.myaw_ticks[cond] = t
            return
        end
        antiaims.myaw_ticks[cond] = 0
        if antiaims.myaw[antiaims.current_cond] <= minang then
            modifier[antiaims.current_cond] = 1
        end
        if antiaims.myaw[antiaims.current_cond] >= maxang then
            modifier[antiaims.current_cond] = -1
        end
        antiaims.myaw[antiaims.current_cond] = pui.clamp(antiaims.myaw[antiaims.current_cond] + (modifier[antiaims.current_cond] * speed), minang, maxang)
    end
end
local nexttickjit = {}
antiaims.swap = false
antiaims.jitter, antiaims.lr = {}, {}
antiaims.jit_handler = function(cmd, jitangl, delay, delayr, deltaticks)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    jitangl = tonumber(jitangl) or 0
    delay = math.max(1, math.floor(tonumber(delay) or 1))
    delayr = math.max(0, math.floor(tonumber(delayr) or 0))
    local dt = math.max(1, math.floor(tonumber(deltaticks) or 1))
    local ticks = client.random_int(pui.clamp(delay - delayr, 1, delay), pui.clamp(delay + delayr, delay, 14))
    if delayr > 0 then
        if not nexttickjit[1] or nexttickjit[2] <= globals.tickcount() then
            if ticks == nexttickjit[1] then
                ticks = pui.clamp(ticks - delayr, pui.clamp(delay - delayr, 1, 14), pui.clamp(delay + delayr, 1, 14))
            end
            nexttickjit[1] = ticks
            nexttickjit[2] = globals.tickcount() + dt
        else
            ticks = nexttickjit[1]
        end
    end
    antiaims.jitter[antiaims.current_cond] = antiaims.jitter[antiaims.current_cond] or jitangl
    if cmd.chokedcommands == 0 then
        local delay_factor = 1
        local cfg = antiaims.to_apply
        if cfg ~= nil then
            local bd = tonumber(cfg.body_delay_ticks) or 0
            if bd <= 0 then
                delay_factor = 1
            else
                delay_factor = math.max(1, math.floor(bd))
                if cfg.body_delay == "Randomize tick delay" and delay_factor > 1 then
                    delay_factor = client.random_int(1, delay_factor)
                end
            end
        end

        local jt = ticks * delay_factor
        antiaims.swap = pui.cmd_ticks()%(jt*2) >= jt
        antiaims.jitter[antiaims.current_cond] = (antiaims.swap and jitangl or -jitangl)
    end
end

local function micro_move(cmd, lplayer)
    local speed = math.sqrt(entity.get_prop(lplayer, "m_vecVelocity[0]")^2 + entity.get_prop(lplayer, "m_vecVelocity[1]")^2)
    local is_quickpeek = ui.get(skeetgui.ragegui.other.quick_peek_assist[1]) and ui.get(skeetgui.ragegui.other.quick_peek_assist[2])
    if cmd.chokedcommands == 0 or speed > 2 or is_quickpeek or cmd.in_attack == 1 then return end
    cmd.forwardmove = 0.1
    cmd.in_forward = 1
end
antiaims.lby_breaker = function(cmd)
    if not ui.get(tabs["Anti-aimbot angles"].lby_breaker[1]) or not ui.get(tabs["Anti-aimbot angles"].lby_breaker[2]) then return end
    if antiaims.safe or antiaims.is_antibacsktab then return end
    if ui.get(skeetgui.ragegui.aimbot.double_tap[1]) and ui.get(skeetgui.ragegui.aimbot.double_tap[2]) or ui.get(skeetgui.aagui.other.on_shot_antiaim[1]) and ui.get(skeetgui.aagui.other.on_shot_antiaim[2]) then return end
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local on_ladder = entity.get_prop(lplayer, "m_MoveType") == 9
    if on_ladder then return end
    local weapon = csgo_weapons(entity.get_player_weapon(lplayer))
    if weapon == nil or weapon.type == "grenade" then return end

    micro_move(cmd, lplayer)

    local body_side = ui.get(tabs["Anti-aimbot angles"].inverter[1]) and -ui.get(tabs["Anti-aimbot angles"].lby_breaker[3]) or ui.get(tabs["Anti-aimbot angles"].lby_breaker[3])

    if not antiaims.point_at_enemy_180_active then
        if cmd.chokedcommands == 0 and cmd.in_attack ~= 1 then
            cmd.yaw = cmd.yaw - body_side
            cmd.allow_send_packet = false
        end
    end

    local short = skeetgui.aagui.angles
    local is_manual = antiaims.is_manual ~= nil and antiaims.manuals[antiaims.is_manual].yaw ~= nil
    ui.set(short.yaw[1], "180")
    local manual_yaw = is_manual and antiaims.manuals[antiaims.is_manual] and antiaims.manuals[antiaims.is_manual].yaw or 0
    if type(manual_yaw) == "table" then manual_yaw = manual_yaw[1] or 0 end
    ui.set(short.yaw[2], manual_yaw)
    ui.set(short.yaw_jitter[1], "Off")
    ui.set(short.body_yaw[1], "Static")
end
antiaims.c_cent = {}
antiaims.custom_center = function(cmd, base, factor, ticks)
    base = tonumber(base) or 0
    local amp = math.max(0, math.floor(math.abs(base * (tonumber(factor) or 0)) + 0.5))
    local rndm = client.random_int(-amp, amp)
    antiaims.c_cent[antiaims.current_cond] = antiaims.c_cent[antiaims.current_cond] or 0
    local t = tonumber(ticks) or 1
    t = math.max(1, math.floor(t))
    if cmd.chokedcommands == 0 then
        local period = t * 2
        local swap = (pui.cmd_ticks() % period) >= t
        antiaims.c_cent[antiaims.current_cond] = (swap and -base or base) + rndm
    end
end
antiaims.c_off = {}
antiaims.custom_offset = function(cmd, base, factor, ticks)
    base = tonumber(base) or 0
    local amp = math.max(0, math.floor(math.abs(base * (tonumber(factor) or 0)) + 0.5))
    local rndm = client.random_int(-amp, amp)
    antiaims.c_off[antiaims.current_cond] = antiaims.c_off[antiaims.current_cond] or 0
    local t = tonumber(ticks) or 1
    t = math.max(1, math.floor(t))
    if cmd.chokedcommands == 0 then
        local period = t * 2
        local swap = (pui.cmd_ticks() % period) >= t
        antiaims.c_off[antiaims.current_cond] = swap and (base + rndm) or 0
    end
end
antiaims.center_rand = {}
antiaims.center_next = {}
antiaims.center_rand_handler = function(cmd, base, min_ticks, max_ticks)
    local cond = antiaims.current_cond
    local b = tonumber(base) or 0
    local mn = math.max(1, math.floor(tonumber(min_ticks) or 1))
    local mx = math.max(mn, math.floor(tonumber(max_ticks) or mn))
    if max_ticks < min_ticks then max_ticks = min_ticks end
    if antiaims.center_rand[cond] == nil then antiaims.center_rand[cond] = b end
    if antiaims.center_next[cond] == nil then
        local first = client.random_int(mn, mx)
        antiaims.center_next[cond] = globals.tickcount() + first
    end
    if cmd.chokedcommands == 0 and globals.tickcount() >= antiaims.center_next[cond] then
        antiaims.center_rand[cond] = (antiaims.center_rand[cond] >= 0) and -math.abs(b) or math.abs(b)
        local dur = client.random_int(mn, mx)
        if dur < 1 then dur = 1 end
        antiaims.center_next[cond] = globals.tickcount() + dur
    end
end
antiaims.v2swap = 0
antiaims.jitter2 = function(cmd, base, tick)
    local lplayer = entity.get_local_player()
    local my_weapon = entity.get_player_weapon(lplayer)
    local simtime = entity.get_prop(lplayer, "m_flSimulationTime")
    local curtime = globals.curtime()
    local yaw = entity.get_prop(lplayer, "m_angEyeAngles[1]")
    local can_shoot = false
    local nading = false
    if my_weapon ~= nil then
        local weapon = csgo_weapons(my_weapon)
        if weapon.is_revolver then
            can_shoot = curtime > entity.get_prop(my_weapon, "m_flNextPrimaryAttack")
        elseif weapon.is_melee_weapon then
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack")) - globals.tickinterval()
        elseif weapon.is_grenade then
            can_shoot = false
        else
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack"))
        end
        if weapon.is_grenade and entity.get_prop(my_weapon, "m_fThrowTime") > 0 then nading = true end
    end
    if cmd.in_attack == 1 and can_shoot or nading then return end
    if cmd.chokedcommands == 0 then
        local side = antiaims.maxdelta(lplayer) + base
        antiaims.v2swap = pui.cmd_ticks()%(tick*2) >= tick and -1 or 1
        cmd.yaw = pui.normalize_yaw(yaw + (side * antiaims.v2swap))
        cmd.allow_send_packet = false
    end
end
antiaims.static2 = function(cmd, base, side)
    if base == 0 then return end
    local curside = base < 0 and -1 or 1
    local lplayer = entity.get_local_player()
    local my_weapon = entity.get_player_weapon(lplayer)
    local simtime = entity.get_prop(lplayer, "m_flSimulationTime")
    local curtime = globals.curtime()
    local yaw = entity.get_prop(lplayer, "m_angEyeAngles[1]")
    local can_shoot = false
    local nading = false
    if my_weapon ~= nil then
        local weapon = csgo_weapons(my_weapon)
        if weapon.is_revolver then
            can_shoot = curtime > entity.get_prop(my_weapon, "m_flNextPrimaryAttack")
        elseif weapon.is_melee_weapon then
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack")) - globals.tickinterval()
        elseif weapon.is_grenade then
            can_shoot = false
        else
            can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack"))
        end
        if weapon.is_grenade and entity.get_prop(my_weapon, "m_fThrowTime") > 0 then nading = true end
    end
    if cmd.in_attack == 1 and can_shoot or nading then return end
    if cmd.chokedcommands == 0 then
        local angle = (antiaims.maxdelta(lplayer) * curside) + base
        cmd.yaw = pui.normalize_yaw(yaw + (angle * side))
        cmd.allow_send_packet = false
    end
end
antiaims.lr_handler = function(cmd, left, right, factor, body_type)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    local rndm = client.random_int(left * factor, right * factor)
    antiaims.lr[antiaims.current_cond] = antiaims.lr[antiaims.current_cond] or 0
    if cmd.chokedcommands == 0 then
        local sidelr;
        if body_type == "Custom Jitter" then
            sidelr = (antiaims.swap and left or right) + rndm
        elseif body_type == "Jitter v2" then
            sidelr = (antiaims.v2swap == -1 and left or right) + rndm
        else
            local sideflag = antiaims.current_side
            if body_type == nil or body_type == "Off" then
                sideflag = (pui.cmd_ticks(cmd) % 2 == 0)
            end
            sidelr = (sideflag == false and left or right) + rndm
        end
        antiaims.lr[antiaims.current_cond] = pui.clamp(sidelr, -180, 180)
    end
end
antiaims.delayed = {}
antiaims.delayed_handler = function(cmd, left, right, ticks)
    antiaims.delayed[antiaims.current_cond] = antiaims.delayed[antiaims.current_cond] or 0
    if cmd.chokedcommands == 0 then
        antiaims.delayed[antiaims.current_cond] = pui.cmd_ticks()%(ticks*2) >= ticks and left or right
    end
end
local function get_fov(vector1, vector2)
    local delta = vector2 - vector1
    delta:normalize()
    return math.sqrt(delta.x^2 + delta.y^2)
end
antiaims.closest_enemy_targeting = function(crosshair, force_distance)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then antiaims.target = nil; return end
    local target = {}
    local lox, loy, loz = entity.get_origin(lplayer)
    if not lox then antiaims.target = nil; return end
    local lorig = vector(lox, loy, loz)
    local sw, sh = client.screen_size()
    local center = vector(sw*0.5, sh*0.5)
    local leyes = vector(client.eye_position())
    for ent=1, globals.maxplayers() do
        if not entity.is_alive(ent) or not entity.is_enemy(ent) or entity.is_dormant(ent) then goto skip end
        local ex, ey, ez = entity.get_origin(ent)
        if not ex then goto skip end
        local orig = vector(ex, ey, ez)
        local sx, sy = renderer.world_to_screen(orig:unpack())
        local dist
        if crosshair then
            if sx and sy then
                local toscreen = vector(sx, sy)
                dist = center:dist(toscreen)
            else
                goto skip
            end
        elseif force_distance then
            dist = lorig:dist(orig)
        else
            local angles = vector(leyes:to(orig):angles())
            dist = get_fov(vector(client.camera_angles()), angles)
        end
        if dist ~= nil and (target.dist == nil or dist < target.dist) then
            target.dist = dist
            target.index = ent
        end
        ::skip::
    end
    if target.dist then
        antiaims.target = target.index
        return target
    end
    antiaims.target = nil
end
antiaims.crosshair = false
antiaims.force_distance = false
client.set_event_callback("paint", function()
    antiaims.closest_enemy_targeting(antiaims.crosshair, antiaims.force_distance)
end)
antiaims.fluctate_def = {}
mod = {}
antiaims.fluctate_handler = function(cmd, offset1, offset2, speed, oneway, ignored)
    local min = math.min(offset1, offset2)
    local max = math.max(offset1, offset2)
    antiaims.fluctate_def[antiaims.current_cond] = antiaims.fluctate_def[antiaims.current_cond] or min
    mod[antiaims.current_cond] = oneway and 1 or mod[antiaims.current_cond] or 1
    if cmd.chokedcommands == 0 or ignored then
        if antiaims.fluctate_def[antiaims.current_cond] >= max and oneway then
            antiaims.fluctate_def[antiaims.current_cond] = min
        elseif not oneway and antiaims.fluctate_def[antiaims.current_cond] >= max then
            mod[antiaims.current_cond] = -1
        elseif not oneway and antiaims.fluctate_def[antiaims.current_cond] <= min then
            mod[antiaims.current_cond] = 1
        end
        antiaims.fluctate_def[antiaims.current_cond] = pui.clamp(antiaims.fluctate_def[antiaims.current_cond] + speed * mod[antiaims.current_cond], min, max)
    end
end
