        if antiaims.spin2[antiaims.current_cond] >= max then antiaims.spin2[antiaims.current_cond] = min end
        antiaims.spin2[antiaims.current_cond] = pui.clamp(antiaims.spin2[antiaims.current_cond] + speed, min, max)
    end
