antiaims.adaptive_pitch = {}
antiaims.adaptive_pitch_handler = function(cmd, min_pitch, max_pitch, reaction)
    local lplayer = entity.get_local_player()
    if not lplayer or not entity.is_alive(lplayer) then return end

    local vx, vy = entity.get_prop(lplayer, "m_vecVelocity")
    vx = tonumber(vx) or 0
    vy = tonumber(vy) or 0
    local speed = math.sqrt(vx*vx + vy*vy)

    local norm_speed = speed / 260
    if norm_speed < 0 then norm_speed = 0 end
    if norm_speed > 1 then norm_speed = 1 end

    min_pitch = tonumber(min_pitch) or -20
    max_pitch = tonumber(max_pitch) or 30
    if min_pitch > max_pitch then
        local tmp = min_pitch
        min_pitch = max_pitch
        max_pitch = tmp
    end

    local base_target = min_pitch + (max_pitch - min_pitch) * norm_speed
    local key = antiaims.current_cond
    antiaims.adaptive_pitch[key] = antiaims.adaptive_pitch[key] or base_target
    local cur = antiaims.adaptive_pitch[key]

    local rate = (tonumber(reaction) or 50) * 0.01
    rate = pui.clamp(rate, 0.01, 1)
    local span = math.abs(max_pitch - min_pitch)
    local t = (pui.cmd_ticks and pui.cmd_ticks(cmd)) or globals.tickcount()
    local phase = (t % 12 < 6) and 1 or -1

    local close_factor = 0
    local lx, ly, lz = entity.get_prop(lplayer, "m_vecOrigin")
    if lx and ly and lz then
        local enemies = entity.get_players and entity.get_players(true) or nil
        if enemies then
            local best
            for i = 1, #enemies do
                local e = enemies[i]
                if e ~= nil and entity.is_alive(e) and entity.is_enemy(e) then
                    local ex, ey, ez = entity.get_prop(e, "m_vecOrigin")
                    if ex and ey and ez then
                        local dx = ex - lx
                        local dy = ey - ly
                        local dz = ez - lz
                        local d2 = dx*dx + dy*dy + dz*dz
                        if not best or d2 < best then
                            best = d2
                        end
                    end
                end
            end
            if best then
                local dist = math.sqrt(best)
                if dist <= 350 then
                    close_factor = 1
                elseif dist < 900 then
                    close_factor = (900 - dist) / 550
                end
                if close_factor < 0 then close_factor = 0 end
                if close_factor > 1 then close_factor = 1 end
            end
        end
    end

    local base_jitter = span * 0.35 + 6
    local speed_factor = 0.3 + norm_speed * 0.7
    local jitter_amp = base_jitter * (speed_factor + close_factor)
    local jitter = 0
    if jitter_amp > 0 then
        local rnd = client.random_int(-jitter_amp * 0.4, jitter_amp * 0.4)
        jitter = phase * jitter_amp * 0.3 + rnd * 0.7
    end

    if (t % 73) == 0 then
        jitter = jitter + client.random_int(-15, 15)
    elseif (t % 127) == 0 then
        jitter = jitter + client.random_int(-10, 10)
    end
    antiaims.adaptive_pitch_flick = antiaims.adaptive_pitch_flick or {}
    local f = antiaims.adaptive_pitch_flick[key] or {next_tick = 0, end_tick = 0, offset = 0}
    local now = globals.tickcount()
    if now >= (f.next_tick or 0) then
        local flick_span = span + 35 + 30 * close_factor
        f.offset = client.random_int(-flick_span, flick_span)
        f.end_tick = now + client.random_int(1, 2)
        local min_cd = 32
        local max_cd = 75
        if close_factor > 0 then
            local scale = 1 - 0.7 * close_factor
            min_cd = math.floor(min_cd * scale)
            max_cd = math.floor(max_cd * scale)
            if min_cd < 6 then min_cd = 6 end
        end
        f.next_tick = now + client.random_int(min_cd, max_cd)
    end
    if now > (f.end_tick or 0) then
        f.offset = 0
    end

    local target = base_target + jitter + (f.offset or 0)

    if cmd.chokedcommands == 0 then
        if (f.offset or 0) ~= 0 then
            cur = target
        else
            cur = cur + (target - cur) * rate
        end
        if cur < min_pitch then cur = min_pitch end
        if cur > max_pitch then cur = max_pitch end
        antiaims.adaptive_pitch[key] = cur
        antiaims.adaptive_pitch_flick[key] = f
    end
end
antiaims.adaptive_yaw = {}
antiaims.adaptive_yaw_handler = function(cmd, left_yaw, right_yaw, center_bias, reaction)
    local lplayer = entity.get_local_player()
    if not lplayer or not entity.is_alive(lplayer) then return end

    local vx, vy = entity.get_prop(lplayer, "m_vecVelocity")
    vx = tonumber(vx) or 0
    vy = tonumber(vy) or 0
    local speed = math.sqrt(vx*vx + vy*vy)

    local norm_speed = speed / 260
    if norm_speed < 0 then norm_speed = 0 end
    if norm_speed > 1 then norm_speed = 1 end

    left_yaw = tonumber(left_yaw) or -50
    right_yaw = tonumber(right_yaw) or 50

    local cb = (tonumber(center_bias) or 55) * 0.01
    cb = pui.clamp(cb, 0, 1)

    local rate = (tonumber(reaction) or 55) * 0.01
    rate = pui.clamp(rate, 0.01, 1)

    local side_offset = antiaims.current_side and right_yaw or left_yaw
    local move_factor = norm_speed
    local weighted_side = side_offset * (1 - cb * (1 - move_factor))

    local span = math.max(math.abs(left_yaw), math.abs(right_yaw))
    local t = (pui.cmd_ticks and pui.cmd_ticks(cmd)) or globals.tickcount()
    local phase = (t % 10 < 5) and 1 or -1

    local close_factor = 0
    local lx, ly, lz = entity.get_prop(lplayer, "m_vecOrigin")
    if lx and ly and lz then
        local enemies = entity.get_players and entity.get_players(true) or nil
        if enemies then
            local best
            for i = 1, #enemies do
                local e = enemies[i]
                if e ~= nil and entity.is_alive(e) and entity.is_enemy(e) then
                    local ex, ey, ez = entity.get_prop(e, "m_vecOrigin")
                    if ex and ey and ez then
                        local dx = ex - lx
                        local dy = ey - ly
                        local dz = ez - lz
                        local d2 = dx*dx + dy*dy + dz*dz
                        if not best or d2 < best then
                            best = d2
                        end
                    end
                end
            end
            if best then
                local dist = math.sqrt(best)
                if dist <= 350 then
                    close_factor = 1
                elseif dist < 900 then
                    close_factor = (900 - dist) / 550
                end
                if close_factor < 0 then close_factor = 0 end
                if close_factor > 1 then close_factor = 1 end
            end
        end
    end

    local base_jitter = span * 0.45 + 40
    local speed_factor = 0.4 + move_factor * 0.6
    local jitter_base = base_jitter * (1 - cb * 0.6) * (1 + 0.8 * close_factor)
    local jitter = jitter_base * speed_factor * phase

    local extra = 0
    if (t % 67) == 0 then
        extra = client.random_int(-45, 45)
    elseif (t % 113) == 0 then
        extra = client.random_int(-25, 25)
    end

    antiaims.adaptive_yaw_flick = antiaims.adaptive_yaw_flick or {}
    local key = antiaims.current_cond
    local fy = antiaims.adaptive_yaw_flick[key] or {next_tick = 0, end_tick = 0, offset = 0}
    local now = globals.tickcount()
    if now >= (fy.next_tick or 0) then
        local flick_span = span + 80 + 40 * close_factor
        fy.offset = client.random_int(-flick_span, flick_span)
        fy.end_tick = now + client.random_int(1, 2)
        local min_cd = 28
        local max_cd = 60
        if close_factor > 0 then
            local scale = 1 - 0.6 * close_factor
            min_cd = math.floor(min_cd * scale)
            max_cd = math.floor(max_cd * scale)
            if min_cd < 8 then min_cd = 8 end
        end
        fy.next_tick = now + client.random_int(min_cd, max_cd)
    end
    if now > (fy.end_tick or 0) then
        fy.offset = 0
    end

    local target = weighted_side + jitter + extra + (fy.offset or 0)

    antiaims.adaptive_yaw[key] = antiaims.adaptive_yaw[key] or target
    local cur = antiaims.adaptive_yaw[key]

    if cmd.chokedcommands == 0 then
        if (fy.offset or 0) ~= 0 then
            cur = target
        else
            cur = cur + (target - cur) * rate
        end
        antiaims.adaptive_yaw[key] = cur
        antiaims.adaptive_yaw_flick[key] = fy
    end
end
antiaims.fluctutatefl = nil;
antiaims.radnomlags = function(fltype, max)
    do
        local enabled_ref = skeetgui and skeetgui.aagui and skeetgui.aagui.fakelag and skeetgui.aagui.fakelag.enabled and skeetgui.aagui.fakelag.enabled[1] or nil
        if enabled_ref ~= nil then
            local disable_os = false
            if pui.multi_parse and tabs and tabs["Anti-aimbot angles"] and tabs["Anti-aimbot angles"].addons then
                disable_os = pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Disable fakelags on os")
                    and ui.get(skeetgui.aagui.other.on_shot_antiaim[1])
                    and ui.get(skeetgui.aagui.other.on_shot_antiaim[2])
            end
            if not disable_os then
                local ok, en = pcall(ui.get, enabled_ref)
                if (not ok) or en == false then
                    pcall(ui.set, enabled_ref, true)
                end
            end
        end
    end

    if type(fltype) ~= "string" or fltype == "" then
        fltype = "Maximum"
    end
    max = tonumber(max) or 1
    if max < 1 then max = 1 end

    local dt_active = false
    if skeetgui and skeetgui.ragegui and skeetgui.ragegui.aimbot and skeetgui.ragegui.aimbot.double_tap then
        local ok1, en = pcall(ui.get, skeetgui.ragegui.aimbot.double_tap[1])
        local ok2, hk = pcall(ui.get, skeetgui.ragegui.aimbot.double_tap[2])
        dt_active = (ok1 and en == true) and (ok2 and hk == true)
    end
    local limit_ref = (dt_active and skeetgui and skeetgui.ragegui and skeetgui.ragegui.aimbot and skeetgui.ragegui.aimbot.double_tap_lag_limit) or (skeetgui and skeetgui.aagui and skeetgui.aagui.fakelag and skeetgui.aagui.fakelag.limit)
    local function set_limit(v)
        local num = tonumber(v) or 1
        if dt_active then
            num = math.floor(num + 0.5)
        end
        if limit_ref ~= nil then
            pcall(ui.set, limit_ref, num)
        end
    end

    local tb = nil
    if tabs and tabs["Anti-aimbot angles"] and antiaims.current_cond and tabs["Anti-aimbot angles"][antiaims.current_cond]
        and tabs["Anti-aimbot angles"][antiaims.current_cond].fakelagc then
        tb = tabs["Anti-aimbot angles"][antiaims.current_cond].fakelagc[fltype]
    end

    if tb == nil then
        pcall(ui.set, skeetgui.aagui.fakelag.amount, "Maximum")
        set_limit(max)
        return
    end
    if ui.get(skeetgui.ragegui.other.duck_peek_assist) then
        set_limit(max)
        return
    end
    if fltype == "Dynamic" or fltype == "Fluctuate" or fltype == "Maximum" then
        ui.set(skeetgui.aagui.fakelag.amount, fltype)
        ui.set(skeetgui.aagui.fakelag.variance, ui.get(tb[1]))
        set_limit(max)
    elseif fltype == "Random" then
        local factor = ui.get(tb[1])*0.1
        ui.set(skeetgui.aagui.fakelag.amount, "Maximum")
        if factor == 0 then set_limit(max) return end
        local min = math.max(max - (max*factor), 1)
        set_limit(client.random_int(math.floor(min + 0.5), math.floor(max + 0.5)))
    elseif fltype == "Jitter" then
        local offset = ui.get(tb[1])
        ui.set(skeetgui.aagui.fakelag.amount, "Maximum")
        set_limit(globals.tickcount()%14 >= 7 and offset or max)
    elseif fltype == "Fluctuate v2" then
        local variance = ui.get(tb[1])*0.01
        local min = ui.get(tb[2])
        antiaims.fluctutatefl = antiaims.fluctutatefl or min
        if math.floor(antiaims.fluctutatefl) ~= ui.get(skeetgui.aagui.fakelag.limit) then antiaims.fluctutatefl = ui.get(skeetgui.aagui.fakelag.limit) end
        if antiaims.fluctutatefl >= max then antiaims.fluctutatefl = min end
        if globals.tickcount()%5 == 0 then antiaims.fluctutatefl = math.min(antiaims.fluctutatefl + 2*variance, max) end
        ui.set(skeetgui.aagui.fakelag.amount, "Maximum")
        set_limit(antiaims.fluctutatefl)
    end
end

