local function antibrute_log_screen(parts, col)
    if not logs or not logs.screen_info then return end
    if not tabs or not tabs["Misc"] or not tabs["Misc"].logs then return end
    if not ui.get(tabs["Misc"].logs[1]) or not pui.multi_parse(tabs["Misc"].logs[2], "Screen") then return end
    local info = {
        alpha = -1,
        time = globals.realtime() + 3,
        col = col or (colors and colors.dark_gray) or {160, 160, 160, 255},
        string = parts
    }
    table.insert(logs.screen_info, 1, info)
end

local function antibrute_log_console(parts)
    if not logs or not logs.printl then return end
    if not tabs or not tabs["Misc"] or not tabs["Misc"].logs then return end
    if not ui.get(tabs["Misc"].logs[1]) or not pui.multi_parse(tabs["Misc"].logs[2], "Console") then return end
    local ui_col = (pui.menu_col and pui.menu_col()) or {255, 255, 255}
    logs.printl(
        {ui_col, "osmanhook > "},
        {(colors and colors.gray) or {128, 128, 128}, tostring(parts[1] or "")},
        {ui_col, tostring(parts[2] or "")}
    )
end

function antiaims.reset_anti_brute_states()
    antiaims.anti_brute_states = {}
    antiaims.anti_brute_spin = {}
end

function antiaims.anti_brute_trigger(source)
    antiaims.anti_brute_last_t = antiaims.anti_brute_last_t or 0
    local now = globals.realtime()
    if now - antiaims.anti_brute_last_t < 0.20 then return end
    antiaims.anti_brute_last_t = now

    if antiaims and antiaims.anti_brute_on_miss then
        antiaims.anti_brute_on_miss(nil)
    end
end

function antiaims.anti_brute_on_miss(e)
    if not tabs or not tabs["Anti-aimbot angles"] then return end
    local cond = antiaims.current_cond
    if cond == nil or tabs["Anti-aimbot angles"][cond] == nil then return end

    local condtab = tabs["Anti-aimbot angles"][cond]
    if condtab.anti_brute == nil then return end

    local ab = condtab.anti_brute
    if not ui.get(ab.enabled) then
        local shared = tabs["Anti-aimbot angles"]["Shared"]
        if cond ~= "Shared" and shared and shared.anti_brute and ui.get(shared.anti_brute.enabled) then
            cond = "Shared"
            condtab = shared
            ab = shared.anti_brute
        else
            return
        end
    end

    local st = antiaims.anti_brute_states[cond] or {active = false, phase = 0, until_t = 0}
    if not st.active then
        st.active = true
        st.phase = 1
    else
        st.phase = (tonumber(st.phase) or 0) % 5 + 1
    end

    local ab_mode = ui.get(ab.mode)
    if ab_mode == "Timer" then
        local sec = tonumber(ui.get(ab.time)) or 3
        st.until_t = globals.curtime() + math.max(0, sec)
    else
        st.until_t = math.huge
    end

    antiaims.anti_brute_states[cond] = st

    do
        local mc = (pui.menu_col and pui.menu_col()) or {157, 156, 218}
        local col = {tonumber(mc[1]) or 157, tonumber(mc[2]) or 156, tonumber(mc[3]) or 218, 255}
        if antibrute_log_screen then
            antibrute_log_screen({"Anti-brute ", "phase " .. tostring(st.phase)}, col)
        end
    end
end

function antiaims.apply_anti_brute(cmd, yaw, yaw_amount)
    if not tabs or not tabs["Anti-aimbot angles"] then return yaw, yaw_amount, false end
    local cond = antiaims.current_cond
    if cond == nil or tabs["Anti-aimbot angles"][cond] == nil then return yaw, yaw_amount, false end
    local condtab = tabs["Anti-aimbot angles"][cond]
    if condtab.anti_brute == nil then return yaw, yaw_amount, false end

    local ab = condtab.anti_brute
    if not ui.get(ab.enabled) then
        local shared = tabs["Anti-aimbot angles"]["Shared"]
        if cond ~= "Shared" and shared and shared.anti_brute and ui.get(shared.anti_brute.enabled) then
            cond = "Shared"
            condtab = shared
            ab = shared.anti_brute
        else
            return yaw, yaw_amount, false
        end
    end

    local st = antiaims.anti_brute_states[cond]
    if st == nil or not st.active then return yaw, yaw_amount, false end

    if ui.get(ab.mode) == "Timer" and globals.curtime() > (tonumber(st.until_t) or 0) then
        st.active = false
        antiaims.anti_brute_states[cond] = st
        return yaw, yaw_amount, false
    end

    local phase_idx = tonumber(st.phase) or 1
    if phase_idx < 1 or phase_idx > 5 then phase_idx = 1 end
    local ph = ab.phase and ab.phase[phase_idx] or nil
    if ph == nil then return yaw, yaw_amount, false end

    local left = tonumber(ui.get(ph.yaw_left)) or 0
    local right = tonumber(ui.get(ph.yaw_right)) or 0
    local ymode = ui.get(ph.yaw)
    local use_side = antiaims.current_side
    if use_side == nil then
        use_side = globals.tickcount() % 2 == 0
    end

    local delta
    if ymode == "Left & Right" then
        delta = use_side and left or right
    else
        delta = (globals.tickcount() % 2 == 0) and left or right
    end

    local mod = ui.get(ph.yaw_modifier)
    local lim = tonumber(ui.get(ph.yaw_modifier_limit)) or 0
    if mod == "Offset" then
        delta = delta + lim
    elseif mod == "Center" then
        delta = delta + ((globals.tickcount() % 2 == 0) and lim or -lim)
    elseif mod == "Random" then
        local a = math.abs(lim)
        delta = delta + client.random_int(-a, a)
    elseif mod == "Spin" then
        antiaims.anti_brute_spin[cond] = antiaims.anti_brute_spin[cond] or 0
        local step = lim
        if step == 0 then step = 5 end
        antiaims.anti_brute_spin[cond] = pui.normalize_yaw((tonumber(antiaims.anti_brute_spin[cond]) or 0) + step)
        delta = delta + antiaims.anti_brute_spin[cond]
    end

    local out_yaw = yaw
    local base
    if out_yaw == nil or out_yaw == "Off" or out_yaw == "Spin" then
        out_yaw = "180"
        base = 0
    else
        base = type(yaw_amount) == "table" and (tonumber(yaw_amount[1] or 0) or 0) or (tonumber(yaw_amount or 0) or 0)
    end

    local out_amount = pui.normalize_yaw(base + delta)
    return out_yaw, out_amount, true
end

antiaims.handler = function(cmd)
    local lplayer = entity.get_local_player()
    if lplayer == nil or not entity.is_alive(lplayer) then return end
    if antiaims.freeze_disable and antiaims.freeze_disable.active then
        return
    end
    if antiaims.current_cond == "Disabled" then
        if antiaims.primry_cond == nil then
            antiaims.primry_cond = "Shared"
        end
        antiaims.current_cond = antiaims.primry_cond
    end
    if antiaims.current_cond == "On-Use" then cmd.in_use = 0 end
    antiaims.to_apply = antiaims.calculate(tabs["Anti-aimbot angles"][antiaims.current_cond])

    do
        antiaims._ui_sig = antiaims._ui_sig or {}
        local cond = antiaims.current_cond
        local t = antiaims.to_apply or {}
        local function v(x)
            if type(x) == "table" then
                return json.stringify(x)
            end
            return tostring(x)
        end
        local sig = table.concat({
            v(t.pitch), v(t.pitchc), v(t.yaw_base), v(t.yaw), v(t.yawc), v(t.yaw_jitter), v(t.yaw_jitterc),
            v(t.body_yaw), v(t.body_yawc), v(t.body_yaw_freestand), v(t.body_delay), v(t.body_delay_ticks),
            v(t.fakelag), v(t.fakelaglimit)
        }, "|")

        if antiaims._ui_sig[cond] ~= sig then
            antiaims._ui_sig[cond] = sig
            if antiaims.lr_center_cache then antiaims.lr_center_cache[cond] = nil end
            if antiaims.center_rand then antiaims.center_rand[cond] = nil end
            if antiaims.center_next then antiaims.center_next[cond] = nil end
            if antiaims.nway then antiaims.nway[cond] = nil end
            if antiaims.xway then antiaims.xway[cond] = nil end
            if antiaims.xway_index then antiaims.xway_index[cond] = nil end
            if antiaims.xway_ticks then antiaims.xway_ticks[cond] = nil end
            if antiaims.myaw then antiaims.myaw[cond] = nil end
            if antiaims.myaw_ticks then antiaims.myaw_ticks[cond] = 0 end
            if antiaims.c_cent then antiaims.c_cent[cond] = nil end
            if antiaims.c_off then antiaims.c_off[cond] = nil end
            if antiaims.body_delay_cached then antiaims.body_delay_cached[cond] = nil end
            if antiaims.body_delay_next then antiaims.body_delay_next[cond] = nil end
            if antiaims.body_tickcount then antiaims.body_tickcount[cond] = nil end
    end
    end

    local is_manual = antiaims.is_manual ~= nil and antiaims.manuals[antiaims.is_manual].yaw ~= nil
    local manual_force_only = is_manual and antiaims.current_cond ~= "Manuals"
    antiaims.defensive_cycle_state = antiaims.defensive_cycle_state or {phase = 1, tick_count = 0}
    local cycle = antiaims.defensive_cycle_state
    local base_tick = antiaims.to_apply.defensive.tick or 1

    if antiaims.to_apply.defensive.enable then
        cycle.tick_count = cycle.tick_count + 1

        if cycle.phase == 1 then
            if cycle.tick_count > 20 then
                cycle.phase = 2
                cycle.tick_count = 0
            end
        elseif cycle.phase == 2 then
            if cycle.tick_count > 30 then
                cycle.phase = 3
                cycle.tick_count = 0
            end
        elseif cycle.phase == 3 then
            if cycle.tick_count > 5 then
                cycle.phase = 1
                cycle.tick_count = 0
            end
        end

        local effective_tick = base_tick
        if cycle.phase == 2 then
            effective_tick = base_tick * 3
        end
    else
        cycle.phase = 1
        cycle.tick_count = 0
    end

    local effective_defensive_tick = antiaims.to_apply.defensive.tick or 1
    if antiaims.to_apply.defensive.enable and antiaims.defensive_cycle_state then
        local cycle = antiaims.defensive_cycle_state
        if cycle.phase == 2 then
            effective_defensive_tick = (antiaims.to_apply.defensive.tick or 1) * 3
        end
    end
    
    local condtab = tabs["Anti-aimbot angles"][antiaims.current_cond]
    if condtab and condtab.force_def then
        local ok, val = pcall(ui.get, condtab.force_def)
        if ok and val and (val == "On-Hittable" or val == "Always") then
            effective_defensive_tick = 1
        end
    end

    local defensive = antiaims.current_cond ~= "Fakelags" and antiaims.current_cond ~= "Duckpeek" and (antiaims.to_apply.defensive.enable and cmd.chokedcommands < 13 and ticks.tickbase_diff ~= nil and ticks.tickbase_diff ~= 1 and ticks.tickbase_diff < -effective_defensive_tick)
    antiaims.point_at_enemy_180_active = false
    do
        local condtab = tabs["Anti-aimbot angles"][antiaims.current_cond]
        local def_ui = condtab and condtab.defensive
        if def_ui and def_ui.point_180 and def_ui.yaw then
            antiaims.point_at_enemy_180_active = defensive and not antiaims.safe and ui.get(def_ui.point_180) and ui.get(def_ui.yaw) == "180"
            if antiaims.point_at_enemy_180_active or antiaims.is_antibacsktab then
                antiaims.crosshair = false
                antiaims.force_distance = true
            end
        end
    end
    local pitch = antiaims.to_apply.pitch
    local custom_pitch = (pitch == "Custom" and antiaims.to_apply.pitchc[1]) or antiaims.to_apply.pitchc[pitch]
    local yaw_base = antiaims.to_apply.yaw_base
    local yaw = antiaims.to_apply.yaw
    local yaw_amount = antiaims.to_apply.yawc[yaw]
    local function get_yaw_value(yaw_val, index)
        if type(yaw_val) == "table" then
            return yaw_val[index] or yaw_val[1] or 0
        else
            return yaw_val or 0
        end
    end
    local yaw_jitter = antiaims.to_apply.yaw_jitter
    local yaw_jitter_amount = antiaims.to_apply.yaw_jitterc[yaw_jitter]
    local body_yaw = antiaims.to_apply.body_yaw
    local body_yaw_amount = antiaims.to_apply.body_yawc[body_yaw] or 0
    local fs_body_yaw = antiaims.to_apply.body_yaw_freestand

    local fs_hotkey_on_yaw = false
    do
        local ok_fs, fs_val = pcall(ui.get, tabs["Anti-aimbot angles"].freestand[1])
        fs_hotkey_on_yaw = ok_fs and (fs_val == true)
    end

    local fs_enabled_yaw = fs_hotkey_on_yaw
    if is_manual then
        fs_enabled_yaw = false
    end
    local function get_global_delay_ticks(mode, ticks)
        local t = tonumber(ticks) or 0
        if t <= 0 then
            t = 1
        else
            t = math.max(1, math.min(17, math.floor(t)))
        end
        if mode == "Randomize tick delay" and t > 1 then
            t = client.random_int(1, t)
        end
        return t
    end
    local jitter_delay = get_global_delay_ticks(antiaims.to_apply.body_delay, antiaims.to_apply.body_delay_ticks)
    local fl_limit = antiaims.to_apply.fakelaglimit
    local fl_type = antiaims.to_apply.fakelag
    antiaims.is_antibacsktab = pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Anti-Backstab") and rage.target_weapon ~= nil and string.match(rage.target_weapon, "Knife") and rage.distance <= 340 and math.abs(rage.zdelta) < 80
    antiaims.radnomlags(fl_type, fl_limit)

		if not (antiaims.freeze_disable and antiaims.freeze_disable.active) then
			ui.set(skeetgui.aagui.angles.enabled, true)
		end
        if pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Disable fakelags on os") and ui.get(skeetgui.aagui.other.on_shot_antiaim[1]) and ui.get(skeetgui.aagui.other.on_shot_antiaim[2]) then
            ui.set(skeetgui.aagui.fakelag.enabled[1], false)
            antiaims.better_os = true
        elseif antiaims.better_os and not ui.get(skeetgui.aagui.fakelag.enabled[1]) then
            ui.set(skeetgui.aagui.fakelag.enabled[1], true)
            antiaims.better_os = false
        end
        local short = skeetgui.aagui.angles

        local manual_yaw = 0
        if is_manual then
            local my = antiaims.manuals[antiaims.is_manual] and antiaims.manuals[antiaims.is_manual].yaw or 0
            if type(my) == "table" then my = my[1] or 0 end
            manual_yaw = tonumber(my) or 0
        end

        if yaw == "Off" or yaw_amount == nil then
            yaw_jitter = "Off"
        end
        if not antiaims.safe and not antiaims.is_antibacsktab then
            if is_manual then
                if pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Local view on manuals") then
                    yaw_base = "Local view"
                end
                if pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Static on manuals") then
                    yaw = "180"
                    yaw_jitter = "Off"
                    body_yaw = "Static"
                    body_yaw_amount = 60
                end
                if (not manual_force_only) and pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Flick manual on peek") and cmd.chokedcommands < 2 then
                    local target = client.current_threat()
                    if target == nil or vector(entity.get_prop(lplayer, 'm_vecVelocity')):lengthsqr() < 1 then goto skip end
                    local flag = entity.get_esp_data(target).flags or 0
                    local is_hittble = bit.band(flag, bit.lshift(1, 11)) ~= 0
                    if is_hittble and antiaims.manuals_tickstoflick == nil then
                        antiaims.manuals_tickstoflick = globals.tickcount() + 7
                    end
                    if antiaims.manuals_tickstoflick ~= nil and antiaims.manuals_tickstoflick > globals.tickcount() then
                        manual_yaw = -manual_yaw
                        pitch = "Custom"
                        custom_pitch = 0
                    elseif antiaims.manuals_tickstoflick ~= nil and antiaims.manuals_tickstoflick <= globals.tickcount() and not rage.hittable then
                            antiaims.manuals_tickstoflick = nil
                        end
                        ::skip::
                    end
                end
                local lr_enabled = (antiaims.to_apply and antiaims.to_apply.yaw_lr) or false
                local use_lr = yaw == "L&R" or (lr_enabled and yaw ~= "Off")
                if use_lr then
                    local lr_amount = (antiaims.to_apply and antiaims.to_apply.yawc and antiaims.to_apply.yawc["L&R"]) or yaw_amount
                    antiaims.lr_handler(cmd, get_yaw_value(lr_amount, 1), get_yaw_value(lr_amount, 2), get_yaw_value(lr_amount, 3) * 0.01, body_yaw)
                    yaw = "180"
                    yaw_amount = pui.normalize_yaw(antiaims.lr[antiaims.current_cond] + (is_manual and manual_yaw or 0))
                elseif yaw == "Delayed" then
                    local delay_ticks = get_yaw_value(yaw_amount, 3)
                    if jitter_delay and jitter_delay > 1 then
                        delay_ticks = math.max(delay_ticks, jitter_delay)
                    end
                    antiaims.delayed_handler(cmd, get_yaw_value(yaw_amount, 1), get_yaw_value(yaw_amount, 2), delay_ticks)
                    yaw = "180"
                    yaw_amount = pui.normalize_yaw(antiaims.delayed[antiaims.current_cond] + (is_manual and manual_yaw or 0))
                end
                if yaw_jitter == "Min/Max Center" then
                    if type(yaw_jitter_amount) == "table" then
                        antiaims.myaw_handler(cmd, yaw_jitter_amount[1], yaw_jitter_amount[2], yaw_jitter_amount[3]*0.01, (tonumber(yaw_jitter_amount[4]) or 1) * jitter_delay)
                        yaw_jitter = "Center"
                        yaw_jitter_amount = antiaims.myaw[antiaims.current_cond]
                    else
                        yaw_jitter = "Off"
                        yaw_jitter_amount = 0
                    end
                elseif yaw_jitter == "Nway" then
                    if type(yaw_jitter_amount) == "table" then
                        antiaims.nway_handler(cmd, yaw_jitter_amount[1], yaw_jitter_amount[2], (tonumber(yaw_jitter_amount[3]) or 1) * jitter_delay)
                        yaw_jitter = "Off"
                        yaw_amount = pui.normalize_yaw(get_yaw_value(yaw_amount, 1)+antiaims.nway[antiaims.current_cond])
                    else
                        yaw_jitter = "Off"
                        yaw_jitter_amount = 0
                    end
                elseif yaw_jitter == "X-way" then
                    local nparams = (type(yaw_jitter_amount) == "table" and yaw_jitter_amount) or (antiaims.to_apply and antiaims.to_apply.yaw_jitterc and antiaims.to_apply.yaw_jitterc["X-way"]) or {}
                    local n = (type(nparams) == "table" and (nparams[1] or 3)) or 3
                    local ang = (type(nparams) == "table" and (nparams[2] or 0)) or 0
                    local del = (type(nparams) == "table" and (nparams[3] or 1)) or 1
                    antiaims.xway_handler(cmd, n, ang, (tonumber(del) or 1) * jitter_delay)
                    yaw_jitter = "Off"
                    yaw_amount = pui.normalize_yaw(get_yaw_value(yaw_amount, 1) + (antiaims.xway[antiaims.current_cond] or 0))
                elseif yaw_jitter == "L&R Center" then
                    antiaims.lr_center_cache = antiaims.lr_center_cache or {}
                    local cond = antiaims.current_cond
                    local cached = antiaims.lr_center_cache[cond]
                    if cmd.chokedcommands == 0 then
                        local cmdtick = pui.cmd_ticks(cmd)
                        if cached == nil or (cmdtick % jitter_delay) == 0 then
                            if type(yaw_jitter_amount) == "table" then
                                local factor = yaw_jitter_amount[3] * 0.01
                                local rndm = client.random_int(yaw_jitter_amount[1] * factor, yaw_jitter_amount[2] * factor)
                                cached = (antiaims.current_side and yaw_jitter_amount[1] or yaw_jitter_amount[2]) + rndm
                                antiaims.lr_center_cache[cond] = cached
                            end
                        end
                    end
                    yaw_jitter = "Center"
                    yaw_jitter_amount = cached or 0
                elseif yaw_jitter == "Skitter" then
                    local per = 3 * jitter_delay
                    local mod = globals.tickcount() % per
                    if mod == 0 then
                    yaw_amount = get_yaw_value(yaw_amount, 1) + (type(yaw_jitter_amount)=="table" and yaw_jitter_amount[1] or yaw_jitter_amount)*0.5
                elseif mod == (2 * jitter_delay) then
                    yaw_amount = get_yaw_value(yaw_amount, 1) - (type(yaw_jitter_amount)=="table" and yaw_jitter_amount[1] or yaw_jitter_amount)*0.5
                end
                yaw_jitter = "Off"
            elseif yaw_jitter == "Center" then
                local base = (type(yaw_jitter_amount) == "table") and get_yaw_value(yaw_jitter_amount, 1) or yaw_jitter_amount
                local min_t = (type(yaw_jitter_amount) == "table") and (tonumber(yaw_jitter_amount[2]) or 3) or 3
                local max_t = (type(yaw_jitter_amount) == "table") and (tonumber(yaw_jitter_amount[3]) or 10) or 10
                if max_t < min_t then max_t = min_t end
                antiaims.center_rand_handler(cmd, tonumber(base) or 0, min_t * jitter_delay, max_t * jitter_delay)
                yaw_jitter = "Off"
                yaw_amount = pui.normalize_yaw(get_yaw_value(yaw_amount, 1) + (antiaims.center_rand[antiaims.current_cond] or 0))
                yaw_jitter_amount = 0
            elseif yaw_jitter == "Custom Center" then
                if type(yaw_jitter_amount) == "table" then
                    antiaims.custom_center(cmd, yaw_jitter_amount[1]*0.5, yaw_jitter_amount[2]*0.01, (tonumber(yaw_jitter_amount[3]) or 1) * jitter_delay)
                    yaw_jitter = "Off"
                    yaw_amount = pui.normalize_yaw(get_yaw_value(yaw_amount, 1) + antiaims.c_cent[antiaims.current_cond])
                    yaw_jitter_amount = 0
                else
                    yaw_jitter = "Off"
                    yaw_jitter_amount = 0
                end
            elseif yaw_jitter == "Custom Offset" then
                if type(yaw_jitter_amount) == "table" then
                    antiaims.custom_offset(cmd, yaw_jitter_amount[1], yaw_jitter_amount[2]*0.01, (tonumber(yaw_jitter_amount[3]) or 1) * jitter_delay)
                    yaw_jitter = "Off"
                    yaw_amount = pui.normalize_yaw(get_yaw_value(yaw_amount, 1) + antiaims.c_off[antiaims.current_cond])
                    yaw_jitter_amount = 0
                else
                    yaw_jitter = "Off"
                    yaw_jitter_amount = 0
                end
            end
            if body_yaw == "Custom Jitter" then
                if type(body_yaw_amount) == "table" then
                    antiaims.jit_handler(cmd, body_yaw_amount[1], body_yaw_amount[2], body_yaw_amount[3], body_yaw_amount[4])
                    body_yaw = "Custom"
                    body_yaw_amount = antiaims.jitter[antiaims.current_cond]
                else
                    body_yaw = "Off"
                    body_yaw_amount = 0
                end
            elseif body_yaw == "Sway" then
                if type(body_yaw_amount) == "table" then
                    antiaims.sway_handler(cmd, body_yaw_amount[1], body_yaw_amount[2], (tonumber(body_yaw_amount[3]) or 1) * (jitter_delay or 1))
                end
                body_yaw = "Off"
            elseif body_yaw == "Jitter v2" then
                if type(body_yaw_amount) == "table" then
                    antiaims.jitter2(cmd, body_yaw_amount[1], (tonumber(body_yaw_amount[2]) or 1) * jitter_delay)
                end
                body_yaw = "Off"
            elseif body_yaw == "Static v2" then
                antiaims.static2(cmd, body_yaw_amount, ui.get(tabs["Anti-aimbot angles"].inverter[1]) and -1 or 1)
                body_yaw = "Off"
            end
            if defensive then
                local defensive_pitch = antiaims.to_apply.defensive.pitch
                local defensive_custom = antiaims.to_apply.defensive.pitchc[defensive_pitch]
                local defensive_yaw = antiaims.to_apply.defensive.yaw
                local defensive_yaw_ammount = antiaims.to_apply.defensive.yawc[defensive_yaw]
                if defensive_pitch ~= "Default" and not antiaims.point_at_enemy_180_active then
                    pitch = "Custom"
                    if defensive_pitch == "Zero" then
                        custom_pitch = 0
                    elseif defensive_pitch == "Custom" then
                        pitch = defensive_pitch
                        custom_pitch = defensive_custom
                    elseif defensive_pitch == "Random v2" then
                        custom_pitch = client.random_int(defensive_custom[1], defensive_custom[2])
                    elseif defensive_pitch == "Fluctate" then
                        local speed_mult = 1.0
                        if antiaims.defensive_cycle_state and antiaims.defensive_cycle_state.phase == 2 then
                            speed_mult = 0.33
                        end
                        antiaims.fluctate_handler(cmd, defensive_custom[2], defensive_custom[3], (defensive_custom[4]*0.01)*20*speed_mult, defensive_custom[1])
                        custom_pitch = antiaims.fluctate_def[antiaims.current_cond]
                    elseif defensive_pitch == "Jitter" then
                        antiaims.pitchjit_hamdler(cmd, defensive_custom[1], defensive_custom[2])
                        custom_pitch = antiaims.pitch_jit[antiaims.current_cond]
                    elseif defensive_pitch == "L&R" then
                        custom_pitch = antiaims.current_side and defensive_custom[1] or defensive_custom[2]
                    elseif defensive_pitch == "Adaptive" then
                        local speed_mult = 1.0
                        if antiaims.defensive_cycle_state and antiaims.defensive_cycle_state.phase == 2 then
                            speed_mult = 0.33  
                        end
                        if type(defensive_custom) == "table" then
                            antiaims.adaptive_pitch_handler(cmd, defensive_custom[1], defensive_custom[2], defensive_custom[3] * speed_mult)
                        else
                            antiaims.adaptive_pitch_handler(cmd, -20, 30, 55 * speed_mult)
                        end
                        custom_pitch = antiaims.adaptive_pitch[antiaims.current_cond]
                    else
                        pitch = defensive_pitch
                    end
                end
                do
                    local def_cfg = antiaims.to_apply and antiaims.to_apply.defensive or nil
                    if def_cfg and def_cfg.pitch_generation then
                        local min_p = def_cfg.pitch_gen_min
                        local max_p = def_cfg.pitch_gen_max
                        if type(min_p) == "number" and type(max_p) == "number" then
                            if min_p > max_p then min_p, max_p = max_p, min_p end

                            local ticks_proc = 0
                            if nigger and nigger.get_data then
                                local ok, data = pcall(nigger.get_data, nigger)
                                if ok and type(data) == "table" and type(data.ticks_processed) == "number" then
                                    ticks_proc = data.ticks_processed
                                end
                            end

                            antiaims.pitch_gen_values = antiaims.pitch_gen_values or {}
                            local key = antiaims.current_cond or ""

                            if ticks_proc <= 2 then
                                antiaims.pitch_gen_values[key] = nil
                            elseif not antiaims.pitch_gen_values[key] then
                                antiaims.pitch_gen_values[key] = client.random_int(min_p, max_p)
                            end

                            if ticks_proc > 2 then
                                if custom_pitch == nil then custom_pitch = 0 end
                                custom_pitch = custom_pitch + (antiaims.pitch_gen_values[key] or 0)
                                pitch = "Custom"
                            end
                        end
                    end
                end
                if defensive_yaw ~= "Default" then
                    if defensive_yaw == "180" or defensive_yaw == "Spin" then
                        yaw = defensive_yaw
                        yaw_amount = defensive_yaw_ammount
                    elseif defensive_yaw == "Spin v2" then
                        local speed_mult = 1.0
                        if antiaims.defensive_cycle_state and antiaims.defensive_cycle_state.phase == 2 then
                            speed_mult = 0.33 
                        end
                        if defensive_yaw_ammount and defensive_yaw_ammount[1] and defensive_yaw_ammount[2] and defensive_yaw_ammount[3] then
                            antiaims.spin2_handler(cmd, defensive_yaw_ammount[1], defensive_yaw_ammount[2], (defensive_yaw_ammount[3]*0.01)*40*speed_mult)
                        else
                            antiaims.spin2_handler(cmd, -180, 180, 2*speed_mult)
                        end
                        yaw = "180"
                        yaw_amount = antiaims.spin2[antiaims.current_cond]
                    elseif defensive_yaw == "Random" then
                        if defensive_yaw_ammount and defensive_yaw_ammount[1] and defensive_yaw_ammount[2] then
                            antiaims.yawrndm_handler(cmd, defensive_yaw_ammount[1], defensive_yaw_ammount[2])
                        else
                            antiaims.yawrndm_handler(cmd, -180, 180)
                        end
                        yaw = "180"
                        yaw_amount = antiaims.yaw_random[antiaims.current_cond]
                    elseif defensive_yaw == "Opposite" then
                        if defensive_yaw_ammount then
                            antiaims.yawopp_handler(cmd, defensive_yaw_ammount)
                        else
                            antiaims.yawopp_handler(cmd, 180)
                        end
                        yaw = "180"
                        yaw_amount = antiaims.yaw_oposite[antiaims.current_cond]
                    elseif defensive_yaw == "Jitter" then
                        if defensive_yaw_ammount and defensive_yaw_ammount[1] and defensive_yaw_ammount[2] then
                            antiaims.yawjit_handler(cmd, defensive_yaw_ammount[1], defensive_yaw_ammount[2])
                        else
                            antiaims.yawjit_handler(cmd, -180, 180)
                        end
                        yaw = "180"
                        yaw_amount = antiaims.yaw_jit[antiaims.current_cond]
                    elseif defensive_yaw == "L&R" then
                        yaw = "180"
                        if defensive_yaw_ammount and defensive_yaw_ammount[1] and defensive_yaw_ammount[2] then
                            yaw_amount = antiaims.current_side and defensive_yaw_ammount[1] or defensive_yaw_ammount[2]
                        else
                            yaw_amount = antiaims.current_side and -180 or 180
                        end
                    elseif defensive_yaw == "Adaptive" then
                        local speed_mult = 1.0
                        if antiaims.defensive_cycle_state and antiaims.defensive_cycle_state.phase == 2 then
                            speed_mult = 0.33
                        end
                        if type(defensive_yaw_ammount) == "table" then
                            antiaims.adaptive_yaw_handler(cmd, defensive_yaw_ammount[1], defensive_yaw_ammount[2], defensive_yaw_ammount[3] * speed_mult, defensive_yaw_ammount[4] * speed_mult)
                        else
                            antiaims.adaptive_yaw_handler(cmd, -50, 50, 55 * speed_mult, 55 * speed_mult)
                        end
                        yaw = "180"
                        yaw_amount = antiaims.adaptive_yaw[antiaims.current_cond]
                    end
                    do
                        local def_cfg = antiaims.to_apply and antiaims.to_apply.defensive or nil
                        if def_cfg and def_cfg.yaw_generation then
                            local min_gen = def_cfg.yaw_gen_min
                            local max_gen = def_cfg.yaw_gen_max
                            if type(min_gen) == "number" and type(max_gen) == "number" then
                                if min_gen > max_gen then
                                    min_gen, max_gen = max_gen, min_gen
                                end
                                local ticks_proc = 0
                                if nigger and nigger.get_data then
                                    local ok, data = pcall(nigger.get_data, nigger)
                                    if ok and type(data) == "table" and type(data.ticks_processed) == "number" then
                                        ticks_proc = data.ticks_processed
                                    end
                                end
                                antiaims.yaw_gen_values = antiaims.yaw_gen_values or {}
                                local key = antiaims.current_cond or ""
                                if ticks_proc <= 2 then
                                    antiaims.yaw_gen_values[key] = nil
                                elseif not antiaims.yaw_gen_values[key] then
                                    antiaims.yaw_gen_values[key] = client.random_int(min_gen, max_gen)
                                end
                                if ticks_proc > 2 then
                                    if yaw_amount == nil then yaw_amount = 0 end
                                    yaw_amount = yaw_amount + (antiaims.yaw_gen_values[key] or 0)
                                end
                            end
                        end
                    end
                end
            end

            do
                if (not manual_force_only) and antiaims and antiaims.apply_anti_brute then
                    local ab_yaw, ab_amount, ab_active = antiaims.apply_anti_brute(cmd, yaw, yaw_amount)
                    if ab_active then
                        yaw = ab_yaw
                        yaw_amount = ab_amount
                    end
                end
            end

            local spin_if = tabs["Anti-aimbot angles"].other and tabs["Anti-aimbot angles"].other[3] or nil
            local spin_mode = spin_if ~= nil and ui.get(spin_if) or ""
            local spin_active = false
            local warmup_active = false
            do
                local gr = entity.get_game_rules()
                if gr ~= nil then
                    local ok, v = pcall(entity.get_prop, gr, "m_bWarmupPeriod")
                    warmup_active = ok and v == 1 or false
                end
            end
            if spin_mode == nil or spin_mode == "" or spin_mode == " " then
                spin_active = false
            elseif type(spin_mode) == "table" then
                local no_enemies = false
                local on_round_end = false
                local on_warmup = false
                for _, v in ipairs(spin_mode) do
                    if v == "No enemies" then
                        no_enemies = true
                    elseif v == "On round end" then
                        on_round_end = true
                    elseif v == "On warmup" then
                        on_warmup = true
                    end
                end
                if no_enemies and rage.isnoenemy then
                    spin_active = true
                end
                if (not spin_active) and on_round_end and ((antiaims.round_end_spin_until or 0) > (globals.tickcount() or 0)) then
                    spin_active = true
                end
                if (not spin_active) and on_warmup and warmup_active then
                    spin_active = true
                end
            elseif spin_mode == "No enemies" then
                spin_active = rage.isnoenemy
            elseif spin_mode == "On round end" then
                spin_active = (antiaims.round_end_spin_until or 0) > (globals.tickcount() or 0)
            elseif spin_mode == "On warmup" then
                spin_active = warmup_active
            end
            if spin_active and (not manual_force_only) then
                pitch = "Custom"
                custom_pitch = 0
                yaw = "Spin"
                yaw_amount = 5
                yaw_jitter = "Off"
                yaw_jitter_amount = 0
                body_yaw = "Static"
                body_yaw_amount = 1
                ui.set(skeetgui.aagui.fakelag.limit, 1)
            end

            local df_enabled = false
            do
                if antiaims.to_apply and antiaims.to_apply.customize == "Defensive" then
                    local df = antiaims.to_apply.def_flick
                    df_enabled = df ~= nil and df[1] == true
                    if not df_enabled and antiaims.current_cond == "Shared" then
                        local function real_state()
                            local lplayer = entity.get_local_player()
                            if lplayer == nil or not entity.is_alive(lplayer) then return nil end
                            local flags = entity.get_prop(lplayer, 'm_fFlags')
                            if flags == nil then return nil end

                            local vx, vy = entity.get_prop(lplayer, 'm_vecVelocity')
                            vx = tonumber(vx) or 0
                            vy = tonumber(vy) or 0

                            local is_crouching = bit.band(flags, bit.lshift(1, 1)) ~= 0
                            local on_ground = bit.band(flags, bit.lshift(1, 0)) ~= 0
                            local standing = math.abs(vx) + math.abs(vy) < 2
                            local is_jumping = cmd ~= nil and cmd.in_jump == 1 or false
                            local slowwalking = false
                            do
                                local sm = skeetgui and skeetgui.aagui and skeetgui.aagui.other and skeetgui.aagui.other.slow_motion or nil
                                if type(sm) == "table" then
                                    if sm[1] ~= nil and sm[2] ~= nil then
                                        local ok1, a = pcall(ui.get, sm[1])
                                        local ok2, b = pcall(ui.get, sm[2])
                                        slowwalking = (ok1 and a == true) and (ok2 and b == true)
                                    else
                                        local ref = sm[2] or sm[1]
                                        if ref ~= nil then
                                            local ok, active = pcall(ui.get, ref)
                                            slowwalking = ok and type(active) == "boolean" and active or false
                                        end
                                    end
                                elseif sm ~= nil then
                                    local ok, active = pcall(ui.get, sm)
                                    slowwalking = ok and type(active) == "boolean" and active or false
                                end
                            end
                            if standing then
                                slowwalking = false
                            end
                            if is_crouching and (not on_ground or is_jumping) then return "Air-Crouch" end
                            if (not is_crouching) and (not on_ground or is_jumping) then return "Air" end
                            if is_crouching and on_ground and not is_jumping and standing then return "Crouch" end
                            if is_crouching and on_ground and not is_jumping and not standing then return "Crouch-Moving" end
                            if slowwalking and on_ground and not is_crouching and not is_jumping then return "Slowwalk" end
                            if (not standing) and on_ground and not is_crouching and not is_jumping then return "Moving" end
                            if standing and on_ground and not is_crouching and not is_jumping then return "Standing" end
                            return nil
                        end
                        local st = real_state()
                        if st and tabs and tabs["Anti-aimbot angles"] and tabs["Anti-aimbot angles"][st]
                            and tabs["Anti-aimbot angles"][st].def_flick and tabs["Anti-aimbot angles"][st].def_flick[1] then
                            local ok, v = pcall(ui.get, tabs["Anti-aimbot angles"][st].def_flick[1])
                            df_enabled = ok and v == true or false
                        end
                    end
                end
            end
            if (not manual_force_only) and df_enabled and rage.exploits and cmd.chokedcommands == 1 and not antiaims.point_at_enemy_180_active then
                local smth = (pui.cmd_ticks()%10 >= 2 and 90 or -90)
                if yaw_amount == nil then yaw_amount = 0 end
                yaw_amount = yaw_amount + (ui.get(tabs["Anti-aimbot angles"].inverter[1]) and -smth or smth)
            end

        elseif antiaims.safe then
            yaw = "180"
            yaw_amount = 0
            yaw_jitter = "Off"
            pitch = "Down"
            body_yaw = "Off"
            yaw_base = "At targets"
        elseif antiaims.is_antibacsktab then

            pitch = "Up"
            yaw_base = "At targets"
            yaw = "Off"
            yaw_amount = 0
            yaw_jitter = "Off"
            body_yaw = "Off"
        end

        local notextdt = not ui.get(tabs["Anti-aimbot angles"].exttep[1]) and not ui.get(tabs["Anti-aimbot angles"].exttep[2])
        if antiaims.current_cond ~= "Fakelags" and antiaims.current_cond ~= "Duckpeek" and notextdt then
            local fd_mode = antiaims.to_apply.force_def
            if type(fd_mode) == "number" and antiaims.defforcebox ~= nil then
                fd_mode = antiaims.defforcebox[fd_mode] or fd_mode
            end
            local is_manual_cond = antiaims.current_cond == "Manuals"
            local force_state
            if fd_mode == "Always" then
                force_state = true
            elseif fd_mode == "On-Hittable" then
                force_state = is_manual_cond and true or (rage.hittable == true)
            else
                force_state = false
            end
            nigger:should_force_defensive(force_state)
            cmd.force_defensive = force_state and true or false
        else
            nigger:should_force_defensive(false)
            cmd.force_defensive = false
        end
        if not antiaims.point_at_enemy_180_active then
            pui.safe_ui_set(short.pitch[1], pitch, "Off")
            pui.safe_ui_set(short.pitch[2], custom_pitch, 0)
        end
        if manual_force_only then
            yaw_base = "Local view"
            yaw = "180"
            yaw_amount = manual_yaw
            yaw_jitter = "Off"
            yaw_jitter_amount = 0
        end
        local ui_yaw_base = (yaw_base == "Closest enemy") and "Local view" or yaw_base
        pui.safe_ui_set(short.yaw_base, ui_yaw_base, "Local view")
        local vj = { ["Off"] = true, ["Offset"] = true, ["Center"] = true, ["Random"] = true }
        if not vj[yaw_jitter] then yaw_jitter = "Off" end
        pui.safe_ui_set(short.yaw_jitter[1], yaw_jitter, "Off")


        local valid_body = { ["Off"]=true, ["Static"]=true, ["Opposite"]=true, ["Jitter"]=true }
        local body_choice
        if body_yaw == "Custom" or body_yaw == "Custom Jitter" then
            body_choice = "Jitter"
        elseif valid_body[body_yaw] then
            body_choice = body_yaw
        else
            body_choice = "Off"
        end
        pui.safe_ui_set(short.body_yaw[1], body_choice, "Off")
        local vy = { ["Off"]=true, ["180"]=true, ["Spin"]=true, ["Static"]=true }
        if not vy[yaw] then yaw = "180" end
        pui.safe_ui_set(short.yaw[1], yaw, "180")
        do
            local ok_e, edge_on = pcall(ui.get, tabs["Anti-aimbot angles"].edgeyaw[1])
            pui.safe_ui_set(short.edge_yaw, (not manual_force_only) and (ok_e and edge_on or false) or false, false)
        end
        do
            local ok_fs, fs_on, fs_key = pcall(ui.get, tabs["Anti-aimbot angles"].freestand[1])
            local ok_bi, _, bi_key = pcall(ui.get, short.freestanding[1])
            local set_key = (ok_bi and bi_key) or fs_key or 0x00
            pcall(ui.set, short.freestanding[1], (not manual_force_only) and ((ok_fs and fs_on) or false) or false, set_key)
        end
        if fs_body_yaw ~= nil then pui.safe_ui_set(short.freestanding_body_yaw, fs_body_yaw, "Off") end

        if yaw_jitter ~= "Off" then
            local yj_num = type(yaw_jitter_amount) == "table" and get_yaw_value(yaw_jitter_amount, 1) or yaw_jitter_amount
            yj_num = tonumber(yj_num) or 0
            pui.safe_ui_set(short.yaw_jitter[2], yj_num, 0)
        end

        if body_yaw ~= "Off" and body_yaw ~= "Opposite" then
            body_yaw_amount = (body_yaw == "Static" and ui.get(tabs["Anti-aimbot angles"].inverter[1])) and -body_yaw_amount or body_yaw_amount
            local by_num = type(body_yaw_amount) == "table" and get_yaw_value(body_yaw_amount, 1) or body_yaw_amount
            by_num = tonumber(by_num) or 0
            pui.safe_ui_set(short.body_yaw[2], by_num, 0)
        end

        if yaw ~= "Off" then
            local yaw_amount_num = type(yaw_amount) == "table" and get_yaw_value(yaw_amount, 1) or yaw_amount
            yaw_amount_num = tonumber(yaw_amount_num) or 0
            pui.safe_ui_set(short.yaw[2], yaw_amount_num, 0)
        end

        if manual_force_only then
            return
        end

        if not (antiaims.freeze_disable and antiaims.freeze_disable.active) then
            ui.set(skeetgui.aagui.angles.enabled, true)
        end
        local my_weapon = entity.get_player_weapon(lplayer)
        local simtime = entity.get_prop(lplayer, "m_flSimulationTime")
        local simdelta = simtime - (oldsimtime or simtime)
        oldsimtime = simtime
        local static_inverter = ui.get(tabs["Anti-aimbot angles"].inverter[1])
        local curtime = globals.curtime()
        local eyes = vector(client.camera_angles())
        local cmdyaw = cmd.yaw
        local tick = globals.tickcount()
        local shifting = simdelta < 0
        local can_shoot = false
        local nading = false
        if my_weapon ~= nil then
            local weapon = csgo_weapons(my_weapon)
            if weapon.is_revolver then
                can_shoot = curtime > entity.get_prop(my_weapon, "m_flNextPrimaryAttack")

            elseif weapon.is_grenade then
                can_shoot = false
            else
                can_shoot = curtime > math.max(entity.get_prop(lplayer, "m_flNextAttack"), entity.get_prop(my_weapon, "m_flNextPrimaryAttack"), entity.get_prop(my_weapon, "m_flNextSecondaryAttack")) - globals.tickinterval()
            end
            if weapon.is_grenade and entity.get_prop(my_weapon, "m_fThrowTime") > 0 then nading = true end
        end
        if not shifting and cmd.in_attack == 1 and can_shoot or nading then return end
        if antiaims.point_at_enemy_180_active and (pitch == "Default" or pitch == nil) then
            local gs_mode = ui.get(skeetgui.aagui.angles.pitch[1])
            if gs_mode == "Off" then
                pitch = nil
            elseif gs_mode == "Up" then
                pitch = -89
            elseif gs_mode == "Down" then
                pitch = 89
            elseif gs_mode == "Random" then
                pitch = client.random_float(-89, 89)
            elseif gs_mode == "Custom" then
                pitch = ui.get(skeetgui.aagui.angles.pitch[2])
            end
        end
        if pitch == "Off" then
            pitch = nil
        elseif pitch == "Up" then
            pitch = -89
        elseif pitch == "Down" then
            pitch = 89
        elseif pitch == "Zero" then
            pitch = 0
        elseif pitch == "Random" then
            pitch = client.random_float(-89, 89)
        elseif pitch == "Custom" then
            pitch = custom_pitch
        end
        if antiaims.point_at_enemy_180_active and pitch == nil then
            local gs_mode = ui.get(skeetgui.aagui.angles.pitch[1])
            if gs_mode == "Off" then
                pitch = nil
            elseif gs_mode == "Up" then
                pitch = -89
            elseif gs_mode == "Down" then
                pitch = 89
            elseif gs_mode == "Random" then
                pitch = client.random_float(-89, 89)
            elseif gs_mode == "Custom" then
                pitch = ui.get(skeetgui.aagui.angles.pitch[2])
            end
        end
        if yaw == "Off" then
            yaw = nil
        elseif yaw == "180" then
            yaw_amount = 180 + get_yaw_value(yaw_amount, 1)
        elseif yaw == "Spin" then
            if (tick+1)%2 == 0 then
                antiaims.spin_yaw = antiaims.spin_yaw + get_yaw_value(yaw_amount, 1)
            end
            yaw_amount = antiaims.spin_yaw
        elseif yaw == "L&R" then
            local y_left = get_yaw_value(yaw_amount, 1) or 0
            local y_right = get_yaw_value(yaw_amount, 2) or 0
            local sideflag = antiaims.current_side
            if body_yaw == nil or body_yaw == "Off" then
                sideflag = (pui.cmd_ticks(cmd) % 2 == 0)
            end
            yaw_amount = 180 + (sideflag and y_left or y_right)
        elseif yaw == "Delayed" then
            yaw_amount = 180 + (tick%(get_yaw_value(yaw_amount, 3)*2) >= get_yaw_value(yaw_amount, 3) and get_yaw_value(yaw_amount, 2) or get_yaw_value(yaw_amount, 1))
        end

        if yaw ~= nil and is_manual then
            if pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Local view on manuals") then
                yaw_base = "Local view"
            end
            if pui.multi_parse(tabs["Anti-aimbot angles"].addons, "Static on manuals") then
                yaw_jitter = "Off"
                body_yaw = "Static"
                body_yaw_amount = 60
            end
            local base = tonumber(yaw_amount) or get_yaw_value(yaw_amount, 1) or 0
            yaw_amount = pui.normalize_yaw(base + (tonumber(manual_yaw) or 0))
        end

        if yaw_jitter == "Off" or yaw == nil then
            yaw_jitter = nil
        elseif yaw_jitter == "Skitter" then
            local per = 3 * (jitter_delay or 1)
            local mod = tick % per
            if mod == 0 then
                yaw_amount = get_yaw_value(yaw_amount, 1) + get_yaw_value(yaw_jitter_amount, 1)*0.5
            elseif mod == (2 * (jitter_delay or 1)) then
                yaw_amount = get_yaw_value(yaw_amount, 1) - get_yaw_value(yaw_jitter_amount, 1)*0.5
            end
        elseif yaw_jitter == "Center" then
            local per = 4 * (jitter_delay or 1)
            local jitflip = (tick % per) < (2 * (jitter_delay or 1)) and -1 or 1
            yaw_amount = get_yaw_value(yaw_amount, 1) + get_yaw_value(yaw_jitter_amount, 1)*0.5*jitflip
        elseif yaw_jitter == "Offset" then
            local per = 4 * (jitter_delay or 1)
            yaw_amount = get_yaw_value(yaw_amount, 1) + ((tick % per) < (2 * (jitter_delay or 1)) and get_yaw_value(yaw_jitter_amount, 1) or 0)
        elseif yaw_jitter == "Random" then
            local jd = (jitter_delay or 1)
            antiaims.yaw_rand_cache = antiaims.yaw_rand_cache or {}
            local cond = antiaims.current_cond
            local cached = antiaims.yaw_rand_cache[cond]
            if cached == nil or (tick % jd) == 0 then
                local yja = math.abs(get_yaw_value(yaw_jitter_amount, 1)*0.5)
                cached = client.random_float(-yja, yja)
                antiaims.yaw_rand_cache[cond] = cached
            end
            yaw_amount = get_yaw_value(yaw_amount, 1) + (cached or 0)
        end

        if antiaims.point_at_enemy_180_active then
            local target_idx = antiaims.target or client.current_threat()
            if target_idx ~= nil then
                local tpose = vector(entity.hitbox_position(target_idx, 0))
                local lpose = vector(client.eye_position())
                local pitcht, yawt = lpose:to(tpose):angles()
                yaw = "Static"
                yaw_jitter = "Off"
                body_yaw = "Off"
                yaw_amount = pui.normalize_yaw(yawt)
            end
        end
            if yaw ~= nil then
                if yaw == "Static" then
                    cmd.yaw = pui.normalize_yaw(yaw_amount)
                else
                    if yaw_base == "At targets" then
                        antiaims.crosshair = true
                        antiaims.force_distance = false
                        local target_idx = antiaims.target or client.current_threat()
                        if target_idx ~= nil then
                            local tx, ty, tz = entity.hitbox_position(target_idx, 0)
                            if not tx then tx, ty, tz = entity.get_origin(target_idx) end
                            if tx then
                                local tpose = vector(tx, ty, tz)
                                local lpose = vector(client.eye_position())
                                local _, yawt = lpose:to(tpose):angles()
                                cmdyaw = yawt
                            end
                        end
                    elseif yaw_base == "Closest enemy" then
                        antiaims.crosshair = false
                        antiaims.force_distance = true
                        local target_idx = antiaims.target or client.current_threat()
                        if target_idx ~= nil then
                            local tx, ty, tz = entity.hitbox_position(target_idx, 0)
                            if not tx then tx, ty, tz = entity.get_origin(target_idx) end
                            if tx then
                                local tpose = vector(tx, ty, tz)
                                local lpose = vector(client.eye_position())
                                local _, yawt = lpose:to(tpose):angles()
                                cmdyaw = yawt
                            end
                        end
                    end
                    cmd.yaw = pui.normalize_yaw(cmdyaw + get_yaw_value(yaw_amount, 1))
                end
            end

            if fs_enabled_yaw and not antiaims.safe and not antiaims.is_antibacsktab then
                if not antiaims.fs_yaw_prev_enabled then
                    local best = antiaims.freestand_best_side(cmdyaw)
                    if best == nil then
                        best = (antiaims.current_side ~= nil) and antiaims.current_side or true
                    end
                    antiaims.fs_yaw_cached_side = best
                    antiaims.fs_yaw_prev_enabled = true
                end
                local side = antiaims.fs_yaw_cached_side
                if side ~= nil then
                    antiaims.current_side = side
                    local yoff = 90
                    cmd.yaw = pui.normalize_yaw(cmdyaw + (side and yoff or -yoff))
                end
            else
                antiaims.fs_yaw_prev_enabled = false
                antiaims.fs_yaw_cached_side = nil
            end
            if pitch ~= nil then
                cmd.pitch = pitch
            end

            local fs_hotkey_on = false
            do
                local ok_fs, fs_val = pcall(ui.get, tabs["Anti-aimbot angles"].freestand[1])
                fs_hotkey_on = ok_fs and (fs_val == true)
            end
            local fs_enabled = (fs_body_yaw == true) or fs_hotkey_on
             if is_manual then
                 fs_enabled = false
             end

            do
                local ang = skeetgui and skeetgui.aagui and skeetgui.aagui.angles or nil
                local fs_ref = ang and ang.freestanding_body_yaw or nil
                if fs_ref then
                    pcall(ui.set, fs_ref, fs_enabled)
                end
            end

            if cmd.chokedcommands == 0 and (body_yaw ~= "Off" or fs_enabled) then

                local cond = antiaims.current_cond

                if body_yaw == "Off" and fs_enabled then
                    body_yaw = "Static"
                    local by_raw = tonumber(body_yaw_amount) or 0
                    if by_raw == 0 then
                        body_yaw_amount = 58
                    end
                end

                local delay_ticks = jitter_delay or 1
                local use_delay = delay_ticks > 1
                local cmdtick = pui.cmd_ticks(cmd)
                local next_tick = antiaims.body_delay_next[cond] or 0

                if body_yaw == "Static" then
                    if not use_delay or cmdtick >= next_tick then
                        antiaims.body_delay_next[cond] = use_delay and (cmdtick + delay_ticks) or cmdtick
                    desync_side = body_yaw_amount == 0 and 0 or body_yaw_amount < 0 and 1 or -1
                    desync_side = static_inverter and -desync_side or desync_side
                        antiaims.body_delay_cached[cond] = desync_side
                    else
                        local cached_side = antiaims.body_delay_cached[cond]
                        if cached_side ~= nil then
                            desync_side = cached_side
                        else
                            desync_side = body_yaw_amount == 0 and 0 or body_yaw_amount < 0 and 1 or -1
                            desync_side = static_inverter and -desync_side or desync_side
                        end
                    end
                elseif body_yaw == "Static v2" then
                    if not use_delay or cmdtick >= next_tick then
                        antiaims.body_delay_next[cond] = use_delay and (cmdtick + delay_ticks) or cmdtick
                    desync_side = body_yaw_amount < 0 and 1 or -1
                    desync_side = static_inverter and -desync_side or desync_side
                        antiaims.body_delay_cached[cond] = desync_side
                    else
                        local cached_side = antiaims.body_delay_cached[cond]
                        if cached_side ~= nil then
                            desync_side = cached_side
                        else
                            desync_side = body_yaw_amount < 0 and 1 or -1
                            desync_side = static_inverter and -desync_side or desync_side
                        end
                    end
                elseif body_yaw == "Opposite" then
                    if not use_delay or cmdtick >= next_tick then
                        antiaims.body_delay_next[cond] = use_delay and (cmdtick + delay_ticks) or cmdtick
                    if math.abs(entity.get_prop(lplayer, 'm_flPoseParameter', 11)*120-60) < 50  then
                        desync_side = -desync_side
                    end
                    body_yaw_amount = 58
                        antiaims.body_delay_cached[cond] = desync_side
                    else
                        local cached_side = antiaims.body_delay_cached[cond]
                        if cached_side ~= nil then
                            desync_side = cached_side
                        end
                        body_yaw_amount = 58
                    end
                elseif body_yaw == "Jitter" then
                    if not use_delay or cmdtick >= next_tick then
                        antiaims.body_delay_next[cond] = use_delay and (cmdtick + delay_ticks) or cmdtick

                        local btick = (antiaims.body_tickcount[cond] or 0) + 1
                        antiaims.body_tickcount[cond] = btick
                        desync_side = btick % 2 == 0 and 1 or -1
                        body_yaw_amount = body_yaw_amount < 0 and -58 or 58
                        antiaims.body_delay_cached[cond] = desync_side
                    else
                        local cached_side = antiaims.body_delay_cached[cond]
                        if cached_side ~= nil then
                            desync_side = cached_side
                        else
                            desync_side = desync_side == 0 and 1 or desync_side
                        end
                        body_yaw_amount = body_yaw_amount < 0 and -58 or 58
                    end
                end

                if fs_enabled and not is_manual then
                    local best = antiaims.freestand_best_side(cmdyaw)
                    if best ~= nil then
                        antiaims.current_side = best
                        desync_side = best and 1 or -1
                        if body_yaw_amount == 0 then
                            body_yaw_amount = 58
                        end
                    end
                end

                local mdelta = antiaims.maxdelta(lplayer)
                local by_num = type(body_yaw_amount) == "table" and get_yaw_value(body_yaw_amount, 1) or body_yaw_amount
                by_num = tonumber(by_num) or 0
                body_yaw_amount = (math.abs(by_num) + mdelta) * desync_side

                cmd.yaw = pui.normalize_yaw(cmd.yaw + body_yaw_amount)
                cmd.allow_send_packet = false
            end


end

client.set_event_callback("aim_miss", function(e)
    logs.on_miss(e)
    local target_name = entity.get_player_name(e.target)
    local weapon = entity.get_classname(entity.get_player_weapon(entity.get_local_player()))
    local reason = e.reason or "unknown"

    local ok_resolver, resolver_enabled = pcall(resolver_is_enabled)
    if ok_resolver and resolver_enabled and e.target ~= nil then
        local player = e.target
        local sid = entity.get_steam64(player)
        local sidn = tonumber(sid)
        if sid and (sidn ~= 0 and tostring(sid) ~= "0") and network_resolver.player_records[sid] then
            network_resolver.player_records[sid].missed_shots = (network_resolver.player_records[sid].missed_shots or 0) + 1
        end

        if sid and (sidn ~= 0 and tostring(sid) ~= "0") then
            if rage.resolver_data.missed_shots[player] == nil then
                rage.resolver_data.missed_shots[player] = 0
            end
            if rage.resolver_data.shot_data[player] == nil then
                rage.resolver_data.shot_data[player] = {}
            end

            rage.resolver_data.missed_shots[player] = rage.resolver_data.missed_shots[player] + 1
            rage.resolver_data.last_hit[player] = false

            local shot_data = rage.resolver_data.shot_data[player]
            shot_data.last_miss_time = globals.curtime()
            shot_data.miss_reason = reason
            shot_data.miss_hitgroup = e.hitgroup
            shot_data.consecutive_misses = (shot_data.consecutive_misses or 0) + 1
            shot_data.consecutive_hits = 0

            if plist.get(player, "Force body yaw") then
                local failed_angle = plist.get(player, "Force body yaw value")

                if shot_data.failed_angles == nil then
                    shot_data.failed_angles = {}
                end

                table.insert(shot_data.failed_angles, {
                    angle = failed_angle,
                    time = globals.curtime(),
                    reason = reason
                })

                if #shot_data.failed_angles > 5 then
                    table.remove(shot_data.failed_angles, 1)
                end
            end
        end
    end

    if reason == "?" then reason = "correction" end
    hitlogger.add_entry("miss", target_name, 0, e.hitgroup, weapon, reason)
end)
    
client.set_event_callback("aim_fire", function(e)
    if logs and logs.on_fire and e ~= nil and e.id ~= nil then
        logs.on_fire(e)
    end

    if not hitlogger or not hitlogger.add_entry then return end
    if not tabs or not tabs["Anti-aimbot angles"] or not tabs["Anti-aimbot angles"].logs then return end
    if not ui.get(tabs["Anti-aimbot angles"].logs[1]) then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[2], "Screen") then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[3], "Ragebot fire") then return end
    if e == nil or e.target == nil then return end

    local target_name = entity.get_player_name(e.target)
    local weapon = entity.get_classname(entity.get_player_weapon(entity.get_local_player()))
    hitlogger.add_entry("fire", target_name, 0, 0, weapon, nil)
end)

client.set_event_callback("aim_hit", function(e)
    if logs and logs.on_hit and e ~= nil and e.id ~= nil then
        logs.on_hit(e)
    end

    if not hitlogger or not hitlogger.add_entry then return end
    if not tabs or not tabs["Anti-aimbot angles"] or not tabs["Anti-aimbot angles"].logs then return end
    if not ui.get(tabs["Anti-aimbot angles"].logs[1]) then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[2], "Screen") then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[3], "On Hit") then return end
    if e == nil or e.target == nil then return end

    local target_name = entity.get_player_name(e.target)
    local weapon = entity.get_classname(entity.get_player_weapon(entity.get_local_player()))
    hitlogger.add_entry("hit", target_name, tonumber(e.damage or 0) or 0, tonumber(e.hitgroup or 0) or 0, weapon, nil)
end)

client.set_event_callback("player_hurt", function(e)
    local lp = entity.get_local_player()
    if lp == nil then return end
    local victim = client.userid_to_entindex(e.userid)
    local attacker = client.userid_to_entindex(e.attacker)

    if attacker == lp and victim ~= nil and victim ~= 0 and victim ~= lp then
        if logs and logs.hurthit then
            logs.hurthit(e)
        end
        return
    end

    if victim ~= lp or attacker == lp then return end

    if attacker ~= nil and attacker ~= 0 and entity.is_enemy(attacker) then
        if antiaims and antiaims.anti_brute_trigger then
            antiaims.anti_brute_trigger("hurt")
        end
    end

    if logs and logs.on_hurt then
        logs.on_hurt(e)
    end

    if not hitlogger or not hitlogger.add_entry then return end
    if not tabs or not tabs["Anti-aimbot angles"] or not tabs["Anti-aimbot angles"].logs then return end
    if not ui.get(tabs["Anti-aimbot angles"].logs[1]) then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[2], "Screen") then return end
    if not pui.multi_parse(tabs["Anti-aimbot angles"].logs[3], "On Hurt") then return end

    local name = entity.get_player_name(attacker)
    if name == "unknown" and attacker == 0 then name = "world" end
    hitlogger.add_entry("hurt_by", name, tonumber(e.dmg_health or 0) or 0, tonumber(e.hitgroup or 0) or 0, e.weapon, nil)
end)

client.set_event_callback("bullet_impact", function(e)
    local lp = entity.get_local_player()
    if lp == nil or not entity.is_alive(lp) then return end
    local attacker = client.userid_to_entindex(e.userid)
    if attacker == nil or attacker == 0 or attacker == lp then return end
    if not entity.is_enemy(attacker) then return end

    local lx, ly, lz = entity.hitbox_position(lp, 3)
    if lx == nil then
        lx, ly, lz = entity.get_origin(lp)
    end
    local ax, ay, az = entity.hitbox_position(attacker, 4)
    if ax == nil then
        ax, ay, az = entity.get_origin(attacker)
    end
    if lx == nil or ax == nil then return end

    local ix, iy, iz = tonumber(e.x), tonumber(e.y), tonumber(e.z)
    if ix == nil or iy == nil or iz == nil then return end

    local triggered = false

    do
        local abx, aby, abz = ix - ax, iy - ay, iz - az
        local apx, apy, apz = lx - ax, ly - ay, lz - az
        local ab_len2 = abx*abx + aby*aby + abz*abz
        if ab_len2 > 0 then
            local t = (apx*abx + apy*aby + apz*abz) / ab_len2
            if t < 0 then t = 0 elseif t > 1 then t = 1 end
            local cx, cy, cz = ax + abx*t, ay + aby*t, az + abz*t
            local dx, dy, dz = lx - cx, ly - cy, lz - cz
            local dist2 = dx*dx + dy*dy + dz*dz
            if dist2 <= (70 * 70) then
                triggered = true
            end
        end
    end

    if not triggered then
        local dx, dy, dz = ix - lx, iy - ly, iz - lz
        local dist2 = dx*dx + dy*dy + dz*dz
        if dist2 <= (190 * 190) then
            triggered = true
        end
    end

    if triggered then
