function antiaims.set_freeze_disable(on)
    local st = antiaims.freeze_disable
    if type(st) ~= "table" then
        st = { active = false, prev_aa = nil, prev_fl = nil }
        antiaims.freeze_disable = st
    end

    if on and not st.active then
        st.active = true
        local aa_ref = pui.ui_ref and pui.ui_ref(skeetgui and skeetgui.aagui and skeetgui.aagui.angles and skeetgui.aagui.angles.enabled) or nil
        local fl_ref = pui.ui_ref and pui.ui_ref(skeetgui and skeetgui.aagui and skeetgui.aagui.fakelag and skeetgui.aagui.fakelag.enabled and skeetgui.aagui.fakelag.enabled[1]) or nil
        if aa_ref then
            st.prev_aa = ui.get(aa_ref)
            pcall(ui.set, aa_ref, false)
        end
        if fl_ref then
            st.prev_fl = ui.get(fl_ref)
            pcall(ui.set, fl_ref, false)
        end
    elseif (not on) and st.active then
        st.active = false
        local aa_ref = pui.ui_ref and pui.ui_ref(skeetgui and skeetgui.aagui and skeetgui.aagui.angles and skeetgui.aagui.angles.enabled) or nil
        local fl_ref = pui.ui_ref and pui.ui_ref(skeetgui and skeetgui.aagui and skeetgui.aagui.fakelag and skeetgui.aagui.fakelag.enabled and skeetgui.aagui.fakelag.enabled[1]) or nil
        if aa_ref and st.prev_aa ~= nil then
            pcall(ui.set, aa_ref, st.prev_aa)
        end
        if fl_ref and st.prev_fl ~= nil then
            pcall(ui.set, fl_ref, st.prev_fl)
        end
        st.prev_aa = nil
        st.prev_fl = nil
    end
end

