function antiaims.anti_brute_cleanup()
    if not antiaims or not antiaims.anti_brute_states then return end
    local now = globals.curtime()
    for cond, st in pairs(antiaims.anti_brute_states) do
        if type(st) == "table" and st.active and st.until_t ~= nil and st.until_t ~= math.huge then
            if now > (tonumber(st.until_t) or 0) then
                st.active = false
                antiaims.anti_brute_states[cond] = st
            end
        end
    end
end

client.set_event_callback("setup_command", function(cmd)
    if rage and rage.resolver_handler then pcall(rage.resolver_handler) end
    if extentedtp ~= nil then pcall(extentedtp, cmd) end
    if misc and misc.fastladder then pcall(misc.fastladder, cmd) end
    if misc and misc.jitterfuck then pcall(misc.jitterfuck, cmd) end
    if misc and misc.globalstates then pcall(misc.globalstates, cmd) end
    if handle_attack then pcall(handle_attack, cmd) end
    if rage and rage.dormant then pcall(rage.dormant, cmd) end
    if rage and rage.jumpshot then pcall(rage.jumpshot, cmd) end
    if rage and rage.cond_mpoints then pcall(rage.cond_mpoints, cmd) end
    local freeze = false
    do
        local gr = entity.get_game_rules()
        if gr ~= nil then
            local ok, v = pcall(entity.get_prop, gr, "m_bFreezePeriod")
            freeze = ok and v == 1 or false
        end
    end
    do
        local lplayer = entity.get_local_player()
        if lplayer ~= nil and entity.is_alive(lplayer) then
            local bombs = entity.get_all("CPlantedC4")
            if bombs ~= nil and #bombs > 0 then
                local c4 = bombs[#bombs]

                local team = entity.get_prop(lplayer, "m_iTeamNum")
                if team == 3 then
                    local lpos = vector(entity.get_origin(lplayer))
                    local c4pos = vector(entity.get_origin(c4))
                    if lpos ~= nil and c4pos ~= nil then
                        local near_bomb = lpos:dist(c4pos) < 50
                        if near_bomb then
                            freeze = true
                        end
                    end
                end

                local defuser = entity.get_prop(c4, "m_hBombDefuser")
                if defuser ~= nil and defuser ~= -1 and defuser == lplayer then
                    local defuse_end = entity.get_prop(c4, "m_flDefuseCountDown")
                    if type(defuse_end) == "number" and defuse_end > 0 and defuse_end > globals.curtime() then
                        freeze = true
                    end
                end
            end
        end
    end
    if antiaims and antiaims.set_freeze_disable then
        antiaims.set_freeze_disable(freeze)
    end
    local ladder_active = misc and misc.fastladder_active
    local on_ladder = false
    do
        local lplayer = entity.get_local_player()
        if lplayer ~= nil then
            local mtype = entity.get_prop(lplayer, "m_MoveType")
            on_ladder = mtype == 9
        end
    end
    if not ladder_active and not on_ladder then
        if antiaims and antiaims.condition then pcall(antiaims.condition, cmd) end
        if antiaims and antiaims.desync_side then pcall(antiaims.desync_side) end
        if antiaims and antiaims.safe_handler then pcall(antiaims.safe_handler, cmd) end
        if antiaims and antiaims.handler then pcall(antiaims.handler, cmd) end
        if antiaims and antiaims.anti_brute_cleanup then pcall(antiaims.anti_brute_cleanup) end
        if antiaims and antiaims.lby_breaker then pcall(antiaims.lby_breaker, cmd) end
        if antiaims and antiaims.point_to_enemy_enforce then pcall(antiaims.point_to_enemy_enforce, cmd) end
    end
end)


