	local _, hs = surface.get_text_size(font, "A")
	local x, y, size = 8, 5, hs
	local frametime = globals.frametime()

	for i = #list, 1, -1 do
		local n = list[i]
		n.time = (n.time or 0) - frametime
		if n.time <= 0 then
			table.remove(list, i)
		end
	end

	if #list == 0 then return end
	while #list > 8 do table.remove(list, 1) end

	for i = 1, #list do
		local n = list[i]
		local left = n.time or 0
		local alpha = 255
		if left < 0.5 then
			local fl = left / 0.5
			if fl < 0 then fl = 0 end
			if fl > 1 then fl = 1 end
			alpha = math.floor(255 * fl)
			if i == 1 and fl < 0.2 then
				y = y - size * (1.0 - fl * 5)
			end
		end

		local segments = n.segments or {}
		local w_o = 0
		for j = 1, #segments do
			local seg = segments[j]
			local text = (seg.text or ""):gsub("\1", "")
			local w = surface.get_text_size(font, text)
			local r, g, b = seg.r or 255, seg.g or 255, seg.b or 255
			surface.draw_text(x + w_o, y, r, g, b, alpha, font, text)
			w_o = w_o + w
		end

		y = y + size
	end
end)

client.set_event_callback("output", function(output)
	local text = output.text or ""
	if text:find("\0") then
		text = text:sub(1, #text - 1)
	end

	local list = osmanhook_console.entries
	if osmanhook_console.skip_line and list[#list] then
		local last = list[#list]
		last.segments = last.segments or {}
		last.segments[#last.segments + 1] = {
			r = output.r, g = output.g, b = output.b, text = text
		}
	else
		for line in text:gmatch("([^\n]+)") do
			list[#list + 1] = {
				time = 8.0,
				segments = {
					{ r = output.r, g = output.g, b = output.b, text = line }
				}
			}
		end
	end

	osmanhook_console.skip_line = (output.text or ""):find("\0") ~= nil
end)

shared_icon_js = nil
 
misc.shared_icon = function()
    if not tabs or not tabs["Misc"] or not tabs["Misc"].shared_icon or not tabs["Misc"].shared_icon[1] then return end
    if not ui.get(tabs["Misc"].shared_icon[1]) then
        if shared_icon_js then
            shared_icon_js.clear()
            shared_icon_js.destroy()
        end
        return
    end

    if not shared_icon_js then
        shared_icon_js = panorama.loadstring([[
            let entity_panels = {}
            let killfeed_panels = {}
            let entity_data = {}
            let event_callbacks = {}
            let SLOT_LAYOUT = `
                <root>
                    <Panel style="min-width: 3px; padding-top: 2px; padding-left: 0px;" scaling='stretch-to-fit-y-preserve-aspect'>
                        <Image id="smaller" textureheight="15" style="horizontal-align: center; opacity: 0.01; transition: opacity 0.1s ease-in-out 0.0s, img-shadow 0.12s ease-in-out 0.0s; overflow: noclip; padding: 3px 5px; margin: -3px -5px;"	/>
                        <Image id="small" textureheight="17" style="horizontal-align: center; opacity: 0.01; transition: opacity 0.1s ease-in-out 0.0s, img-shadow 0.12s ease-in-out 0.0s; overflow: noclip; padding: 3px 5px; margin: -3px -5px;" />
                        <Image id="image" textureheight="21" style="opacity: 0.01; transition: opacity 0.1s ease-in-out 0.0s, img-shadow 0.12s ease-in-out 0.0s; padding: 3px 5px; margin: -3px -5px; margin-top: -5px;" />
                    </Panel>
                </root>
            `
            let KILLFEED_LAYOUT = `
                <root>
                    <Image id="killfeed-icon" textureheight="16" style="opacity: 1; margin-right: 4px; vertical-align: center;" />
                </root>
            `
            let _DestroyEntityPanel = function (key) {
                let panel = entity_panels[key]
                if(panel != null && panel.IsValid()) {
                    var parent = panel.GetParent()
                    let musor = parent.GetChild(0)
                    musor.visible = true
                    if(parent.FindChildTraverse("id-sb-skillgroup-image") != null) {
                        parent.FindChildTraverse("id-sb-skillgroup-image").style.margin = "0px 0px 0px 0px"
                    }
                    panel.DeleteAsync(0.0)
                }
                delete entity_panels[key]
            }
            let _DestroyKillfeedPanels = function() {
                for(key in killfeed_panels){
                    let panel = killfeed_panels[key]
                    if(panel != null && panel.IsValid()) {
                        panel.DeleteAsync(0.0)
                    }
                    delete killfeed_panels[key]
                }
            }
            let _DestroyEntityPanels = function() {
                for(key in entity_panels){
                    _DestroyEntityPanel(key)
                }
            }
            let _GetOrCreateCustomPanel = function(xuid) {
                if(entity_panels[xuid] == null || !entity_panels[xuid].IsValid()){
                    entity_panels[xuid] = null
                    let scoreboard_context_panel = $.GetContextPanel().FindChildTraverse("ScoreboardContainer").FindChildTraverse("Scoreboard") || $.GetContextPanel().FindChildTraverse("id-eom-scoreboard-container").FindChildTraverse("Scoreboard")
                    if(scoreboard_context_panel == null){
                        _Clear()
                        _DestroyEntityPanels()
                        return
                    }
                    scoreboard_context_panel.FindChildrenWithClassTraverse("sb-row").forEach(function(el){
                        let scoreboard_el
                        if(el.m_xuid == xuid) {
                            el.Children().forEach(function(child_frame){
                                let stat = child_frame.GetAttributeString("data-stat", "")
                                if(stat == "rank")
                                    scoreboard_el = child_frame.GetChild(0)
                            })
                            if(scoreboard_el) {
                                let scoreboard_el_parent = scoreboard_el.GetParent()
                                let custom_icons = $.CreatePanel("Panel", scoreboard_el_parent, "revealer-icon", {
                                })
                                if(scoreboard_el_parent.FindChildTraverse("id-sb-skillgroup-image") != null) {
                                    scoreboard_el_parent.FindChildTraverse("id-sb-skillgroup-image").style.margin = "0px 0px 0px 0px"
                                }
                                scoreboard_el_parent.MoveChildAfter(custom_icons, scoreboard_el_parent.GetChild(1))
                                let prev_panel = scoreboard_el_parent.GetChild(0)
                                prev_panel.visible = false
                                let panel_slot_parent = $.CreatePanel("Panel", custom_icons, `icon`)
                                panel_slot_parent.visible = false
                                panel_slot_parent.BLoadLayoutFromString(SLOT_LAYOUT, false, false)
                                entity_panels[xuid] = custom_icons
                                return custom_icons
                            }
                        }
                    })
                }
                return entity_panels[xuid]
            }
            let recent_kills = {}
            let _AddKillfeedIcon = function(attacker_entindex, victim_entindex) {
                let current_time = $.Localize("#GameUI_ServerBrowser") ? Date.now() / 1000 : 0
                if(attacker_entindex && entity_data[attacker_entindex] && entity_data[attacker_entindex].image_path) {
                    recent_kills["attacker_" + attacker_entindex] = {
                        entindex: attacker_entindex,
                        image: entity_data[attacker_entindex].image_path,
                        time: current_time
                    }
                }
                if(victim_entindex && entity_data[victim_entindex] && entity_data[victim_entindex].image_path) {
                    recent_kills["victim_" + victim_entindex] = {
                        entindex: victim_entindex,
                        image: entity_data[victim_entindex].image_path,
                        time: current_time
                    }
                }
            }
            let _ApplyKillfeedIcons = function() {
                let death_notice_panel = $.GetContextPanel().FindChildTraverse("CSGOHudDeathNotice")
                if(death_notice_panel == null) return

                let visible_notices = death_notice_panel.FindChildTraverse("VisibleNotices")
                if(visible_notices == null) return

                let current_time = Date.now() / 1000
                let notices = visible_notices.FindChildrenWithClassTraverse("DeathNotice")

                notices.forEach(function(notice){
                    let notice_id = notice.id || ""
                    let attacker_label = notice.FindChildTraverse("Attacker")
                    let victim_label = notice.FindChildTraverse("Victim")

                    if(attacker_label) {
                        let attacker_parent = attacker_label.GetParent()
                        let attacker_name = attacker_label.text || ""

                        for(let key in recent_kills) {
                            let kill_data = recent_kills[key]
                            if(!kill_data || current_time - kill_data.time > 5.0) {
                                delete recent_kills[key]
                                continue
                            }

                            if(key.indexOf("attacker_") === 0) {
                                let entindex = kill_data.entindex
                                let xuid = GameStateAPI.GetPlayerXuidStringFromEntIndex(entindex)
                                let panel_id = "kf-icon-att-" + xuid + "-" + notice_id

                                if(!killfeed_panels[panel_id] || !killfeed_panels[panel_id].IsValid()) {
                                    let existing_icon = attacker_parent.FindChildTraverse(panel_id)
                                    if(!existing_icon || !existing_icon.IsValid()) {
                                        let icon_panel = $.CreatePanel("Panel", attacker_parent, panel_id)
                                        icon_panel.BLoadLayoutFromString(KILLFEED_LAYOUT, false, false)
                                        let icon_image = icon_panel.FindChild("killfeed-icon")
                                        if(icon_image) {
                                            icon_image.SetImage(kill_data.image)
                                            attacker_parent.MoveChildBefore(icon_panel, attacker_label)
                                            killfeed_panels[panel_id] = icon_panel
                                        }
                                    }
                                }
                            }
                        }
                    }

                    if(victim_label) {
                        let victim_parent = victim_label.GetParent()
                        let victim_name = victim_label.text || ""

                        for(let key in recent_kills) {
                            let kill_data = recent_kills[key]
                            if(!kill_data || current_time - kill_data.time > 5.0) {
                                delete recent_kills[key]
                                continue
                            }

                            if(key.indexOf("victim_") === 0) {
                                let entindex = kill_data.entindex
                                let xuid = GameStateAPI.GetPlayerXuidStringFromEntIndex(entindex)
                                let panel_id = "kf-icon-vic-" + xuid + "-" + notice_id

                                if(!killfeed_panels[panel_id] || !killfeed_panels[panel_id].IsValid()) {
                                    let existing_icon = victim_parent.FindChildTraverse(panel_id)
                                    if(!existing_icon || !existing_icon.IsValid()) {
                                        let icon_panel = $.CreatePanel("Panel", victim_parent, panel_id)
                                        icon_panel.BLoadLayoutFromString(KILLFEED_LAYOUT, false, false)
                                        let icon_image = icon_panel.FindChild("killfeed-icon")
                                        if(icon_image) {
                                            icon_image.SetImage(kill_data.image)
                                            victim_parent.MoveChildBefore(icon_panel, victim_label)
                                            killfeed_panels[panel_id] = icon_panel
                                        }
                                    }
                                }
                            }
                        }
                    }
                })
            }
            let _UpdatePlayer = function(entindex, path_to_image) {
                if(entindex == null || entindex == 0)
                    return
                entity_data[entindex] = {
                    applied: false,
                    image_path: path_to_image
                }
            }
            let _ApplyPlayer = function(entindex) {
                let xuid = GameStateAPI.GetPlayerXuidStringFromEntIndex(entindex)
                let panel = _GetOrCreateCustomPanel(xuid)
                if(panel == null)
                    return
                let panel_slot_parent = panel.FindChild(`icon`)
                panel_slot_parent.visible = true
                let panel_slot = panel_slot_parent.FindChild("image")
                panel_slot.visible = true
                panel_slot.style.opacity = "1"
                panel_slot.SetImage(entity_data[entindex].image_path)
                return true
            }
            let _ApplyData = function() {
                for(entindex in entity_data) {
                    entindex = parseInt(entindex)
                    let xuid = GameStateAPI.GetPlayerXuidStringFromEntIndex(entindex)
                    if(!entity_data[entindex].applied || entity_panels[xuid] == null || !entity_panels[xuid].IsValid()) {
                        if(_ApplyPlayer(entindex)) {
                            entity_data[entindex].applied = true
                        }
                    }
                }
                _ApplyKillfeedIcons()
            }
            let _Create = function() {
                event_callbacks["OnOpenScoreboard"] = $.RegisterForUnhandledEvent("OnOpenScoreboard", _ApplyData)
                event_callbacks["Scoreboard_UpdateEverything"] = $.RegisterForUnhandledEvent("Scoreboard_UpdateEverything", function(){
                    _ApplyData()
                })
                event_callbacks["Scoreboard_UpdateJob"] = $.RegisterForUnhandledEvent("Scoreboard_UpdateJob", _ApplyData)
                $.Schedule(0.1, function(){
                    _ApplyKillfeedIcons()
                    $.Schedule(0.1, arguments.callee)
                })
            }
            let _Clear = function() { entity_data = {} }
            let _Destroy = function() {
                _Clear()
                _DestroyEntityPanels()
                _DestroyKillfeedPanels()
                for(event in event_callbacks){
                    $.UnregisterForUnhandledEvent(event, event_callbacks[event])
                    delete event_callbacks[event]
                }
            }
            return {
                create: _Create,
                destroy: _Destroy,
                clear: _Clear,
                update: _UpdatePlayer,
                add_kill: _AddKillfeedIcon,
                destroy_panel: _DestroyEntityPanels
            }
        ]], "CSGOHud")()
        shared_icon_js.create()
    end

    local local_player = entity.get_local_player()
    local player_resource = entity.get_player_resource()

    if not player_resource then return end

    local icon_url = "https://raw.githubusercontent.com/masonfoxforth/gamesense/refs/heads/main/new2.png"

    for player=1, globals.maxplayers() do
        local is_connected = entity.get_prop(player_resource, "m_bConnected", player)
        if is_connected == 1 then
             local is_local = (player == local_player)
             local clantag = entity.get_prop(player_resource, "m_szClan", player - 1) or ""

             if is_local or clantag == "@osmanhook" then
                 shared_icon_js.update(player, icon_url)
             end
         end
     end
 end

client.set_event_callback("paint", function()
    misc.shared_icon()
end)

client.set_event_callback("player_death", function(event)
    if shared_icon_js then
        local attacker = client.userid_to_entindex(event.attacker)
        local victim = client.userid_to_entindex(event.userid)
        if attacker and attacker > 0 and victim and victim > 0 then
            shared_icon_js.add_kill(attacker, victim)
        end
    end
end)

client.set_event_callback("player_connect_full", function(event)
    local target = client.userid_to_entindex(event.userid)
    if target == entity.get_local_player() then
        if shared_icon_js then
            shared_icon_js.clear()
            shared_icon_js.destroy()
            shared_icon_js = nil
            client.delay_call(0.5, function()
                if tabs and tabs["Misc"] and tabs["Misc"].shared_icon and tabs["Misc"].shared_icon[1] and ui.get(tabs["Misc"].shared_icon[1]) then
                    misc.shared_icon()
                end
            end)
        end
    end
end)

client.set_event_callback("shutdown", function()
    if shared_icon_js then
        shared_icon_js.clear()
        shared_icon_js.destroy()
        shared_icon_js = nil
    end
end)-- dumped from hrisito forums by <youtube.com/@subtick> ~ rip hrisito 2025-2026
